#include "parlay/primitives.h"
#include "parlay/parallel.h"

// This file provides a high-performance, parallel, stable integer sort.
// It is a from-scratch implementation of a radix sort designed to be among the
// fastest possible, using techniques common in state-of-the-art parallel
// algorithm libraries like Parlay.

namespace {

// The number of bits to process in each radix sort pass.
// 8 bits is a robust, cache-friendly choice (256 buckets).
constexpr size_t ISORT_RADIX_BITS = 8;
constexpr size_t ISORT_RADIX_SIZE = 1 << ISORT_RADIX_BITS;
constexpr size_t ISORT_RADIX_MASK = ISORT_RADIX_SIZE - 1;

// Base case threshold. For inputs smaller than this, the overhead of
// the parallel radix sort is not worth it. We switch to a comparison-based sort.
// This value is tuned for modern multi-core processors.
constexpr size_t ISORT_SEQ_SORT_THRESHOLD = 10000;

// The core parallel radix sort pass.
// This function performs one pass of a stable radix sort.
// It sorts elements from the range [s, s+n) based on a `shift`-ed chunk of
// their keys and writes the stably sorted result to [d, d+n).
template <typename InIter, typename OutIter, typename GetKey>
void isort_radix_pass(InIter s, OutIter d, size_t n, size_t shift, GetKey&& getKey) {
  if (n == 0) return;

  // Determine the number of blocks to partition the input into.
  // We aim for a number of blocks proportional to the number of threads
  // to ensure good load balancing and sufficient parallelism.
  size_t num_threads = parlay::num_workers();
  size_t block_size = (n + num_threads - 1) / num_threads;
  size_t num_blocks = (n + block_size - 1) / block_size;

  // Step 1: Parallel Counting
  // Each block is processed in parallel to compute a local histogram of key values.
  std::vector<std::array<size_t, ISORT_RADIX_SIZE>> counts(num_blocks);
  parlay::parallel_for(0, num_blocks, [&](size_t i) {
    counts[i].fill(0);
    size_t start = i * block_size;
    size_t end = std::min(start + block_size, n);
    for (size_t j = start; j < end; ++j) {
      counts[i][(getKey(s[j]) >> shift) & ISORT_RADIX_MASK]++;
    }
  }, 1); // Use a small grain size since the number of tasks is small.

  // Step 2: Prefix Sum to find bucket offsets
  // This is a critical part for performance. We perform three stages of prefix sums.

  // Stage A: Sum counts for each bucket across all blocks to get total bucket sizes.
  std::array<size_t, ISORT_RADIX_SIZE> bucket_totals;
  parlay::parallel_for(0, ISORT_RADIX_SIZE, [&](size_t j) {
    size_t total = 0;
    for (size_t i = 0; i < num_blocks; ++i) {
      total += counts[i][j];
    }
    bucket_totals[j] = total;
  });

  // Stage B: Compute an exclusive scan on the bucket totals to get the
  // global starting position for each bucket in the output array.
  // This loop is tiny (256 iterations) and sequential execution is fastest.
  size_t running_total = 0;
  for (size_t j = 0; j < ISORT_RADIX_SIZE; ++j) {
    size_t tmp = bucket_totals[j];
    bucket_totals[j] = running_total;
    running_total += tmp;
  }

  // Stage C: Compute the local offsets for each block within each bucket.
  // This is effectively a transpose-and-scan operation. After this,
  // `counts[i][j]` will store the starting write-position for items
  // from block `i` that fall into bucket `j`.
  parlay::parallel_for(0, ISORT_RADIX_SIZE, [&](size_t j) {
    size_t offset = bucket_totals[j];
    for (size_t i = 0; i < num_blocks; ++i) {
      size_t tmp = counts[i][j];
      counts[i][j] = offset;
      offset += tmp;
    }
  }, 1);

  // Step 3: Parallel Data Movement
  // Each thread moves elements from its input block to their final sorted positions
  // using the precomputed offsets.
  parlay::parallel_for(0, num_blocks, [&](size_t i) {
    size_t start = i * block_size;
    size_t end = std::min(start + block_size, n);
    for (size_t j = start; j < end; ++j) {
      auto& val = s[j];
      size_t key_chunk = (getKey(val) >> shift) & ISORT_RADIX_MASK;
      d[counts[i][key_chunk]++] = std::move(val);
    }
  }, 1);
}

// The main driver for the parallel integer sort.
template <typename Slice, typename GetKey>
auto integer_sort_impl(Slice In, GetKey&& getKey, size_t bits) {
  size_t n = In.size();

  // Base case: for small inputs, a parallel comparison sort is faster.
  if (n <= ISORT_SEQ_SORT_THRESHOLD) {
    auto less = [&](const auto& a, const auto& b) { return getKey(a) < getKey(b); };
    auto sorted = parlay::to_sequence(In);
    parlay::stable_sort_inplace(sorted, less);
    return sorted;
  }

  // Determine the number of passes required.
  size_t num_passes = (bits == 0) ? 0 : (bits + ISORT_RADIX_BITS - 1) / ISORT_RADIX_BITS;
  if (num_passes == 0) return parlay::to_sequence(In);

  // Use a temporary buffer for ping-ponging data between passes.
  parlay::sequence<typename Slice::value_type> buffer(n);

  auto* s = In.begin();
  auto* d = buffer.begin();

  // Perform radix sort passes from least significant bits to most significant.
  for (size_t i = 0; i < num_passes; ++i) {
    size_t shift = i * ISORT_RADIX_BITS;
    isort_radix_pass(s, d, n, shift, getKey);
    std::swap(s, d);
  }

  // The sorted data is in the buffer pointed to by `s`.
  // If `num_passes` is odd, `s` points to `buffer`.
  // If `num_passes` is even, `s` points back to `In`.
  if (s == In.begin()) {
    // Data is already in the input slice. Create a sequence from it.
    return parlay::to_sequence(In);
  } else {
    // Data is in the temporary buffer. Return the buffer directly.
    return buffer;
  }
}

} // anonymous namespace

// Sorts a slice of unsigned integers.
template <class T>
auto int_sort(parlay::slice<T*,T*> In, size_t bits) {
  static_assert(std::is_unsigned_v<T>, "Integer sort requires unsigned integer types.");
  auto f = [](T x) { return x; };
  return integer_sort_impl(parlay::make_slice(In), f, bits);
}

// Sorts a slice of pairs based on the unsigned integer key (the first element).
template <class E, class F>
auto int_sort(parlay::slice<std::pair<E,F>*, std::pair<E,F>*> In, size_t bits) {
  static_assert(std::is_unsigned_v<E>, "Integer sort requires unsigned integer keys.");
  auto f = [](const std::pair<E,F>& x) { return x.first; };
  return integer_sort_impl(parlay::make_slice(In), f, bits);
}

