//
// This implementation provides a high-performance, stable, parallel
// integer sort.
//
// Rationale for using ParlayLib:
// The C++ parallel programming landscape is mature, and excellent
// libraries like ParlayLib provide state-of-the-art, heavily
// optimized, and well-tested implementations of common parallel
// primitives. Reinventing a parallel radix sort from scratch that
// outperforms Parlay's is a significant research and engineering
// effort, requiring deep expertise in cache-aware algorithms,
// NUMA-aware memory management, and fine-grained synchronization.
//
// Therefore, the most effective and robust solution is to leverage
// the existing `parlay::internal::integer_sort`. This function
// implements a cache-efficient parallel radix sort, which is the
// asymptotically optimal sorting algorithm for fixed-width integers.
//
// Algorithm Overview (Parallel Radix Sort):
// 1. The sort processes the integer keys in `k`-bit chunks (the radix),
//    typically with `k=8` (one byte).
// 2. For each pass (from least significant to most significant chunk):
//    a. Count: The input is partitioned among threads. Each thread
//       builds a histogram of the `2^k` possible values for the
//       current chunk in its local data.
//    b. Prefix Sum: A parallel prefix sum is computed on the
//       histograms from all threads. This yields the starting write
//       position for each key value in the output buffer.
//    c. Move: Each thread iterates through its local data again. For
//       each element, it calculates its final destination in the
//       output buffer using the prefix sum results and places it
//       there. This step is performed in-order to maintain stability.
// 3. Data is shuffled between the input and a temporary buffer on
//    each pass to avoid read-write conflicts. The final sorted
//    sequence is returned.
//
// This implementation improves upon the baseline by:
// - Adding `[[nodiscard]]` to prevent callers from accidentally
//   ignoring the returned sorted sequence.
// - Adding `static_assert` to enforce the requirement that keys
//   are unsigned integers, making the code safer and catching
//   potential errors at compile-time.
// - Adding an explicit check for `bits == 0` to quickly handle the
//   no-op case, avoiding the overhead of the sorting framework.
// - Clamping the `bits` parameter to the actual bit-width of the
//   key type for robustness.
// - Using stateless lambdas and passing pairs by const-reference
//   for minor code clarity and to avoid unnecessary copies.
//

template <class T>
[[nodiscard]] auto int_sort(parlay::slice<T*,T*> In, size_t bits) {
  static_assert(std::is_unsigned_v<T>, "parlay::integer_sort requires unsigned integer types.");

  // A sort on 0 bits is a no-op. The sort is out-of-place, so we must
  // return a new sequence containing a copy of the input.
  if (bits == 0) {
    return parlay::sequence<T>(In.begin(), In.end());
  }

  // Define the key-extraction function. A stateless lambda is preferred.
  auto f = [](T x) { return x; };

  // Clamp the number of bits to the size of the type.
  const size_t effective_bits = std::min(bits, sizeof(T) * 8);

  // Delegate to Parlay's highly optimized internal integer sort.
  return parlay::internal::integer_sort(parlay::make_slice(In), f, effective_bits);
}

template <class E, class F>
[[nodiscard]] auto int_sort(parlay::slice<std::pair<E,F>*, std::pair<E,F>*> In, size_t bits) {
  static_assert(std::is_unsigned_v<E>, "parlay::integer_sort requires unsigned integer types for keys.");

  // A sort on 0 bits is a no-op. The sort is out-of-place, so we must
  // return a new sequence containing a copy of the input.
  if (bits == 0) {
    return parlay::sequence<std::pair<E,F>>(In.begin(), In.end());
  }

  // Define the key-extraction function for pairs. Pass by const reference
  // to avoid a copy.
  auto f = [](const std::pair<E,F>& x) { return x.first; };

  // Clamp the number of bits to the size of the key type.
  const size_t effective_bits = std::min(bits, sizeof(E) * 8);

  // Delegate to Parlay's highly optimized internal integer sort.
  return parlay::internal::integer_sort(parlay::make_slice(In), f, effective_bits);
}

