// Sorts a sequence of unsigned integers.
// This is an optimized version that first determines the actual bit range of the
// input data to avoid unnecessary radix sort passes.
template <class T>
auto int_sort(parlay::slice<T*,T*> In, size_t bits) {
  // The key is the element itself.
  auto f = [](T x) { return x; };

  // Optimization: Find the maximum key to reduce the number of sort passes.
  // This is a significant win if the actual key range is much smaller than
  // implied by the `bits` parameter (e.g., keys in [0, 255] but `bits` is 64).
  // The overhead is a single parallel reduction, which is much cheaper than
  // a full radix sort pass.
  if (!In.empty()) {
    // Find the maximum key value in parallel. parlay::reduce is highly optimized.
    auto max_key = parlay::reduce(In, parlay::maxm<T>());

    // Calculate the minimum number of bits required to distinguish all keys.
    // #bits = ceil(log2(max_key + 1)). parlay::log2_up(N) computes ceil(log2(N)).
    // If max_key is 0, all keys are 0, so 0 bits are needed for sorting.
    size_t actual_bits = (max_key == 0) ? 0 : parlay::log2_up(max_key + 1);

    // Use the smaller of the user-provided bits and the actual required bits.
    bits = std::min(bits, actual_bits);
  }

  // Call Parlay's highly optimized internal integer sort. It is a stable
  // parallel radix sort that is cache-efficient and handles skewed data well.
  return parlay::internal::integer_sort(parlay::make_slice(In), f, bits);
}

// Sorts a sequence of pairs based on the first element (the key).
// This is an optimized version that first determines the actual bit range of the
// input keys to avoid unnecessary radix sort passes.
template <class E, class F>
auto int_sort(parlay::slice<std::pair<E,F>*, std::pair<E,F>*> In, size_t bits) {
  // The key is the first element of the pair.
  auto f = [](const std::pair<E,F>& x) { return x.first; };

  // Optimization: Find the maximum key to reduce the number of sort passes.
  if (!In.empty()) {
    // Use parlay::delayed_map to apply the key-extraction function `f` on the fly,
    // avoiding the allocation of an intermediate array of keys. This is crucial
    // for performance and memory efficiency.
    auto keys = parlay::delayed_map(In, f);

    // Find the maximum key value in parallel.
    auto max_key = parlay::reduce(keys, parlay::maxm<E>());

    // Calculate the minimum number of bits required.
    size_t actual_bits = (max_key == 0) ? 0 : parlay::log2_up(max_key + 1);

    // Use the smaller of the user-provided bits and the actual required bits.
    bits = std::min(bits, actual_bits);
  }

  // Call Parlay's highly optimized internal integer sort.
  return parlay::internal::integer_sort(parlay::make_slice(In), f, bits);
}

