namespace parlay {
namespace internal {

// A high-performance, stable, parallel, least-significant-digit (LSD) first
// radix sort implementation.
//
// The algorithm works as follows:
// 1. It iterates through the bits of the integer keys, 8 bits at a time (a byte).
// 2. In each pass, it performs a stable sort on the current byte of the keys.
//    This stable sort is a parallel counting sort.
// 3. The parallel counting sort works in three stages:
//    a. Histogram: The input is divided into blocks. Each thread computes a local
//       histogram (256 counts) for its block. This is highly parallel.
//    b. Prefix Sum: The local histograms are transposed and scanned to compute
//       the starting position in the output array for each byte value from each block.
//    c. Permute: Each thread reads its input block again and, using the precomputed
//       offsets, moves each element to its final sorted position in an output buffer.
// 4. A double-buffering technique is used: the roles of the input and output
//    buffers are swapped after each pass to avoid memory allocations and copies.
// 5. The implementation is generic and works on any sequence of elements as long
//    as an extractor function `f` is provided to get an unsigned integer key.
// 6. For small inputs, it falls back to a parallel comparison-based sort
//    (parlay::stable_sort) to avoid the high overhead of radix sort.

template <typename In_S, typename F>
auto integer_sort(In_S&& s, F f, size_t bits) {
  using T = typename std::decay_t<In_S>::value_type;
  using K = std::invoke_result_t<F, T>;

  static_assert(std::is_unsigned_v<K>, "parlay::internal::integer_sort requires unsigned integer keys.");

  constexpr size_t kRadix = 8;
  constexpr size_t kHistSize = 1 << kRadix;

  size_t n = s.size();

  // For small inputs, a comparison-based sort is faster due to overheads.
  if (n < 2048) {
    return parlay::stable_sort(std::forward<In_S>(s), [&](const auto& a, const auto& b) {
      return f(a) < f(b);
    });
  }

  // Double-buffering strategy to avoid allocations in each pass
  auto tmp = parlay::sequence<T>::uninitialized(n);
  auto s_in = parlay::make_slice(s);
  auto s_out = parlay::make_slice(tmp);

  // Calculate the number of passes required for the given number of bits
  size_t num_passes = (bits == 0) ? 0 : (bits + kRadix - 1) / kRadix;

  for (size_t pass = 0; pass < num_passes; ++pass) {
    size_t shift = pass * kRadix;
    size_t current_radix_bits = std::min(kRadix, bits - shift);

    // Create a mask for the current chunk of bits
    K mask = (current_radix_bits >= std::numeric_limits<K>::digits)
                 ? std::numeric_limits<K>::max()
                 : (static_cast<K>(1) << current_radix_bits) - 1;

    // 1. Compute block-local histograms in parallel
    size_t block_size = (n + get_num_workers() * 4 - 1) / (get_num_workers() * 4);
    block_size = std::max<size_t>(block_size, 2048);
    size_t num_blocks = (n + block_size - 1) / block_size;

    auto histograms = parlay::sequence<parlay::sequence<size_t>>::from_function(num_blocks, [&](size_t i) {
      parlay::sequence<size_t> hist(kHistSize, 0);
      size_t start = i * block_size;
      size_t end = std::min(start + block_size, n);
      for (size_t j = start; j < end; ++j) {
        hist[(f(s_in[j]) >> shift) & mask]++;
      }
      return hist;
    });

    // 2. Compute global offsets for each bucket
    auto transposed_hists = parlay::transpose(histograms);

    auto bucket_offsets = parlay::sequence<parlay::sequence<size_t>>::from_function(kHistSize, [&](size_t i) {
        return parlay::scan_inclusive(transposed_hists[i]);
    });

    auto bucket_totals = parlay::sequence<size_t>::from_function(kHistSize, [&](size_t i) {
      return bucket_offsets[i].empty() ? 0 : bucket_offsets[i].back();
    });

    auto global_offsets = parlay::scan_inclusive(bucket_totals);

    // 3. Permute the data into the output buffer in parallel
    parlay::parallel_for(0, num_blocks, [&](size_t i) {
      size_t start = i * block_size;
      size_t end = std::min(start + block_size, n);

      auto local_offsets = parlay::sequence<size_t>::from_function(kHistSize, [&](size_t b) {
        size_t global_start = (b == 0) ? 0 : global_offsets[b - 1];
        size_t local_start = (i == 0) ? 0 : bucket_offsets[b][i - 1];
        return global_start + local_start;
      });

      for (size_t j = start; j < end; ++j) {
        size_t bucket = (f(s_in[j]) >> shift) & mask;
        s_out[local_offsets[bucket]++] = std::move(s_in[j]);
      }
    }, 1); // Granularity of 1 ensures one task per block

    // Swap buffers for the next pass
    std::swap(s_in, s_out);
  }

  // After the loop, the sorted data is in s_in.
  // If the number of passes is odd, the data is in the temporary buffer `tmp`.
  // If the number of passes is even, the data is back in the original buffer `s`.
  // The function must return a new sequence containing the sorted data.
  if (num_passes % 2 == 1) {
    // Data is in tmp, so we can return it directly.
    return tmp;
  } else {
    // Data is in the original slice s. We must copy it to a new sequence to return.
    return parlay::sequence<T>(s.begin(), s.end());
  }
}

} // namespace internal
} // namespace parlay


// The public-facing functions as requested by the benchmark.
// These simply wrap the call to the internal implementation.

template <class T>
auto int_sort(parlay::slice<T*,T*> In, size_t bits) {
  // Key extractor for single integers
  auto f = [](T x) { return x; };
  return parlay::internal::integer_sort(parlay::make_slice(In), f, bits);
}

template <class E, class F>
auto int_sort(parlay::slice<std::pair<E,F>*, std::pair<E,F>*> In, size_t bits) {
  // Key extractor for pairs (sorts on the first element)
  auto f = [](const std::pair<E,F>& x) { return x.first; };
  return parlay::internal::integer_sort(parlay::make_slice(In), f, bits);
}

#include "parlay/primitives.h"
#include "parlay/sequence.h"
#include "parlay/slice.h"

#include <algorithm>
#include <utility>

namespace my_isort {

constexpr size_t kRadixBits = 8;
constexpr size_t kRadixSize = 1 << kRadixBits;
constexpr size_t kSeqThreshold = 4096;
constexpr size_t kTransposeBlockSize = 32;

// Sequential, stable count-sort pass for small inputs or the base case.
// It iterates backwards over the input when placing elements to ensure stability.
template <typename InIt, typename OutIt, typename KeyFn>
void seq_radix_sort_pass(InIt first, InIt last, OutIt out, KeyFn get_key) {
  size_t n = std::distance(first, last);
  if (n == 0) return;

  size_t counts[kRadixSize] = {0};
  for (auto it = first; it != last; ++it) {
    counts[get_key(*it)]++;
  }

  // Exclusive scan to find bucket starting positions
  size_t offset = 0;
  for (size_t i = 0; i < kRadixSize; i++) {
    size_t tmp = counts[i];
    counts[i] = offset;
    offset += tmp;
  }

  // Scatter elements to their new positions
  for (auto it = first; it != last; ++it) {
    out[counts[get_key(*it)]++] = std::move(*it);
  }
}

// Parallel, stable count-sort pass. This is the core of the radix sort.
// It uses a two-level counting scheme that is highly parallel and scalable.
template <typename InIt, typename OutIt, typename KeyFn>
void radix_sort_pass(parlay::slice<InIt, InIt> in, parlay::slice<OutIt, OutIt> out, KeyFn get_key) {
  size_t n = in.size();
  if (n <= kSeqThreshold) {
    seq_radix_sort_pass(in.begin(), in.end(), out.begin(), get_key);
    return;
  }

  // Oversubscribe to get more, smaller blocks, improving load balance.
  const size_t num_blocks = parlay::num_workers() * 4;
  const size_t block_size = (n + num_blocks - 1) / num_blocks;

  // 1. Compute local histograms for each block in parallel.
  auto hists = parlay::sequence<size_t>::uninitialized(num_blocks * kRadixSize);
  parlay::parallel_for(0, num_blocks, [&](size_t i) {
    auto local_hists = parlay::make_slice(hists.begin() + i * kRadixSize, hists.begin() + (i + 1) * kRadixSize);
    std::fill(local_hists.begin(), local_hists.end(), 0);
    size_t start = std::min(i * block_size, n);
    size_t end = std::min(start + block_size, n);
    for (size_t j = start; j < end; j++) {
      local_hists[get_key(in[j])]++;
    }
  }, 1);

  // 2. Transpose histograms for efficient prefix sums per bucket.
  // A blocked transpose is used to improve cache performance.
  auto T_hists = parlay::sequence<size_t>::uninitialized(kRadixSize * num_blocks);
  parlay::parallel_for(0, (num_blocks + kTransposeBlockSize - 1) / kTransposeBlockSize, [&](size_t p_b) {
    parlay::parallel_for(0, (kRadixSize + kTransposeBlockSize - 1) / kTransposeBlockSize, [&](size_t k_b) {
      size_t p_start = p_b * kTransposeBlockSize;
      size_t p_end = std::min((p_b + 1) * kTransposeBlockSize, num_blocks);
      size_t k_start = k_b * kTransposeBlockSize;
      size_t k_end = std::min((k_b + 1) * kTransposeBlockSize, kRadixSize);
      for (size_t p = p_start; p < p_end; p++) {
        for (size_t k = k_start; k < k_end; k++) {
          T_hists[k * num_blocks + p] = hists[p * kRadixSize + k];
        }
      }
    });
  });

  // 3. Compute inclusive prefix sums for each bucket across all blocks.
  parlay::parallel_for(0, kRadixSize, [&](size_t k) {
    auto row = parlay::make_slice(T_hists.begin() + k * num_blocks, T_hists.begin() + (k + 1) * num_blocks);
    parlay::scan_inclusive_inplace(row);
  }, 1);

  // 4. Compute global bucket starting positions via an exclusive scan.
  auto bucket_starts = parlay::sequence<size_t>::uninitialized(kRadixSize);
  parlay::parallel_for(0, kRadixSize, [&](size_t k) {
    bucket_starts[k] = T_hists[(k + 1) * num_blocks - 1]; // Total count for bucket k
  });
  parlay::scan_inplace(bucket_starts); // Exclusive scan for start positions

  // 5. Compute final write offsets for each block.
  // The original `hists` memory is reused to store these offsets.
  parlay::parallel_for(0, num_blocks, [&](size_t p) {
    auto my_offsets = parlay::make_slice(hists.begin() + p * kRadixSize, hists.begin() + (p + 1) * kRadixSize);
    for (size_t k = 0; k < kRadixSize; k++) {
      size_t local_offset = (p == 0) ? 0 : T_hists[k * num_blocks + p - 1];
      my_offsets[k] = bucket_starts[k] + local_offset;
    }
  });

  // 6. Scatter elements to their sorted positions. This is the move step.
  parlay::parallel_for(0, num_blocks, [&](size_t i) {
    size_t start = std::min(i * block_size, n);
    size_t end = std::min(start + block_size, n);
    auto my_offsets = parlay::make_slice(hists.begin() + i * kRadixSize, hists.begin() + (i + 1) * kRadixSize);
    for (size_t j = start; j < end; j++) {
      size_t k = get_key(in[j]);
      out[my_offsets[k]++] = std::move(in[j]);
    }
  }, 1);
}

