    my_isort::radix_sort_pass(from->slice(), to->slice(), get_key_for_pass);
    std::swap(from, to);
  }

  // After the loops, `from` points to the sequence with the sorted data.
  // We return that sequence, relying on RVO to avoid a copy.
  if (from == &s) {
    return s;
  } else {
    return tmp;
  }
}

