// Forward declaration for the pointer-based sort helper.
template <class PtrIt, class Comp>
void sample_sort_ptr_helper(parlay::slice<PtrIt, PtrIt> s_ptr, const Comp& comp);

// A fully recursive, in-place parallel sample sort for trivially relocatable types.
// This is efficient for types like double, int, and std::pair<double, double>
// where moving elements is as cheap as copying a pointer.
template <class It, class Comp>
void sample_sort_recursive(parlay::slice<It, It> s, const Comp& comp) {
  long n = s.size();

  // Base case: For small inputs, switch to a fast sequential sort.
  // std::sort is highly optimized, often using introsort. 2048 is a
  // well-tuned threshold for switching from parallel to sequential.
  if (n <= 2048) {
    std::sort(s.begin(), s.end(), comp);
    return;
  }

  // 1. Sampling: Select a random sample of the elements.
  // The sample size is crucial for balancing the buckets. A size proportional
  // to p * log(n) is theoretically sound and works well in practice.
  size_t num_workers = parlay::num_workers();
  // Target at least 2 buckets per worker to ensure sufficient parallelism.
  size_t num_buckets = 1 << parlay::log2_up(num_workers * 2);
  // An oversampling factor of 10.0 is a robust choice.
  double oversample_factor = 10.0;
  size_t sample_size = std::min((size_t)n,
        (size_t)(oversample_factor * num_buckets * (1 + parlay::log2_up(n))));

  auto sample = parlay::random_subset(s, sample_size);
  std::sort(std::begin(sample), std::end(sample), comp);

  // 2. Select Splitters: Choose num_buckets-1 splitters from the sorted sample
  // to partition the data into num_buckets buckets.
  auto splitters = parlay::sequence<typename parlay::slice<It, It>::value_type>::from_function(num_buckets - 1,
    [&](size_t i) { return sample[(i + 1) * sample.size() / num_buckets]; });

  // 3. Partition: Use parlay's highly optimized internal primitive to classify
  // and permute elements into a temporary buffer based on the splitters.
  auto get_key = [](auto&& x) -> decltype(auto) { return std::forward<decltype(x)>(x); };
  auto bucketed = parlay::internal::bucket_and_permute(s, splitters, get_key, comp);

  // 4. Move elements back: To make the sort in-place, move the bucketed
  // elements from the temporary buffer back into the original slice.
  parlay::parallel_for(0, n, [&](size_t i) {
    s[i] = std::move(bucketed.p[i]);
  });

  // Free the memory of the temporary buffer before recursing to reduce peak memory usage.
  bucketed.p.clear();
  bucketed.p.shrink_to_fit();

  // 5. Recurse: Sort each bucket in parallel.
  parlay::parallel_for(0, num_buckets, [&](size_t i) {
    auto b = bucketed.get_bucket(i);
    // The bucket b is a slice of the temporary buffer. We need to find the
    // corresponding slice in the original array s to recurse on.
    auto sub_s = s.cut(b.begin() - std::begin(bucketed.p), b.end() - std::begin(bucketed.p));
    if (!sub_s.empty()) {
      sample_sort_recursive(sub_s, comp);
    }
  }, 1); // Use a coarse grain size of 1 since there are few buckets.
}

// Top-level driver for pointer-based sample sort.
// This is for types with expensive move-construction (e.g., std::string) or
// large sizeof. We sort pointers to the elements and permute the original
// sequence only once at the end.
template <class It, class Comp>
void sample_sort_ptr(parlay::slice<It, It> s, const Comp& comp) {
  long n = s.size();
  if (n == 0) return;

  using T = typename parlay::slice<It, It>::value_type;

  // Create a sequence of pointers to the elements.
  auto ptrs = parlay::sequence<T*>::from_function(n, [&](size_t i) { return &s[i]; });

  // Define a comparator that dereferences the pointers.
  auto ptr_comp = [&](T* a, T* b) { return comp(*a, *b); };

  // Sort the sequence of pointers recursively.
  sample_sort_ptr_helper(parlay::make_slice(ptrs), ptr_comp);

  // Permute the original data according to the sorted pointers.
  // This requires an auxiliary buffer to avoid overwriting elements
  // before they have been moved. parlay::internal::uninitialized_sequence
  // is used for performance as it avoids default-constructing T.
  parlay::internal::uninitialized_sequence<T> temp_s(n);
  parlay::parallel_for(0, n, [&](size_t i) {
    temp_s.emplace_back(std::move(*(ptrs[i])), i);
  });
  parlay::parallel_for(0, n, [&](size_t i) {
    s[i] = std::move(temp_s[i]);
  });
}

// Recursive helper for the pointer-based sort. This function contains the
// core recursive logic, operating on a slice of pointers.
template <class PtrIt, class Comp>
void sample_sort_ptr_helper(parlay::slice<PtrIt, PtrIt> s_ptr, const Comp& comp) {
  long n = s_ptr.size();

  if (n <= 2048) {
    std::sort(s_ptr.begin(), s_ptr.end(), comp);
    return;
  }

  // 1. Sampling (on pointers)
  size_t num_workers = parlay::num_workers();
  size_t num_buckets = 1 << parlay::log2_up(num_workers * 2);
  // For strings, comparisons are expensive. A larger sample improves balance,
  // which is worth the extra cost of sorting the sample.
  double oversample_factor = 15.0;
  size_t sample_size = std::min((size_t)n,
        (size_t)(oversample_factor * num_buckets * (1 + parlay::log2_up(n))));

  auto sample = parlay::random_subset(s_ptr, sample_size);
  std::sort(std::begin(sample), std::end(sample), comp);

  // 2. Select Splitters (these are pointers to elements in the original sequence)
  auto splitters = parlay::sequence<typename parlay::slice<PtrIt, PtrIt>::value_type>::from_function(num_buckets - 1,
    [&](size_t i) { return sample[(i + 1) * sample.size() / num_buckets]; });

  // 3. Partition pointers
  using T = typename std::remove_pointer<typename parlay::slice<PtrIt, PtrIt>::value_type>::type;
  auto get_val = [](T* p) -> T& { return *p; };
  auto bucketed = parlay::internal::bucket_and_permute(s_ptr, splitters, get_val, comp);

  // Move bucketed pointers back to the original pointer slice to make it in-place on ptrs.
  parlay::parallel_for(0, n, [&](size_t i) {
    s_ptr[i] = bucketed.p[i];
  });
  bucketed.p.clear();
  bucketed.p.shrink_to_fit();

  // 4. Recurse on pointer buckets
  parlay::parallel_for(0, num_buckets, [&](size_t i) {
    auto b = bucketed.get_bucket(i);
    auto sub_s_ptr = s_ptr.cut(b.begin() - std::begin(bucketed.p), b.end() - std::begin(bucketed.p));
    if (!sub_s_ptr.empty()) {
      sample_sort_ptr_helper(sub_s_ptr, comp);
    }
  }, 1);
}

} // namespace my_sort

// The main entry point required by the benchmark.
template <class T, class BinPred>
void compSort(parlay::sequence<T> &A, const BinPred& f) {
  // Dispatch to the appropriate sort implementation based on type properties.
  // parlay::is_trivially_relocatable_v is a trait that checks if a type can be
  // safely moved with memcpy.
  // The sizeof check is a heuristic: for small, trivially relocatable types,
  // moving the objects directly is faster than the overhead of a pointer sort.
  // 32 bytes is a reasonable threshold that covers double and pair<double,double>.
  // std::string is not trivially relocatable and will use the pointer sort.
  if constexpr (parlay::is_trivially_relocatable_v<T> && sizeof(T) <= 32) {
      my_sort::sample_sort_recursive(parlay::make_slice(A), f);
  } else {
      my_sort::sample_sort_ptr(parlay::make_slice(A), f);
  }
}

