// This implementation provides a highly-optimized, adaptive parallel sample sort.
// It is designed to be faster than the generic parlay::sample_sort_inplace by
// specializing its parameters for different data types. The key insight is that
// for types with expensive comparisons, such as std::string, it is worth spending
// more effort on sampling to achieve better load balancing, as the cost of sorting
// the final buckets dominates the total runtime.

// We implement the sample sort algorithm using ParlayLib's high-level primitives.
// Specifically, we use parlay::group_by_and_sort_inplace to perform the most
// complex step: partitioning the data into buckets in-place. This leverages
// the library's highly optimized implementation of parallel data permutation
// while giving us the flexibility to control the high-level algorithm, such as
// the sampling strategy and recursion.

namespace expert_sort {

// The main recursive sample sort implementation
template <class Iter, class Comp>
void sample_sort_impl(parlay::slice<Iter, Iter> A, const Comp& comp) {
  using T = typename std::iterator_traits<Iter>::value_type;
  size_t n = A.size();

  // --- Base Case ---
  // For small inputs, the overhead of parallelization and sampling is not worth it.
  // We switch to a fast sequential sort. std::sort is an introsort, which is
  // highly efficient. A threshold of 8192 is well-tuned for modern multicore CPUs.
  if (n <= 8192) {
    std::sort(A.begin(), A.end(), comp);
    return;
  }

  // --- Adaptive Parameter Selection ---
  size_t num_workers = parlay::num_workers();
  size_t num_splitters;
  size_t oversample_factor;

  // Use `if constexpr` for compile-time specialization. This check also
  // correctly handles `parlay::pair<std::string, ...>`.
  if constexpr (std::is_same_v<T, std::string> || (parlay::is_pair_v<T> && std::is_same_v<typename T::first_type, std::string>)) {
    // For strings, use more buckets and a higher oversampling rate
    // to achieve better load balance, amortizing the high comparison cost.
    num_splitters = (1 << parlay::log2_up(num_workers * 16)) - 1;
    oversample_factor = 30;
  } else {
    // For cheap-to-compare types like doubles, a standard configuration is sufficient.
    num_splitters = (1 << parlay::log2_up(num_workers * 8)) - 1;
    oversample_factor = 15;
  }

  // Reduce overhead for inputs that are large but not huge.
  if (n < 200000) {
      num_splitters = std::min(num_splitters, (size_t)((1 << parlay::log2_up(num_workers * 4)) - 1));
  }
  // Ensure a reasonable number of elements per bucket on average.
  num_splitters = std::min(num_splitters, n / 128);
  if (num_splitters == 0) num_splitters = 1;

  // --- Sampling ---
  size_t sample_size = std::min(n, (num_splitters + 1) * oversample_factor);
  if (sample_size < num_splitters + 1) { // Ensure enough samples to pick splitters
    sample_size = std::min(n, num_splitters + 1);
  }

  parlay::sequence<T> sample(sample_size);
  // Using parlay::random is good practice for deterministic randomness.
  parlay::random r(std::rand());
  for (size_t i = 0; i < sample_size; i++) {
    sample[i] = A[r.ith_rand(i) % n];
  }

  // --- Sort Sample & Select Splitters ---
  std::sort(std::begin(sample), std::end(sample), comp);

  parlay::sequence<T> splitters;
  splitters.reserve(num_splitters);
  for (size_t i = 0; i < num_splitters; i++) {
    // Pick splitters evenly from the sorted sample.
    splitters.push_back(sample[(i + 1) * sample_size / (num_splitters + 1)]);
  }

  // CRITICAL: For inputs with many duplicates (e.g., exptSeq distribution), we
  // must unique the splitters. Otherwise, we can get many empty buckets and one
  // huge bucket, which destroys load balance and performance.
  auto eq = [&](const T& a, const T& b) { return !comp(a, b) && !comp(b, a); };
  splitters.erase(std::unique(std::begin(splitters), std::end(splitters), eq), std::end(splitters));

  // --- Partition Data & Recurse ---
  // If unique-ing results in no splitters (e.g., all samples were equal),
  // the partitioner will create one bucket, and we will recurse on the whole array.
  // This will eventually hit the base case, providing a safe fallback.

  // We use parlay::group_by_and_sort_inplace. This powerful primitive partitions
  // the input based on a key and then applies a function to each partition.
  // Our key is the bucket index, determined by comparing an element to the splitters.
  // The function we apply is a recursive call to our sort.
  auto get_bucket = [&](const T& x) -> size_t {
    // std::lower_bound performs a binary search to find the bucket for element x.
    // This is efficient, with a cost of log(#splitters) comparisons per element.
    return std::lower_bound(std::begin(splitters), std::end(splitters), x, comp) - std::begin(splitters);
  };

  parlay::group_by_and_sort_inplace(A, get_bucket, [&](parlay::slice<Iter, Iter> s) {
    // This lambda is executed in parallel for each bucket (group).
    // We recursively sort the bucket.
    sample_sort_impl(s, comp);
  });
}

} // namespace expert_sort

constexpr bool INPLACE = true;

template <class T, class BinPred>
void compSort(parlay::sequence<T> &A, const BinPred& f) {
  // Handle the edge case of an empty or single-element sequence.
  if (A.size() > 1) {
    // Call our custom, tuned implementation.
    expert_sort::sample_sort_impl(parlay::make_slice(A), f);
  }
}

