// Forward declaration for mutual recursion
namespace parlay {
template <typename R, typename Compare>
void sample_sort_inplace(R& S, Compare comp);
}

// The main out-of-place sample sort implementation
namespace parlay {

// sample_sort: returns a new sequence containing the sorted elements of S
template <typename R, typename Compare>
auto sample_sort(R&& S, Compare comp) {
  auto s_slice = parlay::make_slice(S);
  size_t n = s_slice.size();
  using T = typename parlay::slice_value_type_t<decltype(s_slice)>;

  // Base case: for small inputs, use a fast sequential sort.
  // 2048 is a good threshold for modern CPUs.
  if (n <= 2048) {
    auto s = parlay::to_sequence(s_slice);
    std::sort(s.begin(), s.end(), comp);
    return s;
  }

  // Step 1: Select a sample of the input elements.
  // The number of splitters is proportional to the number of threads (p).
  // A common choice is k*p-1 splitters. We use k=8.
  // We oversample to get a good distribution of splitters, which is
  // critical for load balancing.
  size_t num_splitters = parlay::num_workers() * 8;
  if (num_splitters == 0) num_splitters = 1; else num_splitters--;
  size_t oversample_factor = 20;

  // Cap sample size to avoid it becoming a bottleneck on huge inputs or core counts.
  size_t sample_size = std::min((size_t)100000, 1 + oversample_factor * num_splitters);
  sample_size = std::min(sample_size, n);

  // Take a random sample to be representative of the overall data.
  auto samples = parlay::random_permutation(sample_size, parlay::random(0));
  auto sample_seq = parlay::delayed_seq<T>(sample_size, [&](size_t i) -> const T& { return s_slice[samples[i]]; });

  // Step 2: Sort the sample and select splitters.
  auto sorted_samples = parlay::sort(sample_seq, comp);

  auto splitters = parlay::tabulate(num_splitters, [&](size_t i) {
    return sorted_samples[(i + 1) * sorted_samples.size() / (num_splitters + 1)];
  });

  // Remove duplicate splitters to ensure progress and avoid empty buckets between identical splitters.
  auto eq = [&](const T& a, const T& b) { return !comp(a, b) && !comp(b, a); };
  auto unique_splitters = parlay::unique(splitters, eq);

  // Handle the case where all elements are equal.
  if (unique_splitters.empty()) {
    return parlay::to_sequence(s_slice);
  }

  // Step 3: Bucket the input elements based on the splitters.
  // parlay::split_by is a high-level primitive that partitions elements
  // into buckets based on a key (the bucket index) and returns the
  // partitioned sequence and the starting offsets of each bucket. This is
  // an extremely efficient implementation of the bucketing and distribution steps.
  auto [bucketed, bucket_offsets] = parlay::split_by(s_slice, parlay::delayed_seq<unsigned int>(n, [&](size_t i) {
    // Find bucket for element s_slice[i] by binary searching in splitters.
    return std::upper_bound(std::begin(unique_splitters), std::end(unique_splitters), s_slice[i], comp) - std::begin(unique_splitters);
  }));

  // Step 4: Recursively sort each bucket in parallel.
  // The recursive call is to the in-place version of the sort, which will
  // modify the slices of the `bucketed` sequence directly.
  parlay::parallel_for(0, bucket_offsets.size() - 1, [&](size_t i) {
    auto bucket = bucketed.slice(bucket_offsets[i], bucket_offsets[i+1]);
    if (bucket.size() > 1) {
      parlay::sample_sort_inplace(bucket, comp);
    }
  }, 1); // Use a small grain size for better load balancing of buckets.

  return bucketed;
}

} // namespace parlay


// The in-place wrapper for sample sort
namespace parlay {

// sample_sort_inplace: sorts the given sequence S in-place.
template <typename R, typename Compare>
void sample_sort_inplace(R& S, Compare comp) {
  size_t n = S.size();

  // Base case: for small inputs, use a fast sequential sort.
  if (n <= 2048) {
    std::sort(std::begin(S), std::end(S), comp);
    return;
  }

  // The standard way to implement a fast "in-place" sample sort is to
  // use an out-of-place version to do the work in a temporary buffer,
  // and then move the result back. This uses O(n) auxiliary space but
  // is much faster than true in-place algorithms due to better memory access patterns.
  auto sorted = parlay::sample_sort(parlay::make_slice(S), comp);

  // Move the sorted elements back to the original sequence.
  // This is cheap for types with fast moves (like std::string).
  parlay::parallel_for(0, n, [&](size_t i) {
    S[i] = std::move(sorted[i]);
  });
}

} // namespace parlay

#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/internal/quicksort.h"
#include "parlay/internal/group_by.h" // for block_partition
#include "parlay/random.h"
#include <algorithm>
#include <vector>

// Set to true to indicate that the user-facing sequence is modified in-place.
// The implementation may use an auxiliary buffer for performance, but the
// final sorted result is placed back into the original sequence.
constexpr bool INPLACE = true;

// A robust, in-place parallel quicksort.
// This is used as the base sorter for buckets created by the sample sort,
// and as a fallback for smaller inputs. It uses median-of-9 pivot selection
// for robustness and a 3-way partition to handle duplicate keys efficiently.
template <typename Slice, typename Comp>
void parallel_quicksort_3way(Slice A, const Comp& f) {
  // For small inputs, a sequential sort is faster due to overheads.
  // std::sort is highly optimized (typically an introsort).
  if (A.size() <= (1 << 13)) { // Cutoff = 8192
    std::sort(std::begin(A), std::end(A), f);
    return;
  }

  // Pivot Selection: Median of 9 random elements.
  // This is very robust against patterned data (sorted, reverse-sorted, etc.).
  auto pivot = parlay::internal::median_of_ninthers(A, f);

  // 3-way Partition: Efficiently handles large numbers of duplicate keys,
  // which is critical for distributions like the exponential one.
  // It partitions A into [< pivot | == pivot | > pivot].
  auto [mid1, mid2] = parlay::internal::partition3(A, pivot, f);

  // Parallel Recursion: Sort the sub-arrays for elements less than and
  // greater than the pivot in parallel. The middle part (equal to pivot)
  // is already sorted.
  parlay::par_do(
      [&]() { parallel_quicksort_3way(A.cut(A.begin(), mid1), f); },
      [&]() { parallel_quicksort_3way(A.cut(mid2, A.end()), f); }
  );
}

// The main sorting function.
// This is a hybrid algorithm that combines Sample Sort with the robust
// parallel 3-way Quicksort defined above. This approach is designed to be
// one of the fastest parallel comparison sorts.
//
// How it works:
// 1. For large inputs, it uses Sample Sort to partition the data into
//    a number of buckets equal to the number of available workers. This
//    step provides excellent scalability and cache efficiency, which are
//    key to performance on modern multi-core processors.
// 2. Each bucket is then sorted independently and in parallel using the
//    robust parallel_quicksort_3way. This mitigates the main weakness of
//    a naive Sample Sort, which is poor load balancing on inputs with many
//    duplicate keys. The 3-way quicksort handles such cases gracefully.
// 3. For smaller inputs, it falls back directly to the parallel quicksort,
//    avoiding the overhead of the sampling and partitioning phases.
// 4. The algorithm uses an O(n) auxiliary buffer to hold the partitioned
//    data. This is a deliberate trade-off: the extra memory allows for a
//    more efficient and scalable partitioning step (parlay::internal::block_partition),
//    leading to higher overall performance, which is the primary goal.
template <class T, class BinPred>
void compSort(parlay::sequence<T>& A, const BinPred& f) {
  size_t n = A.size();

  // For inputs under 1M elements, use the robust quicksort directly.
  // The sample sort partitioning step has overhead that is only justified for very large n.
  if (n <= (1 << 20)) { // Cutoff = 1,048,576
    parallel_quicksort_3way(make_slice(A), f);
    return;
  }

  // --- Sample Sort Stage ---
  size_t p = parlay::num_workers();
  // Use a reasonably large oversampling factor for better splitter quality and load balancing.
  size_t samples_per_worker = 64;
  size_t num_samples = (p > 1) ? (p - 1) * samples_per_worker : 0;

  if (p <= 1 || num_samples == 0) {
    parallel_quicksort_3way(make_slice(A), f);
    return;
  }

  // 1. Sample and find splitters
  // We take random samples, sort them, and pick elements at regular intervals
  // to serve as splitters that divide the key space into p regions.
  auto samples = parlay::tabulate(num_samples, [&](size_t) {
    parlay::random_generator gen;
    std::uniform_int_distribution<size_t> dis(0, n - 1);
    return A[dis(gen)];
  });
  std::sort(std::begin(samples), std::end(samples), f);

  auto splitters = parlay::tabulate(p - 1, [&](size_t i) {
    return samples[(i + 1) * samples_per_worker - 1];
  });

  // 2. Partition using splitters
  // parlay::internal::block_partition is a highly optimized, cache-efficient
  // routine that partitions A into p buckets based on the splitters.
  // It returns the partitioned data in a new sequence (B) and the sizes of the buckets.
  auto [B, bucket_sizes] = parlay::internal::block_partition(make_slice(A), splitters, f);

  // 3. Recursive sort on buckets
  // Find the starting offset of each bucket.
  auto bucket_offsets = parlay::scan(bucket_sizes).first;

  // Sort each bucket in parallel using our robust 3-way quicksort.
  parlay::parallel_for(0, p, [&](size_t i) {
    auto bucket = B.cut(bucket_offsets[i], bucket_offsets[i] + bucket_sizes[i]);
    if (bucket.size() > 0) {
      parallel_quicksort_3way(bucket, f);
    }
  }, 1); // Granularity of 1, as we have exactly p coarse-grained tasks.

  // 4. Move the sorted result from the auxiliary buffer B back to A.
  // std::move is efficient as it just transfers ownership of the underlying memory.
  A = std::move(B);
}

#include "parlay/sequence.h"
#include "parlay/primitives.h"
#include "parlay/internal/insertion_sort.h"
#include <algorithm>
#include <utility>

constexpr bool INPLACE = true;

// Custom sort implementation namespace to avoid conflicts and organize helpers
namespace expert_sort {
namespace detail {

// Use std::sort for the sequential base case. It's a highly-optimized introsort
// (hybrid of quicksort, heapsort, and insertion sort). For very small inputs,
// however, a direct call to insertion sort has less overhead.
constexpr size_t kInsertionSortThreshold = 32;

// Threshold for switching from the parallel to the sequential algorithm.
// This value is critical for performance and is best determined empirically
// on the target machine, but 2048 is a solid, general-purpose choice that
// balances scheduler overhead with parallel work generation.
constexpr size_t kParallelThreshold = 2048;

template<typename Slice, typename Compare>
void p_sort(Slice s, Compare f);

// Sequential sort: std::sort with an insertion sort base case.
template<typename Slice, typename Compare>
void seq_sort(Slice s, Compare f) {
  if (s.size() <= kInsertionSortThreshold) {
    parlay::internal::insertion_sort(s, f);
  } else {
    std::sort(std::begin(s), std::end(s), f);
  }
}

// 3-way partition (Dutch National Flag algorithm).
// Partitions s into three sections: [< p, == p, > p].
// This is highly effective for inputs with many duplicate keys (e.g., exponential distribution).
// Returns a pair of indices {m1, m2} defining the equal range [m1, m2).
template<typename Slice, typename Compare, typename T = typename Slice::value_type>
std::pair<size_t, size_t> partition3_way(Slice s, Compare f, const T& p) {
  size_t lt = 0, i = 0, gt = s.size();
  // Invariant: s[0..lt-1] < p, s[lt..i-1] == p, s[i..gt-1] is unprocessed, s[gt..n-1] > p
  while (i < gt) {
    if (f(s[i], p)) {
      std::swap(s[lt++], s[i++]);
    } else if (f(p, s[i])) {
      std::swap(s[i], s[--gt]);
    } else {
      i++;
    }
  }
  return {lt, gt};
}

// In-place dual-pivot partition, a key component of modern fast quicksorts.
// Partitions s into three sections: [< p1, p1 <= x <= p2, > p2].
// Returns a pair of indices {m1, m2} defining the partitions [0, m1), [m1, m2), [m2, n).
template<typename Slice, typename Compare, typename T = typename Slice::value_type>
std::pair<size_t, size_t> partition_dual_pivot(Slice s, Compare f, const T& p1, const T& p2) {
  size_t l = 0, m = 0, g = s.size();
  // Invariant: s[0..l-1] < p1, s[l..m-1] is p1<=x<=p2, s[m..g-1] is unprocessed, s[g..n-1] > p2
  while (m < g) {
    if (f(s[m], p1)) {
      std::swap(s[l++], s[m++]);
    } else if (f(p2, s[m])) {
      std::swap(s[m], s[--g]);
    } else {
      m++;
    }
  }
  return {l, g};
}

template<typename Slice, typename Compare>
void p_sort(Slice s, Compare f) {
  size_t n = s.size();
  if (n <= kParallelThreshold) {
    seq_sort(s, f);
    return;
  }

  // --- Pivot Selection (Median of 5) ---
  // Pick 5 elements and sort them to find good pivots. This is robust against
  // various input distributions (random, sorted, etc.) and avoids O(n^2) complexity.
  size_t i0=0, i1=n/4, i2=n/2, i3=3*n/4, i4=n-1;
  // Use a sorting network to sort the 5 elements at their positions.
  if (f(s[i1], s[i0])) { std::swap(s[i0], s[i1]); }
  if (f(s[i2], s[i0])) { std::swap(s[i0], s[i2]); }
  if (f(s[i3], s[i0])) { std::swap(s[i0], s[i3]); }
  if (f(s[i4], s[i0])) { std::swap(s[i0], s[i4]); }
  if (f(s[i2], s[i1])) { std::swap(s[i1], s[i2]); }
  if (f(s[i3], s[i1])) { std::swap(s[i1], s[i3]); }
  if (f(s[i4], s[i1])) { std::swap(s[i1], s[i4]); }
  if (f(s[i3], s[i2])) { std::swap(s[i2], s[i3]); }
  if (f(s[i4], s[i2])) { std::swap(s[i2], s[i4]); }
  if (f(s[i4], s[i3])) { std::swap(s[i3], s[i4]); }

  // Choose p1 and p2 from the sorted sample. Using the 2nd and 4th elements
  // (approx. 1/4 and 3/4 quantiles of the sample) gives a good balance.
  auto p1 = s[i1];
  auto p2 = s[i3];

  // --- Partitioning and Recursing ---
  bool p1_eq_p2 = !f(p1, p2) && !f(p2, p1);

  if (p1_eq_p2) {
    // Fallback to 3-way partition if pivots are equal.
    auto [m1, m2] = partition3_way(s, f, p1);
    parlay::par_do(
      [&]() { p_sort(s.cut(0, m1), f); },
      [&]() { p_sort(s.cut(m2, n), f); }
    );
  } else {
    // Use dual-pivot partition for the general case.
    auto [m1, m2] = partition_dual_pivot(s, f, p1, p2);
    parlay::par_do(
      [&]() { p_sort(s.cut(0, m1), f); },
      [&]() { p_sort(s.cut(m1, m2), f); },
      [&]() { p_sort(s.cut(m2, n), f); }
    );
  }
}

