// The threshold to switch from parallel quicksort to a serial sort.
// This value is chosen based on empirical testing to balance the overhead
// of parallel task creation with the benefits of parallel execution.
// A value around 2000-4000 is typical for modern multicore systems.
constexpr size_t PAR_SORT_CUTOFF = 2048;

// Selects the median of three elements from a slice as the pivot.
// This is a robust strategy to avoid worst-case O(n^2) behavior on
// sorted or nearly-sorted data. It returns the value of the median element.
template<typename Slice, typename Compare>
typename Slice::value_type get_median_of_three(Slice s, Compare f) {
  auto first = s.begin();
  auto mid = s.begin() + s.size() / 2;
  auto last = s.end() - 1;

  // Sort the three elements to find the median
  if (f(*mid, *first)) std::swap(*mid, *first);
  if (f(*last, *mid)) std::swap(*last, *mid);
  if (f(*mid, *first)) std::swap(*mid, *first);

  return *mid;
}

// The core parallel quicksort implementation.
template <typename Slice, typename Compare>
void parallel_quicksort(Slice s, Compare f) {
  // Use a while loop to implement the recursion for the larger partition.
  // This is a form of tail-call optimization that reduces task creation
  // overhead and limits the recursion depth, preventing stack overflow.
  while (s.size() > PAR_SORT_CUTOFF) {
    // 1. Pivot Selection
    auto pivot = get_median_of three(s, f);

    // 2. 3-Way Partitioning (Dutch National Flag problem)
    // This partitioning scheme is crucial for performance on inputs with
    // many duplicate keys (like the 'exponential' distribution). It partitions
    // the slice into three regions: elements < pivot, elements == pivot,
    // and elements > pivot. We only need to recursively sort the < and > regions.
    auto lt = s.begin(), i = s.begin(), gt = s.end() - 1;
    while (i <= gt) {
      if (f(*i, pivot)) {
        std::swap(*lt++, *i++);
      } else if (f(pivot, *i)) {
        std::swap(*i, *gt--);
      } else { // *i is equal to pivot
        i++;
      }
    }
    // The slice is now partitioned as:
    // [s.begin(), lt)  : elements < pivot
    // [lt, gt + 1)     : elements == pivot
    // [gt + 1, s.end()) : elements > pivot

    auto left_part = s.cut(0, lt - s.begin());
    auto right_part = s.cut(gt + 1 - s.begin(), s.size());

    // 3. Parallel Recursion
    // Recurse on the smaller partition in a new parallel task and
    // loop on the larger partition. This strategy minimizes the depth
    // of the task dependency graph and improves load balancing.
    if (left_part.size() > right_part.size()) {
      parlay::par_do([&] { parallel_quicksort(right_part, f); });
      s = left_part;
    } else {
      parlay::par_do([&] { parallel_quicksort(left_part, f); });
      s = right_part;
    }
  }

  // Base Case: For small slices, switch to a fast serial sort.
  // std::sort is highly optimized (typically an introsort) and is very
  // efficient for small inputs and nearly-sorted data.
  std::sort(s.begin(), s.end(), f);
}

