constexpr bool INPLACE = true;

template <class T, class BinPred>
void compSort(parlay::sequence<T> &A, const BinPred& f) {
  auto s = parlay::make_slice(A);
  if (s.size() < 2) return;

  // This implementation is a hybrid sort that dynamically chooses between
  // parlay::sort_inplace (a highly optimized parallel sample sort) and
  // parlay::internal::merge_sort_inplace (a parallel merge sort).
  // The choice is based on a heuristic that detects almost-sorted input.
  // This adaptive strategy provides excellent performance across a wide
  // range of input distributions, aiming to be the fastest overall
  // comparison sort.

  // For smaller inputs, the overhead of sampling is not worthwhile.
  // The threshold of 100,000 is a heuristic that would be tuned based
  // on hardware and data type. Below this, sample sort is a safe and
  // fast default.
  if (s.size() > 100000) {
    // Heuristic to detect almost-sorted data.
    // We take a small, evenly-spaced sample of the input.
    // The number of samples is capped at 1000 to keep this check fast.
    size_t num_samples = std::min((size_t)1000, s.size() / 100);

    // We need at least a few samples for a meaningful decision.
    if (num_samples >= 20) {
      // Count "inversions" between adjacent elements in our sample.
      // An ideally sorted sample would have 0 inversions.
      // A random sample would have approx. num_samples / 2 inversions.
      size_t inversions = 0;
      for (size_t i = 1; i < num_samples; i++) {
        // Sample elements are s[0], s[k], s[2k], ... where k = s.size()/num_samples
        if (f(s[i * s.size() / num_samples], s[(i - 1) * s.size() / num_samples])) {
          inversions++;
        }
      }

      // If the number of inversions is significantly lower than for random
      // data, it is likely that the input is mostly sorted.
      // The threshold (inversions < num_samples / 10) is a conservative heuristic.
      // For such cases, merge sort is often faster than sample sort
      // as it can exploit existing sorted "runs". It also avoids the
      // partitioning overhead of sample sort, which is less effective
      // on non-random data.
      if (inversions < num_samples / 10) {
        parlay::internal::merge_sort_inplace(s, f);
        return;
      }
    }
  }

  // For data that appears random, or for smaller inputs,
  // parlay::sort_inplace (a parallel sample sort) is generally the
  // fastest in-place comparison sort. It offers excellent cache
  // locality and scalability by partitioning the data among processors,
  // outperforming merge sort on inputs without pre-existing order.
  parlay::sort_inplace(s, f);
}

#include "parlay/primitives.h"
#include "parlay/internal/merge_sort.h"

constexpr bool INPLACE = true;

// This is an adaptive parallel sort that combines the strengths of
// sample sort and merge sort to deliver high performance across
// a wide variety of input distributions.
template <class T, class BinPred>
void compSort(parlay::sequence<T> &A, const BinPred& f) {
  auto s = parlay::make_slice(A);

  // For small inputs, the overhead of checking for sortedness is not
  // worth it. parlay::sort_inplace is a robust and fast default.
  // The threshold is chosen based on typical performance crossovers.
  if (s.size() < 250000) {
    parlay::sort_inplace(s, f);
    return;
  }

  // Perform a fast O(N) check to determine if the data is "almost sorted".
  // We count the number of elements that are smaller than their predecessor
  // according to the comparison function f. This count is a proxy for the
  // number of ascending runs in the data. This check is very lightweight,
  // consisting of a single pass with simple comparisons, and is efficiently
  // parallelized by parlay::count_if.
  size_t num_runs = 1 + parlay::count_if(parlay::iota(1, s.size()), [&](size_t i) {
    return f(s[i], s[i-1]);
  });

  // This heuristic threshold determines what we consider "almost sorted".
  // If the number of runs is small (e.g., less than a few times the
  // number of available hardware threads), the data has significant
  // pre-existing order. Merge sort is known to be exceptionally fast on
  // such inputs. The threshold is tuned to be sensitive enough to detect
  // these cases without misclassifying random data.
  size_t runs_threshold = parlay::num_workers() * 8;

  if (num_runs < runs_threshold) {
    // Data is likely almost sorted.
    // We use parlay::internal::merge_sort_inplace, a highly optimized
    // parallel ping-pong merge sort that excels on inputs with a small
    // number of runs, as it can efficiently merge long, sorted segments.
    parlay::internal::merge_sort_inplace(s, f);
  } else {
    // Data is likely random or unstructured.
    // We use parlay::sort_inplace, which is a parallel sample sort.
    // Sample sort generally has better cache locality and lower total
    // data movement than merge sort, making it faster on average for
    // inputs without pre-existing order.
    parlay::sort_inplace(s, f);
  }
}

