// Set to true since the final sorted result is in the input sequence A.
constexpr bool INPLACE = true;

// A namespace to encapsulate the sorting implementation.
namespace my_sort {

// The main recursive implementation of a parallel sample sort.
// It sorts the given slice `A` in-place according to the comparator `comp`.
template<typename Slice, typename Comp>
void sample_sort_inplace(Slice A, const Comp& comp) {
  size_t n = A.size();

  // 1. Base Case: For small inputs, parallel overhead is not worth it.
  // Switch to a fast sequential sorting algorithm. std::sort is highly
  // optimized (typically an introsort). The threshold is a crucial tuning
  // parameter. 8192 is chosen as a balance point where the overhead of
  // sample sort (sampling, partitioning) starts to pay off.
  if (n <= (1 << 13)) { // 8192
    std::sort(A.begin(), A.end(), comp);
    return;
  }

  // 2. Sampling and Splitter Selection
  // The goal is to find `p-1` splitters to partition the data into `p`
  // buckets, where `p` is the number of available worker threads.
  size_t num_workers = parlay::num_workers();
  size_t num_buckets = num_workers;

  // To find good splitters that create balanced buckets, we take a random
  // sample of the input data that is larger than the number of splitters needed.
  // This is called oversampling. An oversampling factor of 15 is a robust
  // choice that works well across different input distributions.
  size_t oversample_factor = 15;
  // We cap the number of samples to avoid excessive work on this step.
  size_t num_samples = std::min((size_t)num_workers * oversample_factor, n / 2);

  using T = typename Slice::value_type;
  parlay::sequence<T> samples(num_samples);
  parlay::random r;
  // Populate the sample sequence with random elements from the input.
  for (size_t i = 0; i < num_samples; i++) {
    samples[i] = A[r(n)];
  }

  // Sort the sample. Since the sample is small, a sequential sort is fast.
  std::sort(samples.begin(), samples.end(), comp);

  // Select `num_buckets - 1` splitters from the sorted sample.
  // These are the quantiles of the sample, which approximate the quantiles
  // of the full dataset.
  parlay::sequence<T> splitters;
  if (num_buckets > 1) {
    splitters.resize(num_buckets - 1);
    for (size_t i = 0; i < num_buckets - 1; i++) {
      // Pick elements at evenly spaced positions in the sorted sample.
      splitters[i] = samples[static_cast<size_t>((i + 1.0) * num_samples / num_buckets)];
    }
  }

  // In case of inputs with many duplicate values, the sampled splitters may
  // not be unique. This can lead to suboptimal partitioning. We remove
  // duplicates to ensure each splitter defines a unique boundary.
  auto unique_splitters_seq = parlay::unique(parlay::make_slice(splitters), comp);
  auto unique_splitters = parlay::make_slice(unique_splitters_seq);
  num_buckets = unique_splitters.size() + 1;

  // 3. Partitioning
  // We now partition the full input array `A` into `num_buckets` based on the
  // chosen splitters. The most efficient way to do this in parallel is to
  // use a temporary buffer.
  parlay::sequence<T> B = parlay::sequence<T>::uninitialized(n);

  // parlay::internal::block_partition_by_splitters is a highly-optimized
  // primitive that performs this partitioning in a single pass over the data.
  // It scatters elements from A into their correct bucket in B.
  // It returns a sequence containing the size of each bucket.
  auto counts = parlay::internal::block_partition_by_splitters(A, unique_splitters, parlay::make_slice(B), comp);

  // The partitioned, but unsorted, elements are now in the buffer B.
  // We copy them back to A to prepare for the in-place recursive calls.
  // The cost of this copy is O(n) work, which is acceptable as the total
  // work is O(n log n).
  parlay::copy(B, A);

  // To find the boundaries of each bucket in A, we compute a prefix sum
  // (exclusive scan) on the bucket counts.
  auto offsets = parlay::scan(counts).first;

  // 4. Recursive Calls
  // We now have `num_buckets` subproblems (the buckets) in A, which can be
  // sorted independently and in parallel.
  parlay::parallel_for(0, num_buckets, [&](size_t i) {
    size_t start = offsets[i];
    size_t end = (i == num_buckets - 1) ? n : offsets[i+1];
    // A bucket might be empty if splitters are not well-distributed.
    if (start < end) {
      // Recursively sort the sub-slice representing the bucket.
      sample_sort_inplace(A.cut(start, end), comp);
    }
  }, 1); // A granularity of 1 is appropriate here, as we are creating a small
         // number of large, independent tasks (one per bucket).
}

