constexpr bool INPLACE = true;

// A high-performance parallel merge sort using a double-buffering (ping-pong)
// strategy. This avoids the copy-back step at each level of recursion that
// is present in a simpler inplace merge sort, reducing memory bandwidth usage
// by up to a factor of two.
//
// The core of the algorithm is `p_merge_sort_impl(to, from, f)`, which sorts
// the elements in the `from` slice and writes the sorted result into the `to`
// slice. It works by recursively calling itself with the roles of `to` and
// `from` swapped. This causes the sorted subproblems to be written into the
// `from` slice, which are then merged into the `to` slice.

// Base case size for the recursion. Below this size, std::sort is used.
// This value is tuned for modern CPUs, balancing recursion overhead against
// the efficiency of std::sort (which is typically introsort).
constexpr size_t P_MERGE_SORT_BASE_CASE = 4096;

// Recursive helper function: sorts `from` and places the result in `to`.
template <class Slice1, class Slice2, class BinPred>
void p_merge_sort_impl(Slice1 to, Slice2 from, const BinPred& f) {
  size_t n = from.size();

  // Base case: for small inputs, sort `from` directly and copy to `to`.
  if (n <= P_MERGE_SORT_BASE_CASE) {
    std::sort(std::begin(from), std::end(from), f);
    parlay::copy(from, to);
    return;
  }

  // Split ranges for recursion.
  auto from_mid = from.begin() + n / 2;
  auto to_mid = to.begin() + n / 2;

  // Recurse in parallel. Note the swap of `to` and `from` slices.
  // The subproblems will sort data from `to`'s halves into `from`'s halves.
  // The `from` buffer of the recursive call must contain the data to be sorted.
  // However, at this point, `to` is uninitialized scratch space. The data is
  // in `from`. Therefore, the recursive calls must sort the data from `from`'s
  // halves into `to`'s halves.
  parlay::par_do(
    [&]() { p_merge_sort_impl(to.cut(0, n / 2), from.cut(0, n / 2), f); },
    [&]() { p_merge_sort_impl(to.cut(n / 2, n), from.cut(n / 2, n), f); }
  );

  // After recursion, `to` contains two sorted sub-sequences.
  // Merge them from `to` into `from` using Parlay's optimized parallel merge.
  parlay::internal::merge_into(to.cut(0, n / 2), to.cut(n / 2, n), from, f);
}

template <class T, class BinPred>
void compSort(parlay::sequence<T> &A, const BinPred& f) {
  size_t n = A.size();
  if (n <= 1) return;

  // For smaller inputs, the overhead of the double-buffer setup is not
  // worthwhile. The baseline is already well-tuned for these sizes.
  if (n <= 1000000) {
    parlay::internal::merge_sort_inplace(parlay::make_slice(A), f);
    return;
  }

  // Create a temporary sequence of the same size as A.
  // It is important that this sequence has the same capacity as A,
  // since we will be swapping them.
  parlay::sequence<T> B = parlay::sequence<T>::uninitialized(n);

  // The logic of p_merge_sort_impl is that it sorts from a source buffer
  // into a destination buffer. The recursive calls then use the destination
  // as the source for the next level down.
  //
  // Let's trace the buffers.
  // Level 0 (our call): sorts from `from` to `to`.
  // Level 1 (recursion): sorts from `to` to `from`.
  // Level 2 (recursion): sorts from `from` to `to`.
  // ...
  // Base case (sort + copy): sorts from one buffer to the other.
  //
  // We start with data in A. The final sorted data must end up in A.
  // To achieve this, we can swap A and B and then call the sort.
  // The sort will place the result in the original A buffer.
  parlay::copy(A, B);
  p_merge_sort_impl(parlay::make_slice(A), parlay::make_slice(B), f);
}

