// This is an adaptive parallel comparison sort.
//
// It leverages two excellent sorting algorithms from the Parlay library:
//   1. Sample Sort: Generally the fastest parallel comparison sort for random
//      or unstructured data due to superior cache efficiency and load balancing.
//   2. Merge Sort: Exceptionally fast for data that is already "almost sorted",
//      as it can efficiently merge long, pre-existing sorted runs.
//
// The core idea is to perform a quick, low-overhead check on the input data
// to determine if it's almost sorted. Based on this heuristic, it dispatches
// to the most suitable algorithm.
//
// This approach provides performance that is robust across a wide range of
// input distributions, including the difficult "almost-sorted" case, which
// can be a weakness for a pure sample sort implementation.
//
// Key optimizations over the baseline:
//   - Unstable Sort: The problem specifies that stability is not required.
//     We use unstable sort algorithms, which are significantly faster than their
//     stable counterparts as they avoid the overhead of tracking original element
//     positions.
//   - Adaptive Algorithm Selection: We use a fast, parallel heuristic to detect
//     almost-sorted data and switch to merge sort, while using the faster
//     sample sort for all other cases.
template <class T, class BinPred>
parlay::sequence<T> compSort(parlay::sequence<T> const &A, const BinPred& f) {
  size_t n = A.size();

  // For smaller inputs, the overhead of the adaptive check is not worthwhile.
  // A direct call to sample sort is both simple and highly efficient. The
  // threshold is chosen empirically to be large enough to make the subsequent
  // check meaningful.
  if (n < 500000) {
    return parlay::internal::sample_sort(parlay::make_slice(A), f, false);
  }

  // Heuristic to detect almost-sorted data:
  // We perform a fast, single parallel pass to count the number of adjacent
  // inversions, i.e., pairs (A[i], A[i+1]) where f(A[i+1], A[i]) is true.
  // This count serves as a cheap and effective proxy for the overall sortedness
  // of the sequence.
  size_t adjacent_inversions = parlay::reduce(parlay::tabulate(n - 1, [&](size_t i) {
    return f(A[i+1], A[i]) ? size_t{1} : size_t{0};
  }), parlay::plus<size_t>());

  // If the number of adjacent inversions is very small, we conclude that the
  // data is "almost sorted". In this case, we delegate to merge sort.
  // The threshold (0.05% of elements out of place) is a heuristic that balances
  // correctly identifying suitable inputs for merge sort without being overly
  // sensitive.
  if (adjacent_inversions < n / 2000) {
    // parlay::internal::merge_sort is a highly optimized, out-of-place,
    // unstable parallel merge sort. It excels on inputs with long sorted runs.
    return parlay::internal::merge_sort(parlay::make_slice(A), f);
  } else {
    // For all other cases (random, exponential, or heavily shuffled data),
    // sample sort is the algorithm of choice. We use the non-stable version
    // (`false`), which is a major optimization over the stable baseline.
    return parlay::internal::sample_sort(parlay::make_slice(A), f, false);
  }
}

