template <class T, class BinPred>
parlay::sequence<T> compSort(parlay::sequence<T> const &A, const BinPred& f) {
  // For small inputs, a simple, low-overhead sort like merge sort is best.
  // The setup cost of sample sort is not worth it for smaller N.
  if (A.size() < 20000) {
    return parlay::stable_sort(A, f);
  }

  // Heuristic to detect almost-sorted data for large inputs.
  // The 'almostSortedSeq' input generator creates a sorted sequence and then
  // performs a small number of random swaps. This results in long sorted
  // runs and a small number of adjacent inversions. We can detect this
  // pattern by checking a small prefix of the array. This check is
  // extremely fast (microseconds) and allows us to switch to a more
  // suitable adaptive algorithm.
  size_t num_samples = 10000;
  long long adjacent_inversions = 0;
  for (size_t i = 0; i < num_samples - 1; i++) {
    if (f(A[i+1], A[i])) {
      adjacent_inversions++;
    }
  }

  // If the density of adjacent inversions is low, the data is likely
  // almost sorted. A parallel merge sort (parlay::stable_sort) is adaptive
  // and performs very well on such inputs, often achieving near O(n) time.
  // A threshold of 1% is a robust choice for identifying this pattern.
  if (static_cast<double>(adjacent_inversions) / (num_samples - 1) < 0.01) {
    return parlay::stable_sort(A, f);
  }

  // For all other cases (random, exponential with repeats, etc.), a highly
  // optimized unstable sample sort is the fastest comparison-based algorithm.
  // The baseline uses a stable sample sort. We gain significant performance by
  // allowing an unstable sort, as permitted by the problem description
  // ("The sort need not be stable.").
  return parlay::internal::sample_sort(parlay::make_slice(A), f, false);
}

