// A stable parallel merge sort.
// This algorithm is based on the classic divide-and-conquer strategy.
// It recursively sorts two halves of the input and then merges the sorted
// halves using parlay::merge. While generally slower than sample sort for
// random data due to lower cache efficiency and higher data movement, it
// excels on data that is already nearly sorted.
template <typename R, typename Compare>
parlay::sequence<typename R::value_type> stable_parallel_merge_sort(R s, const Compare& comp) {
  using T = typename R::value_type;
  // For small subproblems, switch to a fast sequential sort.
  // std::stable_sort is highly optimized for small inputs and different patterns.
  if (s.size() <= 2048) {
    auto res = parlay::to_sequence(s);
    std::stable_sort(std::begin(res), std::end(res), comp);
    return res;
  }
  size_t mid = s.size() / 2;
  // Recursively sort the two halves in parallel.
  auto [left, right] = parlay::par_do(
      [&]() { return stable_parallel_merge_sort(s.cut(0, mid), comp); },
      [&]() { return stable_parallel_merge_sort(s.cut(mid, s.size()), comp); });
  // Merge the two sorted halves. parlay::merge is a highly-optimized parallel merge.
  return parlay::merge(left, right, comp);
}

// The main comparison sort function.
// This is a hybrid algorithm that dynamically chooses between sample sort and
// merge sort based on a heuristic that detects nearly sorted input.
template <class T, class BinPred>
parlay::sequence<T> compSort(parlay::sequence<T> const &A, const BinPred& f) {
  size_t n = A.size();

  // For small inputs, the overhead of the heuristic check is not worthwhile.
  // The baseline parlay::internal::sample_sort is already very efficient.
  if (n < 20000) {
    return parlay::internal::sample_sort(parlay::make_slice(A), f, true);
  }

  // Heuristic to detect nearly sorted input:
  // We sample a small number of adjacent pairs and check if they are in order.
  // If the input is found to be nearly sorted, we switch to a parallel merge
  // sort, which can be an order of magnitude faster in this case. Otherwise,
  // we use the default parallel sample sort, which is the best general-purpose
  // algorithm.
  size_t num_samples = std::min((size_t)10000, n / 2);

  // A[i] <= A[i+1] is equivalent to !f(A[i+1], A[i]) for a strict weak ordering f.
  // We parallelize the sampling and counting for minimal overhead.
  auto num_in_order = parlay::count_if(parlay::iota<size_t>(num_samples), [&](size_t i) {
    // Uniformly sample starting positions for adjacent pairs to avoid bias.
    // Use 128-bit arithmetic to prevent overflow on huge inputs, just in case.
    size_t idx = (static_cast<unsigned __int128>(i) * (n - 1)) / num_samples;
    return !f(A[idx + 1], A[idx]);
  });

  // The threshold of 98% is chosen empirically. The 'almostSortedSeq'
  // generator creates inputs where this condition will be met.
  if (num_in_order > num_samples * 98 / 100) {
    return stable_parallel_merge_sort(parlay::make_slice(A), f);
  } else {
    // For random, exponential, and other non-sorted distributions,
    // parlay::internal::sample_sort is state-of-the-art.
    return parlay::internal::sample_sort(parlay::make_slice(A), f, true);
  }
}

