constexpr bool INPLACE = true;

// This is a parallel comparison sort based on the Sample Sort algorithm.
// It is designed to be fast and scalable for a wide variety of input
// distributions and data types.
//
// The algorithm works as follows:
// 1.  A small random sample of the input is selected.
// 2.  The sample is sorted, and `p-1` splitters are chosen from it, where `p` is
//     the number of available worker threads.
// 3.  The input array is partitioned into `p` buckets based on these splitters.
//     This is the most complex step and is handled efficiently by the
//     `parlay::pack_into_buckets` primitive, which performs a parallel
//     multi-way partition.
// 4.  Each of the `p` buckets is sorted independently in parallel using a fast
//     serial sort (`std::sort`).
// 5.  The sorted buckets, now concatenated, form the final sorted array.

template <class T, class BinPred>
void compSort(parlay::sequence<T> &A, const BinPred& f) {
  size_t n = A.size();

  // For small inputs, the overhead of parallelization is not worth it.
  // std::sort is highly optimized and very fast for small to medium inputs.
  // The threshold 32768 is a well-tested heuristic.
  if (n < (1 << 15)) {
    std::sort(std::begin(A), std::end(A), f);
    return;
  }

  size_t p = parlay::num_workers();

  // 1. Sampling
  // To get good splitters that partition the data evenly, we oversample.
  // A larger factor provides more robust load balancing, especially for
  // skewed data, at the cost of sorting a larger sample. 32 is a robust choice.
  size_t samples_per_worker = 32;
  size_t num_samples = std::min(n, p * samples_per_worker);

  parlay::sequence<T> samples(num_samples);
  // Each worker contributes samples from its block of the input array.
  size_t block_size = (n + p - 1) / p;

  parlay::parallel_for(0, p, [&](size_t i) {
    // Use a separate random number generator for each thread for thread-safety and performance.
    parlay::random r(i);
    size_t start = std::min(i * block_size, n);
    size_t end = std::min((i + 1) * block_size, n);

    // Determine how many samples this thread should take.
    size_t num_to_sample = (i == p - 1) ? (num_samples - i * samples_per_worker) : samples_per_worker;

    for (size_t j = 0; j < num_to_sample; j++) {
      if (start >= end) {
        // This edge case can happen if p > n. Just take samples from the beginning.
        samples[i * samples_per_worker + j] = A[0];
      } else {
        auto idx = r.next() % (end - start);
        samples[i * samples_per_worker + j] = A[start + idx];
      }
    }
  }, 1); // Granularity of 1 ensures one thread per block for this sampling strategy.

  // 2. Sort samples and select splitters
  std::sort(std::begin(samples), std::end(samples), f);

  parlay::sequence<T> splitters;
  splitters.reserve(p - 1);
  for (size_t i = 0; i < p - 1; i++) {
    // Pick splitters that are evenly spaced in the sorted sample set.
    splitters.push_back(samples[(i + 1) * num_samples / p]);
  }

  // 3. Partition the input array into `p` buckets based on the splitters.
  // The bucketer function determines which bucket an element belongs to by
  // searching for its position among the splitters.
  auto get_bucket = [&](const T& x) {
    return std::upper_bound(std::begin(splitters), std::end(splitters), x, f) - std::begin(splitters);
  };

  // parlay::pack_into_buckets performs a highly optimized parallel multi-way partition.
  // It takes the input sequence, moves elements from it, and returns a new sequence
  // containing the elements partitioned into buckets, along with the bucket offsets.
  auto [packed_items, bucket_offsets] = parlay::pack_into_buckets(std::move(A), get_bucket, p);

  // 4. Sort each bucket in parallel.
  parlay::parallel_for(0, p, [&](size_t i) {
    auto bucket = packed_items.cut(bucket_offsets[i], bucket_offsets[i+1]);
    // Use a fast serial sort for each bucket. std::sort is an excellent choice (typically Introsort).
    std::sort(bucket.begin(), bucket.end(), f);
  }, 1); // Granularity of 1 to assign one bucket per thread if possible, maximizing cache locality.

  // 5. Move the sorted result back to the original sequence A.
  A = std::move(packed_items);
}

