// --- Configuration ---
// Threshold for switching to serial sort. Below this size, the overhead of
// parallelism is not worth it. std::sort is highly optimized.
constexpr size_t SERIAL_SORT_THRESHOLD = 2048;
// Number of samples to pick per bucket. More samples lead to better-balanced
// partitions at the cost of a larger sorting overhead for the samples.
constexpr size_t SAMPLES_PER_BUCKET = 32;
// Block size for parallel partitioning. This should be large enough to amortize
// parallel overhead but small enough for good cache performance (e.g., fit in L2).
constexpr size_t BLOCK_SIZE = 2048;

// --- Forward declarations for recursive ping-pong sort ---
template <class T, class BinPred>
void sample_sort_inplace(parlay::slice<T> s, parlay::slice<T> tmp, const BinPred& f);

template <class T, class BinPred>
void sample_sort_to_tmp(parlay::slice<T> s, parlay::slice<T> tmp, const BinPred& f);


// Partitions slice `s` into buckets and moves the elements to slice `tmp`.
// Returns a sequence of bucket start indices in `tmp`.
// This is the core of the samplesort algorithm.
template <class T, class BinPred>
parlay::sequence<size_t> partition_to_tmp(parlay::slice<T> s, parlay::slice<T> tmp, size_t num_buckets, const BinPred& f) {
  size_t n = s.size();

  // --- Step 1: Sampling and Splitter Selection ---
  parlay::sequence<T> samples(std::min(n, num_buckets * SAMPLES_PER_BUCKET));
  // Use deterministic sampling for performance consistency and easier debugging.
  // A random sample would be more robust against adversarially constructed inputs.
  for (size_t i = 0; i < samples.size(); i++) {
    samples[i] = s[(static_cast<uint64_t>(i) * n) / samples.size()];
  }
  std::sort(samples.begin(), samples.end(), f);

  parlay::sequence<T> splitters;
  splitters.reserve(num_buckets - 1);
  for (size_t i = 1; i < num_buckets; i++) {
    const T& sample = samples[i * samples.size() / num_buckets];
    // Ensure unique splitters to avoid empty buckets and simplify logic.
    if (splitters.empty() || f(splitters.back(), sample)) {
      splitters.push_back(sample);
    }
  }
  size_t actual_buckets = splitters.size() + 1;

  // --- Step 2: Count elements per bucket in parallel blocks ---
  size_t num_blocks = (n + BLOCK_SIZE - 1) / BLOCK_SIZE;
  parlay::sequence<parlay::sequence<size_t>> counts(num_blocks, parlay::sequence<size_t>(actual_buckets, 0));

  parlay::parallel_for(0, num_blocks, [&](size_t i) {
    size_t start = i * BLOCK_SIZE;
    size_t end = std::min(start + BLOCK_SIZE, n);
    for (size_t j = start; j < end; j++) {
      // Find bucket for s[j] using binary search on sorted splitters.
      auto it = std::upper_bound(splitters.begin(), splitters.end(), s[j], f);
      size_t bucket_idx = std::distance(splitters.begin(), it);
      counts[i][bucket_idx]++;
    }
  }, 1);

  // --- Step 3: Compute bucket offsets and move elements ---
  // A parallel scan computes the starting position for each block's contribution to each bucket.
  parlay::sequence<size_t> bucket_offsets = parlay::scan(parlay::flatten(counts)).first;

  // In parallel, each thread moves its elements from s to their final bucketed position in tmp.
  parlay::parallel_for(0, num_blocks, [&](size_t i) {
    size_t start = i * BLOCK_SIZE;
    size_t end = std::min(start + BLOCK_SIZE, n);
    for (size_t j = start; j < end; j++) {
      auto it = std::upper_bound(splitters.begin(), splitters.end(), s[j], f);
      size_t bucket_idx = std::distance(splitters.begin(), it);
      // Use std::move for efficiency with complex types like strings or pairs.
      tmp[bucket_offsets[i * actual_buckets + bucket_idx]++] = std::move(s[j]);
    }
  }, 1);

  // --- Step 4: Calculate final bucket boundaries ---
  parlay::sequence<size_t> bucket_starts(actual_buckets + 1, 0);
  for(size_t i = 0; i < num_blocks; i++) {
    for (size_t j = 0; j < actual_buckets; j++) {
      bucket_starts[j+1] += counts[i][j];
    }
  }
  std::partial_sum(bucket_starts.begin(), bucket_starts.end(), bucket_starts.begin());

  return bucket_starts;
}


// Sorts slice `s` and places the sorted result back into `s`, using `tmp` as scratch space.
template <class T, class BinPred>
void sample_sort_inplace(parlay::slice<T> s, parlay::slice<T> tmp, const BinPred& f) {
  size_t n = s.size();
