  // The bitwise AND is a fast way to compute `hash % num_buckets` since
  // num_buckets is a power of two.
  auto bucketed_elements = parlay::map(A, [num_buckets](const T& x) {
    return std::make_pair(parlay::hash<T>{}(x) & (num_buckets - 1), x);
