// Implementation for unsigned integral types
template <class T>
struct dedup_impl<T, std::enable_if_t<std::is_integral_v<T> && std::is_unsigned_v<T>>> {
  static parlay::sequence<T> apply(parlay::sequence<T> const &A) {
    if (A.empty()) {
      return parlay::sequence<T>();
    }

    auto [min_v, max_v] = parlay::minmax_element(A);
    unsigned long long range = static_cast<unsigned long long>(*max_v) - static_cast<unsigned long long>(*min_v);

    // Heuristic for using the atomic bitmap optimization.
    // Use the bitmap if:
    // 1. The memory for the bitmap is not excessive (e.g., < 512 MiB).
    // 2. The range is not excessively sparse compared to the number of elements.
    //    A sparse range would lead to a very large but mostly empty bitmap,
    //    wasting memory and initialization time. The factor of 16 is a heuristic trade-off.
    constexpr size_t max_bitmap_bytes = 512 * 1024 * 1024;
    if ((range + 1) < max_bitmap_bytes && range < static_cast<unsigned long long>(A.size()) * 16) {
      parlay::sequence<std::atomic<bool>> seen(range + 1);
      // Initialize the bitmap in parallel. Using a grain size can improve
      // performance for the parallel_for.
      parlay::parallel_for(0, range + 1, [&](size_t i) {
        seen[i].store(false, std::memory_order_relaxed);
      }, 1024);

      auto min_val = *min_v;
      // Filter the input sequence, keeping only the elements that are seen
      // for the first time. The atomic exchange operation ensures that only
      // one thread will succeed for each unique value.
      return parlay::filter(A, [&](const T& x) {
        return !seen[static_cast<unsigned long long>(x) - min_val].exchange(true, std::memory_order_relaxed);
      });
    } else {
      // Fallback to the default hash-based implementation for sparse ranges.
      return parlay::remove_duplicates(A);
    }
  }
};

