    // `parlay::pack` is an efficient parallel primitive for this filtering operation.
    return parlay::pack(sorted, flags);
  } else {
    // For all other types (e.g., strings, custom objects) or large/unsupported integers,
    // a hash-based approach is the most robust and generally fastest method.
    // Hashing is typically much faster than comparison for complex types, making
    // the O(n) expected work of the hash-based algorithm superior to an
    // O(n log n) comparison-sort-based one. The hash-based approach is also more
    // memory-efficient when there are many duplicates (e.g., exponential distribution),
    // as the size of the hash table depends on the number of unique elements.
    // `parlay::remove_duplicates` provides a state-of-the-art implementation of this strategy.
    return parlay::remove_duplicates(A);
