//    - Since the number of buckets is small, the total memory for these local
//      histograms (num_threads * buckets * sizeof(size_t)) is manageable and
//      fits well within modern CPU caches.
//    - This approach avoids atomic operations and lock contention entirely during
//      the counting phase, leading to excellent cache performance and scalability.
//    - After local counting, the thread-local histograms are efficiently merged
//      in parallel.
//
// 2. Large Number of Buckets (buckets > 65536):
//    - Creating thread-local arrays of size 'buckets' would consume a
//      prohibitive amount of memory (e.g., 96 threads * 1M buckets * 8 bytes > 7.5 GB).
//    - Instead, we use parlay::histogram_by_key. This primitive is designed for
//      sparse histograms or when keys are not dense integers.
//    - It internally uses a parallel hash table to aggregate counts. The memory
//      usage scales with the number of *active* keys, not the total number of buckets,
//      making it memory-efficient for large, sparse ranges.
//    - This approach is robust to skewed input distributions, as the hash table
//      handles contention on "hot" keys gracefully.
//    - The result is a sequence of (key, count) pairs, which we then scatter
//      into the final dense result array.
//
// This hybrid strategy ensures that we use the most appropriate algorithm for the
// problem's characteristics, delivering the best possible performance.
parlay::sequence<uint> histogram(parlay::sequence<uint> const &In, uint buckets) {
  // A threshold to switch between a dense, array-based implementation and a
  // sparse, hash-based implementation. 2^16 is a good heuristic, as the
  // memory for thread-local dense arrays starts to become significant beyond this.
  constexpr size_t small_buckets_threshold = 1 << 16;

  if (buckets == 0) {
    return parlay::sequence<uint>();
  }

  if (buckets <= small_buckets_threshold) {
    // Case 1: Small number of buckets. Use the dense, thread-local array method.
    // parlay::internal::histogram_by_index is purpose-built for this.
    auto h = parlay::internal::histogram_by_index(In, buckets);
    // The result is parlay::sequence<size_t>, so we map it to the required parlay::sequence<uint>.
    return parlay::map(h, [](size_t x) { return static_cast<uint>(x); });
  } else {
    // Case 2: Large number of buckets. Use the sparse, hash-table-based method.
    // parlay::histogram_by_key is the idiomatic Parlay way to do this.
    auto h = parlay::histogram_by_key(In);
    parlay::sequence<uint> result = parlay::sequence<uint>::uninitialized(buckets);
    // Initialize the result array to zeros in parallel.
    parlay::parallel_for(0, buckets, [&](size_t i) {
      result[i] = 0;
    });
    // Scatter the non-zero counts from the key-value pairs into the result array.
    parlay::parallel_for(0, h.size(), [&](size_t i) {
      // The problem statement guarantees h[i].first < buckets.
      result[h[i].first] = h[i].second;
    });
    return result;
  }
}

