// You are an expert C++ programmer with extensive experience in parallel programming.
// Write a parallel histogram/sequential procedure in C++ that is correct and is the fastest parallel histogram/sequential program you can generate.

parlay::sequence<uint> histogram(parlay::sequence<uint> const &In, uint buckets) {
  if (buckets == 0) {
    return parlay::sequence<uint>();
  }

  // A threshold for the total size of local histograms (in number of elements).
  // If (num_threads * buckets) is below this, we use a contention-free
  // local histogram approach. 4M elements = 16MB, which is a safe size
  // to keep L3 caches happy on most modern server CPUs.
  constexpr size_t local_hist_size_threshold = 4000000;
  size_t num_threads = parlay::num_thread_ids();

  // Strategy 1: Per-thread local histograms.
  // This is the fastest approach when the total memory for local histograms is
  // reasonable. It is contention-free during the main counting phase, leading
  // to excellent scaling. It is ideal for small-to-medium numbers of buckets.
  if (buckets * num_threads <= local_hist_size_threshold && In.size() > 2048) {
    auto local_hists = parlay::tabulate(num_threads, [buckets](size_t) {
      return parlay::sequence<uint>(buckets, 0);
    });

    // Each thread computes its own histogram on a slice of the input.
    // No atomics or locks are needed here, maximizing throughput.
    parlay::parallel_for(0, In.size(), [&](size_t i) {
      local_hists[parlay::my_thread_id()][In[i]]++;
    }, 1024);

    // Reduce the local histograms into the first one using a tree-like reduction.
    // This minimizes sequential work and completes in log(num_threads) steps.
    for (size_t step = 1; step < num_threads; step *= 2) {
      parlay::parallel_for(0, num_threads, [&](size_t i) {
        if (i % (2 * step) == 0 && (i + step) < num_threads) {
          // Thread i merges the histogram from thread (i + step).
          // This inner loop is sequential and thus cache-friendly.
          auto& dest = local_hists[i];
          const auto& src = local_hists[i + step];
          for (size_t k = 0; k < buckets; k++) {
            dest[k] += src[k];
          }
        }
      });
    }
    // The final result is in the first local histogram.
    return std::move(local_hists[0]);
  }

  // Strategy 2: Atomic increments.
  // This is the best approach for a very large number of buckets, where local
  // histograms would consume too much memory. Contention is less of an issue
  // when buckets are numerous and the input distribution is not pathologically
  // skewed. This path is also used for small inputs where the setup overhead
  // of the local-histogram strategy is not worthwhile.
  auto counts = parlay::sequence<std::atomic<uint>>::from_function(buckets, [](size_t){ return 0; });
  parlay::parallel_for(0, In.size(), [&](size_t i) {
    // Relaxed memory order is sufficient and fastest since we only need the
    // final sum for each bucket, not a specific ordering of increments.
    // This avoids expensive memory fences on each operation.
    counts[In[i]].fetch_add(1, std::memory_order_relaxed);
