parlay::sequence<uint> histogram(parlay::sequence<uint> const &In, uint buckets) {
  if (buckets == 0) {
    return parlay::sequence<uint>{};
  }

  size_t p = parlay::num_workers();
  // Determine the number of blocks to split the input into.
  // We want enough blocks for good load balancing, but not so many that
  // the overhead of managing them becomes too high.
  // A minimum block size of 2048 is a reasonable choice to amortize overhead.
  size_t num_blocks = In.empty() ? 1 : std::min((size_t)p * 8, (In.size() + 2047) / 2048);

  // Heuristic to choose the best algorithm.
  //
  // 1. Local-histogram approach: Fast, but uses O(num_blocks * buckets) memory.
  //    It is efficient when this memory footprint is manageable and the input
  //    size 'n' is large enough to dominate the O(num_blocks * buckets)
  //    initialization and merge costs.
  //
  // 2. parlay::histogram_by_key: Uses O(n) memory and is better for very large
  //    or sparse 'buckets' where the local-histogram approach would use too
  //    much memory or be dominated by its setup/merge costs.
  //
  // We set a memory limit for the local histograms (e.g., 256MB). We also
  // check if the work density (n / (num_blocks*buckets)) is high enough.
  size_t local_hist_mem = num_blocks * buckets * sizeof(uint);
  bool use_local_hists = (local_hist_mem < (1UL << 28)) && (In.size() > num_blocks * buckets / 4);

  if (use_local_hists) {
    //
    // Algorithm 1: Per-block local histograms
    //

    // 1. Create 'num_blocks' local histograms, each of size 'buckets', initialized to zero.
    auto hists = parlay::tabulate(num_blocks, [=](size_t) {
      return parlay::sequence<uint>(buckets, 0);
    });

    // 2. In parallel, each thread processes a block of the input and computes its local histogram.
    parlay::parallel_for(0, num_blocks, [&](size_t i) {
      size_t start = (i * In.size()) / num_blocks;
      size_t end = ((i + 1) * In.size()) / num_blocks;
      for (size_t j = start; j < end; j++) {
        // As per the problem description, In[j] is guaranteed to be in [0, buckets).
        // No bounds check is needed in this hot loop for maximum performance.
        hists[i][In[j]]++;
      }
    });

    // 3. Merge the local histograms in a cache-friendly tree-reduction.
    // In each step, we merge hists[i+dist] into hists[i] for active 'i'.
    for (size_t dist = 1; dist < num_blocks; dist *= 2) {
      // The parallel_for iterates over all possible destination indices 'i'.
      // The 'if' selects the active ones for this reduction step.
      // A small grain size (1) helps balance the load, since many tasks are empty.
      parlay::parallel_for(0, num_blocks, [&](size_t i) {
        if ((i % (2 * dist) == 0) && (i + dist < num_blocks)) {
          // The merge itself is a sequential loop over buckets.
          // This provides excellent cache performance as it accesses memory contiguously.
          for (size_t b = 0; b < buckets; b++) {
            hists[i][b] += hists[i + dist][b];
          }
        }
      }, 1);
    }

    // The final result is in the first histogram. We move it to avoid a copy.
    return std::move(hists[0]);

  } else {
    //
    // Algorithm 2: Use parlay::histogram_by_key
    //

    // 1. Use parlay::histogram_by_key to get (key, count) pairs.
    // This is the most direct and efficient way to count occurrences in Parlay
    // for sparse or large-range cases. It returns a sorted sequence of pairs.
    auto counts = parlay::histogram_by_key(In);

    // 2. Scatter the counts into the final dense histogram.
    auto result = parlay::sequence<uint>(buckets, 0);

    // This scatter is efficient because 'counts' is sorted by key.
    // Parlay's parallel_for scheduler will assign contiguous blocks of 'counts'
    // to threads, which will then write to mostly disjoint regions of 'result',
    // minimizing cache contention.
    parlay::parallel_for(0, counts.size(), [&](size_t i) {
      // The problem guarantees keys are in [0, buckets), but a check is prudent
      // in this less performance-critical part of the code.
      if (counts[i].first < buckets) {
        result[counts[i].first] = counts[i].second;
      }
    });
    return result;
  }
}

