  if (buckets <= local_hist_threshold) {
    // --- STRATEGY 1: Per-thread local histograms ---
    // This is optimal for a small number of buckets. Each thread gets a private
    // histogram, eliminating atomic operations and contention. The main loop
    // has excellent cache performance if the local histograms fit in cache.

    size_t num_workers = parlay::num_workers();

    // To prevent false sharing, we pad the size of each local histogram so that
    // they start on different cache lines.
    constexpr size_t cache_line_size = 64;
    constexpr size_t uints_per_cache_line = cache_line_size / sizeof(uint);
    size_t padded_buckets = ((buckets + uints_per_cache_line - 1) / uints_per_cache_line) * uints_per_cache_line;

    // A single flat allocation for all local histograms is more cache-friendly
    // than a sequence of sequences.
    auto local_hists = parlay::sequence<uint>::uninitialized(num_workers * padded_buckets);

    // Initialize all local histograms to 0 in parallel.
    parlay::parallel_for(0, num_workers, [&](size_t i) {
      std::fill(local_hists.begin() + i * padded_buckets,
                local_hists.begin() + i * padded_buckets + buckets, 0);
    });

    // Each thread processes a block of the input and updates its private histogram.
    // This loop is contention-free. A grain size is used to reduce scheduling overhead.
    parlay::parallel_for(0, In.size(), [&](size_t i) {
      size_t worker = parlay::worker_id();
      local_hists[worker * padded_buckets + In[i]]++;
    }, 1024);

    // Sum the local histograms into the final result. This is a parallel reduction
    // where each thread is responsible for summing a range of final buckets.
    auto result = parlay::sequence<uint>::uninitialized(buckets);
    parlay::parallel_for(0, buckets, [&](size_t b) {
      uint64_t sum = 0; // Use 64-bit accumulator for safety against overflow
      for (size_t i = 0; i < num_workers; i++) {
        sum += local_hists[i * padded_buckets + b];
      }
      result[b] = static_cast<uint>(sum);
    });
