  } else {
    // --- STRATEGY 2: Sort-based histogram ---
    // This is optimal for a large number of buckets. It avoids the O(num_workers * buckets)
    // memory overhead and the cache-thrashing random writes of Strategy 1.
    // The complexity is dominated by the parallel sort, which is effectively O(n) for integers.

    // 1. Create a sorted copy of the input. parlay::sort is a fast parallel radix sort.
    auto sorted_in = parlay::sort(In);

    // 2. parlay::group_by_key is highly optimized for sorted ranges. It finds
    //    all consecutive runs of equal elements and returns a sequence of
    //    pairs: (key, slice_of_equal_keys). This is much faster than hashing.
    auto hist_pairs = parlay::group_by_key(sorted_in);

