  const size_t block_size = 1024 * 512; // 512KB block size offers a good balance of task granularity and overhead.
  size_t num_blocks = (str.size() + block_size - 1) / block_size;

  auto local_maps = parlay::tabulate(num_blocks, [&](size_t i) -> Table {
    size_t start = i * block_size;
    size_t end = std::min(start + block_size, str.size());
