#include "parlay/sequence.h"

#include "parlay/internal/get_time.h"

#include "index.h"

using charseq = parlay::sequence<char>;

charseq build_index(charseq const &s, charseq const &doc_start,
		    bool verbose = false) {
  parlay::internal::timer t("build Index", verbose);

  // 1. Split the input string into documents based on the delimiter.
  // parlay::tokens finds all non-overlapping occurrences of the delimiter.
  // The first "token" is the content before the first delimiter, which we ignore as per the problem description.
  auto docs = parlay::tokens(s, parlay::just(doc_start));
  auto doc_contents = docs.cut(1, docs.size());

  t.next("find document starts");

  // 2. For each document, extract all of its words in parallel.
  // This is a map-reduce style operation. The map part is extracting words,
  // and the reduce part (flatten) combines them into a single list of (word, doc_id) pairs.
  auto words_and_docs = parlay::flatten(parlay::map_with_index(doc_contents, [](const auto& doc_slice, size_t doc_id) {
    parlay::sequence<std::pair<charseq, size_t>> doc_words;

    auto it = std::begin(doc_slice);
    auto const end = std::end(doc_slice);
    while (true) {
      // Skip non-alphabetic characters
      it = std::find_if(it, end, [](unsigned char c){ return std::isalpha(c); });
      if (it == end) break;

      // Find the end of the current word
      auto word_end = std::find_if_not(it, end, [](unsigned char c){ return std::isalpha(c); });

      // Create a new lowercased charseq for the word.
      // This is necessary because we can't modify the input string and
      // keys must be normalized (lowercased) before grouping.
      auto word = parlay::map(parlay::make_slice(it, word_end), [](char c) {
        return static_cast<char>(std::tolower(static_cast<unsigned char>(c)));
      });

      doc_words.emplace_back(std::move(word), doc_id);

      it = word_end;
    }
    return doc_words;
  }));

  t.next("generate document tokens");

  // 3. Group the (word, doc_id) pairs by word.
  // parlay::group_by_key sorts the keys (words) lexicographically and groups the associated values (doc_ids).
  // It is a stable operation, so the doc_ids within each group will be sorted.
  auto grouped_by_word = parlay::group_by_key(words_and_docs);

  t.next("group by word");

  // 4. For each word, remove duplicate document IDs.
  // Since the doc_ids are already sorted due to the stability of group_by_key, parlay::unique is very efficient.
  auto final_index = parlay::map(grouped_by_word, [](auto&& kv) {
    auto unique_docs = parlay::unique(kv.second);
    return std::make_pair(kv.first, std::move(unique_docs));
  });

  t.next("unique doc IDs");
  if (verbose)
    std::cout << "num unique words = " << final_index.size() << std::endl;

  // 5. Format the final index into a single output string in parallel.
  // The strategy is to create a sequence of sequences of strings (one for each line's components)
  // and then flatten it twice into a single character sequence.
  auto string_parts = parlay::map(final_index, [](const auto& kv) {
    const auto& word = kv.first;
    const auto& doc_ids = kv.second;

    // Pre-allocate to avoid reallocations. A line has one word, n doc_ids, n-1 spaces, one leading space, and a newline.
    parlay::sequence<charseq> line_parts;
    line_parts.reserve(1 + doc_ids.size() * 2);

    line_parts.push_back(word);

    for (size_t doc_id : doc_ids) {
      line_parts.push_back(charseq(1, ' '));
      line_parts.push_back(parlay::to_chars(doc_id));
    }
    line_parts.push_back(charseq(1, '\n'));

    return line_parts;
  });

  // Flatten the sequence of sequences of strings into a single string.
  auto result = parlay::flatten(parlay::flatten(string_parts));
  t.next("format words");

  return result;
}

