    // Copy the word
    out = std::copy(std::begin(word), std::end(word), out);

    // Copy the doc_ids
    for (size_t doc_id : doc_ids) {
      *out++ = ' ';
      // std::to_chars is a fast, non-allocating way to convert int to string
      auto [ptr, ec] = std::to_chars(out, result.data() + total_size, doc_id);
      out = ptr;
    }
    *out++ = '\n';
  });
  t.next("format output");

  return result;
}
