#include <iostream>
#include <algorithm>
#include <cctype>

#include "parlay/io.h"
#include "parlay/primitives.h"
#include "parlay/sequence.h"

#include "parlay/internal/get_time.h"

#include "index.h"

using namespace std;

charseq build_index(charseq const &s, charseq const &doc_start,
		    bool verbose = false) {
  parlay::internal::timer t("build Index", verbose);

  // 1. Find all occurrences of the document start string in parallel.
  // Each iterator in the result points to the beginning of a doc_start sequence.
  auto doc_starts = parlay::str_search_all(s, doc_start);
  size_t num_docs = doc_starts.size();
  t.next("find documents");

  if (num_docs == 0) {
    return charseq{};
  }

  // 2. In parallel for each document, generate a sequence of (word, doc_id) pairs.
  // A word is a sequence of chars, normalized to lower case.
  auto pairs_per_doc = parlay::tabulate(num_docs, [&](size_t doc_id) {
    auto doc_content_start = doc_starts[doc_id] + doc_start.size();
    auto doc_content_end = (doc_id + 1 == num_docs) ? s.end() : doc_starts[doc_id + 1];

    parlay::sequence<std::pair<parlay::sequence<char>, size_t>> doc_pairs;

    auto it = doc_content_start;
    while (it < doc_content_end) {
      // Skip non-alphabetic characters
      it = std::find_if(it, doc_content_end, [](unsigned char c) { return std::isalpha(c); });
      if (it == doc_content_end) break;

      // Find the end of the current word
      auto word_end = std::find_if_not(it, doc_content_end, [](unsigned char c) { return std::isalpha(c); });

      // Create the normalized (lowercase) word
      parlay::sequence<char> word(word_end - it);
      std::transform(it, word_end, word.begin(), [](unsigned char c) { return std::tolower(c); });
      doc_pairs.emplace_back(std::move(word), doc_id);

      it = word_end;
    }
    return doc_pairs;
  });

  // Flatten the sequence of sequences into a single sequence of pairs.
  auto all_pairs = parlay::flatten(pairs_per_doc);
  t.next("generate document tokens");

  // 3. Group the pairs by word to form the inverted index.
  // This is done by sorting, keeping unique pairs, and then grouping.

  // Sort by word, then by doc_id
  parlay::sort_inplace(all_pairs);

  // Remove duplicate (word, doc_id) pairs. This ensures each word lists a doc_id at most once.
  auto unique_pairs = parlay::unique(all_pairs);

  // Group by key (the word) to get the final inverted index structure.
  // The result is sorted by word. The doc_id lists are sorted and unique
  // due to the previous steps.
  auto grouped_by_word = parlay::group_by_key(unique_pairs);
  t.next("group by word");

  if (verbose)
    cout << "num unique words = " << grouped_by_word.size() << endl;

  // 4. Format the output string in parallel.
  // This is a highly optimized approach that calculates the final string size,
  // allocates once, and then writes the parts in parallel.

  // Pre-generate string representations of all document IDs.
  auto doc_id_strs = parlay::tabulate(num_docs, [](size_t i) {
    return parlay::to_chars(i);
  });

  // In parallel, calculate the length of each line in the output.
  auto line_lengths = parlay::map(grouped_by_word, [&](const auto& entry) {
    const auto& word = entry.first;
    const auto& ids = entry.second;
    size_t ids_len = 0;
    // This inner loop is sequential, which is efficient since the outer map is parallel.
    for (size_t id : ids) {
      ids_len += doc_id_strs[id].size();
    }
    size_t spaces = ids.empty() ? 0 : ids.size() - 1;
    // Format: word + ' ' + (ids joined by ' ') + '\n'
    return word.size() + 1 + ids_len + spaces + 1;
  });

  // Compute the starting offset of each line and the total length of the string.
  auto [offsets, total_len] = parlay::scan(line_lengths);

  // Allocate the final result string.
  charseq result(total_len, '\0');

  // In parallel, write each formatted line into its correct position.
  parlay::parallel_for(0, grouped_by_word.size(), [&](size_t i) {
    char* out = result.begin() + offsets[i];
    const auto& word = grouped_by_word[i].first;
    const auto& ids = grouped_by_word[i].second;

    // Write word
    out = std::copy(word.begin(), word.end(), out);
    *out++ = ' ';

    // Write document IDs
    for (size_t j = 0; j < ids.size(); j++) {
      const auto& id_str = doc_id_strs[ids[j]];
      out = std::copy(id_str.begin(), id_str.end(), out);
      if (j < ids.size() - 1) {
        *out++ = ' ';
      }
    }
    *out++ = '\n';
  });
  t.next("format words");

  return result;
}

