  // 2a. Create a processed version of the string for tokenization in a single pass.
  // This avoids many small allocations and copies from the per-document approach.
  auto s_processed = parlay::map(s, [](char c) {
    if (c >= 'A' && c <= 'Z') return (char)(c + 32);
    if (c >= 'a' && c <= 'z') return c;
    return ' '; // Use space as a universal delimiter
  });
  t.next("preprocess string");

  // 2b. Get all tokens from the entire text at once.
  auto all_tokens = parlay::tokens(s_processed, [](char c) { return c == ' '; });
  t.next("tokenize");

  // 2c. Tag each token with its document ID and filter invalid ones.
  // parlay::map_maybe is used to map and filter in a single pass.
  auto word_doc_pairs = parlay::map_maybe(all_tokens, [&](parlay::chars token) -> std::optional<std::pair<parlay::chars, unsigned int>> {
    size_t pos = token.begin() - s_processed.begin();

    // Find which document interval [starts[i], starts[i+1]) the token is in.
    auto it = std::upper_bound(std::begin(starts), std::end(starts), pos);

    // If token is before the first doc, it's invalid.
    if (it == std::begin(starts)) {
      return std::nullopt;
    }

    // The token is in the interval of the previous document start.
    unsigned int doc_id = std::distance(std::begin(starts), it) - 1;

    // Check if the token is part of the actual document content, not the <doc> tag.
    if (pos < starts[doc_id] + m) {
      return std::nullopt;
    }

    return std::make_pair(token, doc_id);
  });
  t.next("tag & filter tokens");

  // 3. Deduplication
  // A single large sort is more efficient than many small per-document sorts.
  parlay::sort_inplace(word_doc_pairs);
  t.next("sort pairs");

