  // per-document word deduplication but performed globally and more efficiently.
  auto unique_pairs = parlay::unique(word_doc_pairs);
  t.next("unique pairs");

  // 4. Grouping
  // parlay::group_by_key is highly optimized. Since input is sorted, it's very fast.
  // The resulting groups are sorted by key (word), and doc_ids within each group are sorted.
  auto words = parlay::group_by_key(std::move(unique_pairs));
  t.next("group by key");

