  auto line_lengths = parlay::map(words, [&](const auto& group) {
    size_t len = group.first.size() + 1; // word + newline
    for (auto id : group.second) {
      len += 1 + docstr[id].size(); // ' ' + id_string
    }
    return len;
  });
  t.next("calc line lengths");

  // 5c. Calculate offsets for each line and the total output size.
  auto [offsets, total_len] = parlay::scan(line_lengths);
  t.next("scan lengths");

  // 5d. Allocate the final output string once.
  charseq result(total_len);

  // 5e. Write to the output string in parallel.
  parlay::for_each(parlay::iota(words.size()), [&](size_t i) {
    const auto& [word, doc_ids] = words[i];
    char* out = result.data() + offsets[i];

    // Copy word
    std::memcpy(out, word.data(), word.size());
    out += word.size();

    // Copy doc ids, separated by spaces
    for (auto id : doc_ids) {
      *out++ = ' ';
      const auto& s_id = docstr[id];
      std::memcpy(out, s_id.data(), s_id.size());
      out += s_id.size();
    }

    *out = '\n';
  }, 1000); // Use a grain size for better load balancing
  t.next("parallel write");

  return result;
}

