    }
    return size;
  });

  // b) Compute the prefix sum of sizes to find the start offset of each line.
  auto offsets = parlay::scan_inclusive(line_sizes).first;

  // c) Allocate the final output string with the total size.
  charseq result(offsets.empty() ? 0 : offsets.back());

  // d) In parallel, write each formatted line directly into its final position.
  parlay::parallel_for(0, words.size(), [&](size_t i) {
    size_t offset = (i == 0) ? 0 : offsets[i - 1];
    size_t current_pos = offset;
    const auto& [word, doc_ids] = words[i];

    // Write word
    auto word_it = std::begin(word);
    auto result_it = std::begin(result) + current_pos;
    while(word_it != std::end(word)) *result_it++ = *word_it++;
    current_pos += word.size();

    // Write doc_ids
    for (unsigned int doc_id : doc_ids) {
      result[current_pos++] = ' ';
      const auto& ds = docstr[doc_id];
      auto ds_it = std::begin(ds);
      result_it = std::begin(result) + current_pos;
      while(ds_it != std::end(ds)) *result_it++ = *ds_it++;
      current_pos += ds.size();
    }

    // Write newline
    result[current_pos++] = '\n';
  }, 1); // Use a grain size of 1 as work per line can be very different.
  t.next("format output");

  return result;
}

