#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/io.h"
#include "parlay/internal/get_time.h"
#include "index.h"

using charseq = parlay::sequence<char>;
using string_view = parlay::string_view;

charseq build_index(charseq const &s, charseq const &doc_start,
		    bool verbose = false) {
  parlay::internal::timer t("build Index", verbose);
  size_t n = s.size();

  // Find all occurrences of the document start string. parlay::search returns
  // iterators, so we map them to indices.
  auto doc_start_iters = parlay::search(s, doc_start);
  auto doc_starts = parlay::map(doc_start_iters, [&](const char* p) {
    return static_cast<size_t>(p - s.begin());
  });
  size_t num_docs = doc_starts.size();
  t.next("get starts");

  if (num_docs == 0) {
    return charseq{};
  }

  // Create a single, mutable copy of the input string that will be cleaned
  // in-place. Use a shared_ptr to manage its lifetime, ensuring it exists
  // as long as the string_views that point into it.
  auto scopy = std::make_shared<parlay::sequence<char>>(s);

  // Clean the string in-place: convert to lowercase and replace all
  // non-alphabetic characters with a null terminator, which acts as a
  // delimiter for parlay::tokens.
  parlay::for_each(*scopy, [](char& c) {
    if (c >= 'A' && c <= 'Z') c += 32;
    else if (c < 'a' || c > 'z') c = 0;
  });
  t.next("clean string");

  // In parallel, process each document to generate a flat list of
  // (word, doc_id) pairs. The words are string_views into `scopy`.
  auto word_doc_pairs = parlay::flatten(parlay::tabulate(num_docs,
    [&, scopy_ptr = scopy](size_t doc_id) {
      size_t start = doc_starts[doc_id] + doc_start.size();
      size_t end = (doc_id == num_docs - 1) ? n : doc_starts[doc_id + 1];

      // Get a slice of the cleaned document
      auto doc_slice = scopy_ptr->cut(start, end);

      // Extract tokens (words) from the slice
      auto tokens = parlay::tokens(doc_slice, [](char c) { return c == 0; });

      // Remove duplicate words within the same document
      tokens = parlay::remove_duplicates(tokens);

      // Map each unique word to a (word, doc_id) pair
      return parlay::map(tokens, [doc_id](string_view sv) {
        return std::make_pair(sv, (unsigned int)doc_id);
      });
  }));
  t.next("generate document tokens");

  // Group pairs by word. parlay::group_by_key is sort-based, so the
  // resulting groups will be sorted lexicographically by word.
  // It also preserves the relative order of values, and since doc_ids
  // are processed in increasing order, the list of doc_ids for each
  // word will also be sorted.
  auto words = parlay::group_by_key(std::move(word_doc_pairs));
  t.next("group by word");

  // Pre-calculate the string representation of all possible document IDs.
  // This avoids repeated integer-to-string conversions.
  auto docstr = parlay::tabulate(num_docs, [](size_t i) {
    return parlay::to_chars(i);
  });
  t.next("doc_id to string");

  // --- Output Formatting using Scan-and-Write ---

  // 1. In parallel, calculate the length of the output string for each word group.
  auto line_lengths = parlay::map(words, [&](const auto& group) {
    size_t len = group.first.size(); // word
    // For each doc_id, add 1 for the space and the length of the id's string
    len += group.second.size(); // one space for each doc_id
    for (unsigned int doc_id : group.second) {
      len += docstr[doc_id].size();
    }
    len += 1; // newline
    return len;
  });
  t.next("calc line lengths");

  // 2. Compute the exclusive scan of the lengths to find the starting offset
  //    for each line in the final output string. The second part of the
  //    scan result is the total length.
  auto [offsets, total_len] = parlay::scan(line_lengths);
  charseq result(total_len); // Uninitialized is fine.
  t.next("scan lengths");

  // 3. In parallel, write each formatted line directly into its final
  //    position in the output sequence.
  parlay::for_each(parlay::iota(words.size()), [&](size_t i) {
    const auto& group = words[i];
    char* p = result.data() + offsets[i];

    // Copy the word
    p = std::copy(std::begin(group.first), std::end(group.first), p);

    // Copy the document IDs
    for (unsigned int doc_id : group.second) {
      *p++ = ' ';
      p = std::copy(std::begin(docstr[doc_id]), std::end(docstr[doc_id]), p);
    }

    // Copy the newline
    *p++ = '\n';
  });
  t.next("format words");

  return result;
}

