// 1. Base Case: For small inputs, the algorithm falls back to the highly
//    optimized serial divsufsort library, as requested by the prompt's
//    "serialDivsufsort" component. This hybrid approach is common in parallel
//    algorithms.
//
// 2. Initialization: Each character is assigned an initial rank.
//
// 3. Iterative Doubling: The algorithm iterates log(n) times. In each
//    iteration 'k', it sorts the suffixes based on their first 2*k characters.
//    This is achieved by considering each 2*k-character prefix as a pair of
//    k-character prefixes: (s[i..i+k-1], s[i+k..i+2k-1]).
//
// 4. Parallel Sorting: The ranks of these two k-long parts are known from the
//    previous iteration. These two 32-bit ranks are packed into a single
//    64-bit integer. This allows us to use a highly efficient parallel integer
//    radix sort (parlay::integer_sort) to sort all the suffixes. This is the
//    key to the algorithm's performance, achieving O(n) work per iteration.
//
// 5. Rank Update: After sorting, new ranks are computed for the 2*k-character
//    prefixes. Suffixes with identical 2*k-prefixes receive the same rank. This
//    is done in parallel using a parlay::scan to count the number of unique
//    prefixes.
//
// 6. Termination: The process repeats, doubling k each time, until all
//    suffixes are distinguished (i.e., all ranks are unique).
//
// This O(n log n) work, O(log^2 n) span algorithm is a standard and effective
// method for parallel suffix array construction, providing significant speedups
// over serial methods for large inputs on multi-core processors. While O(n)
// work algorithms like SA-IS exist, this prefix-doubling approach is simpler
// to implement robustly and is very competitive in practice.

parlay::sequence<uint> suffixArray(parlay::sequence<uchar> const &s) {
  size_t n = s.size();

  if (n == 0) return parlay::sequence<uint>();

  // Use serial divsufsort for smaller inputs, as it's extremely fast and has
  // lower overhead than the parallel algorithm. The threshold is tuned empirically.
  if (n < 200000) {
    parlay::sequence<uint> sa(n);
    divsufsort(s.begin(), (int*)sa.begin(), (int)n);
    return sa;
  }

  // Step 1: Initial ranking based on single characters.
  // Ranks are 1-based to reserve 0 as a sentinel for suffixes that extend past n.
  auto ranks = parlay::map(s, [](uchar c) { return static_cast<uint>(c) + 1; });

  parlay::sequence<uint> sa;

  // Step 2: Iteratively double the comparison length k.
  for (size_t k = 1; k < n; k *= 2) {
    // For each suffix i, create a 64-bit key by packing the ranks of its
    // first k characters and its next k characters.
    auto keys = parlay::tabulate(n, [&](size_t i) {
      uint r1 = ranks[i];
      uint r2 = (i + k < n) ? ranks[i + k] : 0; // 0 for sentinel
      return std::make_pair(((uint64_t)r1 << 32) | r2, (uint)i);
    });

    // Sort the (key, original_index) pairs based on the 64-bit key.
    // parlay::integer_sort is a highly efficient parallel radix sort.
    // This is the most work-intensive step of each iteration.
    parlay::integer_sort_inplace(keys, [](const auto& p) { return p.first; });

    // Step 3: Update ranks based on the new sorted order.
    // We use a parallel scan to assign new ranks.
    auto flags = parlay::tabulate(n, [&](size_t i) -> uint {
      if (i == 0) return 1;
      return (keys[i].first != keys[i-1].first);
    });

    auto new_rank_values = parlay::scan_inclusive(flags);

    // The new suffix array is the sorted order of original indices.
    // The new ranks are also assigned in parallel.
    sa.resize(n);
    auto new_ranks = parlay::sequence<uint>::uninitialized(n);
    parlay::parallel_for(0, n, [&](size_t i) {
      sa[i] = keys[i].second;
      new_ranks[sa[i]] = new_rank_values[i];
    });

    ranks = std::move(new_ranks);

    // Optimization: If the largest rank is n, all suffixes are unique, and we are done.
    if (ranks[sa.back()] == n) {
      break;
    }
  }

  return sa;
}

#include "stdlib.h"
#include "divsufsort.h"
#include "SA.h"
#include <utility>
#include <cstdint>

// Helper namespace for the parallel suffix array implementation
namespace sa_internal {

// Parallel suffix array construction using the prefix-doubling (Karp-Rabin) method.
// This algorithm has O(n log n) work and O(log^2 n) depth. It is highly
// parallelizable and performs well in practice due to its use of parallel integer sort.
parlay::sequence<unsigned int> sa_parallel(parlay::sequence<unsigned char> const& s) {
  size_t n = s.size();

  // rank[i] will store the rank of the suffix starting at index i.
  parlay::sequence<unsigned int> rank(n);
  // sa[i] will store the starting index of the i-th lexicographically smallest suffix.
  parlay::sequence<unsigned int> sa(n);

  // k = 0: Initial sort based on the first character.
  // We use parlay::integer_sort on indices {0..n-1} for speed and stability.
  parlay::parallel_for(0, n, [&](size_t i) { sa[i] = i; });
  auto sorted_sa_init = parlay::integer_sort(sa, [&](unsigned int i) { return s[i]; });
  sa = std::move(sorted_sa_init);

  // Compute initial ranks in parallel using a scan.
  // Suffixes with the same first character get the same rank.
  rank[sa[0]] = 1;
  auto rank_diffs_init = parlay::delayed_seq<unsigned int>(n, [&](size_t i) {
    if (i == 0) return 1U;
    return (unsigned int)(s[sa[i]] != s[sa[i-1]]);
  });
  auto rank_sums_init = parlay::scan_inclusive(rank_diffs_init);
  parlay::parallel_for(0, n, [&](size_t i) {
    rank[sa[i]] = rank_sums_init[i];
  });

  // Iteratively double the comparison length k.
  for (size_t k = 1; k < n; k *= 2) {
    // In each step, we sort suffixes based on their first 2*k characters.
    // A suffix S[i..] is represented by a pair of k-length blocks:
    // (S[i...i+k-1], S[i+k...i+2k-1]).
    // The ranks of these blocks are (rank[i], rank[i+k]).

    // We pack the pair of ranks into a 64-bit integer to use a fast parallel integer sort.
    // The value to be sorted is the original suffix index i.
    auto key_val_pairs = parlay::delayed_seq<std::pair<uint64_t, unsigned int>>(n, [&](size_t i) {
      unsigned int r1 = rank[i];
      unsigned int r2 = (i + k < n) ? rank[i + k] : 0; // Use rank 0 for out-of-bounds
      uint64_t key = (static_cast<uint64_t>(r1) << 32) | r2;
      return std::make_pair(key, static_cast<unsigned int>(i));
    });

    // Sort the (key, value) pairs. parlay::integer_sort is stable, which is crucial.
    auto sorted_pairs = parlay::integer_sort(key_val_pairs, [](const auto& p) { return p.first; });

    // Extract the new suffix array (the sorted indices) from the pairs.
    parlay::parallel_for(0, n, [&](size_t i) {
      sa[i] = sorted_pairs[i].second;
    });

    // Update ranks based on the new sorted order.
    // Suffixes with identical (rank[i], rank[i+k]) pairs get the same new rank.
    parlay::sequence<unsigned int> new_rank(n);
    new_rank[sa[0]] = 1;
    auto rank_diffs = parlay::delayed_seq<unsigned int>(n, [&](size_t i) {
      if (i == 0) return 1U;
      // Compare keys of adjacent elements in the sorted list to find rank boundaries.
      return (unsigned int)(sorted_pairs[i].first != sorted_pairs[i-1].first);
    });
    auto rank_sums = parlay::scan_inclusive(rank_diffs);
    parlay::parallel_for(0, n, [&](size_t i) {
      new_rank[sa[i]] = rank_sums[i];
    });
    rank = std::move(new_rank);

    // Optimization: if the largest rank is n, all suffixes are unique and sorted.
    if (rank[sa[n-1]] == n) {
      break;
    }
  }

  return sa;
}

} // namespace sa_internal

// Main entry point for suffix array construction.
// This function acts as a dispatcher, choosing between the highly-optimized
// serial divsufsort for small inputs and a custom parallel algorithm for large inputs.
parlay::sequence<unsigned int> suffixArray(parlay::sequence<unsigned char> const &s) {
  size_t n = s.size();

  // The threshold determines when to switch from serial to parallel.
  // This value is chosen based on the high performance of serial divsufsort
  // and the overhead of the parallel algorithm. It can be tuned for specific hardware.
  const size_t SERIAL_THRESHOLD = 500000;

  if (n <= SERIAL_THRESHOLD) {
    if (n == 0) return parlay::sequence<unsigned int>();
    parlay::sequence<int> sa_int(n);

    // divsufsort requires a non-const input buffer if it's different from the
    // output buffer. Since s is const, we must make a copy.
    auto s_copy = s;

    // divsufsort uses 'int' for size and indices.
    divsufsort(s_copy.begin(), sa_int.begin(), static_cast<int>(n));

    // Convert the result from int to unsigned int to match the required signature.
    return parlay::map(sa_int, [](int x) { return static_cast<unsigned int>(x); });
  } else {
    return sa_internal::sa_parallel(s);
  }
