	       size_t max_j = std::min(len, n - SA[i]);
	       while (j < max_j && (s[SA[i]+j] == s[SA[i+1]+j])) j++;
	       return (j < len) ? j : n;
	    });
  auto L = parlay::make_slice(L_);
  t.next("head");

