  t.next("max element");

  return result_type(lcps[idx],sa[idx],sa[idx+1]);
}

result_type lrs(charseq const &s) {
  // Use 64-bit integers for suffix array if string is large
  if (s.size() > std::numeric_limits<unsigned int>::max()) {
    return lrs_<uint64_t>(s);
  }
  return lrs_<unsigned int>(s);
