using std::endl;
double infinity = std::numeric_limits<double>::infinity();

// some parameters

// minimum size of a node to split
constexpr size_t min_size = 2;
// the following helps prevent overfitting if > 0.0
// probably should be in range [0..1]
constexpr double encode_node_factor = 0.0;

struct tree; // Forward declaration

// A thread-safe arena allocator for tree nodes to avoid the overhead
// of many small thread-safe allocations (e.g., `new`) and to prevent
// memory leaks. All nodes are freed when the arena is destroyed.
struct TreeArena {
  static constexpr size_t CHUNK_SIZE = 1 << 16; // 65536 nodes per chunk
  std::vector<std::unique_ptr<tree[]>> chunks;
  std::atomic<size_t> chunk_idx{0};
  std::atomic<size_t> chunk_offset{0};
  std::mutex m;

  TreeArena() {
    chunks.emplace_back(std::make_unique<tree[]>(CHUNK_SIZE));
  }

  // Non-copyable
  TreeArena(const TreeArena&) = delete;
  TreeArena& operator=(const TreeArena&) = delete;

  tree* alloc() {
    size_t offset = chunk_offset.fetch_add(1, std::memory_order_relaxed);
    if (offset < CHUNK_SIZE) {
      return &chunks[chunk_idx.load(std::memory_order_relaxed)][offset];
    }

    std::lock_guard<std::mutex> lock(m);
    // Another thread might have allocated a new chunk while we were
    // waiting for the lock, so we check again.
    if (chunk_offset.load(std::memory_order_acquire) >= CHUNK_SIZE) {
      chunks.emplace_back(std::make_unique<tree[]>(CHUNK_SIZE));
      chunk_idx.fetch_add(1, std::memory_order_release);
      chunk_offset.store(1, std::memory_order_release); // Start from 1 as we take the 0th element
      return &chunks.back()[0];
    } else {
      // Another thread already added a chunk. We can retry our allocation.
      return alloc();
    }
  }
};

struct tree {
  bool is_leaf;
  int feature_index;
  int feature_cut;
  int best;
  size_t size;
  sequence<tree*> children;

  // Constructor for Internal nodes
  tree(int i, int c, int best, sequence<tree*> children, size_t s)
    : is_leaf(false), feature_index(i), feature_cut(c), best(best), size(s), children(std::move(children)) {}

  // Constructor for Leaf nodes
  tree(int best, size_t s) : is_leaf(true), feature_index(-1), feature_cut(-1), best(best), size(s) {}
};

tree* Leaf(int best, size_t size, TreeArena& arena) {
  if (best > max_value) abort();
  return new (arena.alloc()) tree(best, size);
}

tree* Internal(int i, int cut, int majority, sequence<tree*> children, TreeArena& arena) {
  size_t total_size = parlay::reduce(parlay::delayed_map(children, [] (tree* t) {return t->size;}));
  return new (arena.alloc()) tree(i, cut, majority, std::move(children), total_size);
}

template <typename Range>
bool all_equal(const Range& r) {
  if (std::begin(r) == std::end(r)) return true;
  auto first = *std::begin(r);
  return parlay::all_of(r, [first](const auto& x) { return x == first; });
}

template <typename Range>
auto majority(const Range& a, size_t m) {
  if (parlay::size(a) == 0) return -1;
  auto x = parlay::histogram_by_index(a, m);
  return std::max_element(std::begin(x), std::end(x)) - std::begin(x);
}

// entropy * total given a histogram a (total = sum(a))
template <typename Seq>
double entropy(const Seq& a, size_t total) {
  double ecost = encode_node_factor * log2(static_cast<float>(1 + total)); // to prevent overfitting
  return ecost + parlay::reduce(parlay::delayed_map(a, [=] (int l) {
      return (l > 0) ? -(static_cast<double>(l) * log2(static_cast<float>(l)/total)) : 0.0;
  }));
}

// info of a conditioned on b
auto cond_info(features const& A, int feature_idx, const parlay::sequence<int>& indices) {
  const feature& a = A[0]; // labels
  const feature& b = A[feature_idx];
  size_t n = indices.size();
  if (n == 0) return std::pair(infinity, -1);

  int num_buckets = a.num * b.num;
  auto key_vals = parlay::delayed_map(indices, [&](int i) {
    return a.vals[i] + b.vals[i] * a.num;
  });
  auto sums = parlay::histogram_by_index(key_vals, num_buckets);

  if (b.discrete) {
    double total_entropy = parlay::reduce(parlay::tabulate(b.num, [&](size_t i) {
      auto x = sums.cut(i * a.num, (i + 1) * a.num);
      return entropy(x, parlay::reduce(x));
    }));
    return std::pair(total_entropy, -1);
  } else { // continuous
    parlay::sequence<int> low_counts(a.num, 0);
    parlay::sequence<int> high_counts(a.num, 0);
    for (int i = 0; i < num_buckets; i++) high_counts[i % a.num] += sums[i];

    double cur_e = infinity;
    int cur_i = 0;
    size_t m = 0;
    for (int i = 0; i < b.num - 1; i++) {
      size_t split_count = 0;
      for (int j = 0; j < a.num; j++) {
        int count = sums[a.num * i + j];
        low_counts[j] += count;
        high_counts[j] -= count;
        split_count += count;
      }
      m += split_count;
      if (m > 0 && n - m > 0) {
        double e = entropy(low_counts, m) + entropy(high_counts, n - m);
        if (e < cur_e) {
          cur_e = e;
          cur_i = i + 1;
        }
      }
    }
    return std::pair(cur_e, cur_i);
  }
}

tree* build_tree(features const& A, parlay::sequence<int> indices, TreeArena& arena, bool verbose) {
  size_t num_entries = indices.size();
  auto label_vals = parlay::delayed_map(indices, [&](int i) { return A[0].vals[i]; });
  int majority_value = majority(label_vals, A[0].num);

  if (num_entries < min_size || all_equal(label_vals)) {
    return Leaf(majority_value, num_entries, arena);
  }

  auto label_hist = parlay::histogram_by_index(label_vals, A[0].num);
  double label_info = entropy(label_hist, num_entries);

  int num_features = A.size();
  auto costs = parlay::tabulate(num_features - 1, [&](int i) {
    auto [info, cut] = cond_info(A, i + 1, indices);
    return std::tuple(info, i + 1, cut);
  }, 1);

  auto min1 = [](auto a, auto b) { return (std::get<0>(a) < std::get<0>(b)) ? a : b; };
  auto min_m = parlay::make_monoid(min1, std::tuple(infinity, 0, 0));
  auto [best_info, best_i, cut] = parlay::reduce(costs, min_m);

  double min_info_gain = (num_features <= 1) ? 0.0 : log2(static_cast<float>(num_features - 1));

  if (verbose) {
    cout << "n=" << num_entries << ", best_i=" << best_i << ", cut=" << cut 
         << ", label_info=" << label_info << ", best_info=" << best_info 
         << ", gain=" << label_info - best_info << endl;
  }

  if (best_info == infinity || label_info - best_info < min_info_gain) {
    return Leaf(majority_value, num_entries, arena);
  } else {
    parlay::sequence<parlay::sequence<int>> grouped_indices;
    int feature_to_classify = best_i - 1;

    if (A[best_i].discrete) {
      auto split_on_vals = parlay::delayed_map(indices, [&](int i) { return A[best_i].vals[i]; });
      grouped_indices = parlay::group_by_index(indices, split_on_vals, A[best_i].num);
    } else {
      auto split_keys = parlay::delayed_map(indices, [&](int i) -> value { return A[best_i].vals[i] >= cut; });
      grouped_indices = parlay::group_by_index(indices, split_keys, 2);
    }

    auto children = parlay::map(grouped_indices, [&](auto& child_indices) {
      return build_tree(A, std::move(child_indices), arena, verbose);
    }, 1);

    return Internal(feature_to_classify, cut, majority_value, std::move(children), arena);
  }
}

int classify_row(tree* T, row const& r) {
  while (!T->is_leaf) {
    int child_idx;
    if (T->feature_cut == -1) { // discrete partition
      int val = r[T->feature_index];
      if (val >= T->children.size()) {
        return T->best; // unseen feature value, return node majority
      }
      child_idx = val;
    } else { // continuous cut
      child_idx = (r[T->feature_index] < T->feature_cut) ? 0 : 1;
    }
    T = T->children[child_idx];
  }
  return T->best;
}

row classify(features const &Train, rows const &Test, bool verbose) {
  auto t_build_start = parlay::internal::get_time();
  TreeArena arena;
  auto indices = parlay::iota<int>(Train[0].vals.size());
  tree* T = build_tree(Train, std::move(indices), arena, verbose);
  auto t_build_end = parlay::internal::get_time();

  if (true) {
    cout << "Tree size = " << T->size << endl;
    cout << "Build time = " << (t_build_end - t_build_start) << endl;
  }

  auto t_classify_start = parlay::internal::get_time();
  row result = parlay::map(Test, [&](row const& r) -> value { return classify_row(T, r); });
  auto t_classify_end = parlay::internal::get_time();
  if (true) {
    cout << "Classify time = " << (t_classify_end - t_classify_start) << endl;
  }
  return result;
}

auto classify(features const &Train, rows const &Test, bool verbose) {
  features A = Train;
  TreeArena arena;
  // A loose upper bound on the number of nodes is 2*N - 1.
  if (!Train.empty() && !Train[0].vals.empty()) {
    arena.reserve(2 * Train[0].vals.size());
  }

  tree* T = build_tree(arena, A, verbose);
  if (verbose) cout << "Tree has " << arena.nodes.size() << " nodes, covering " << T->size << " samples." << endl;

  return map(Test, [T] (row const& r) -> value {
    int result = classify_row(T, r);
    // If a node was empty, its majority is -1. Map to a valid value (e.g. max_value).
    return (result == -1) ? max_value : static_cast<value>(result);
  });
}
