#include <iostream>
#include <memory>
#include <algorithm>
#include <cmath>
#include <limits>

#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/delayed.h"
#include "parlay/io.h"

#include "classify.h"

using namespace parlay;
using std::cout;
using std::endl;
constexpr double infinity = std::numeric_limits<double>::infinity();

// --- Parameters ---
// Minimum number of samples required to split an internal node.
constexpr size_t min_split_size = 2;
// A regularization factor to prevent overfitting. A non-zero value penalizes
// larger nodes, encouraging smaller trees.
constexpr double encode_node_factor = 0.0;

// --- Tree Data Structure ---

struct tree; // Forward declaration

// A sequence of unique pointers to own the child nodes.
using tree_children = sequence<std::unique_ptr<tree>>;

// The decision tree node.
// Using std::unique_ptr for automatic memory management to prevent leaks.
struct tree {
  const bool is_leaf;
  const int feature_index; // Index of the feature used for splitting.
  const int feature_cut;   // Cut-off value for continuous features.
  const int best;          // Majority label in the node.
  const size_t num_samples;  // Number of training samples in the node.
  const tree_children children; // Child nodes.

  // Constructor for an internal node.
  tree(int i, int c, int best, tree_children children)
      : is_leaf(false),
        feature_index(i),
        feature_cut(c),
        best(best),
        num_samples(parlay::reduce(parlay::delayed_map(children,
            [](const auto& t) { return t->num_samples; }))),
        children(std::move(children)) {}

  // Constructor for a leaf node.
  tree(int best, size_t s)
      : is_leaf(true),
        feature_index(-1),
        feature_cut(-1),
        best(best),
        num_samples(s) {}
};

// Helper to create a leaf node.
auto Leaf(int best, size_t s) {
  if (best > max_value) abort(); // Sanity check
  return std::make_unique<tree>(best, s);
}

// Helper to create an internal node.
auto Internal(int i, int cut, int majority, tree_children children) {
  return std::make_unique<tree>(i, cut, majority, std::move(children));
}


// --- Entropy and Information Gain Calculation ---

// Calculates entropy * total_count from a histogram.
template <typename Seq>
double entropy(const Seq& hist, size_t total) {
  if (total == 0) return 0.0;
  double cost = encode_node_factor * log2(static_cast<float>(1 + total));
  return cost + parlay::reduce(parlay::delayed_map(hist, [=](int count) {
    return (count > 0) ? -(count * log2(static_cast<float>(count) / total)) : 0.0;
  }));
}

// Calculates the conditional information for a discrete feature.
double cond_info_discrete(const features& A, const parlay::sequence<int>& indices, int label_idx, int feature_idx) {
  const auto& a = A[label_idx];
  const auto& b = A[feature_idx];
  int num_buckets = a.num * b.num;

  auto pairs = parlay::delayed_map(indices, [&](int i) {
    return a.vals[i] + b.vals[i] * a.num;
  });
  auto sums = parlay::histogram_by_index(pairs, num_buckets);

  return parlay::reduce(parlay::tabulate(b.num, [&](size_t i) {
    auto x = sums.cut(i * a.num, (i + 1) * a.num);
    return entropy(x, parlay::reduce(x));
  }));
}

// Calculates the conditional information and the best cut-point for a continuous feature.
auto cond_info_continuous(const features& A, const parlay::sequence<int>& indices, int label_idx, int feature_idx) {
  size_t n = indices.size();
  const auto& a = A[label_idx];
  const auto& b = A[feature_idx];
  int num_buckets = a.num * b.num;

  auto pairs = parlay::delayed_map(indices, [&](int i) {
    return a.vals[i] + b.vals[i] * a.num;
  });
  auto sums = parlay::histogram_by_index(pairs, num_buckets);

  sequence<long> low_counts(a.num, 0);
  sequence<long> high_counts(a.num, 0);

  for (int i = 0; i < b.num; i++)
    for (int j = 0; j < a.num; j++)
      high_counts[j] += sums[a.num * i + j];

  double cur_e = infinity;
  int cur_i = 0;
  size_t m = 0;
  for (int i = 0; i < b.num - 1; i++) {
    size_t current_slice_total = 0;
    for (int j = 0; j < a.num; j++) {
      int count = sums[a.num * i + j];
      low_counts[j] += count;
      high_counts[j] -= count;
      current_slice_total += count;
    }
    m += current_slice_total;
    if (m > 0 && m < n) { // Avoid trivial splits
      double e = entropy(low_counts, m) + entropy(high_counts, n - m);
      if (e < cur_e) {
        cur_e = e;
        cur_i = i + 1;
      }
    }
  }
  return std::pair(cur_e, cur_i);
}

// --- Tree Building ---

// Forward declaration
std::unique_ptr<tree> build_tree(const features& A, parlay::sequence<int> indices, bool verbose);

// Recursively builds the decision tree.
// This version is optimized to avoid data copying by passing sequences of indices
// instead of partitioning the feature data at each step.
std::unique_ptr<tree> build_tree(const features& A, parlay::sequence<int> indices, bool verbose) {
  size_t num_entries = indices.size();
  int num_features = A.size();

  // --- Base Cases for Recursion ---
  auto labels = parlay::delayed_map(indices, [&](int i) { return A[0].vals[i]; });

  int majority_value = -1;
  bool all_same_label = false;

  if (num_entries > 0) {
    auto h = parlay::histogram_by_index(labels, A[0].num);
    majority_value = std::max_element(h.begin(), h.end()) - h.begin();
    all_same_label = (h[majority_value] == num_entries);
  }

  if (num_entries < min_split_size || all_same_label) {
    return Leaf(majority_value, num_entries);
  }

  // --- Find Best Split ---
  double label_info = entropy(parlay::histogram_by_index(labels, A[0].num), num_entries);

  auto costs = parlay::tabulate(num_features - 1, [&](int i) {
    if (A[i + 1].discrete) {
      double info = cond_info_discrete(A, indices, 0, i + 1);
      return std::tuple(info, i + 1, -1);
    } else {
      auto [info, cut] = cond_info_continuous(A, indices, 0, i + 1);
      return std::tuple(info, i + 1, cut);
    }
  });

  auto min_cost = parlay::min_element(costs, [](const auto& a, const auto& b) {
    return std::get<0>(a) < std::get<0>(b);
  });
  auto [best_info, best_i, cut] = *min_cost;

  // --- Split or Create Leaf ---
  double threshold = (num_features > 1) ? log2(static_cast<float>(num_features - 1)) : 0.0;

  if (verbose) {
    cout << "n=" << num_entries << ", feature=" << best_i << ", cut=" << cut
         << ", label_info=" << label_info << ", best_info=" << best_info
         << ", gain=" << (label_info - best_info) << endl;
  }

  // If information gain is not significant, create a leaf node.
  if (label_info - best_info < threshold || best_info == infinity) {
    return Leaf(majority_value, num_entries);
  }

  // Partition indices for recursive calls.
  int num_children;
  parlay::sequence<int> split_keys;
  if (A[best_i].discrete) {
    num_children = A[best_i].num;
    split_keys = parlay::map(indices, [&](int idx) { return A[best_i].vals[idx]; });
  } else {
    num_children = 2;
    split_keys = parlay::map(indices, [&](int idx) -> int { return A[best_i].vals[idx] >= cut; });
  }

  auto grouped_indices = parlay::group_by_index(indices, split_keys, num_children);

  // Recurse on children.
  auto children = parlay::tabulate(num_children, [&](int i) {
    return build_tree(A, std::move(grouped_indices[i]), verbose);
  });

  // feature index in the tree is relative to the test data (0 to k-1)
  return Internal(best_i - 1, cut, majority_value, std::move(children));
}


// --- Classification ---

// Traverses the tree to classify a single data row.
int classify_row(const tree* T, const row& r) {
  if (T->is_leaf) {
    return T->best;
  }

  int val;
  if (T->feature_cut == -1) { // Discrete split
    value feature_val = r[T->feature_index];
    if (!(feature_val < T->children.size())) {
      // Unseen feature value in test data, return majority of current node.
      return T->best;
    }
    val = classify_row(T->children[feature_val].get(), r);
  } else {  // Continuous split
    int child_idx = (r[T->feature_index] < T->feature_cut) ? 0 : 1;
    val = classify_row(T->children[child_idx].get(), r);
  }

  // If a child node was empty (best=-1), fall back to this node's majority.
  return (val == -1) ? T->best : val;
}

// Main classification function.
row classify(features const &Train, rows const &Test, bool verbose) {
  size_t num_train_samples = Train.empty() ? 0 : Train[0].vals.size();
  if (num_train_samples == 0 || Test.empty()) {
    return parlay::sequence<value>();
  }

  // Create initial indices [0, 1, 2, ..., n-1]
  auto indices = parlay::tabulate(num_train_samples, [](int i) { return i; });

  // Build the tree
  auto T = build_tree(Train, std::move(indices), verbose);

  if (verbose) cout << "Tree built on " << T->num_samples << " samples." << endl;

  // Classify all test samples in parallel
  return parlay::map(Test, [&](const row& r) -> value {
    return static_cast<value>(classify_row(T.get(), r));
  });
}

#include <iostream>
#include <memory>
#include <numeric>
#include <algorithm>
#include <optional>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/delayed.h"
#include "parlay/io.h"
#include "parlay/internal/get_time.h"
#include "classify.h"

using namespace parlay;
using std::cout;
using std::endl;
constexpr double infinity = std::numeric_limits<double>::infinity();

// Parameters
constexpr size_t min_size = 2; // A node of size 1 is always a leaf
constexpr double encode_node_factor = 0.0; // Prevents overfitting if > 0

struct tree; // Forward declaration
using tree_ptr = std::unique_ptr<tree>;

struct tree {
  bool is_leaf;
  int feature_index; // Index into the test row (0 to k-1)
  int feature_cut;   // Cut value for continuous, -1 for discrete
  value best;        // Majority label in this node's data
  size_t size;       // Number of leaves in the subtree
  sequence<tree_ptr> children;

  // Internal node constructor
  tree(int i, int c, value best, sequence<tree_ptr>&& children)
    : is_leaf(false), feature_index(i), feature_cut(c), best(best),
      children(std::move(children)) {
    size = reduce(delayed_map(this->children, [](const tree_ptr& t) {
      return t ? t->size : 0;
    }));
  }
  // Leaf node constructor
  tree(value best) : is_leaf(true), best(best), size(1) {}
};

// --- Helper Functions ---

static tree_ptr Leaf(value best) {
  return std::make_unique<tree>(best);
}

static tree_ptr Internal(int i, int cut, value majority, sequence<tree_ptr>&& children) {
  return std::make_unique<tree>(i, cut, majority, std::move(children));
}

template <typename S1>
static bool all_equal(S1 const &a) {
  if (a.size() < 2) return true;
  value first = a[0];
  return parlay::all_of(a, [first](value v) { return v == first; });
}

template <typename S1>
static value majority(S1 const &a, size_t m) {
  if (a.empty()) return 0; // Default label
  auto x = histogram_by_index(a, m);
  return static_cast<value>(std::max_element(x.begin(), x.end()) - x.begin());
}

// entropy * total given a histogram a (total = sum(a))
template <typename Seq>
static double entropy(Seq const& a, long long total) {
  if (total <= 1) return 0.0;
  double ecost = encode_node_factor * log2(static_cast<float>(1 + total));
  return ecost + reduce(delayed_map(a, [=] (long long l) {
      return (l > 0) ? -(l * log2(static_cast<float>(l)/total)) : 0.0;}));
}

// information content of s (i.e. entropy * size)
static double info(row const& s, int num_vals) {
  size_t n = s.size();
  if (n == 0) return 0.0;
  auto x = histogram_by_index(s, num_vals);
  return entropy(delayed_map(x, [](size_t c){ return static_cast<long long>(c); }), n);
}

// info of a conditioned on b
static double cond_info_discrete(feature const &a, feature const &b) {
  int num_buckets = a.num * b.num;
  size_t n = a.vals.size();
  if (n == 0) return 0.0;

  auto sums = histogram_by_index(delayed_tabulate(n, [&] (size_t i) {
			   return a.vals[i] + b.vals[i]*a.num;}), num_buckets);

  return reduce(tabulate(b.num, [&] (size_t i) {
      auto x = sums.cut(i*a.num,(i+1)*a.num);
      return entropy(delayed_map(x, [](size_t c){ return static_cast<long long>(c); }), reduce(x));
  }));
}

// Optimized parallel version for continuous features
static auto cond_info_continuous(feature const &a, feature const &b) {
  int num_buckets = a.num * b.num;
  size_t n = a.vals.size();
  if (n == 0) return std::pair(infinity, 0);

  auto sums = histogram_by_index(delayed_tabulate(n, [&] (size_t i) {
               return a.vals[i] + b.vals[i]*a.num;}), num_buckets);

  auto total_label_counts = tabulate(a.num, [&](size_t j) {
    long long total = 0;
    for(size_t i = 0; i < b.num; i++) total += sums[i * a.num + j];
    return total;
  });

  auto low_counts_prefix_sum = sequence<long long>::uninitialized(num_buckets);
  parallel_for(0, a.num, [&](size_t j) {
    long long current_sum = 0;
    for(size_t i = 0; i < b.num; i++) {
      current_sum += sums[i * a.num + j];
      low_counts_prefix_sum[i * a.num + j] = current_sum;
    }
  });

  auto costs = tabulate(b.num - 1, [&](size_t i) {
    long long m = 0;
    for(size_t j=0; j<a.num; j++) m += low_counts_prefix_sum[i * a.num + j];

    if (m == 0 || m == n) return std::pair(infinity, static_cast<int>(i+1));

    auto low_counts = delayed_tabulate(a.num, [&](size_t j) { return low_counts_prefix_sum[i * a.num + j]; });
    auto high_counts = delayed_tabulate(a.num, [&](size_t j) { return total_label_counts[j] - low_counts_prefix_sum[i * a.num + j]; });

    double e = entropy(low_counts, m) + entropy(high_counts, n - m);
    return std::pair(e, static_cast<int>(i+1));
  });

  if (costs.empty()) return std::pair(infinity, 0);
  auto min_it = min_element(costs);
  return *min_it;
}


static tree_ptr build_tree(features &A, bool verbose) {
  size_t num_features = A.size();
  size_t num_entries = A[0].vals.size();

  if (num_entries == 0) return nullptr;

  value majority_value = majority(A[0].vals, A[0].num);

  if (num_entries < min_size || all_equal(A[0].vals))
    return Leaf(majority_value);

  double label_info = info(A[0].vals,A[0].num);
  auto costs = tabulate(num_features - 1, [&] (int i) {
      if (A[i+1].discrete) {
	      return std::tuple(cond_info_discrete(A[0], A[i+1]), i+1, -1);
      } else {
	      auto [info, cut] = cond_info_continuous(A[0], A[i+1]);
	      return std::tuple(info, i+1, cut);
      }
    }, 1);

  auto [best_info, best_i, cut] = reduce(costs, make_monoid([](auto a, auto b) {
    return (std::get<0>(a) < std::get<0>(b)) ? a : b;
  }, std::tuple(infinity, 0, 0)));

  double threshold = log2(static_cast<float>(num_features));

  if (verbose)
    cout << num_entries << ", " << best_i << ", " << cut << ", " << label_info << ", "
	 << best_info << endl;

  if (label_info - best_info < threshold || best_info == infinity)
    return Leaf(majority_value);
  else {
    int m;
    row split_on;
    if (A[best_i].discrete) {
      m = A[best_i].num;
      split_on = A[best_i].vals;
    } else {
      m = 2;
      split_on =  map(A[best_i].vals, [c=cut] (value x) -> value {return x >= c;});
    }

    auto B = tabulate(m, [&](size_t) {
        return tabulate(num_features, [&](size_t j) {
            return feature(A[j].discrete, A[j].num);
        });
    });

    parallel_for (0, num_features, [&] (size_t j) {
      auto grouped_vals = group_by_index(split_on, A[j].vals, m);
      for (int i=0; i < m; i++) B[i][j].vals = std::move(grouped_vals[i]);
    }, 1);

    auto children = map(B, [&](features &a) {return build_tree(a, verbose);}, 1);
    return Internal(best_i - 1, cut, majority_value, std::move(children));
  }
}

static value classify_row(const tree* T, row const&r) {
  while (!T->is_leaf) {
    if (T->feature_cut == -1) { // discrete partition
      value feature_val = r[T->feature_index];
      if (feature_val >= T->children.size() || T->children[feature_val] == nullptr) {
        return T->best; // Fallback to parent's majority
      }
      T = T->children[feature_val].get();
    } else {  // continuous cut
      int idx = (r[T->feature_index] < T->feature_cut) ? 0 : 1;
      if (idx >= T->children.size() || T->children[idx] == nullptr) {
          return T->best;
      }
      T = T->children[idx].get();
    }
  }
  return T->best;
}

row classify(features const &Train, rows const &Test, bool verbose) {
  features A = Train;
  tree_ptr T = build_tree(A, verbose);
  if (verbose) cout << "Tree size = " << (T ? T->size : 0) << endl;
  return map(Test, [&](row const& r) -> value {
    if (!T) return 0; // Default prediction for empty training set
    return classify_row(T.get(), r);
  });
}

#include <iostream>
#include <vector>
#include <mutex>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/delayed.h"
#include "parlay/io.h"
#include "parlay/internal/get_time.h"
#include "parlay/alloc.h"

// ======================================================================
// The problem description specifies these types and constants.
// ======================================================================
constexpr int max_value = 255;
using value = unsigned char; 
using row = parlay::sequence<value>;
using rows = parlay::sequence<row>;

struct feature {
  bool discrete; 
  int num;       
  row vals;      
  feature(bool discrete, int num) : discrete(discrete), num(num) {}
  feature(bool d, int n, row v) : discrete(d), num(n), vals(v) {}
};

using features = parlay::sequence<feature>;

// ======================================================================
// Forward declarations
// ======================================================================

struct tree;
row classify(features const &Train, rows const &Test, bool verbose);
tree* build_tree_recursive(const features& AllData, const parlay::sequence<int>& indices, bool verbose,
                           parlay::concurrent_arena_allocator<tree>& alloc);
int classify_row(tree* T, row const&r);

// ======================================================================
// Core data structures and parameters
// ======================================================================

using namespace parlay;
using std::cout;
using std::endl;
double infinity = std::numeric_limits<double>::infinity();

// The following helps prevent overfitting if > 0.0
// Probably should be in range [0..1].
double encode_node_factor = 0.0; 

// A mutex to make verbose output readable in parallel execution.
static std::mutex mtx;

// A tree node. Can be a leaf or an internal node.
struct tree {
  bool is_leaf;
  int feature_index;
  int feature_cut;
  int best;
  size_t size;
  sequence<tree*> children;

  // Constructor for an internal node
  tree(int i, int c, int best, sequence<tree*> children)
    : is_leaf(false), best(best), feature_index(i), feature_cut(c), children(children) {
      size_t s = 0;
      for (auto child : children) s += child->size;
      this->size = s;
  }
  // Constructor for a leaf node
  tree(int best) : is_leaf(true), best(best), feature_index(-1), feature_cut(-1), size(1) {}
};

// Custom allocator for tree nodes to improve performance and fix memory leaks.
// Using a static arena means memory is reused across calls to classify in a benchmark
// setting. We clear it at the start of each top-level call.
static parlay::concurrent_arena_allocator<tree> tree_allocator;

// Factory function for a leaf node
tree* Leaf(int best, parlay::concurrent_arena_allocator<tree>& alloc) {
  if (best > max_value) abort(); // Should not happen with valid data
  return new (alloc.allocate(1)) tree(best);
}

// Factory function for an internal node
tree* Internal(int i, int cut, int majority, sequence<tree*> children, parlay::concurrent_arena_allocator<tree>& alloc) {
  return new (alloc.allocate(1)) tree(i, cut, majority, children);
}

// ======================================================================
// Helper functions for entropy calculation
// ======================================================================

// entropy * total given a histogram a (total = sum(a))
template <typename Seq>
double entropy(Seq a, long long total) {
  if (total == 0) return 0.0;
  // A penalty term to prevent overfitting by penalizing large nodes
  double ecost = encode_node_factor * log2(static_cast<float>(1 + total));
  return ecost + reduce(delayed_map(a, [=] (long long l) {
      return (l > 0) ? -(l * log2(static_cast<float>(l)/total)) : 0.0;}));
}

// ======================================================================
// Index-based information theory calculations
// These functions operate on indices into the original dataset, avoiding
// costly data movement and copying.
// ======================================================================

// Find the majority label in an indexed subset of data
template <typename Indices>
auto majority_indexed(Indices const &indices, const feature& label_feature) {
  if (indices.empty()) return -1;
  auto indexed_labels = delayed_map(indices, [&](int idx) { return label_feature.vals[idx]; });
  auto x = histogram_by_index(indexed_labels, label_feature.num);
  return std::max_element(std::begin(x), std::end(x)) - std::begin(x);
}

// Calculate the information content (entropy) of an indexed subset
template <typename Indices>
double info_indexed(Indices const &indices, const feature& label_feature) {
  size_t n = indices.size();
  if (n == 0) return 0.0;
  auto indexed_labels = delayed_map(indices, [&](int idx) { return label_feature.vals[idx]; });
  auto x = histogram_by_index(indexed_labels, label_feature.num);
  return entropy(x, n);
}

// Calculate conditional information for a discrete feature split
template <typename Indices>
double cond_info_discrete_indexed(Indices const &indices, const feature& label_feature, const feature& split_feature) {
  size_t n = indices.size();
  if (n == 0) return 0.0;
  int num_buckets = label_feature.num * split_feature.num;

  auto combined_vals = delayed_map(indices, [&](int idx) {
    return label_feature.vals[idx] + split_feature.vals[idx] * label_feature.num;
  });
  auto sums = histogram_by_index(combined_vals, num_buckets);

  return reduce(tabulate(split_feature.num, [&](size_t i) {
    auto x = sums.cut(i * label_feature.num, (i + 1) * label_feature.num);
    return entropy(x, reduce(x));
  }));
}

// Calculate conditional information for a continuous feature split.
// This is a highly parallel implementation that considers all possible split points.
template <typename Indices>
auto cond_info_continuous_indexed(Indices const &indices, const feature& label_feature, const feature& split_feature) {
  const size_t n = indices.size();
  if (n < 2) return std::pair(infinity, 0);

  const int num_labels = label_feature.num;
  const int num_vals = split_feature.num;
  const int num_buckets = num_labels * num_vals;

  // Create a 2D histogram of (label, feature_value)
  auto combined_vals = delayed_map(indices, [&](int idx) {
    return label_feature.vals[idx] + split_feature.vals[idx] * num_labels;
  });
  auto hist = histogram_by_index(combined_vals, num_buckets);

  // Transpose histogram to be counts[label][value]
  sequence<sequence<long long>> counts_by_label(num_labels, sequence<long long>(num_vals));
  parallel_for(0, num_labels, [&](size_t l) {
    for (size_t v = 0; v < num_vals; v++) {
      counts_by_label[l][v] = hist[v * num_labels + l];
    }
  });

  // Compute prefix sums for each label to find counts <= split point
  sequence<sequence<long long>> low_prefix_sums(num_labels);
  parallel_for(0, num_labels, [&](size_t l) {
    low_prefix_sums[l] = scan(counts_by_label[l]).first;
  });

  auto total_counts_by_label = map(low_prefix_sums, [](const auto& s) {
    return s.empty() ? 0LL : s.back();
  });

  // Compute total items <= split point
  auto total_low_prefix_sum = scan(map(iota(num_vals), [&](size_t v) {
    long long total = 0;
    for (size_t l = 0; l < num_labels; l++) total += counts_by_label[l][v];
    return total;
  })).first;

  // In parallel, calculate entropy for every possible split point
  auto split_entropies = tabulate(num_vals - 1, [&](size_t i) {
    long long m = total_low_prefix_sum[i];
    if (m == 0 || m == n) return std::pair(infinity, i + 1);

    sequence<long long> low_counts(num_labels);
    sequence<long long> high_counts(num_labels);
    for (int l = 0; l < num_labels; l++) {
      low_counts[l] = low_prefix_sums[l][i];
      high_counts[l] = total_counts_by_label[l] - low_counts[l];
    }
    double e = entropy(low_counts, m) + entropy(high_counts, n - m);
    return std::pair(e, i + 1);
  });

  if (split_entropies.empty()) return std::pair(infinity, 0);

  // Find the split with the minimum entropy (maximum information gain)
  return *min_element(split_entropies);
}


// ======================================================================
// Recursive decision tree construction
// ======================================================================

tree* build_tree_recursive(const features& AllData, const parlay::sequence<int>& indices, bool verbose,
                           parlay::concurrent_arena_allocator<tree>& alloc) {

  size_t num_entries = indices.size();
  const int num_features = AllData.size();
  const auto& label_feature = AllData[0];

  int majority_value = majority_indexed(indices, label_feature);

  // Base Case 1: Node is too small or empty.
  if (num_entries < 2) {
    return Leaf(majority_value, alloc);
  }

  // Base Case 2: All elements in the node have the same label.
  auto indexed_labels = delayed_map(indices, [&](int idx) { return label_feature.vals[idx]; });
  if (parlay::count(indexed_labels, indexed_labels[0]) == num_entries) {
    return Leaf(majority_value, alloc);
  }

  // Calculate entropy of the current node's labels.
  double label_info = info_indexed(indices, label_feature);

  // In parallel, find the cost (conditional entropy) for splitting on each feature.
  auto costs = tabulate(num_features - 1, [&](int i) {
    const auto& split_feature = AllData[i + 1];
    if (split_feature.discrete) {
      double info = cond_info_discrete_indexed(indices, label_feature, split_feature);
      return std::tuple(info, i + 1, -1);
    } else {
      auto [info, cut] = cond_info_continuous_indexed(indices, label_feature, split_feature);
      return std::tuple(info, i + 1, cut);
    }
  });

  // Find the feature that gives the best split (minimum conditional entropy).
  auto [best_info, best_i, cut] = reduce(costs, minm<std::tuple<double, int, int>>());

  // Pre-pruning: if information gain is too small, create a leaf.
  // This uses a simple Minimum Description Length (MDL) principle.
  double threshold = log2(static_cast<float>(num_features));

  if (verbose) {
    std::lock_guard<std::mutex> lock(mtx);
    cout << "n=" << num_entries << ", feature=" << best_i << ", cut=" << cut << ", info=" << label_info
         << ", best_info=" << best_info << ", gain=" << label_info - best_info << endl;
  }

  if (label_info - best_info < threshold || best_i == 0) {
    return Leaf(majority_value, alloc);
  }

  // Partition indices based on the best split and recurse.
  int num_groups;
  parlay::sequence<int> split_keys;
  const auto& split_feature = AllData[best_i];

  if (split_feature.discrete) { // Split into a group for each discrete value
    num_groups = split_feature.num;
    split_keys = parlay::map(indices, [&](int idx) { return split_feature.vals[idx]; });
  } else { // Split into two groups based on the continuous cut
    num_groups = 2;
    split_keys = parlay::map(indices, [&](int idx) -> int { return split_feature.vals[idx] >= cut; });
  }

  // group_by_index is much faster on indices than on the full dataset.
  auto grouped_indices = parlay::group_by_index(indices, split_keys, num_groups);

  // Recursively build child trees in parallel.
  auto children = parlay::tabulate(num_groups, [&](size_t i) {
    return build_tree_recursive(AllData, grouped_indices[i], verbose, alloc);
  });

  return Internal(best_i - 1, cut, majority_value, children, alloc);
}

// ======================================================================
// Classification using the built tree
// ======================================================================

// Classify a single row by traversing the decision tree.
int classify_row(tree* T, row const&r) {
  if (T->is_leaf) {
    return T->best;
  } else if (T->feature_cut == -1) { // Discrete feature split
    int feature_val = r[T->feature_index];
    // Handle test values not seen in training data by returning parent's majority.
    if (!(feature_val < T->children.size())) return T->best;
    // Recurse on the appropriate child.
    int val = classify_row(T->children[feature_val], r);
    // If child branch was pruned (val=-1), use this node's majority.
    return (val == -1) ? T->best : val;
  } else {  // Continuous feature split
    // Go to child based on whether value is below or at/above the cut.
    int idx = (r[T->feature_index] < T->feature_cut) ? 0 : 1;
    int val = classify_row(T->children[idx], r);
    return (val == -1) ? T->best : val;
  }
}

// ======================================================================
// Main entry point
// ======================================================================

row classify(features const &Train, rows const &Test, bool verbose) {
  // Clear the arena allocator to free memory from any previous runs.
  tree_allocator.clear();

  // Build the decision tree from the training data.
  // The initial call uses indices [0, 1, ..., n-1].
  auto indices = parlay::iota(Train[0].vals.size());
  tree* T = build_tree_recursive(Train, indices, verbose, tree_allocator);

  if (verbose) {
      std::lock_guard<std::mutex> lock(mtx);
      cout << "Total tree leaf nodes = " << T->size << endl;
  }

  // Classify all test rows in parallel.
  return parlay::map(Test, [&](row const& r) -> value {
    return static_cast<value>(classify_row(T, r));
  });
}

