#include <iostream>
#include <limits.h>
#include <atomic>
#include "parlay/primitives.h"
#include "parlay/parallel.h"
#include "parlay/internal/get_time.h"
#include "common/graph.h"
#include "algorithm/kth_smallest.h"
#include "MST.h"

// **************************************************************
//    PARALLEL VERSION OF KRUSKAL'S ALGORITHM
// **************************************************************

// An edge tagged with its original index.
struct indexedEdge {
  vertexId u; vertexId v; edgeId id; edgeWeight w;
  indexedEdge(vertexId u, vertexId v, edgeId id, edgeWeight w)
    : u(u), v(v), id(id), w(w){}
  indexedEdge() : u(0), v(0), id(0), w(0.0) {};
};

// A concurrent union-find data structure using atomic operations.
// This is used to replace the combination of the simpler union-find
// and speculative_for from the baseline, reducing overhead.
template <class vertexId>
struct unionFind {
  parlay::sequence<std::atomic<vertexId>> parents;

  unionFind(size_t n) {
    parents = parlay::tabulate(n, [](size_t i) -> std::atomic<vertexId> { return i; });
  }

  // find with path halving
  vertexId find(vertexId i) {
    while (i != parents[i].load(std::memory_order_relaxed)) {
      vertexId p = parents[i].load(std::memory_order_relaxed);
      // This CAS is non-blocking. If it fails, another thread is also
      // compressing the path. We just continue with the old parent `p`.
      parents[i].compare_exchange_strong(p, parents[p].load(std::memory_order_relaxed),
                                          std::memory_order_relaxed);
      i = p;
    }
    return i;
  }

  // Fully compress all paths by calling find on every vertex.
  // This is beneficial between the light and heavy edge processing phases.
  void flatten() {
    parlay::parallel_for(0, parents.size(), [&](size_t i) {
      find(i);
    }, 1024);
  }
};

parlay::sequence<edgeId> mst(wghEdgeArray<vertexId,edgeWeight> &E) {
  parlay::internal::timer t("mst", false);
  size_t m = E.m;
  size_t n = E.n;

  // Create a mutable sequence of indexed edges.
  // This is necessary for in-place sorting and partitioning.
  auto edges = parlay::tabulate(m, [&](size_t i) {
    return indexedEdge(E[i].u, E[i].v, i, E[i].weight);
  });
  t.next("create_indexed_edges");

  // A comparator for edges that breaks ties deterministically using the original index.
  auto edgeLess = [](const indexedEdge& a, const indexedEdge& b) {
    if (a.w != b.w) return a.w < b.w;
    return a.id < b.id;
  };

  // Heuristic for the number of light edges to process in the first phase.
  // An MSF has at most n-1 edges, so we aim to select a pivot that keeps
  // at least n edges in the light partition. The 5/4 factor provides slack.
  size_t k = std::min<size_t>(5 * n / 4, m);

  // Use a fast, approximate selection algorithm to find a pivot edge.
  indexedEdge pivot = pbbs::approximate_kth_smallest(edges, k, edgeLess);
  t.next("approximate_kth_smallest");

  // Partition the edges in-place into "light" (weight < pivot's) and "heavy".
  // This is more memory-efficient than filtering into new sequences.
  auto heavy_it = parlay::partition_inplace(edges, [&](const auto& e) { return edgeLess(e, pivot); });
  auto light_edges = parlay::make_slice(edges.begin(), heavy_it);
  auto heavy_edges = parlay::make_slice(heavy_it, edges.end());
  t.next("partition_inplace");

  // Sort the light edges. They are the most likely to be in the MSF.
  parlay::sort_inplace(light_edges, edgeLess);
  t.next("sort_light_edges");

  parlay::sequence<bool> mstFlags(m, false);
  unionFind<vertexId> UF(n);

  // Process the light edges in parallel.
  parlay::parallel_for(0, light_edges.size(), [&](size_t i) {
    auto& e = light_edges[i];
    vertexId root_u = UF.find(e.u);
    vertexId root_v = UF.find(e.v);
    if (root_u != root_v) {
      // Unite the two components. To avoid cycles in the union-find parent pointers
      // and to provide some balance, we deterministically link the smaller ID root
      // to the larger ID root.
      if (root_u > root_v) std::swap(root_u, root_v);
      vertexId expected_parent = root_u;
      // Atomically attempt to link root_u to root_v.
      // If successful, this edge is the first to connect these two components
      // within this batch of edges, so we add it to the MSF.
      if (UF.parents[root_u].compare_exchange_strong(expected_parent, root_v)) {
        mstFlags[e.id] = true;
      }
    }
  }, 1); // Use a small granularity to reduce contention on adjacent edges.
  t.next("process_light_edges");

  // Fully compress the union-find trees. This makes the subsequent filtering
  // and processing of heavy edges much faster as `find` operations will be nearly O(1).
  UF.flatten();
  t.next("flatten_union_find");

  // From the heavy partition, filter out edges that would form a cycle
  // with the MSF edges found so far.
  auto surviving_heavy = parlay::filter(heavy_edges, [&](const auto& e) {
    return UF.find(e.u) != UF.find(e.v);
  });
  t.next("filter_heavy_edges");

  // Sort the remaining heavy edges.
  parlay::sort_inplace(surviving_heavy, edgeLess);
  t.next("sort_heavy_edges");

  // Process the surviving heavy edges in parallel using the same union-find logic.
  parlay::parallel_for(0, surviving_heavy.size(), [&](size_t i) {
    auto& e = surviving_heavy[i];
    // Find must be called again as other threads may have modified the UF structure.
    vertexId root_u = UF.find(e.u);
    vertexId root_v = UF.find(e.v);
    if (root_u != root_v) {
      if (root_u > root_v) std::swap(root_u, root_v);
      vertexId expected_parent = root_u;
      if (UF.parents[root_u].compare_exchange_strong(expected_parent, root_v)) {
        mstFlags[e.id] = true;
      }
    }
  }, 1);
  t.next("process_heavy_edges");

  // Pack the indices of the edges that were marked as part of the MSF.
  auto mst_edges = parlay::pack_index<edgeId>(mstFlags);
  t.next("pack_results");

  return mst_edges;
}

