// This implementation uses a hybrid of Boruvka's algorithm and Kruskal's
// algorithm. This is a common strategy for high-performance parallel MSF.
//
// 1. Boruvka's Phase:
//    - This phase is highly parallel and works well on large graphs.
//    - It proceeds in rounds. In each round:
//      a. For each component in the current forest, find the minimum-weight
//         edge connecting it to another component. This is done in parallel
//         over all edges, using atomic compare-and-swap (`write_min`) to
//         update the minimum edge for each component.
//      b. Add all such minimum-weight edges to the MSF. The union of
//         components is done serially over the list of components. This is a
//         bottleneck, but the number of components decreases exponentially
//         with each round, so it quickly becomes inexpensive.
//      c. The graph is "contracted" by filtering out edges that now connect
//         vertices within the same component.
//    - This phase repeats until the number of components is small or progress
//      stalls.
//
// 2. Kruskal's Phase:
//    - Once the number of components and active edges is significantly
//      reduced, the algorithm switches to a parallel-sort Kruskal's.
//    - The remaining active edges are sorted by weight in parallel.
//    - A final serial pass over the sorted edges adds the remaining MST
//      edges using the same union-find data structure. This is fast
//      because the input size has been drastically reduced by the Boruvka
//      phase.

namespace {

// An edge with its original index
struct edgeAndIndex {
  vertexId u;
  vertexId v;
  edgeWeight weight;
  edgeId id;
};

// Comparison function for edges, using ID as a tie-breaker
auto edgeLess = [](const edgeAndIndex& a, const edgeAndIndex& b) {
  if (a.weight != b.weight) return a.weight < b.weight;
  return a.id < b.id;
};

} // namespace

parlay::sequence<edgeId> mst(wghEdgeArray<vertexId,edgeWeight> &G) {
  size_t n = G.n;
  size_t m = G.m;

  if (m == 0) {
    return parlay::sequence<edgeId>{};
  }

  // 1. Create a sequence of edges tagged with their original IDs
  auto EI = parlay::tabulate(m, [&](size_t i) -> edgeAndIndex {
    return {G.E[i].u, G.E[i].v, G.E[i].weight, (edgeId)i};
  });

  unionFind<vertexId> UF(n);
  parlay::sequence<edgeId> mst_edges;
  mst_edges.reserve(n > 0 ? n - 1 : 0);

  parlay::sequence<edgeAndIndex> active_edges = EI;
  size_t num_components = n;

  // --- Boruvka's Phase ---
  // Repeat while the number of components is large and we are making progress.
  while (num_components > 1 && !active_edges.empty()) {
    // Switch to Kruskal's when the problem is small enough
    if (num_components < std::max((size_t)1000, n / 20)) {
      break;
    }

    // a. Find minimum weight edge for each component
    parlay::sequence<std::atomic<edgeId>> min_edge_indices(n);
    parlay::parallel_for(0, n, [&](size_t i) {
      min_edge_indices[i].store((edgeId)-1, std::memory_order_relaxed);
    });

