    : u(_u), v(_v), weight(w), id(_id) {}
};

// Serial Union-Find loop. Processes a sorted slice of edges.
void unionFindLoop(parlay::slice<const edgeAndIndex> E,
		  unionFind<vertexId> &UF, parlay::sequence<edgeId> &mst) {
  for (const auto& edge : E) {
    vertexId root_u = UF.find(edge.u);
    vertexId root_v = UF.find(edge.v);

    // union by rank
    if (root_u != root_v) {
      UF.union_roots(root_u, root_v);
      mst.push_back(edge.id); // add edge to output
    }
  }
}

parlay::sequence<edgeId> mst(wghEdgeArray<vertexId,edgeWeight> &G) {
  // Tag edges with their original indices
  auto EI = parlay::tabulate(G.m, [&] (size_t i) -> edgeAndIndex {
      return edgeAndIndex(G.E[i].u, G.E[i].v, G.E[i].weight, i);});

  auto edgeLess = [&] (const edgeAndIndex& a, const edgeAndIndex& b) {
    if (a.weight != b.weight) return a.weight < b.weight;
    return a.id < b.id;
  };

  // Heuristic: process a prefix of edges first.
  // This is effective when m >> n, as it reduces the input size to the second sort.
  size_t l = std::min(static_cast<size_t>(4) * G.n / 3, G.m);

  // Partition so minimum `l` elements are at the beginning.
  if (l < G.m) {
    parlay::nth_element(EI.begin(), EI.begin() + l, EI.end(), edgeLess);
  }

  // Sort the prefix in parallel.
  parlay::sort_inplace(parlay::make_slice(EI.begin(), EI.begin() + l), edgeLess);

  // Create union-find structure.
  unionFind<vertexId> UF(G.n);

  // MST edges are added to this sequence.
  parlay::sequence<edgeId> mst;
  mst.reserve(G.n); // An MSF has at most n-1 edges.

  // Run serial union-find over the sorted prefix.
  // This part is kept serial to correctly respect edge weights according to Kruskal's algorithm.
  unionFindLoop(parlay::make_slice(EI.begin(), EI.begin() + l), UF, mst);

  // If we processed all edges or found a spanning tree for a connected graph, we are done.
  if (l == G.m || mst.size() >= G.n - 1) {
    return mst;
  }

  // Filter remaining edges in parallel: keep only those that connect different components.
  // This is safe because UF.find is thread-safe and this is a read-only phase.
  auto remaining_edges = parlay::filter(parlay::make_slice(EI.cbegin() + l, EI.cend()),
                                        [&](const edgeAndIndex& edge) {
    return UF.find(edge.u) != UF.find(edge.v);
  });

  // Sort the filtered remaining edges in parallel.
  parlay::sort_inplace(remaining_edges, edgeLess);

  // Run serial union-find on the (hopefully much smaller) set of remaining edges.
  unionFindLoop(parlay::make_slice(remaining_edges), UF, mst);

  return mst;
}

