parlay::sequence<edgeId> st(edgeArray<vertexId> const &EA) {
  size_t m = EA.nonZeros;
  size_t n = EA.numRows;

  if (m == 0) return parlay::sequence<edgeId>();

  unionFind<vertexId> UF(n);
  parlay::sequence<reservation> R(n);

  // Use a random permutation to process edges. This avoids adversarial inputs
  // and reduces contention in the speculative loop, improving performance.
  auto p = parlay::random_permutation(m);

  // Use a lock-free bag to collect ST edges. This is more efficient than the
  // baseline's final filter over all n vertices, especially when n is large.
  // A forest on n vertices has at most n-1 edges.
  parlay::sequence<edgeId> st_edges((n > 0) ? n - 1 : 0);
  std::atomic<size_t> st_count = 0;

  // This struct encapsulates the logic for a single step in the speculative loop.
  // It is copied for each parallel lane of execution, so its member variables
  // (u, v) safely carry state from reserve to commit for a single edge.
  struct unionFindStep {
    vertexId u, v;
    const edgeArray<vertexId>& E;
    parlay::sequence<reservation>& R;
    unionFind<vertexId>& UF;
    const parlay::sequence<edgeId>& p; // Permutation
    parlay::sequence<edgeId>& st_edges;
    std::atomic<size_t>& st_count;

    unionFindStep(const edgeArray<vertexId>& E,
                  unionFind<vertexId>& UF,
                  parlay::sequence<reservation>& R,
                  const parlay::sequence<edgeId>& p,
                  parlay::sequence<edgeId>& st_edges,
                  std::atomic<size_t>& st_count)
      : E(E), R(R), UF(UF), p(p), st_edges(st_edges), st_count(st_count) {}

    // The reserve phase: speculatively attempt to process an edge.
    // i is the loop index from speculative_for, p[i] is the actual edge index.
    bool reserve(edgeId i) {
      const edgeId edge_idx = p[i];
      u = UF.find(E[edge_idx].u);
      v = UF.find(E[edge_idx].v);

      if (u != v) {
        // Canonicalize the parent-child relationship to avoid cycles
        // and to have a single reservation target for the pair of components.
        if (u < v) std::swap(u, v);
        // Reserve the edge on the component with the larger root ID.
        R[u].reserve(edge_idx);
        return true; // The edge might be added to the ST.
      } else {
        return false; // The edge is internal to a component, discard.
      }
    }

    // The commit phase: confirm the reservation and perform the update.
    bool commit(edgeId i) {
      const edgeId edge_idx = p[i];
      // u and v are member variables set in the reserve() phase.
      // Check if our reservation on the larger root 'u' was successful.
      if (R[u].check(edge_idx)) {
        // Link the two components. This is safe because only one thread
        // can win the reservation for a given component root.
        UF.link(u, v);
        // Add the edge to our concurrent bag. Relaxed memory order is sufficient
        // as we only need atomicity for the counter, not synchronization.
        size_t current_pos = st_count.fetch_add(1, std::memory_order_relaxed);
        st_edges[current_pos] = edge_idx;
        return true; // Commit successful.
      } else {
        return false; // Lost the race, another edge connected to this component.
      }
    }
  };

  unionFindStep UFStep(EA, UF, R, p, st_edges, st_count);

  // A larger granularity can reduce the overhead of speculative_for, which is
  // beneficial on large graphs, especially when randomization reduces contention.
  pbbs::speculative_for<edgeId>(UFStep, 0, m, 256);

  st_edges.resize(st_count.load());
  return st_edges;
}

