using reservation = pbbs::reservation<edgeId>;

// The step struct for speculative_for.
// It attempts to add an edge to the spanning forest.
struct unionFindStep {
  vertexId u;
  vertexId v;
  edgeId edge_idx; // The actual index of the edge in the input array
  edgeArray<vertexId> const &E;
  parlay::sequence<reservation> &R;
  unionFind<vertexId> &UF;
  const parlay::sequence<edgeId>& p; // A permutation of edge indices

  unionFindStep(edgeArray<vertexId> const &E,
                unionFind<vertexId> &UF,
                parlay::sequence<reservation> &R,
                const parlay::sequence<edgeId>& p)
    : E(E), R(R), UF(UF), p(p) {}

  // The reserve step is the first phase of a speculative execution.
  // It checks if an edge can potentially be added and makes a reservation.
  // 'i' is the loop counter from speculative_for (0 to m-1).
  bool reserve(edgeId i) {
    // Process edges in a random order to reduce contention and break adversarial patterns.
    edge_idx = p[i];
    u = UF.find(E[edge_idx].u);
    v = UF.find(E[edge_idx].v);

    // If the endpoints are already in the same component, this edge would form a cycle.
    if (u == v) {
      return false;
    }

    // Canonicalize the component pair to ensure consistent reservations.
    // We always try to reserve on the component with the larger ID.
    if (u > v) std::swap(u,v);

    // Try to reserve this edge's index on the larger component's reservation slot.
    // The edge with the smallest index will win the reservation due to pbbs::write_min.
    R[v].reserve(edge_idx);
    return true;
  }

  // The commit step is the second phase.
  // It checks if the reservation was successful and performs the union.
  // 'i' is the loop counter from speculative_for (0 to m-1).
  bool commit(edgeId i) {
    // Check if our edge (edge_idx) won the reservation for component v.
    if (R[v].check(edge_idx)) {
      // We won. Link the two components.
      // UF.link(v, u) is used instead of a more complex union-by-rank/size
      // to avoid race conditions. The reservation system guarantees that for a
      // given `v`, only one thread will attempt this link, making it safe.
      // The canonical ordering (v > u) prevents trivial cycles in the UF parent pointers.
      UF.link(v, u);
      return true; // Success
    } else {
      return false; // Lost the race, another edge connected to v first.
    }
  }
};

parlay::sequence<edgeId> st(edgeArray<vertexId> const &G){
  size_t m = G.nonZeros;
  size_t n = G.numRows;

  if (m == 0) return parlay::sequence<edgeId>();

  // The baseline algorithm is a highly optimized speculative version of Kruskal's.
  // Its performance can be sensitive to contention, which arises when many
  // edges try to connect the same components simultaneously. This can happen
  // with certain graph structures or edge orderings.
  //
  // To improve robustness and performance across different graph types, this
  // implementation processes the edges in a random order. This helps to break
  // adversarial patterns and distribute the workload more evenly, reducing
  // contention and the number of failed speculative attempts.
  auto p = parlay::random_permutation(m);

  unionFind<vertexId> UF(n);
  parlay::sequence<reservation> R(n);

  unionFindStep UFStep(G, UF, R, p);

  // Use speculative_for to process all edges in parallel. It handles conflicts
  // and retries automatically. The granularity parameter is tuned for good performance.
  pbbs::speculative_for<edgeId>(UFStep, 0, m, 200);

  // After speculative_for completes, the reservation array R contains the
  // indices of the edges that were successfully added to the spanning forest.
  // We use parlay::map_maybe to efficiently extract these indices.
  return parlay::map_maybe(R, [](const reservation& a) {
    return a.reserved() ? std::make_optional(a.get()) : std::nullopt;
  });
}

