// **************************************************************
//    PARALLEL SPANNING FOREST
// **************************************************************
// The algorithm is a parallel version of Kruskal's algorithm that works
// in rounds. In each round, it connects components of the graph
// using a Boruvka-like approach and then filters out edges that have
// become internal to a component. This is often called a filter-Kruskal
// or a repeat-until-stable algorithm.
//
// The algorithm proceeds as follows:
//
// 1. Initialization:
//    - A union-find (UF) data structure is initialized for all n vertices.
//    - The set of active edges starts as all m edges in the graph.
//
// 2. Iterative Rounds:
//    The process repeats until no more edges can be added or the set of
//    active edges is small enough to process serially.
//
//    a. Find Candidates (Parallel):
//       For each component, we find the minimum-indexed edge that connects it
//       to another component. This is done by iterating over all active
//       edges in parallel. For each edge (u, v), if u and v are in different
//       components (checked with UF.find), we use an atomic write_min to
//       propose this edge as a candidate for the roots of both components.
//
//    b. Union (Serial on Candidates):
//       We collect all unique candidate edges from the previous step. This list
//       is small (at most n). We iterate over this list serially. For each
//       candidate edge, we re-check if it still connects two different
//       components and, if so, union them and add the edge to our spanning forest.
//       The serial iteration on the small candidate set is fast and correctly
//       avoids race conditions and cycles during the union step.
//
//    c. Filter (Parallel):
//       We create the active edge list for the next round by filtering the current
//       list in parallel, keeping only the edges that still connect different
//       components after the union step.
//
// 3. Base Case:
//    If the number of active edges becomes small, the algorithm switches to
//    a simple serial Kruskal's loop for efficiency.
//
// This process converges quickly because the number of components decreases
// and the number of active edges shrinks in each round.
parlay::sequence<edgeId> st(edgeArray<vertexId> const &E) {
  edgeId m = E.nonZeros;
  vertexId n = E.numRows;

  if (m == 0) {
    return parlay::sequence<edgeId>();
  }

  unionFind<vertexId> UF(n);
  auto edge_indices = parlay::iota<edgeId>(m);
  parlay::sequence<edgeId> st_edges;
  st_edges.reserve(n > 0 ? n - 1 : 0);

  // Heuristic threshold to switch to a serial algorithm for small inputs
  size_t serial_threshold = std::max(2000UL, static_cast<size_t>(n / 20));

  while (!edge_indices.empty()) {
    // Base Case: Finish with a serial loop if the remaining problem is small
    if (edge_indices.size() < serial_threshold) {
      parlay::sequence<edgeId> final_edges;
      for (edgeId i : edge_indices) {
        vertexId u_root = UF.find(E[i].u);
        vertexId v_root = UF.find(E[i].v);
        if (u_root != v_root) {
          UF.union_roots(u_root, v_root);
          final_edges.push_back(i);
        }
      }
      st_edges.insert(st_edges.end(), final_edges.begin(), final_edges.end());
      break;
    }

    // Step 1: Find a candidate edge for each component in parallel.
    auto min_edges = parlay::sequence<std::atomic<edgeId>>(n);
    const edgeId max_edge_id = std::numeric_limits<edgeId>::max();
    parlay::for_each(min_edges, [&](auto& a) { a.store(max_edge_id); });

    parlay::for_each(edge_indices, [&](edgeId idx) {
      vertexId u_root = UF.find(E[idx].u);
      vertexId v_root = UF.find(E[idx].v);
      if (u_root != v_root) {
        pbbs::write_min(&min_edges[u_root], idx, std::less<edgeId>());
        pbbs::write_min(&min_edges[v_root], idx, std::less<edgeId>());
      }
    });

    // Step 2: Collect unique candidates and union them serially.
    auto candidates = parlay::tabulate(n, [&](size_t i) {
      return UF.is_root(i) ? min_edges[i].load() : max_edge_id;
    });

    auto unique_candidates = parlay::unique(parlay::sort(candidates));

    parlay::sequence<edgeId> added_this_round;
    for (edgeId idx : unique_candidates) {
      if (idx == max_edge_id) continue;
      vertexId u_root = UF.find(E[idx].u);
      vertexId v_root = UF.find(E[idx].v);
      if (u_root != v_root) {
        UF.union_roots(u_root, v_root);
        added_this_round.push_back(idx);
      }
    }

    // If no edges were added, the forest is complete.
    if (added_this_round.empty()) {
      break;
    }
    st_edges.insert(st_edges.end(), added_this_round.begin(), added_this_round.end());

    // Step 3: Filter edges for the next round in parallel.
    edge_indices = parlay::filter(edge_indices, [&](edgeId idx) {
      return UF.find(E[idx].u) != UF.find(E[idx].v);
    });
  }

  return st_edges;
}

