namespace {

// A lock-free parallel union-find data structure.
// Uses parent-pointer trees with path halving for finding roots.
// A vertex `i` is a root if `parents[i] == i`.
struct parallel_union_find {
  parlay::sequence<std::atomic<vertexId>> parents;

  parallel_union_find(size_t n) : parents(n) {
    parlay::parallel_for(0, n, [&](size_t i) {
      parents[i].store(static_cast<vertexId>(i), std::memory_order_relaxed);
    });
  }

  // Find the root of the component containing `i` with path halving.
  vertexId find(vertexId i) {
    while (i != parents[i].load(std::memory_order_relaxed)) {
      vertexId p = parents[i].load(std::memory_order_relaxed);
      vertexId gp = parents[p].load(std::memory_order_relaxed);
      parents[i].compare_exchange_strong(p, gp, std::memory_order_relaxed, std::memory_order_relaxed);
      i = parents[i].load(std::memory_order_relaxed);
    }
    return i;
  }
};

// Hasher for std::pair<vertexId, vertexId> to be used in the hash table.
struct EdgePairHasher {
  size_t operator()(const std::pair<vertexId, vertexId>& p) const {
    // A common way to combine two hashes.
    // Same as boost::hash_combine
    size_t h1 = parlay::hash<vertexId>()(p.first);
    size_t h2 = parlay::hash<vertexId>()(p.second);
    return h1 ^ (h2 + 0x9e3779b9 + (h1 << 6) + (h1 >> 2));
  }
};

} // anonymous namespace

// Computes a spanning forest of the given graph using a randomized,
// round-based algorithm with a parallel union-find data structure.
// This is a variant of the algorithm by Shun, Blelloch, and Fineman.
parlay::sequence<edgeId> st(edgeArray<vertexId> const &E) {
  edgeId m = E.nonZeros;
  vertexId n = E.numRows;

  if (m == 0 || n == 0) return parlay::sequence<edgeId>();

  parallel_union_find UF(n);
  auto active_edges = parlay::to_sequence(parlay::random_permutation(m));
  parlay::sequence<edgeId> st_edges;
  st_edges.reserve(n - 1);

  while (!active_edges.empty() && st_edges.size() < static_cast<size_t>(n - 1)) {
    // Step 1: For each component, find one outgoing edge to a different component.
    // Use a concurrent hash table to select one edge per pair of components.
    // The first thread to insert a given {root_u, root_v} pair wins.
    using EdgePair = std::pair<vertexId, vertexId>;
    auto table = parlay::hash_table<parlay::hash_map_based<EdgePair, edgeId, EdgePairHasher>>(active_edges.size());

    parlay::parallel_for(0, active_edges.size(), [&](size_t i) {
      edgeId edge_idx = active_edges[i];
      vertexId r_u = UF.find(E[edge_idx].u);
      vertexId r_v = UF.find(E[edge_idx].v);
      if (r_u != r_v) {
        if (r_u > r_v) std::swap(r_u, r_v);
        table.insert({r_u, r_v}, edge_idx);
      }
    }, 1024);

    auto unique_edges = table.entries();
    if (unique_edges.empty()) break;

    // Step 2: Attempt to unite the components for the unique candidate edges.
    // An edge's CAS succeeds if it is the first to link its two components.
    auto added_flags = parlay::map(unique_edges, [&](const auto& entry) {
      auto [r_u, r_v] = entry.first; // Note: r_u < r_v from the swap above
      vertexId expected = r_u;
      // Atomically try to hook r_u to r_v. This is cycle-free due to the ordering.
      return UF.parents[r_u].compare_exchange_strong(expected, r_v, std::memory_order_relaxed, std::memory_order_relaxed);
    }, 1024);

    // Step 3: Collect the edges that successfully united components.
    auto edge_indices = parlay::map(unique_edges, [](const auto& entry){ return entry.second; });
    auto new_st_edges = parlay::pack(edge_indices, added_flags);
    st_edges.insert(st_edges.end(), new_st_edges.begin(), new_st_edges.end());

    // Step 4: Filter edges for the next round. An edge is still active if its
    // endpoints are not yet in the same component.
    auto still_active_flags = parlay::delayed_seq<bool>(active_edges.size(), [&](size_t i) {
      edgeId edge_idx = active_edges[i];
      return UF.find(E[edge_idx].u) != UF.find(E[edge_idx].v);
    });
    active_edges = parlay::pack(active_edges, still_active_flags);
  }

  return st_edges;
}

