// Recursive helper function for the parallel spanning forest algorithm.
// This function implements a randomized divide-and-conquer strategy,
// which is a highly effective parallel algorithm for this problem.
parlay::sequence<edgeId> st_recursive(const edgeArray<vertexId>& E, parlay::sequence<edgeId>&& edge_indices) {
    size_t m = edge_indices.size();
    vertexId n = E.numRows;

    // Base Case: For a small number of edges, switch to the efficient serial algorithm.
    // This avoids the overhead of recursion and parallelism on small inputs.
    if (m < 20000) {
        unionFind<vertexId> UF(n);
        parlay::sequence<edgeId> result;
        if (n > 0) { // A spanning forest can have at most n-1 edges.
          result.reserve(std::min((size_t)n - 1, m));
        }
        for (edgeId i : edge_indices) {
            auto edge = E[i];
            vertexId root_u = UF.find(edge.u);
            vertexId root_v = UF.find(edge.v);
            if (root_u != root_v) {
                UF.union_roots(root_u, root_v);
                result.push_back(i);
            }
        }
        return result;
    }

    // --- Divide Step ---
    // 1. Randomly shuffle the edges to ensure the sample is random.
    // This is crucial for the algorithm's work efficiency on all graph types.
    parlay::random_shuffle(edge_indices);

    // 2. Split the edges into two halves: a sample and the remainder.
    // Using move iterators is an efficient way to partition the sequence.
    size_t num_samples = m / 2;
    auto sample_indices = parlay::sequence<edgeId>(
        std::make_move_iterator(edge_indices.begin()),
        std::make_move_iterator(edge_indices.begin() + num_samples));
    auto remaining_indices = parlay::sequence<edgeId>(
        std::make_move_iterator(edge_indices.begin() + num_samples),
        std::make_move_iterator(edge_indices.end()));
    edge_indices.clear(); // Elements have been moved out

    // --- Recursive Calls ---
    // 3. Recursively find a spanning forest on the sample.
    auto st_from_sample = st_recursive(E, std::move(sample_indices));

    // --- Conquer Step ---
    // 4. Contract the graph based on the components found in the sample's spanning forest.
    unionFind<vertexId> UF(n);
    for (edgeId i : st_from_sample) {
        auto edge = E[i];
        vertexId root_u = UF.find(edge.u);
        vertexId root_v = UF.find(edge.v);
        // The check is technically not needed if st_recursive is correct, but is harmless.
        if (root_u != root_v) {
            UF.union_roots(root_u, root_v);
        }
    }

    // 5. Filter the remaining edges, keeping only those that connect different components.
    // The UF.find() operation has benign races (due to path compression) when called
    // in parallel. This is a standard and safe technique in this context, as all
    // concurrent modifications point a node to a higher ancestor in the UF tree.
    auto remaining_to_process = parlay::filter(remaining_indices, [&](edgeId i) {
        return UF.find(E[i].u) != UF.find(E[i].v);
    });

    // 6. Recursively find a spanning forest on the filtered remaining edges.
    auto st_from_remaining = st_recursive(E, std::move(remaining_to_process));

    // 7. Combine the results from the two subproblems.
    return parlay::append(st_from_sample, st_from_remaining);
}

// The main entry point for the spanning forest algorithm.
parlay::sequence<edgeId> st(edgeArray<vertexId> const &E) {
  // The recursive function operates on a sequence of edge indices.
  // Initially, we consider all edges in the graph, from index 0 to m-1.
  return st_recursive(E, parlay::to_sequence(parlay::iota<edgeId>(E.nonZeros)));
}

