// Helper to create a graph from a sorted edge list.
// This is a parallel implementation of converting a sorted
// coordinate (COO) format to a compressed sparse row (CSR) format.
template <class intV, class intE>
graph<intV, intE> graph_from_sorted_edges(const parlay::sequence<std::pair<intV, intV>>& edges, size_t num_vertices) {
  // 1. Find the start of each vertex's adjacency list in the sorted edge list.
  //    flags[i] is true if edges[i] is the first edge for a new vertex.
  auto flags = parlay::tabulate(edges.size(), [&](size_t i) {
    return (i == 0) || (edges[i].first != edges[i-1].first);
  });

  // 2. Get the indices of the starts.
  auto starts = parlay::pack_index<intE>(flags);

  // 3. Create the offset array.
  auto offsets = parlay::sequence<intE>::from_function(num_vertices + 1, [](size_t){ return 0; });
  // For each vertex that has outgoing edges, write its starting offset.
  parlay::parallel_for(0, starts.size(), [&](size_t i) {
    offsets[edges[starts[i]].first] = starts[i];
  });
  offsets[num_vertices] = edges.size();

  // 4. Fill in gaps for vertices with degree 0 by propagating the previous offset.
  parlay::parallel_scan_inclusive_inplace(offsets, parlay::maxm<intE>());

  // 5. Get the edge array (destinations).
  auto edge_array = parlay::map(edges, [](const auto& p) { return p.second; });

  return graph<intV, intE>(std::move(offsets), std::move(edge_array), num_vertices);
}

