// **************************************************************
//    DIRECTION-OPTIMIZING PARALLEL BREADTH FIRST SEARCH
// **************************************************************

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, 
			       bool /*verbose*/) {
  size_t n = G.numVertices();

  // ----------------- PREPROCESSING: BUILD TRANSPOSE GRAPH -----------------
  // A pull-based (bottom-up) approach requires iterating over in-edges.
  // For a directed graph, this means we need the transpose graph.
  // 1. Flatten all edges from G into a sequence of pairs (u, v)
  auto edges = parlay::flatten(parlay::tabulate(n, [&](size_t u) {
    return parlay::tabulate(G[u].degree, [&](size_t i) {
      return std::make_pair(static_cast<vertexId>(u), G[u].Neighbors[i]);
    });
  }));
  // 2. Create transposed edges (v, u)
  auto transposed_edges = parlay::map(edges, [](auto p){ return std::make_pair(p.second, p.first); });
  // 3. Sort by the new source vertex (original destination)
  parlay::sort_inplace(transposed_edges);
  // 4. Build the adjacency graph G_T from the sorted transposed edges
  auto G_T = graph_from_sorted_edges<vertexId, edgeId>(transposed_edges, n);

  // ----------------- BFS INITIALIZATION -----------------
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) { return -1; });
  parent[start] = start;
  parlay::sequence<vertexId> frontier(1, start);
  size_t visited_count = 1;
  // Heuristic parameter from Ligra paper.
  // A larger alpha biases towards the push-based approach.
  const size_t alpha = 15;

  // ----------------- MAIN BFS LOOP -----------------
  while (!frontier.empty()) {
    // ----------------- HEURISTIC: CHOOSE PUSH OR PULL -----------------
    size_t frontier_size = frontier.size();
    size_t edges_to_check = parlay::reduce(parlay::delayed_map(frontier, [&](vertexId u) { return G[u].degree; }));

    if (frontier_size + edges_to_check > (n - visited_count) / alpha) {
      // ----------------- PULL (BOTTOM-UP) STEP -----------------
      // Efficient for large frontiers. Unvisited nodes check their in-edges for a visited parent.

      // a. Mark current frontier members for fast lookup
      auto is_in_frontier = parlay::sequence<bool>(n, false);
      parlay::parallel_for(0, frontier.size(), [&](size_t i) { is_in_frontier[frontier[i]] = true; });

      // b. Filter all vertices to find the ones that can be visited in this step
      auto next_frontier = parlay::filter(parlay::iota<vertexId>(n), [&](vertexId v) {
        if (parent[v].load(std::memory_order_relaxed) == -1) {
          // Check incoming edges from G (which are outgoing edges in G_T)
          for (size_t i = 0; i < G_T[v].degree; ++i) {
            vertexId u = G_T[v].Neighbors[i];
            if (is_in_frontier[u]) {
              vertexId expected = -1;
              // Try to claim v. If we succeed, it's in the next frontier.
              // If we fail, another thread claimed it, so it's not our job.
              // In either case, we are done with v.
              return parent[v].compare_exchange_strong(expected, u, std::memory_order_relaxed);
            }
          }
        }
        return false; // Already visited or no parent in frontier
      });
      frontier = std::move(next_frontier);

    } else {
      // ----------------- PUSH (TOP-DOWN) STEP -----------------
      // Efficient for small frontiers. Frontier nodes visit all their neighbors.

      // a. For each vertex u in the frontier, map its neighbors to an optional<vertexId>.
      //    The optional will contain the neighbor's ID if it was successfully visited.
      auto nested_next = parlay::map(frontier, [&](vertexId u) {
        return parlay::delayed_map(parlay::make_slice(G[u].Neighbors, G[u].Neighbors + G[u].degree),
          [u, &parent](vertexId v) -> std::optional<vertexId> {
            vertexId expected = -1;
            // Use relaxed memory order for performance. The CAS provides enough synchronization.
            if (parent[v].load(std::memory_order_relaxed) == -1 &&
                parent[v].compare_exchange_strong(expected, u, std::memory_order_relaxed)) {
              return v;
            }
            return std::nullopt;
          });
      });

      // b. Flatten the nested sequences of optionals and pack the non-empty ones.
      frontier = parlay::pack(parlay::flatten(nested_next));
    }

    visited_count += frontier.size();
  }

  // ----------------- FINALIZE RESULT -----------------
  // Convert atomic parent array to a regular sequence for the output.
  return parlay::map(parent, [](const auto& p) { return p.load(); });
}

