namespace {

// Helper function to transpose a graph.
// This is needed for the bottom-up BFS step.
Graph transpose(const Graph& G) {
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    // 1. Create a flat list of reversed edges (v, u) for each edge (u, v) in G
    auto reversed_edges = parlay::sequence<std::pair<vertexId, vertexId>>(m);
    parlay::parallel_for(0, n, [&](size_t u) {
        size_t offset = G.get_offsets()[u];
        auto neighbors = G[u];
        for (size_t i = 0; i < neighbors.degree; i++) {
            reversed_edges[offset + i] = {neighbors.Neighbors[i], u};
        }
    }, 1024);

    // 2. Sort edges by the new source vertex (the original destination)
    parlay::sort_inplace(reversed_edges);

    // 3. Extract the new edge destinations
    auto t_edges = parlay::map(reversed_edges, [](const auto& p) { return p.second; });

    // 4. Find the start of each vertex's adjacency list in the sorted edge list
    auto flags = parlay::sequence<bool>(m);
    parlay::parallel_for(0, m, [&](size_t i) {
        flags[i] = (i == 0) || (reversed_edges[i].first != reversed_edges[i-1].first);
    });
    auto starts = parlay::pack_indices<size_t>(flags);

    // 5. Create the offset array for the transposed graph
    auto t_offsets = parlay::sequence<edgeId>::from_function(n + 1, [](size_t) { return 0; });
    t_offsets[n] = m;
    parlay::parallel_for(0, starts.size(), [&](size_t i) {
        vertexId v = reversed_edges[starts[i]].first;
        t_offsets[v] = starts[i];
    });

    // 6. Fill in the gaps for vertices with 0 in-degree by propagating the
    //    last valid offset forward.
    parlay::scan_inclusive_inplace(t_offsets, parlay::maxm<edgeId>());

    return Graph(std::move(t_offsets), std::move(t_edges), n);
}

