      auto get_neighbor = [](const auto& edge) {
        return edge.second; // Return the newly visited vertex v
      };

      frontier = parlay::delayed::filter_map(edges, visit_f, get_neighbor);
    }
  }

  // Convert the atomic parent array to a regular sequence for the final result.
  return parlay::map(parent, [](const auto &x) { return x.load(); });
}

