// Helper function to build the transpose of a graph.
// The transpose graph GT has an edge (v, u) for every edge (u, v) in G.
// This is needed for the bottom-up steps of the BFS.
static Graph build_transpose(const Graph& G) {
  size_t n = G.numVertices();
  size_t m = G.numEdges();

  // 1. Count in-degrees for each vertex in parallel.
  //    atomic_in_degrees[v] will store the number of edges pointing to v.
  auto atomic_in_degrees = parlay::sequence<std::atomic<edgeId>>::from_function(n, [](size_t){ return 0; });
  parlay::parallel_for(0, n, [&](size_t u) {
    for (size_t i = 0; i < G[u].degree; i++) {
      atomic_in_degrees[G[u].Neighbors[i]]++;
    }
  }, 1024);

  // 2. Compute the offsets for the transposed graph's edge array.
  //    This is an exclusive prefix sum of the in-degrees.
  auto offsets = parlay::sequence<edgeId>(n + 1);
  offsets[0] = 0;
  parlay::parallel_for(0, n, [&](size_t i) {
    offsets[i+1] = atomic_in_degrees[i].load(std::memory_order_relaxed);
  });
  parlay::scan_inplace(offsets, parlay::plus<edgeId>());

  // 3. Populate the edge array of the transposed graph.
  //    For each edge (u, v) in G, we add u to v's adjacency list in GT.
  auto T_edges = parlay::sequence<vertexId>::uninitialized(m);
  // current_offsets tracks the next empty slot for each vertex's adjacency list.
  auto current_offsets = parlay::sequence<std::atomic<edgeId>>(offsets.begin(), offsets.end() - 1);

  parlay::parallel_for(0, n, [&](size_t u) {
    for (size_t i = 0; i < G[u].degree; i++) {
      vertexId v = G[u].Neighbors[i];
      // Atomically get the next available slot and write the edge.
      edgeId edge_idx = current_offsets[v].fetch_add(1, std::memory_order_relaxed);
      T_edges[edge_idx] = u;
    }
  }, 1024);

  return Graph(std::move(offsets), std::move(T_edges), n);
}

// Direction-optimizing parallel breadth-first search
parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();
  if (n == 0) return parlay::sequence<vertexId>{};
  if (start >= n) {
    // Or throw an exception, depending on desired error handling.
    // For now, return an empty tree consistent with no vertices visited.
    return parlay::sequence<vertexId>::from_function(n, [](size_t){ return -1; });
  }

  // Build the transpose graph for bottom-up steps
  Graph GT = build_transpose(G);
  t.next("Build Transpose");

  // parent[i] = parent of i in the BFS tree.
  // -1 for unvisited, root's parent is root.
  // Use atomics for safe parallel updates from multiple threads.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) {
    return -1;
  });
  parent[start].store(start, std::memory_order_relaxed);

  // The set of vertices to visit in the current level
  parlay::sequence<vertexId> frontier(1, start);

  // Heuristics for switching between top-down and bottom-up.
  // These values are based on the original Ligra paper and work well in practice.
  const size_t top_down_threshold = n / 20;
  bool top_down = true;
  size_t round = 0;

  while (!frontier.empty()) {
    if (verbose) {
      std::cout << "Round " << round << ", frontier size = " << frontier.size()
                << ", step = " << (top_down ? "top-down" : "bottom-up") << std::endl;
    }
    round++;

    if (top_down) {
      // =================================================================
      // TOP-DOWN: Iterate over the frontier's out-edges.
      // Efficient for small frontiers.
      // =================================================================
      auto nested_edges = parlay::map(frontier, [&](vertexId u) {
        return parlay::delayed_tabulate(G[u].degree, [u, &G](size_t i) {
          return std::make_pair(u, G[u].Neighbors[i]);
        });
      });
      auto edges = delayed::flatten(nested_edges);

      auto edge_f = [&](std::pair<vertexId, vertexId> u_v) {
        auto [u, v] = u_v;
        vertexId expected = -1;
        // Use relaxed load for a fast check before the expensive atomic op.
        if (parent[v].load(std::memory_order_relaxed) == -1) {
          return parent[v].compare_exchange_strong(expected, u, std::memory_order_release, std::memory_order_relaxed);
        }
        return false;
      };

      // filter_map keeps edges where edge_f is true, then maps them to get the destination vertex.
      // This forms the next frontier.
      frontier = delayed::filter_map(edges, edge_f, [](auto x) { return x.second; });

      // Heuristic: Switch to bottom-up if the new frontier becomes large
      if (frontier.size() > top_down_threshold) {
        top_down = false;
      }
    } else {
      // =================================================================
      // BOTTOM-UP: Iterate over all unvisited vertices and check their in-edges.
      // Efficient for large frontiers.
      // =================================================================

      // Create a boolean array for O(1) frontier membership checking
      auto is_frontier = parlay::sequence<bool>::from_function(n, [](size_t){ return false; });
      parlay::parallel_for(0, frontier.size(), [&](size_t i) {
        is_frontier[frontier[i]] = true;
      });

      // Filter all vertices to find the ones that are unvisited but have an
      // in-neighbor in the current frontier.
      auto next_frontier = parlay::filter(parlay::iota<vertexId>(n), [&](vertexId v) {
        // Fast path for already visited vertices
        if (parent[v].load(std::memory_order_relaxed) != -1) return false;

        // Check in-neighbors using the transposed graph GT
        for (size_t i = 0; i < GT[v].degree; i++) {
          vertexId u = GT[v].Neighbors[i];
          if (is_frontier[u]) {
            vertexId expected = -1;
            if (parent[v].compare_exchange_strong(expected, u, std::memory_order_release, std::memory_order_relaxed)) {
              return true; // Successfully visited, include v in next frontier
            }
            // If CAS fails, another thread visited v just now. It's not "new"
            // for this thread, and we can stop checking in-neighbors for v.
            return false;
          }
        }
        return false; // No parent found in the current frontier
      });

      frontier = next_frontier;

      // Heuristic: Switch back to top-down if the new frontier becomes small
      if (frontier.size() < top_down_threshold) {
        top_down = true;
      }
    }
  }
  t.next("BFS rounds");

  // Convert atomic parent array to a regular sequence for the output
  auto result = parlay::map(parent, [](const auto& x) -> vertexId {
    return x.load(std::memory_order_relaxed);
  });
  t.next("Final map");

  return result;
}

