using namespace std;

// **************************************************************
//    HYBRID PARALLEL NON-DETERMINISTIC BREADTH FIRST SEARCH
// **************************************************************
// This implementation uses a direction-optimizing (hybrid) approach.
// - It starts with a top-down approach (frontier vertices explore outgoing edges),
//   which is efficient for small frontiers.
// - It switches to a bottom-up approach (unvisited vertices search for an
//   already-visited parent) when the frontier becomes large.
// - The bottom-up step assumes the input graph is symmetric. This is true for
//   the benchmark's specified graph generators (`-j` flag). For a symmetric
//   graph, the neighbors of a vertex are the same as its in-neighbors.
// This hybrid strategy is significantly faster than a pure top-down or
// bottom-up approach on a wide variety of graphs.

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G,
                               bool verbose = false) {
  size_t n = G.numVertices();
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) {
    return -1;
  });
  parent[start] = start;
  parlay::sequence<vertexId> frontier(1, start);

  // Heuristic to switch between top-down and bottom-up
  const size_t bottom_up_threshold = n / 20;

  while (!frontier.empty()) {
    if (frontier.size() < bottom_up_threshold) {
      // --- TOP-DOWN STEP (efficient for small frontiers) ---

      // Get out-edges of the frontier and flatten
      auto nested_edges = parlay::map(frontier, [&](vertexId u) {
        return parlay::delayed_tabulate(G[u].degree, [&, u](size_t i) {
          return std::pair(u, G[u].Neighbors[i]);
        });
      });
      auto edges = delayed::flatten(nested_edges);

      // Filter for edges that connect to an unvisited vertex,
      // using an atomic compare-and-swap to claim the parent.
      // Then map to just the newly visited vertex.
      auto edge_f = [&](auto u_v) {
        vertexId expected = -1;
        auto [u, v] = u_v;
        // Quick non-atomic check to avoid expensive atomic operation
        return (parent[v] == -1) &&
               parent[v].compare_exchange_strong(expected, u);
      };
      frontier = delayed::filter_map(edges, edge_f, [](auto x) { return x.second; });

    } else {
      // --- BOTTOM-UP STEP (efficient for large frontiers) ---

      // Mark current frontier vertices for O(1) lookup.
      auto is_frontier = parlay::sequence<bool>(n, false);
      parlay::for_each(frontier, [&](vertexId u) { is_frontier[u] = true; });

      // In parallel, each unvisited vertex checks its neighbors
      // to see if any are in the frontier.
      auto next_frontier = parlay::filter(parlay::iota(n), [&](vertexId v) {
        if (parent[v] == -1) { // If unvisited
          // Check neighbors (which are also in-neighbors for a symmetric graph)
          for (size_t i = 0; i < G[v].degree; i++) {
            vertexId u = G[v].Neighbors[i];
            if (is_frontier[u]) {
              vertexId expected = -1;
              // Atomically claim parent u.
              if (parent[v].compare_exchange_strong(expected, u)) {
                return true; // Success: v is part of the next frontier.
              } else {
                // Another thread claimed v just now. It is visited,
                // but we don't need to add it to the frontier again.
                return false;
              }
            }
          }
        }
        return false; // Already visited or no parent found in frontier.
      });
      frontier = std::move(next_frontier);
    }
  }

  // Convert from atomic to regular sequence for output.
  return parlay::map(parent, [](auto const &x) -> vertexId { return x.load(); });
}

