// **************************************************************
//    Direction-Optimizing (Back-Forward) Breadth-First Search
// **************************************************************
// This implementation uses a direction-optimizing strategy, also known as
// back-forward BFS. It dynamically switches between a "push" (sparse) and
// "pull" (dense) phase based on the size of the frontier.
//
// - PUSH (Forward): When the frontier is small, we iterate over vertices in
//   the frontier and "push" their parent ID to their unvisited neighbors.
//   This is efficient as it only touches nodes and edges connected to the
//   frontier.
//
// - PULL (Backward): When the frontier becomes large, it is more efficient
//   to iterate over all unvisited vertices in the graph and "pull" a parent
//   from any neighbor that is in the current frontier. This avoids iterating
//   over many edges from a large frontier that may point to already
//   visited vertices.
//
// For directed graphs, the PULL phase requires iterating over incoming edges.
// This implementation lazily builds the transpose graph (reversed edges)
// on the first transition to the PULL phase. This one-time cost is
// amortized over subsequent PULL iterations.
//
// The implementation heavily leverages the Parlay library for high-level,
// efficient parallel primitives like `map`, `flatten`, `tabulate`, `find_if`,
// `group_by_key`, and `scan`. Atomics with relaxed memory ordering are used
// for safe and fast updates to the shared parent array.
parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();

  // The parent array stores the BFS tree.
  // parent[i] = -1 if unvisited, otherwise it's the parent of i.
  // The root's parent is itself.
  // We use atomics for safe concurrent updates from multiple threads.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t){ return static_cast<vertexId>(-1); });
  parent[start].store(start, std::memory_order_relaxed);

  // The frontier of the BFS.
  parlay::sequence<vertexId> frontier = {start};

  // A dense representation of the frontier (a boolean array), used in PULL mode.
  parlay::sequence<bool> dense_frontier;
  bool is_dense = false;
  size_t frontier_size = 1;

  // Transpose graph, lazily built for the PULL phase.
  std::unique_ptr<Graph> GT;

  // Heuristic parameters for switching between PUSH and PULL.
  // These are common values from frameworks like Ligra.
  const size_t alpha = 15; // Switch to PULL if frontier is large.
  const size_t beta = 20;  // Switch back to PUSH if frontier becomes small.
  t.next("init");

  while (frontier_size > 0) {
    // --- Heuristic to decide between PUSH and PULL ---
    if (!is_dense) { // Currently in PUSH mode, consider switching to PULL
      size_t out_degrees = parlay::reduce(parlay::delayed_map(frontier, [&](vertexId v){
        return G[v].degree;
      }));
      if (frontier_size + out_degrees > G.numEdges() / alpha) {
        is_dense = true;
        dense_frontier = parlay::sequence<bool>(n, false);
        parlay::parallel_for(0, frontier.size(), [&](size_t i){
          dense_frontier[frontier[i]] = true;
        });
        frontier.clear(); // Free memory
      }
    } else { // Currently in PULL mode, consider switching to PUSH
      if (frontier_size < n / beta) {
        is_dense = false;
        frontier = parlay::pack_index<vertexId>(dense_frontier);
        dense_frontier.clear(); // Free memory
      }
    }
    t.next("heuristic");

    // --- Execute PUSH or PULL step ---
    if (!is_dense) { // PUSH (sparse)
      auto new_frontier_nested = parlay::map(frontier, [&](vertexId u) {
        auto neighbors = G[u];
        // For each neighbor, try to atomically claim it.
        // delayed_filter_map is used to build a sequence of successfully claimed neighbors.
        return parlay::delayed_filter_map(parlay::make_slice(neighbors.Neighbors, neighbors.Neighbors + neighbors.degree),
          [&](vertexId v) {
            vertexId expected = -1;
            // A relaxed load is a fast check to avoid the expensive CAS.
            return parent[v].load(std::memory_order_relaxed) == -1 &&
                   parent[v].compare_exchange_strong(expected, u, std::memory_order_relaxed);
          },
          [](vertexId v) { return v; }
        );
      });
      frontier = parlay::flatten(new_frontier_nested);
      frontier_size = frontier.size();
    } else { // PULL (dense)
      if (!GT) { // Build transpose graph on first PULL
        t.next("build_transpose_start");
        // 1. Create a flat list of all reversed edges {v, u} for each edge u -> v.
        auto rev_edges = parlay::flatten(parlay::map(parlay::iota(G.numVertices()), [&](vertexId u) {
          return parlay::delayed_tabulate(G[u].degree, [u, &G](size_t i) -> std::pair<vertexId, vertexId> {
            return {G[u].Neighbors[i], u};
          });
        }));
        // 2. Sort reversed edges to group them by the new source vertex.
        parlay::sort_inplace(rev_edges);
        // 3. Construct the CSR (Compressed Sparse Row) representation for the transpose graph GT.
        auto gt_edges = parlay::map(rev_edges, [](auto p){ return p.second; });
        auto grouped = parlay::group_by_key(rev_edges);
        auto gt_offsets = parlay::sequence<edgeId>(G.numVertices() + 1, 0);
        parlay::parallel_for(0, grouped.size(), [&](size_t i) {
          gt_offsets[grouped[i].first] = grouped[i].second.begin() - rev_edges.begin();
        });
        gt_offsets[G.numVertices()] = rev_edges.size();
        parlay::scan_inplace(gt_offsets, parlay::maxm<edgeId>());
        GT = std::make_unique<Graph>(std::move(gt_offsets), std::move(gt_edges), G.numVertices());
        t.next("build_transpose_done");
      }

      auto next_dense_frontier = parlay::tabulate(n, [&](size_t v) -> bool {
        if (parent[v].load(std::memory_order_relaxed) != -1) return false;
        auto in_neighbors = (*GT)[v];
        // Find the first in-neighbor 'u' that is in the current frontier.
        auto it = parlay::find_if(parlay::make_slice(in_neighbors.Neighbors, in_neighbors.Neighbors + in_neighbors.degree),
                                    [&](vertexId u){ return dense_frontier[u]; });
        if (it != in_neighbors.Neighbors + in_neighbors.degree) {
          parent[v].store(*it, std::memory_order_relaxed);
          return true; // v is now in the next frontier
        }
        return false;
      });
      dense_frontier = std::move(next_dense_frontier);
      frontier_size = parlay::count(dense_frontier, true);
    }
    t.next("iteration");
  }

  // Convert atomic parent array to regular sequence for output
  auto result = parlay::map(parent, [](auto const &x) -> vertexId { return x.load(); });
  t.next("map_result");
  return result;
}

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();

  // The parent array stores the BFS tree.
  // parent[i] = parent of vertex i.
  // parent[start] = start.
  // Unvisited vertices have parent = -1.
  // We use atomics because multiple threads in the push phase might race
  // to claim the same vertex.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) { return -1; });
  parent[start].store(start, std::memory_order_relaxed);

  // The frontier of the BFS.
  parlay::sequence<vertexId> frontier(1, start);

  // A buffer used for deduplicating the frontier in the push phase.
  // Allocated once to avoid repeated allocations.
  parlay::sequence<vertexId> dup_buffer;
  if (n > 0) {
    dup_buffer = parlay::sequence<vertexId>::uninitialized(n);
  }

  // Use a one-way switch from push to pull. Once we are in pull mode,
  // we stay in pull mode, as the frontier size tends to increase until
  // the end of the search.
  bool in_pull_mode = false;

  t.next("init");

  while (!frontier.empty()) {
    // Heuristic to switch from push to pull. Based on the Ligra paper,
    // we switch if the number of edges to visit from the frontier is large.
    if (!in_pull_mode) {
      size_t frontier_size = frontier.size();
      // Only compute out-degrees if the frontier is not excessively large,
      // to avoid a costly reduction.
      if (frontier_size < n / 100) {
        size_t out_degree_sum = parlay::reduce(parlay::delayed_map(frontier,
          [&](vertexId u) { return static_cast<size_t>(G[u].degree); }));
        if (frontier_size + out_degree_sum > G.numEdges() / 20) {
          in_pull_mode = true;
        }
      } else { // Switch if frontier is very large, regardless of degrees
          if (frontier_size > n / 20) {
            in_pull_mode = true;
          }
      }
    }

    if (in_pull_mode) {
      // PULL phase (or backward search)
      // When the frontier is large, it's more efficient to iterate over all
      // unvisited vertices and "pull" an edge from the frontier.

      // Represent the large frontier as a dense boolean array for O(1) lookups.
      parlay::sequence<bool> frontier_dense(n, false);
      parlay::parallel_for(0, frontier.size(), [&](size_t i) {
        frontier_dense[frontier[i]] = true;
      });

      parlay::sequence<bool> next_frontier_dense(n, false);

      // For each vertex v, check if it has an incoming edge from the frontier.
      // This is implemented by iterating over v's *outgoing* neighbors u and
      // checking if u is in the frontier.
      parlay::parallel_for(0, n, [&](size_t v) {
        if (parent[v].load(std::memory_order_relaxed) == -1) {
          auto v_neighbors = G[v];
          for (int i = 0; i < v_neighbors.degree; i++) {
            vertexId u = v_neighbors.Neighbors[i];
            if (frontier_dense[u]) {
              vertexId expected = -1;
              // Try to claim v. Use relaxed memory order for performance.
              if (parent[v].compare_exchange_strong(expected, u, std::memory_order_relaxed)) {
                next_frontier_dense[v] = true;
                // Optimization: v is claimed, no need to check other neighbors.
                break;
              } else {
                // v was claimed by another thread in this pull step.
                // We can also stop checking.
                break;
              }
            }
          }
        }
      }, 1024); // Use a grain size to balance load and overhead.

      // Convert the dense next frontier back to a sparse representation.
      frontier = parlay::pack_index<vertexId>(next_frontier_dense);
