      // When the frontier is small, it's more efficient to iterate over
      // vertices in the frontier and "push" to their neighbors.

      auto new_frontier_with_dups = parlay::flatten(parlay::map(frontier, [&](vertexId u) {
        auto u_neighbors = G[u];
