        // Filter neighbors that we can successfully claim.
        return parlay::filter(neighbors_slice, [&](vertexId v) {
          vertexId expected = -1;
          return parent[v].compare_exchange_strong(expected, u, std::memory_order_relaxed);
        });
      }));

      if (new_frontier_with_dups.empty()) {
        frontier = {};
      } else {
        // Deduplicate the new frontier.
        // This method is faster than sort+unique for this workload.
        // Each thread races to write its index into a shared buffer at a
        // position corresponding to the vertex ID. The winner is the one
        // whose index is read back.
        parlay::parallel_for(0, new_frontier_with_dups.size(), [&](size_t i) {
          // Benign race: we only care that one write succeeds.
          dup_buffer[new_frontier_with_dups[i]] = i;
        });

        auto flags = parlay::delayed_tabulate(new_frontier_with_dups.size(), [&](size_t i) {
          return i == dup_buffer[new_frontier_with_dups[i]];
        });

        frontier = parlay::pack(new_frontier_with_dups, flags);
      }
      t.next("push");
    }
  }

  // Convert the atomic parent array to a regular sequence for the output.
  return parlay::map(parent, [](auto const &x) -> vertexId {
    return x.load(std::memory_order_relaxed);
  });
}

