// Helper to create a transpose of a graph.
// This is needed for the PULL direction of the BFS.
auto transpose_graph(const Graph& G) {
  using vertexId = typename Graph::vertexId;
  using edgeId = typename Graph::edgeId;

  // 1. Count in-degrees using atomics for thread-safe parallel counting.
  auto deg_counts = parlay::sequence<std::atomic<edgeId>>::from_function(G.numVertices(), [](size_t){ return 0; });
  parlay::parallel_for(0, G.numVertices(), [&](size_t u){
    auto vtx = G[u];
    for(size_t i=0; i<vtx.degree; ++i) {
      deg_counts[vtx.Neighbors[i]]++;
    }
  }, 1024); // Use a reasonable grain size.

  // 2. Compute offsets for the transpose graph (an exclusive scan of in-degrees).
  auto t_offsets = parlay::sequence<edgeId>(G.numVertices() + 1);
  auto loaded_degrees = parlay::map(deg_counts, [](auto& x){ return x.load(); });
  parlay::scan_inclusive_inplace(loaded_degrees, parlay::addm<edgeId>());
  t_offsets[0] = 0;
  parlay::parallel_for(1, G.numVertices() + 1, [&](size_t i){ t_offsets[i] = loaded_degrees[i-1]; });

  // 3. Place edges into the transpose graph's edge array.
  // We use the computed offsets as atomic counters to know where to place each edge.
  auto t_edges = parlay::sequence<vertexId>(G.numEdges());
  auto t_counters = parlay::map(parlay::make_slice(t_offsets), [](edgeId x){ return std::atomic<edgeId>(x); });

  parlay::parallel_for(0, G.numVertices(), [&](size_t u){
    auto vtx = G[u];
    for(size_t i=0; i<vtx.degree; ++i) {
      vertexId v = vtx.Neighbors[i];
      edgeId dest_idx = t_counters[v]++;
      t_edges[dest_idx] = u;
    }
  }, 1024);

  return Graph(std::move(t_offsets), std::move(t_edges), G.numVertices());
}


parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose) {
  parlay::internal::timer t("BFS",verbose);
  size_t n = G.numVertices();

  // Create the transpose graph for the PULL direction.
  auto GT = transpose_graph(G);
  t.next("transpose");

  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [] (size_t) {
      return -1;});
  parent[start] = start;

  // fa (function application) tries to CAS a vertex's parent from -1 to u.
  // Returns true on success.
  auto edge_fa = [iparent=parent.begin()] (vertexId u, vertexId v) -> bool {
    vertexId expected = -1;
    return iparent[v].compare_exchange_strong(expected, u, std::memory_order_relaxed);
  };

  // cond (condition) checks if a vertex has been visited.
  auto cond_f = [iparent=parent.begin()] (vertexId v) { return iparent[v] == -1;};

  // The edge_map object encapsulates the PUSH/PULL logic.
  auto frontier_map = ligra::edge_map(G, GT, edge_fa, cond_f, false, verbose);

  auto frontier = ligra::vertex_subset(start);
  t.next("start");

  while (frontier.size() > 0) {
    frontier = frontier_map(frontier);
    t.next("iter");
  }

  // Convert atomic parents to a regular sequence for the output.
  return parlay::map(parent, [] (auto const &x) -> vertexId {
      return x.load();});
}

