parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose) {
  size_t n = G.numVertices();
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(
      n, [](size_t) { return -1; });
  auto visited = parlay::sequence<std::atomic<bool>>::from_function(
      n, [](size_t) { return false; });

  parent[start] = start;
  visited[start] = true;

  parlay::sequence<vertexId> frontier(1, start);
  size_t total_visited = 0;
  size_t round = 0;

  while (!frontier.empty()) {
    total_visited += frontier.size();
    if (verbose) {
      cout << "Round " << round << ": frontier size = " << frontier.size() << endl;
    }
    round++;

    // Heuristic to switch between sparse and dense modes.
    // The dense mode is better when the frontier is large and collectively
    // has many outgoing edges, as it can amortize the cost of sorting.
    // A common heuristic is to switch when the number of edges to visit
    // exceeds a fraction of the total vertices.
    size_t frontier_edges = parlay::reduce(parlay::map(
        frontier, [&](vertexId u) -> size_t { return G[u].degree; }));

    if (frontier.size() + frontier_edges > n / 20) {
      // DENSE MODE: "group-by" approach
      // 1. Get all (destination, source) edges from the current frontier.
      auto edges = parlay::flatten(parlay::map(frontier, [&](vertexId u) {
        return parlay::map(G[u], [=](vertexId v) {
          return std::make_pair(v, u); // (dest, src)
        });
      }));

      // 2. Optimization: Filter out edges to already visited vertices to reduce
      // the size of the data to be sorted in the group_by_key step.
      auto candidate_edges = parlay::filter(edges, [&](const auto &edge) {
        return !visited[edge.first].load(std::memory_order_relaxed);
      });

      // 3. Group candidate edges by their destination vertex.
      auto grouped_by_dest = parlay::group_by_key(candidate_edges);

      // 4. For each destination, atomically claim it, find the max-ID parent,
      // and add the destination to the next frontier.
      frontier = parlay::filter_map(grouped_by_dest, [&](const auto &group) {
        vertexId v = group.first;
        bool expected_visited = false;
        // Atomically check and set the visited flag. This is the critical step
        // to ensure each vertex is processed exactly once across the whole BFS.
        if (std::atomic_compare_exchange_strong(&visited[v], &expected_visited,
                                                true)) {
          // If we successfully claimed this vertex, find its parent.
          // The parent is the maximum vertex ID among all sources in this
          // round that have an edge to v.
          auto parents =
              parlay::delayed_map(group.second, [](auto p) { return p.second; });
          vertexId max_parent = parlay::reduce(parents, parlay::maxm<vertexId>());
          parent[v].store(max_parent, std::memory_order_relaxed);
          return std::make_optional(v);
        } else {
          // The vertex was already visited.
          return std::optional<vertexId>{};
        }
      });
    } else {
      // SPARSE MODE: "compare-and-swap" approach (similar to baseline)
      // This mode is efficient for small frontiers as it avoids the overhead of sorting.
      // 1. Create a delayed sequence of all (source, destination) edges from the frontier.
      auto nested_edges = parlay::map(frontier, [&](vertexId u) {
        return parlay::delayed_tabulate(G[u].degree, [=](size_t i) {
          return std::make_pair(u, G[u].Neighbors[i]);
