      // parlay::write_max uses a CAS-like operation to update parent[v] to u
      // only if u is greater than the current parent. This creates a
      // deterministic BFS tree where parents are max-ID neighbors from the
      // frontier. The `!visited[v]` check is a crucial fast-path to avoid
      // atomic operations on already-visited nodes.
      auto filtered_edges = delayed::filter(edges, [&](auto u_v) {
        auto [u, v] = u_v;
        return !visited[v] &&
               parlay::write_max(&parent[v], u, std::less<vertexId>());
      });

      // 3. The new frontier consists of vertices that were successfully claimed.
      // We identify the "winners" of the write_max race and mark them as
      // visited. This two-step process (compete, then collect winners) is
      // necessary because the final parent is not known until all races for
      // that vertex in the current round are finished.
      frontier = delayed::filter_map(
          filtered_edges,
          [&](auto u_v) { return parent[u_v.second] == u_v.first; },
          [&](auto u_v) {
            visited[u_v.second] = true;
            return u_v.second;
          });
    }
  }

  if (verbose) {
    cout << "BFS finished. Total vertices visited: " << total_visited << endl;
  }

  // Convert the atomic parent sequence to a plain sequence for the return value.
  return parlay::map(parent, [](auto const &x) -> vertexId { return x.load(); });
}

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose) {
  size_t n = G.numVertices();

  // parent[i] stores the parent of vertex i in the BFS tree.
  // A value of -1 indicates the vertex is unvisited.
  // The root's parent is itself.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) {
    return static_cast<vertexId>(-1);
  });
  parent[start] = start;

  // visited[i] is true if vertex i was visited in a *previous* round.
  // This prevents re-visiting vertices and ensures correctness.
  // Using std::atomic<char> is safer than std::atomic<bool> and more
  // memory-efficient than std::atomic<int>.
  auto visited = parlay::sequence<std::atomic<char>>::from_function(n, [](size_t) {
    return 0;
  });
  visited[start] = 1;

  // The frontier contains vertices to be explored in the current round.
  parlay::sequence<vertexId> frontier(1, start);

  while (!frontier.empty()) {
    // Step 1: Flatten all outgoing edges from the current frontier.
    // An edge is represented as a pair (source, destination).
    auto edges = parlay::delayed::flatten(parlay::map(frontier, [&](vertexId u) {
      return parlay::delayed::map(G[u], [u](vertexId v) {
        return std::make_pair(u, v);
      });
    }));

    // Step 2 (Compete): Filter for edges (u,v) where v has not been visited
    // in a previous round. Use atomic write_min to compete for parentage.
    // An edge (u,v) passes if u is a potential parent for v.
    auto contenders = parlay::delayed::filter(edges, [&](auto uv_pair) {
      auto [u, v] = uv_pair;
      // Only consider visiting 'v' if it wasn't visited in a previous round.
      // The relaxed load is sufficient as synchronization is handled by write_min.
      return (visited[v].load(std::memory_order_relaxed) == 0) &&
             parlay::write_min(&parent[v], u, std::less<vertexId>());
    });

    // Step 3 (Commit): From the contenders, find the final winners.
    // A vertex 'v' is added to the next frontier if its parent is confirmed
    // to be the 'u' from the contender edge.
    frontier = parlay::delayed::filter_map(contenders,
      [&](auto uv_pair) -> std::optional<vertexId> {
        auto [u, v] = uv_pair;
        // Confirm that 'u' is the final winner for 'v' in this round.
        // A relaxed load is sufficient because all write_mins for this round
        // have completed before this stage begins (due to the delayed evaluation
        // pipeline).
        if (parent[v].load(std::memory_order_relaxed) == u) {
          // 'u' is the winner. Mark 'v' as visited for future rounds
          // and add it to the next frontier.
          visited[v].store(1, std::memory_order_relaxed);
          return v;
        }
        return std::nullopt;
      });
  }

  // Convert the atomic parent array to a plain sequence for the output.
  return parlay::map(parent, [](const auto& p) { return p.load(); });
}

