// A deterministic parallel breadth-first search implementation.
//
// The algorithm is a hybrid of sparse and dense approaches, similar to the one
// used in the Ligra/GBBS frameworks. This allows for high performance across a
// variety of graph structures.
//
// 1.  Data Structures:
//     - `parent`: A sequence of size n. `parent[i]` stores the parent of
//       vertex `i` in the BFS tree. Initialized to -1. The root's parent
//       is itself. This array is also used to track visited vertices
//       (a vertex `v` is visited if `parent[v] != -1`).
//     - `frontier`: A sequence storing the vertices at the current level of
//       the BFS.
//
// 2.  Hybrid Approach:
//     The algorithm dynamically switches between two modes for processing the
//     frontier based on its size.
//
//     - Sparse Mode: Used when the frontier is small. It iterates over the
//       outgoing edges of only the vertices in the frontier. This is efficient
//       when the total number of outgoing edges from the frontier is not
//       overwhelmingly large.
//
//     - Dense Mode: Used when the frontier is large. Instead of iterating from
//       the frontier, it iterates over all vertices `v` in the graph and checks
//       if any of their neighbors are in the current frontier. This avoids
//       redundant work and improves memory access patterns when many vertices in
//       the frontier might be trying to visit the same neighbors.
//
// 3.  Determinism:
//     To ensure the BFS tree is deterministic, a consistent rule is applied
//     for choosing a parent when a vertex can be reached by multiple vertices
//     from the current frontier: the vertex with the minimum ID is chosen as
//     the parent.
//     - In sparse mode, this is achieved by generating all potential
//       `(neighbor, parent)` edges, sorting them by `neighbor` then `parent`,
//       and then taking the first unique entry for each `neighbor`.
//     - In dense mode, for each unvisited vertex `v`, we find all its neighbors
//       `u` in the frontier and use an atomic `parlay::write_min` to select the
//       one with the minimum ID.
//
parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose) {
  (void)verbose; // The verbose parameter is unused.
  size_t n = G.numVertices();
  auto parent = parlay::sequence<vertexId>::from_function(n, [](size_t) { return -1; });

  if (start >= n) {
    return parent;
  }

  parent[start] = start;
  parlay::sequence<vertexId> frontier(1, start);

  // Reusable buffer for the dense step. Using std::atomic for write_min.
  auto new_parents = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t){ return -1; });

  constexpr size_t DENSE_THRESHOLD_DIVISOR = 20;

  while (!frontier.empty()) {
    // Heuristic: switch to dense mode if the frontier is large.
    if (frontier.size() > n / DENSE_THRESHOLD_DIVISOR) {
      // DENSE STEP
      auto is_in_frontier = parlay::sequence<bool>(n, false);
      parlay::parallel_for(0, frontier.size(), [&](size_t i) {
        is_in_frontier[frontier[i]] = true;
      });

      parlay::parallel_for(0, n, [&](vertexId v) {
        if (parent[v] == -1) {
          auto neighbors = G[v];
          // In dense mode, we check incoming edges. Since we don't have them,
          // we iterate over our neighbors and check if they are in the frontier.
          for (vertexId i = 0; i < neighbors.degree; i++) {
            vertexId u = neighbors.Neighbors[i];
            if (is_in_frontier[u]) {
              // Atomically find the minimum parent ID from the frontier.
              parlay::write_min(&new_parents[v], u, std::less<vertexId>());
            }
          }
        }
      }, 1024); // Use a grain size to reduce overhead for small loops

      // Pack the newly discovered vertices into the next frontier.
      // Also, update the main parent array and reset the new_parents buffer.
      auto new_frontier = parlay::pack(parlay::delayed_seq<vertexId>(n, [](auto i){return i;}),
                                      parlay::delayed_seq<bool>(n, [&](auto v){
                                          vertexId p = new_parents[v].load(std::memory_order_relaxed);
                                          if(p != -1) {
                                              parent[v] = p;
                                              new_parents[v].store(-1, std::memory_order_relaxed); // Reset for next use
                                              return true;
                                          }
                                          return false;
                                      }));
      frontier = std::move(new_frontier);
    } else {
      // SPARSE STEP
      // Flatten the neighbors of the frontier into a list of (neighbor, parent) pairs.
      auto edges = parlay::flatten(parlay::map(frontier, [&](vertexId u) {
        auto neighbors = G[u];
        return parlay::delayed_map(parlay::make_slice(neighbors.Neighbors, neighbors.Neighbors + neighbors.degree), [=](vertexId v) {
          return std::make_pair(v, u);
        });
      }));

      // Filter out neighbors that have already been visited.
      auto filtered_edges = parlay::filter(edges, [&](const auto& p) {
        return parent[p.first] == -1;
      });

      // Sort by neighbor (primary key) and then by parent (secondary key).
      parlay::sort_inplace(filtered_edges, [](const auto& a, const auto& b) {
        if (a.first != b.first) return a.first < b.first;
        return a.second < b.second;
      });

      // For each neighbor, keep only the one with the minimum parent ID.
      auto new_edges = parlay::unique_by_key(filtered_edges);

      // Create the new frontier from the unique neighbors.
      frontier = parlay::map(new_edges, [](const auto& p) { return p.first; });
      // Update the parent array in parallel.
      parlay::parallel_for(0, new_edges.size(), [&](size_t i) {
        parent[new_edges[i].first] = new_edges[i].second;
      });
    }
  }

  return parent;
}

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose) {
  size_t n = G.numVertices();

  // Pre-computation: Build the transpose graph (for bottom-up steps)
  // This is a one-time cost.
  Graph GT = [&]() {
    auto edge_list = parlay::sequence<std::pair<vertexId, vertexId>>(G.numEdges());
    parlay::parallel_for(0, n, [&](size_t u) {
      size_t offset = G.get_offsets()[u];
      for (size_t i = 0; i < G[u].degree; i++) {
        edge_list[offset + i] = {G[u].Neighbors[i], static_cast<vertexId>(u)};
      }
    }, 1);

    parlay::sort_inplace(edge_list); // Sort by new source vertex (original destination)

    auto edges = parlay::map(edge_list, [](auto p) { return p.second; });

    auto flags = parlay::delayed_seq<edgeId>(edge_list.size(), [&](size_t i) {
      return (i == 0) || (edge_list[i].first != edge_list[i - 1].first);
    });
    auto starts = parlay::pack_indices<edgeId>(flags);

    auto offsets = parlay::sequence<edgeId>(n + 1, G.numEdges());
    parlay::parallel_for(0, starts.size(), [&](size_t i) {
      vertexId v = edge_list[starts[i]].first;
      offsets[v] = starts[i];
    });

    parlay::scan_inplace(offsets, parlay::minm<edgeId>());
    return Graph(std::move(offsets), std::move(edges), n);
  }();

  // Parent array: parent[i] stores the parent of vertex i in the BFS tree.
  // -1: unvisited
  // >= 0: parent's ID
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) { return -1; });
  parent[start].store(start, std::memory_order_relaxed);

  // The current frontier of the BFS
  parlay::sequence<vertexId> frontier(1, start);

  // Heuristic constants for switching between TD and BU
  const size_t alpha = 15; // from Ligra paper

  size_t visited_count = 1;

  while (!frontier.empty()) {
    // Heuristic: decide whether to use Top-Down or Bottom-Up
    // based on the number of edges to check from the frontier vs. from unvisited vertices.
    size_t out_degree_sum = parlay::reduce(parlay::map(frontier, [&](vertexId u) { return G[u].degree; }));

    if (out_degree_sum > (G.numVertices() - visited_count) / alpha) {
      // --- Bottom-Up Step ---
      // More efficient when the frontier is large.
      // Unvisited vertices check their in-edges for a parent in the frontier.
      auto frontier_bools = parlay::sequence<bool>(n, false);
      parlay::for_each(frontier, [&](vertexId u) { frontier_bools[u] = true; });

      auto new_frontier = parlay::filter(parlay::iota(n), [&](vertexId v) {
        if (parent[v].load(std::memory_order_relaxed) != -1) return false;

        auto in_neighbors = GT[v];
        vertexId min_p = -1;
        // Find the smallest-ID parent in the frontier
        for (int i = 0; i < in_neighbors.degree; i++) {
          vertexId u = in_neighbors.Neighbors[i];
          if (frontier_bools[u]) {
            if (min_p == -1 || u < min_p) {
              min_p = u;
            }
          }
        }

        if (min_p != -1) {
          // This side-effect is safe because each lambda instance operates on a unique 'v'.
          parent[v].store(min_p, std::memory_order_relaxed);
          return true;
        }
        return false;
      });
      frontier = new_frontier;

    } else {
      // --- Top-Down Step ---
      // More efficient when the frontier is small.
      // Vertices in the frontier explore their out-edges.
      auto nested_out = parlay::map(frontier, [&](vertexId u) {
        return parlay::delayed_tabulate(G[u].degree, [=](size_t i) {
          return std::pair(u, G[u].Neighbors[i]);
        });
      });
      auto out_edges = parlay::delayed::flatten(nested_out);

      auto winning_edges = parlay::delayed::filter(out_edges, [&](auto e) {
        auto [u, v] = e;
        // Fast path check, then atomic write_min for deterministic parent selection
        return parent[v].load(std::memory_order_relaxed) == -1 &&
               parlay::write_min(&parent[v], u);
      });

      // The new frontier consists of vertices that were successfully claimed
      // by a parent from the current frontier.
      frontier = parlay::delayed::filter_map(winning_edges,
        [&](auto e) { return parent[e.second].load(std::memory_order_relaxed) == e.first; },
        [](auto e) { return e.second; });
    }
    visited_count += frontier.size();
  }

  // Convert atomic parents to a regular sequence for the output
  return parlay::map(parent, [](auto const& x) -> vertexId { return x.load(std::memory_order_relaxed); });
