// **************************************************************
//    PARALLEL BREADTH FIRST SEARCH (Direction-Optimizing)
// **************************************************************
// This implementation uses a hybrid direction-optimizing strategy inspired by
// the algorithm from "Direction-Optimizing Breadth-First Search" by Scott Beamer et al.
//
// - It starts with a sparse, "top-down" (or "push") approach, which is efficient
//   when the BFS frontier is small. In this phase, we iterate over vertices in the
//   current frontier and "push" parent information to their unvisited neighbors.
//
// - When the frontier becomes large, the algorithm switches to a dense, "top-down"
//   approach. This approach still "pushes" from the frontier, but it uses a
//   bitmap to represent the next frontier. This avoids the significant overhead
//   of memory allocation and flattening that the sparse approach would incur with
//   a large number of edges.
//
// - A true "bottom-up" (or "pull") approach, which would iterate over all unvisited
//   nodes and check for parents in the frontier, is optimal for dense frontiers but
//   requires an efficient way to access in-edges. Since the provided graph structure
//   only gives out-edges, this dense top-down strategy is used as a high-performance
//   substitute.
//
// - Synchronization is handled using parlay::atomic_cas, which provides a correct
//   and efficient way for parallel threads to "claim" unvisited vertices.
parlay::sequence<vertexId> BFS(vertexId start, const Graph &G,
                               bool verbose = false) {
  size_t n = G.numVertices();
  if (start >= n) {
    // Handle invalid start vertex by returning a fully unvisited parent array.
    return parlay::sequence<vertexId>(n, -1);
  }

  // Parent array also serves as the visited set.
  // A value of -1 indicates an unvisited vertex.
  auto Parent = parlay::sequence<vertexId>(n, -1);

  // The root of the BFS tree points to itself.
  Parent[start] = start;

  // The frontier contains all vertices at the current level of the BFS.
  auto Frontier = parlay::sequence<vertexId>{start};

  // Heuristic threshold to switch between sparse and dense modes.
  // When the number of vertices in the frontier exceeds this, we switch
  // to a more memory-efficient dense representation for the next frontier.
  const size_t TD_THRESHOLD = n / 20;

  while (!Frontier.empty()) {
    if (Frontier.size() < TD_THRESHOLD) {
      // ----- SPARSE / TOP-DOWN PHASE -----
      // Efficient for small frontiers.
      // We iterate over the current frontier and "push" to neighbors.
      // The next frontier is built by mapping, filtering, and flattening.

      auto next_frontier_nested = parlay::map(Frontier, [&](vertexId u) {
        auto neighbors = G[u];
        // Filter neighbors to keep only unvisited ones.
        // Atomically "claim" a neighbor by setting its parent.
        return parlay::filter(parlay::make_slice(neighbors.Neighbors, neighbors.Neighbors + neighbors.degree),
          [&](vertexId v) {
            // Attempt to transition Parent[v] from -1 to u.
            // If successful, this vertex is now visited and becomes part of the next frontier.
            return parlay::atomic_cas(&Parent[v], (vertexId)-1, u);
          });
      });
      Frontier = parlay::flatten(next_frontier_nested);

    } else {
      // ----- DENSE / TOP-DOWN PHASE -----
      // Efficient for large frontiers.
      // We still "push" from the frontier, but use a bitmap for the next frontier
      // to avoid high memory allocation/copying costs from flatten.

      auto next_frontier_bitmap = parlay::sequence<bool>(n, false);

      // For each vertex in the current frontier, iterate through its neighbors.
      // Use a small grain size for better load balancing, especially for graphs
      // with skewed degree distributions.
      parlay::parallel_for(0, Frontier.size(), [&](size_t i) {
        vertexId u = Frontier[i];
        auto neighbors = G[u];
        for (int j = 0; j < neighbors.degree; j++) {
          vertexId v = neighbors.Neighbors[j];
          // The `Parent[v] == -1` check is a fast-path optimization to avoid
          // a more expensive atomic operation on an already-visited node.
          if (Parent[v] == -1 && parlay::atomic_cas(&Parent[v], (vertexId)-1, u)) {
            // If we successfully claimed v, mark it in the bitmap.
            // This write is safe (no race) because the successful CAS on Parent[v]
            // acts as a lock, ensuring only one thread will perform this write for a given v.
            next_frontier_bitmap[v] = true;
          }
        }
      }, 1);

      // Convert the dense bitmap back into a sparse sequence of vertex IDs
      // for the next iteration's frontier.
      Frontier = parlay::pack_index<vertexId>(n, [&](size_t k) { return next_frontier_bitmap[k]; });
    }
  }

  return Parent;
}

