      // Find all neighbors of the current frontier
      auto all_neighbors = parlay::flatten(parlay::map(frontier, [&](vertexId u) {
        return parlay::delayed_seq<std::pair<vertexId, vertexId>>(G[u].degree,
          [&](size_t i) { return std::make_pair(G[u].Neighbors[i], u); });
      }));

