      auto new_frontier_pairs = parlay::filter(all_neighbors, [&](const auto& p) {
        return parent[p.first] == -1 && parlay::compare_and_swap(&parent[p.first], -1, p.second);
      });

      // Extract the new frontier vertices
      frontier = parlay::map(new_frontier_pairs, [](const auto& p) { return p.first; });
    }
  }

  return parent;
