// The parallel maximal matching algorithm is based on a priority-based approach,
// executed in rounds. This approach guarantees finding the same maximal matching
// as the serial greedy algorithm because it uses the edge index as a priority,
// ensuring that an edge `i` is chosen over an edge `j` if `i < j`.
//
// The algorithm proceeds as follows:
// 1. All edges start as 'active'. All vertices start as 'unmatched'.
// 2. In each round, we perform the following steps on the set of active edges:
//    a. **Propose**: Each active edge (u, v) with index `i` proposes itself to its
//       endpoints `u` and `v`. A vertex `w` accepts the proposal from the edge
//       with the smallest index. This is implemented using `parlay::write_min`
//       on a 'proposals' array, where `proposals[w]` stores the index of the
//       best edge proposing to it.
//    b. **Accept**: An edge `i = (u, v)` is added to the matching for this round
//       if it won the proposal phase for both its endpoints (i.e., if
//       `proposals[u] == i` and `proposals[v] == i`).
//    c. **Update**: The vertices of the newly matched edges are marked as 'matched'.
//       The new edges are added to the final matching result.
//    d. **Filter**: The set of active edges for the next round is determined by
//       filtering out any edge that has at least one 'matched' endpoint.
// 3. The process repeats until no new edges can be matched, at which point the
//    set of active edges becomes empty and the algorithm terminates.
//
// This iterative structure is highly parallel and efficient for many graph types,
// including the random, RMAT, and grid graphs specified.
// The use of `std::atomic<bool>` for the matched flags and `std::atomic<edgeId>`
// for proposals ensures thread safety. Memory ordering is kept relaxed where
// possible, as the rounds provide sufficient synchronization.
parlay::sequence<edgeId> maximalMatching(edges const &EA) {
  size_t n = std::max(EA.numCols, EA.numRows);
  size_t m = EA.nonZeros;

  if (m == 0) {
    return parlay::sequence<edgeId>();
  }

  // matched[v] is true if vertex v is in the matching.
  // Using atomics for safe concurrent reads/writes across rounds.
  parlay::sequence<std::atomic<bool>> matched(n);
  parlay::parallel_for(0, n, [&](size_t i) {
    matched[i].store(false, std::memory_order_relaxed);
  });

  // The set of edges that are still candidates for the matching.
  // Initially, all edges are active.
  parlay::sequence<edgeId> active_edges = parlay::iota<edgeId>(m);

  // The final resulting matching.
  parlay::sequence<edgeId> final_matching;
  final_matching.reserve(n / 2);

  while (!active_edges.empty()) {
    // Step 1: Propose
    // Each vertex receives proposals from incident active edges and picks the
    // one with the minimum edge index.
    parlay::sequence<std::atomic<edgeId>> proposals(n);
    const edgeId max_id = std::numeric_limits<edgeId>::max();
    parlay::parallel_for(0, n, [&](size_t i) {
      proposals[i].store(max_id, std::memory_order_relaxed);
    });

    parlay::parallel_for_each(active_edges, [&](edgeId i) {
      auto e = EA[i];
      parlay::write_min(&proposals[e.u], i, std::less<edgeId>());
      parlay::write_min(&proposals[e.v], i, std::less<edgeId>());
    });

    // Step 2: Accept
    // An edge is a "winner" if it's the best proposal for both its endpoints.
    auto winners = parlay::filter(active_edges, [&](edgeId i) {
      auto e = EA[i];
      return proposals[e.u].load(std::memory_order_relaxed) == i &&
             proposals[e.v].load(std::memory_order_relaxed) == i;
    });

    // If no new edges were matched, we are done.
    if (winners.empty()) {
      break;
    }

    // Step 3: Update state
    // Mark vertices of winning edges as matched. This is safe to do in parallel
    // because each vertex can belong to at most one winning edge.
    parlay::parallel_for_each(winners, [&](edgeId i) {
      auto e = EA[i];
      matched[e.u].store(true, std::memory_order_relaxed);
      matched[e.v].store(true, std::memory_order_relaxed);
    });

    // Add winners to the final result.
    final_matching.insert(std::end(final_matching), std::begin(winners), std::end(winners));

    // Step 4: Filter for the next round
    // An edge remains active only if both its endpoints are still unmatched.
    // This is the most expensive step, but necessary when working from an edge list.
    active_edges = parlay::filter(active_edges, [&](edgeId i) {
      auto e = EA[i];
      return !matched[e.u].load(std::memory_order_relaxed) &&
             !matched[e.v].load(std::memory_order_relaxed);
    });
  }

  return final_matching;
}

