using namespace std;

// This is a parallel implementation of the randomized greedy algorithm for
// maximal matching. It is a highly effective and practical parallel algorithm.
//
// The core idea is as follows:
// 1. Process edges in a random order. This is achieved by generating a
//    random permutation of the edge indices. Randomization helps to break
//    long dependency chains found in the original edge order and reduces
//    contention on high-degree vertices by statistically distributing the
//    workload.
//
// 2. Use an atomic array `matched_state` to keep track of whether a vertex
//    is part of the matching. A vertex can be in one of two states:
//    unmatched (0) or matched (1).
//
// 3. Iterate through the permuted edges in parallel. For each edge (u, v):
//    a. First, perform a cheap, non-blocking check using a relaxed atomic
//       load to see if either u or v is already matched. If so, this edge
//       cannot be part of the matching, and we move on.
//    b. If both vertices appear to be free, we attempt to "lock" them for our
//       matching. To prevent deadlocks (e.g., two threads trying to lock
//       vertices u and v in opposite orders), we enforce a consistent locking
//       order, such as by vertex ID.
//    c. We use an atomic `compare_exchange_strong` operation to try to change
//       the state of the vertices from unmatched (0) to matched (1).
//    d. If we successfully lock both u and v, the edge is added to the
//       matching. We record its index in the `is_in_matching` array.
//    e. If we lock u but fail to lock v (because another thread matched v
//       in the meantime), we must release our lock on u by atomically
//       setting its state back to 0.
//
// 4. After the parallel loop finishes, we use `parlay::pack_index` to
//    efficiently collect the indices of all edges that were successfully
//    added to the matching into the final result sequence.
//
// This approach is work-efficient (linear work in the number of edges) and
// highly parallel. It avoids complex graph transformations, respecting the
// problem's constraint not to reorder the graph for locality.
parlay::sequence<edgeId> maximalMatching(edges const &E) {
  size_t n = max(E.numCols,E.numRows);
  size_t m = E.nonZeros;
  timer t("max matching", true);

  // Matched status for each vertex. 0 = unmatched, 1 = matched.
  // Using std::atomic<int> for thread-safety. int is also less prone
  // to false sharing than bool.
  auto matched_state = parlay::sequence<std::atomic<int>>::from_function(n, [](size_t) {
    return std::atomic<int>(0);
  });

  // A boolean array to mark which edges are chosen for the matching.
  // Non-atomic is fine since each edge index is unique and processed once.
  auto is_in_matching = parlay::sequence<bool>(m, false);

  // Generate a random permutation of edge indices to process.
  // This breaks symmetries and reduces contention in a statistical way.
  auto p = parlay::random_permutation(m);

  // Process all edges in parallel according to the random permutation.
  parlay::parallel_for(0, m, [&](size_t i) {
    edgeId eid = p[i];
    auto [u, v] = E[eid];

    // Optimization: A relaxed load is a cheap way to check if either vertex
    // is already matched. A stale read is harmless, as the CAS will fail later.
    if (matched_state[u].load(std::memory_order_relaxed) != 0 ||
        matched_state[v].load(std::memory_order_relaxed) != 0) {
      return;
    }

    // To prevent deadlock, enforce a consistent order for locking vertices by ID.
    if (u > v) std::swap(u, v);

    // Try to atomically mark the first vertex as matched using CAS.
    // acq_rel memory order ensures proper synchronization.
    int expected = 0;
    if (matched_state[u].compare_exchange_strong(expected, 1, std::memory_order_acq_rel)) {
      // Succeeded on u. Now try to match v.
      expected = 0;
      if (matched_state[v].compare_exchange_strong(expected, 1, std::memory_order_acq_rel)) {
        // Succeeded on both. This edge is in the matching.
        is_in_matching[eid] = true;
      } else {
        // Failed on v. We must release our lock on u.
        matched_state[u].store(0, std::memory_order_release);
      }
    }
  });

  // Pack the indices of the edges that were successfully matched.
  return parlay::pack_index<edgeId>(is_in_matching);
}

