// Parallel Maximal Matching using a round-based algorithm (related to Luby's MIS)
// This algorithm does not build an adjacency list, to respect the constraint
// that the graph should not be reordered for locality.
parlay::sequence<edgeId> maximalMatching(edges const &E) {
  size_t n = max(E.numCols, E.numRows);
  size_t m = E.nonZeros;

  if (m == 0) {
    return parlay::sequence<edgeId>();
  }

  parlay::sequence<edgeId> matching;
  // matched_vertices[i] is true if vertex i is covered by the matching
  auto matched_vertices = parlay::tabulate(n, [](size_t) { return std::atomic<bool>(false); });

  // active_edges stores the indices of edges not yet covered by the matching
  parlay::sequence<edgeId> active_edges = parlay::pack_index<edgeId>(m);

  size_t round_num = 0;

  while (!active_edges.empty()) {
    // 1. Candidate Selection: Each active edge is a candidate with probability 0.5.
    // We use a deterministic hash function based on edge ID and round number
    // to avoid the overhead of a random number generator.
    auto candidates = parlay::filter(active_edges, [&](edgeId i) {
      return (parlay::hash64(i ^ round_num) & 1) == 0;
    });
