// The problem asks for a parallel maximalMatching procedure.
// The baseline is a greedy serial algorithm. A standard and effective parallel
// approach for this type of problem (related to Maximal Independent Set) is a
// randomized iterative algorithm.
//
// The algorithm proceeds in rounds. In each round:
// 1. We consider the set of "active" edges, i.e., edges whose endpoints are
//    both still unmatched.
// 2. We generate a random permutation of the active edges to break symmetries
//    and avoid livelock.
// 3. In parallel, for each edge in the random permutation, we attempt to add it
//    to the matching.
//    - An edge (u, v) can be added only if both u and v are currently unmatched.
//    - We use atomic compare-and-swap (CAS) operations to "claim" the vertices.
//    - To prevent deadlocks, we enforce a consistent claiming order (e.g.,
//      always claim the vertex with the smaller ID first).
//    - If an edge successfully claims both its endpoints, it is added to this
//      round's matching. If it claims the first but fails on the second, it must
//      release the first.
// 4. After the parallel phase, we collect all edges that were successfully added.
// 5. We then update the set of active edges by filtering out any edge that has
//    at least one now-matched endpoint.
// 6. We repeat this process until the set of active edges is empty.
//
// This approach is highly parallel, makes progress in every round (in expectation),
// and converges quickly (typically in O(log m) rounds). It works directly on the
// input edge list without reordering the graph structure, thus satisfying the
// problem constraints. A serial fallback is included to guarantee termination in
// worst-case scenarios where the randomized scheduler makes no progress, which is
// rare but possible with small conflicting subgraphs.
parlay::sequence<edgeId> maximalMatching(edges const &E) {
  size_t n = max(E.numCols,E.numRows);
  size_t m = E.nonZeros;
  timer t("max matching", true);

  // mate[v] = -1 if vertex v is unmatched.
  // mate[v] = 1 if vertex v is matched.
  // Using std::atomic to handle concurrent access.
  parlay::sequence<std::atomic<int>> mate(n);
  parlay::parallel_for(0, n, [&](size_t i) {
    mate[i].store(-1, std::memory_order_relaxed);
  });

  // Initially, all edges are active.
  auto active_edges = parlay::to_sequence(parlay::iota<edgeId>(m));

  parlay::sequence<edgeId> final_matching;
  final_matching.reserve(n / 2);

  while (!active_edges.empty()) {
    // Randomly permute the active edges to break symmetry.
    auto p = parlay::random_permutation(active_edges.size());

    // A flag for each edge in the original graph to mark if it's added in this round.
    parlay::sequence<bool> added_in_round(m, false);

    // In parallel, try to match edges.
    parlay::parallel_for(0, active_edges.size(), [&](size_t i) {
      edgeId eid = active_edges[p[i]];
      vertexId u = E[eid].u;
      vertexId v = E[eid].v;

      // Quick check to avoid contention on the atomics for already matched vertices.
      if (mate[u].load(std::memory_order_relaxed) == -1 && mate[v].load(std::memory_order_relaxed) == -1) {
        // Enforce a consistent claiming order to prevent deadlock.
        vertexId u_lock = std::min(u, v);
        vertexId v_lock = std::max(u, v);

        int expected = -1;
        // Try to "claim" the first vertex.
        if (parlay::atomic_compare_exchange_strong(&mate[u_lock], &expected, 1)) {
          expected = -1;
          // Succeeded, now try to "claim" the second vertex.
          if (parlay::atomic_compare_exchange_strong(&mate[v_lock], &expected, 1)) {
            // Success! This edge is now in the matching for this round.
            added_in_round[eid] = true;
          } else {
            // Failed to claim the second vertex, so we must release the first one.
            mate[u_lock].store(-1, std::memory_order_relaxed);
          }
        }
      }
    }, 1); // Use a small grain size for better load balancing

    // Collect the edges that were successfully added in this round.
    auto round_matching = parlay::pack_index<edgeId>(added_in_round);

    // Fallback for rare cases where no progress is made
    if (round_matching.empty() && !active_edges.empty()) {
        for (auto eid : active_edges) {
            vertexId u = E[eid].u;
            vertexId v = E[eid].v;
            if (mate[u].load() == -1 && mate[v].load() == -1) {
                mate[u].store(1);
                mate[v].store(1);
                final_matching.push_back(eid);
            }
        }
        break; // Exit the main loop
    }

    final_matching.append(round_matching);

    // Filter active_edges for the next round. An edge is no longer active if
    // either of its endpoints has been matched. Checking one is sufficient
    // due to the logic of the algorithm.
    active_edges = parlay::filter(active_edges, [&](edgeId i) {
      return mate[E[i].u].load(std::memory_order_relaxed) == -1;
    });
  }

