// A step for the speculative_for loop for maximal matching.
// Each step corresponds to considering one edge.
struct MMStep {
  const edges& E;
  parlay::sequence<pbbs::reservation<long>>& R; // Reservations for each vertex
  parlay::sequence<edgeId>& matching;
  std::atomic<size_t>& matching_offset;

  MMStep(const edges& _E, parlay::sequence<pbbs::reservation<long>>& _R,
         parlay::sequence<edgeId>& _m, std::atomic<size_t>& _mo)
    : E(_E), R(_R), matching(_m), matching_offset(_mo) {}

  // reserve is called on every item in the speculative batch.
  // It tries to reserve the endpoints of edge `i`.
  bool reserve(edgeId i) {
    auto [u_orig, v_orig] = E[i];
    vertexId u = u_orig, v = v_orig;

    // The value stored in the reservation is the edge index.
    // pbbs::reservation<long> is used so that freeze() can use -1.
    // A smaller index means higher priority.
    // The write_min in reserve() correctly fails if a vertex is already
    // frozen (value -1) or reserved by a higher-priority edge (value < i).

    // Ensure consistent locking order to prevent deadlock.
    if (u > v) std::swap(u, v);

    if (R[u].reserve(i)) {
      if (R[v].reserve(i)) {
        return true; // Succeeded in reserving both endpoints.
      } else {
        // Failed to reserve v, so we must release u.
        // checkReset ensures we only release it if we were the ones who reserved it.
        R[u].checkReset(i);
        return false;
      }
    }
    return false; // Failed to reserve u.
  }

  // commit is called only if reserve returned true for an edge.
  // It checks if the reservation is still held and finalizes the match.
  bool commit(edgeId i) {
    auto [u, v] = E[i];

    // Check if we still hold the reservation for both vertices.
    // A higher-priority edge (index j < i) from a different thread
    // might have stolen the reservation in the meantime.
    if (R[u].check(i) && R[v].check(i)) {
      // We won the race. Commit the match.
      // Freeze the vertices so no other edge can use them.
      R[u].freeze();
      R[v].freeze();
      // Add the edge to the matching atomically.
      size_t dest = matching_offset.fetch_add(1, std::memory_order_relaxed);
      matching[dest] = i;
      return true; // Success, this iteration is finished.
    } else {
      // We lost the race. We must release any reservation we still hold.
      // It's possible we hold one but not the other if two different
      // edges with higher priority stole our two vertices respectively.
      R[u].checkReset(i);
      R[v].checkReset(i);
      // Return false to indicate failure. speculative_for will retry this iteration.
      return false;
    }
  }
};


parlay::sequence<edgeId> maximalMatching(edges const &E) {
  timer t("max matching", true);
  size_t n = max(E.numCols, E.numRows);
  size_t m = E.nonZeros;

  if (m == 0) {
    return parlay::sequence<edgeId>();
  }

  // Pre-allocate space for the matching. The size is at most m, and likely closer to n/2.
  // m is a safe upper bound.
  parlay::sequence<edgeId> matching(m);
  std::atomic<size_t> matching_offset = 0;

  // Create a reservation object for each vertex.
  // We use pbbs::reservation<long> because its freeze() method sets the
  // value to -1, which requires a signed type. This works correctly with
  // write_min to ensure frozen vertices can't be reserved.
  auto R = parlay::tabulate(n, [](size_t) { return pbbs::reservation<long>(); });

  // Create the step object for the speculative loop.
  auto s = MMStep(E, R, matching, matching_offset);

  // Use speculative_for to process all edges in parallel.
  // It handles batching, conflicts, and retries automatically.
  // The granularity parameter can be tuned; a larger value is generally better
  // for high-contention graphs. `hasState=false` is a small optimization
  // as our step object's methods are thread-safe.
  pbbs::speculative_for<edgeId>(s, static_cast<edgeId>(0), static_cast<edgeId>(m), 20, false);

  // Resize the matching sequence to the actual number of matched edges.
  matching.resize(matching_offset.load());
  return matching;
}

