  matching.reserve(n / 2);
  parlay::sequence<bool> vertex_matched(n, false);

  // Initially, all edges are active, except for self-loops.
  auto active_edges = parlay::filter(parlay::iota<edgeId>(m), [&](edgeId id) {
    return E[id].u != E[id].v;
