#include "common/get_time.h"
#include "MIS.h"

// **************************************************************
//    MAXIMAL INDEPENDENT SET
// **************************************************************

// A parallel greedy MIS algorithm based on Luby's algorithm.
// It uses randomized priorities to select an independent set of vertices in each round.
//
// The state of each vertex is stored in a `Flags` array:
//   0: undecided (active)
//   1: in the MIS
//   2: neighbor of a vertex in the MIS (removed)
//
// The algorithm proceeds in rounds:
// 1. A set of `active` vertices is maintained. Initially, all vertices are active.
// 2. In each round, for each active vertex, a random priority is generated.
// 3. A vertex is chosen as a candidate if it has a higher priority than all its active neighbors.
// 4. All candidate vertices are added to the MIS.
// 5. All neighbors of candidate vertices are removed from the active set.
// 6. The process repeats with the remaining active vertices until the active set is empty.

parlay::sequence<char> maximalIndependentSet(Graph const &G) {
  size_t n = G.n;
  parlay::sequence<char> Flags(n, 0);
  auto active = parlay::iota<vertexId>(n);
  int round = 0;

  // A deterministic hash function to generate priorities.
  // Using the round number ensures priorities change in each round, breaking symmetries.
  auto priority = [&](vertexId v, int r) {
    return parlay::hash<std::pair<vertexId, int>>{}(std::make_pair(v, r));
  };

  // Temporary storage for round decisions. Reused to reduce allocations.
  // 0: undecided, 1: candidate for MIS, 2: to be removed
  parlay::sequence<char> round_flags(n);

  while (!active.empty()) {
    round++;

    // Reset round_flags for currently active vertices. This is a sparse write.
    parlay::parallel_for(0, active.size(), [&](size_t i) {
      round_flags[active[i]] = 0;
    });

    // Phase 1: Select candidates.
    // An active vertex becomes a candidate if its priority is a strict local maximum
    // among all its active neighbors. Tie-breaking is done by vertex ID.
    parlay::parallel_for(0, active.size(), [&](size_t i) {
      vertexId u = active[i];
      auto p_u = priority(u, round);
      bool is_local_max = true;
      for (size_t j = 0; j < G[u].degree; j++) {
        vertexId v = G[u].Neighbors[j];
        if (Flags[v] == 0) { // Check only active neighbors
          auto p_v = priority(v, round);
          if (p_v > p_u || (p_v == p_u && v > u)) {
            is_local_max = false;
            break;
          }
        }
      }
      if (is_local_max) {
        round_flags[u] = 1; // Mark as candidate
      }
    }, 512); // Granularity of 512 is a good balance.

    // Phase 2: Mark neighbors of candidates for removal.
    // An active vertex that is not a candidate checks if any of its neighbors
    // became a candidate. If so, it marks itself for removal.
    parlay::parallel_for(0, active.size(), [&](size_t i) {
      vertexId u = active[i];
      if (round_flags[u] == 0) { // Not a candidate
        for (size_t j = 0; j < G[u].degree; j++) {
          vertexId v = G[u].Neighbors[j];
          // A neighbor v could be inactive (Flags[v] != 0), in which case
          // it could not have been a candidate in this round.
          // So we only need to check round_flags.
          if (round_flags[v] == 1) {
            round_flags[u] = 2; // Mark for removal
            break;
          }
        }
      }
    }, 512);

    // Phase 3: Commit round decisions to global Flags and prepare the next active set.
    // This uses parlay::pack to efficiently filter the active set.
    auto next_active = parlay::pack(active, parlay::delayed_seq<bool>(active.size(), [&](size_t i) {
      vertexId u = active[i];
      char decision = round_flags[u];
      if (decision > 0) {
        Flags[u] = decision;
        return false; // Remove from active set
      }
      return true; // Keep in active set
    }));
    active = std::move(next_active);
  }

  return Flags;
}

#include <iostream>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/random.h"
#include "common/graph.h"
#include "common/speculative_for.h"
#include "common/get_time.h"
#include "MIS.h"
using namespace std;

// **************************************************************
//    MAXIMAL INDEPENDENT SET
// **************************************************************

// For each vertex:
//   flags = 0 indicates undecided
//   flags = 1 indicates chosen for the MIS
//   flags = 2 indicates a neighbor is chosen
parlay::sequence<char> maximalIndependentSet(Graph const &G) {
  size_t n = G.n;
  if (n == 0) return parlay::sequence<char>();

  auto flags = parlay::sequence<char>(n, 0);
  auto priorities = parlay::sequence<uint64_t>(n);
  auto active_nodes = parlay::to_sequence(parlay::iota<vertexId>(n));
  long round = 0;

  while (!active_nodes.empty()) {
    // Small case: switch to a sequential greedy algorithm for efficiency
    if (active_nodes.size() < 2048) {
      for (vertexId u : active_nodes) {
        if (flags[u] == 0) {
          bool neighbor_in_mis = false;
          auto u_vtx = G[u];
          for (size_t j = 0; j < u_vtx.degree; j++) {
            if (flags[u_vtx.Neighbors[j]] == 1) {
              neighbor_in_mis = true;
              break;
            }
          }
          if (!neighbor_in_mis) {
            flags[u] = 1;
          } else {
            flags[u] = 2;
          }
        }
      }
      break; // All remaining nodes decided
    }

    round++;

    // Step 1: Assign random priorities to all active nodes
    parlay::parallel_for(0, active_nodes.size(), [&](size_t i) {
      vertexId u = active_nodes[i];
      priorities[u] = parlay::hash64_2(u ^ round);
    });

    // Step 2: Each active node checks if it has the highest priority in its active neighborhood
    auto is_winner = parlay::sequence<bool>(active_nodes.size());
    parlay::parallel_for(0, active_nodes.size(), [&](size_t i) {
      vertexId u = active_nodes[i];
      bool can_win = true;
      auto u_vtx = G[u];
      for (size_t j = 0; j < u_vtx.degree; j++) {
        vertexId v = u_vtx.Neighbors[j];
        if (flags[v] == 0 && (priorities[v] > priorities[u] || (priorities[v] == priorities[u] && v > u))) {
          can_win = false;
          break;
        }
      }
      is_winner[i] = can_win;
    });

    // Step 3: Winners join the MIS and remove their neighbors.
    // This is done in a single pass. A winner u sets its own flag to 1.
    // It then attempts to set its neighbors' flags to 2.
    // The only race is when two winners share a neighbor. Both will try to set its flag to 2.
    // Using atomic_cas ensures this is handled correctly and efficiently.
    parlay::parallel_for(0, active_nodes.size(), [&](size_t i) {
      if (is_winner[i]) {
        vertexId u = active_nodes[i];
        flags[u] = 1; // No race possible on this write
        auto u_vtx = G[u];
        for (size_t j = 0; j < u_vtx.degree; j++) {
          vertexId v = u_vtx.Neighbors[j];
          char expected = 0;
          parlay::atomic_cas(&flags[v], expected, (char)2);
        }
      }
    }, 1);

    // Step 4: Create the active set for the next round by packing undecided nodes
    active_nodes = parlay::pack(active_nodes, parlay::delayed_seq<bool>(active_nodes.size(), [&](size_t i) {
      return flags[active_nodes[i]] == 0;
    }));
  }

  return flags;
}

#include <atomic>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "common/graph.h"
#include "MIS.h"

// **************************************************************
//    MAXIMAL INDEPENDENT SET
// **************************************************************

// A parallel randomized algorithm for Maximal Independent Set (MIS).
// The algorithm is based on the Jones-Plassmann / Luby's algorithm.
// It proceeds in rounds. In each round:
// 1. Each active vertex picks a random priority.
// 2. A vertex is added to the MIS if it has a higher priority than all its
//    active neighbors.
// 3. Vertices added to the MIS, and all their neighbors, are removed from
//    the active set.
// This process repeats until no vertices remain.
//
// The state of each vertex is stored in a `flags` array:
//   flags = 0: undecided (active)
//   flags = 1: chosen for the MIS
//   flags = 2: neighbor of a vertex in the MIS (removed)

parlay::sequence<char> maximalIndependentSet(Graph const &G) {
  size_t n = G.n;

  auto flags = parlay::sequence<char>::uninitialized(n);
  parlay::parallel_for(0, n, [&](size_t i) { flags[i] = 0; });

  auto priorities = parlay::sequence<uint64_t>::uninitialized(n);
  auto active_vertices = parlay::iota<vertexId>(n);

  size_t round_num = 0;

  while (!active_vertices.empty()) {
    round_num++;

    // 1. Assign random priorities to active vertices.
    // Using a combination of vertex ID and round number as a seed
    // ensures priorities are different in each round.
    parlay::parallel_for(0, active_vertices.size(), [&](size_t i) {
      vertexId u = active_vertices[i];
      priorities[u] = parlay::hash64_2(u ^ round_num);
    }, 1024);

    // 2. In parallel, select vertices for the MIS and remove their neighbors.
    // This is the core of the round, combining selection and update in one pass
    // over the active vertices for efficiency.
    parlay::parallel_for(0, active_vertices.size(), [&](size_t i) {
      vertexId u = active_vertices[i];

      if (flags[u] == 0) { // Process only if still active.
        uint64_t my_priority = priorities[u];
        bool is_max = true;

        // Check priority against all neighbors.
        auto u_vtx = G[u];
        for (edgeId j = 0; j < u_vtx.degree; j++) {
          vertexId ngh = u_vtx.Neighbors[j];
          if (flags[ngh] == 0) { // Only consider active neighbors.
            uint64_t ngh_priority = priorities[ngh];
            // If neighbor has higher priority, or same priority and lower ID, we lose.
            if (ngh_priority > my_priority || (ngh_priority == my_priority && ngh < u)) {
              is_max = false;
              break;
            }
          }
        }

        if (is_max) {
          // This vertex wins the priority contest, add it to the MIS.
          // A non-atomic write is safe: the priority logic ensures that only this
          // thread (for vertex u) can decide to set flags[u] to 1 in this round.
          flags[u] = 1;

          // Mark all neighbors as removed from consideration.
          for (edgeId j = 0; j < u_vtx.degree; j++) {
            vertexId ngh = u_vtx.Neighbors[j];
            // Use an atomic compare-and-swap to safely mark neighbors.
            // This handles the benign race where multiple new MIS vertices
            // try to remove the same neighbor. It changes the flag from 0 to 2.
            char expected = 0;
            std::atomic_ref<char>(flags[ngh]).compare_exchange_strong(
                expected, 2, std::memory_order_relaxed);
          }
        }
      }
    }, 1024);

    // 3. Filter the active set for the next round.
    // parlay::pack_inplace is used for efficiency, as it modifies the sequence
    // without allocating a new one.
    auto is_active = parlay::delayed_seq<bool>(active_vertices.size(), [&](size_t i) {
        return flags[active_vertices[i]] == 0;
    });
    auto new_end = parlay::pack_inplace(active_vertices, is_active);
    active_vertices.resize(std::distance(active_vertices.begin(), new_end));
  }

  return flags;
}

#include <iostream>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/random.h"
#include "common/graph.h"
#include "MIS.h"

// **************************************************************
//    MAXIMAL INDEPENDENT SET
// **************************************************************

// This implementation uses the parallel randomized algorithm for MIS, often
// attributed to Luby or Alon, Babai, and Itai. It is an iterative algorithm
// that is guaranteed to terminate in O(log n) rounds with high probability.
//
// The algorithm proceeds as follows:
// 1. Assign a random, unique priority to every vertex in the graph.
// 2. In each round, every "active" vertex (one that is not yet in the MIS
//    or removed) proposes to join the MIS.
// 3. A vertex's proposal is accepted if it has a higher priority than all of
//    its active neighbors.
// 4. All vertices with accepted proposals are added to the MIS.
// 5. All neighbors of these newly added vertices are removed from consideration
//    for all future rounds.
// 6. Repeat until no active vertices remain.
//
// This approach is highly parallel and avoids the performance pitfalls of
// deterministic priority schemes (like using vertex IDs), which can suffer
// from long dependency chains in certain graph structures (e.g., paths or grids).

// For each vertex, the `flags` array stores its state:
//   0: undecided/active
//   1: chosen for the MIS
//   2: removed (a neighbor was chosen for the MIS)
parlay::sequence<char> maximalIndependentSet(Graph const &G) {
  size_t n = G.n;
  if (n == 0) {
    return parlay::sequence<char>();
  }

  // Assign a random, unique priority to each vertex.
  // parlay::random_permutation is an efficient way to generate unique
  // priorities from 0 to n-1, which simplifies the logic by removing
  // the need for tie-breaking.
  auto priorities = parlay::random_permutation<unsigned int>(n);

  parlay::sequence<char> flags(n, 0);

  // The set of vertices that are still undecided.
  // Initially, all vertices are active.
  auto active = parlay::tabulate(n, [](vertexId i) { return i; });

  while (!active.empty()) {
    // A temporary boolean array to mark which vertices are candidates to be
    // added to the MIS in this round. It is allocated once per round.
    parlay::sequence<bool> to_add(n, false);

    // 1. Selection Phase:
    // In parallel, each active vertex determines if it has the highest priority
    // among all its active neighbors. If so, it becomes a candidate.
    parlay::parallel_for(0, active.size(), [&](size_t i) {
      vertexId u = active[i];
      bool is_local_max = true;
      auto u_vtx = G[u];
      for (size_t j = 0; j < u_vtx.degree; j++) {
        vertexId v = u_vtx.Neighbors[j];
        // We only need to compare with neighbors that are also still active (flags[v] == 0).
        // If an active neighbor has a higher priority, u cannot be a candidate.
        if (flags[v] == 0 && priorities[v] > priorities[u]) {
          is_local_max = false;
          break;
        }
      }
      if (is_local_max) {
        to_add[u] = true;
      }
    }, 1024); // Use a grain size to improve load balancing for irregular graphs.

    // 2. Update Phase:
    // In parallel, add the selected candidates to the MIS and mark their neighbors as removed.
    parlay::parallel_for(0, active.size(), [&](size_t i) {
      vertexId u = active[i];
      if (to_add[u]) {
        // Add u to the MIS. This write is safe. Since priorities are unique,
        // if u is a candidate, none of its neighbors can be, so we are not
        // racing with a neighbor that is also trying to join the MIS.
        flags[u] = 1;

        // Mark all of u's neighbors as removed.
        auto u_vtx = G[u];
        for (size_t j = 0; j < u_vtx.degree; j++) {
          vertexId v = u_vtx.Neighbors[j];
          // Atomically set the neighbor's flag to 2 (removed).
          // We use write_max, which is a benign race. If multiple new MIS vertices
          // are neighbors of v, they all try to set flags[v] to 2.
          // This is safe because a neighbor v of a new MIS vertex u cannot itself
          // be a new MIS vertex, so its flag is guaranteed not to be 1.
          // write_max will correctly change its flag from 0 to 2.
          parlay::write_max(&flags[v], (char)2);
        }
      }
    }, 1024);

    // 3. Filter Phase:
    // Create the active set for the next round, consisting of all vertices
    // that are still undecided (flag == 0). parlay::filter is a highly
    // optimized parallel primitive for this task.
    active = parlay::filter(active, [&](vertexId v) {
      return flags[v] == 0;
    });
  }

  return flags;
}

#include <iostream>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/hash.h"
#include "common/graph.h"
#include "MIS.h"

// **************************************************************
//    MAXIMAL INDEPENDENT SET
// **************************************************************
// This implementation uses the classic randomized algorithm by Luby.
// It proceeds in rounds. In each round:
// 1. Assign a random priority to each undecided vertex.
// 2. An undecided vertex 'u' joins the MIS if it has a higher priority
//    than all of its undecided neighbors. These are the "winners".
// 3. All winners are added to the MIS (flag = 1).
// 4. All neighbors of winners are removed from consideration (flag = 2).
// 5. Remaining undecided vertices proceed to the next round.
// This process is repeated until no undecided vertices remain.
//
// The algorithm is highly parallel and work-efficient, finishing in
// O(log n) rounds with high probability. It is significantly faster
// than the baseline's speculative_for approach, which suffers from
// high contention and dependency chains on many graph types.
//
// For each vertex, the state is stored in a `flags` array:
//   Flags = 0 indicates undecided
//   Flags = 1 indicates chosen for the MIS
//   Flags = 2 indicates a neighbor is chosen, so this vertex is removed

parlay::sequence<char> maximalIndependentSet(Graph const &G) {
  size_t n = G.n;
  auto flags = parlay::sequence<char>(n, 0);

  // active_vertices: a packed list of vertices that are still undecided.
  auto active_vertices = parlay::iota<vertexId>(n);

  // Priorities: pair of (random_value, vertex_id) to break ties.
  // Generated once at the beginning for efficiency. Using parlay::hash64
  // provides good pseudo-random, deterministic values.
  auto priorities = parlay::tabulate(n, [](size_t i) {
    return std::make_pair(parlay::hash64(i), (vertexId)i);
  });

  while (!active_vertices.empty()) {
    // Optimization: if the number of active vertices is small,
    // switch to a sequential greedy algorithm to avoid parallel overhead.
    if (active_vertices.size() < 10000) {
      for (vertexId u : active_vertices) {
        if (flags[u] == 0) {
          // If u is undecided, add it to the MIS.
          flags[u] = 1;
          // Mark all its undecided neighbors as removed.
          for (auto v : G[u]) {
            if (flags[v] == 0) {
              flags[v] = 2;
            }
          }
        }
      }
      // All remaining vertices are now decided, so we can break.
      break;
    }

    // 1. Determine winners in parallel
    // A vertex u is a winner if it has a higher priority than all its active neighbors.
    auto is_winner = parlay::tabulate(active_vertices.size(), [&](size_t i) {
      vertexId u = active_vertices[i];
      // Pre-condition: flags[u] must be 0. This is guaranteed by how active_vertices is built.
      for (auto v : G[u]) {
        // We only care about neighbors that are also active (flags[v] == 0).
        // If a neighbor has a higher priority, u is not a winner.
        if (flags[v] == 0 && priorities[v] > priorities[u]) {
          return false;
        }
      }
      return true;
    });

    // 2. Update flags based on winners
    // First, add winners to the MIS. This is non-blocking as winners are independent.
    parlay::parallel_for(0, active_vertices.size(), [&](size_t i) {
      if (is_winner[i]) {
        flags[active_vertices[i]] = 1;
      }
    });

    // Second, remove neighbors of winners. This requires atomics as a vertex
    // can be a neighbor of multiple winners.
    parlay::parallel_for(0, active_vertices.size(), [&](size_t i) {
      if (is_winner[i]) {
        vertexId u = active_vertices[i];
        for (auto v : G[u]) {
          // Atomically try to set the flag of an undecided neighbor to 2.
          // Use parlay's CAS for C++17 compatibility.
          char expected = 0;
          parlay::compare_and_swap(&flags[v], expected, (char)2);
        }
      }
    });

    // 3. Prepare for the next round by filtering out decided vertices.
    active_vertices = parlay::filter(active_vertices, [&](vertexId u) {
      return flags[u] == 0;
    });
  }

  return flags;
}

