    // Using a hash of vertex ID and round number gives deterministic "random" priorities
    // that change each round. This is fast and avoids pathological cases.
    parlay::parallel_for(0, Active.size(), [&](size_t i) {
      vertexId v = Active[i];
      P[v] = parlay::hash<vertexId>{}(v) ^ parlay::hash<size_t>{}(round);
    });

    // This sequence stores whether the i-th vertex in `Active` is a winner.
    // Using a sequence of size `Active.size()` is more memory-efficient
