          vertexId ngh = neighbors.Neighbors[j];
          // Use CAS to remove neighbors. This is race-safe if multiple
          // new MIS vertices border the same undecided vertex.
          pbbs::atomic_compare_and_swap(&Flags[ngh], (char)0, (char)2);
