    // `pack_inplace` is efficient as it avoids reallocating the Active buffer each round.
    auto new_end = parlay::pack_inplace(Active, [&](vertexId v) {
      return Flags[v] == 0;
    });
    Active.resize(new_end - Active.begin());
  }

  return Flags;
}

