  parlay::sequence<char> flags(n, (char)0);

  auto active_vertices = parlay::tabulate(n, [](size_t i) -> vertexId { return i; });
  parlay::sequence<std::pair<double, vertexId>> priorities(n);

  // A pool of thread-local random number generators to produce high-quality
  // parallel random numbers without contention.
  parlay::random_generator<std::mt19937> rand_gens;

  while (!active_vertices.empty()) {
    // Step 1: Assign random priorities to all active vertices.
    // The priority is a pair (random_value, vertex_id) to break ties deterministically.
    parlay::parallel_for(0, active_vertices.size(), [&](size_t i) {
      vertexId v = active_vertices[i];
      auto& gen = rand_gens.get();
      priorities[v] = {std::uniform_real_distribution<double>(0.0, 1.0)(gen), v};
    });

    // Step 2: Select candidates. A vertex is a candidate if its priority is
    // strictly greater than all of its active neighbors' priorities.
