    auto candidates = parlay::filter(active_vertices, [&](vertexId v) {
      auto pv = priorities[v];
      auto neighbors = G[v];
      for (size_t j = 0; j < neighbors.degree; j++) {
        vertexId ngh = neighbors.Neighbors[j];
        // Only check against neighbors that are also still active.
        if (flags[ngh] == 0 && priorities[ngh] > pv) {
          return false; // A neighbor has higher priority.
        }
      }
      return true; // This vertex is a local maximum.
    });

    // Step 3: Add candidates to the MIS and remove their neighborhoods.
    // First, mark all candidates as being in the MIS (flag = 1).
    // This loop is race-free because the `candidates` set is an independent set
    // by construction, so no two threads will write to the same `flags` location.
    parlay::parallel_for(0, candidates.size(), [&](size_t i) {
      flags[candidates[i]] = 1;
    });

    // Second, mark all neighbors of the candidates as removed (flag = 2).
    // This loop has a benign data race: if a vertex is a neighbor of two
    // different candidates, both threads might try to write '2' to its flag.
    // The final result is correct, and this is much faster than using atomics.
    parlay::parallel_for(0, candidates.size(), [&](size_t i) {
      vertexId v = candidates[i];
      auto neighbors = G[v];
      for (size_t j = 0; j < neighbors.degree; j++) {
        flags[neighbors.Neighbors[j]] = 2;
      }
    });

