    // vertices that are now decided (in MIS or removed). parlay::pack_inplace
    // is an efficient way to shrink the sequence of active vertices.
    auto packed_end = parlay::pack_inplace(active_vertices, parlay::delayed_seq<bool>(active_vertices.size(), [&](size_t i) {
      return flags[active_vertices[i]] == 0;
    }));
    active_vertices.resize(std::distance(active_vertices.begin(), packed_end));
  }

  return flags;
}

