// 1. Assigns a unique random priority to each undecided vertex.
// 2. Selects a set of candidate vertices to join the MIS. A vertex is a
//    candidate if it has a higher priority than all of its undecided neighbors.
//    This candidate set is guaranteed to be an independent set.
// 3. Adds all candidate vertices to the MIS and marks their neighbors as
//    removed from future consideration.
// The algorithm terminates when no undecided vertices remain. This is known
// to be a work-efficient parallel algorithm, finishing in O(log n) rounds
// with high probability. It avoids the spinning and high-contention issues
// of the baseline implementation.

// Flags: 0 = undecided, 1 = in MIS, 2 = not in MIS
parlay::sequence<char> maximalIndependentSet(const Graph &G) {
  const size_t n = G.n;
  auto flags = parlay::sequence<char>(n);

  // Initially, all non-isolated vertices are active (flag = 0).
  // Isolated vertices (degree 0) are immediately added to the MIS (flag = 1).
  parlay::parallel_for(0, n, [&](size_t i) {
    flags[i] = (G[i].degree == 0) ? 1 : 0;
  });

  // active_indices stores the indices of all vertices with flag = 0.
  // Using pack_index is efficient, as it focuses work only on undecided vertices.
  auto active_indices = parlay::pack_index<vertexId>(parlay::delayed_seq<bool>(n, [&](size_t i) {
    return flags[i] == 0;
  }));

  // Use a thread-safe random number generator.
  // Priorities are pairs of (random_val, vertex_id) to ensure they are unique.
  auto priorities = parlay::sequence<std::pair<uint32_t, vertexId>>(n);
  parlay::random_generator gen;
  std::uniform_int_distribution<uint32_t> dist;

  while (!active_indices.empty()) {
    // Step 1: Assign unique random priorities to all active vertices.
    parlay::parallel_for(0, active_indices.size(), [&](size_t i) {
      vertexId v = active_indices[i];
      auto r = gen[i]; // Each thread gets a different seed from the generator
      priorities[v] = {dist(r), v};
    });

    // Step 2: Identify candidates for the MIS. A vertex is a candidate if it has a
    // higher priority than all its active neighbors.
    auto is_candidate = parlay::sequence<bool>(active_indices.size());
    parlay::parallel_for(0, active_indices.size(), [&](size_t i) {
      vertexId v = active_indices[i];
      bool is_max = true;
      for (size_t j = 0; j < G[v].degree; j++) {
        vertexId u = G[v].Neighbors[j];
        // Only compare with other active vertices (flags[u] == 0)
        if (flags[u] == 0 && priorities[v] < priorities[u]) {
          is_max = false;
          break;
        }
      }
      is_candidate[i] = is_max;
    });

    // Step 3: Update flags in a single pass. Add candidates to the MIS (flag=1)
    // and remove their neighbors (flag=2).
    parlay::parallel_for(0, active_indices.size(), [&](size_t i) {
      if (is_candidate[i]) {
        vertexId v = active_indices[i];
        // Add v to the MIS. This write is safe because no neighbor of v can be a
        // candidate, so no other thread will try to write to flags[v].
        flags[v] = 1;
        // Mark all neighbors of v as removed from consideration.
        for (size_t j = 0; j < G[v].degree; j++) {
          vertexId u = G[v].Neighbors[j];
          // A neighbor u might also be a neighbor of another new MIS vertex.
          // Use an atomic compare-and-swap to safely mark it as removed (2)
          // only if it's currently undecided (0).
          if (flags[u] == 0) {
            pbbs::atomic_compare_and_swap(&flags[u], (char)0, (char)2);
          }
        }
      }
    });

    // Step 4: Pack the remaining active vertices for the next round.
    active_indices = parlay::pack_index<vertexId>(parlay::delayed_seq<bool>(n, [&](size_t i) {
      return flags[i] == 0;
    }));
  }

  return flags;
}

