// Flags[v] = 0 means undecided, Flags[v] = 1 means vertex is in MIS,
// and Flags[v] = 2 means vertex is not in MIS

// This implementation uses a variant of Luby's algorithm, a randomized
// round-based approach known for its excellent parallelism and theoretical guarantees.
// It is generally faster and more robust than speculative spin-lock algorithms,
// especially on graphs with high-degree vertices or high contention.
//
// The algorithm proceeds in rounds:
// 1. Propose: Each undecided ('active') vertex generates a unique random priority.
// 2. Select: An active vertex is added to the MIS if it has a higher priority
//    than all of its active neighbors.
// 3. Update: The neighbors of these newly selected MIS vertices are marked as
//    'not in MIS'.
// 4. Filter: The set of active vertices for the next round is constructed from
//    all vertices that remain undecided.
// This process repeats until no vertices are undecided.
parlay::sequence<char> maximalIndependentSet(const Graph &G) {
  size_t n = G.n;
  parlay::sequence<char> flags(n, 0);
  auto active = parlay::iota<vertexId>(n);
  parlay::sequence<std::pair<uint64_t, vertexId>> priorities(n);
  parlay::random_generator gen;

  size_t remaining = n;

  while (remaining > 0) {
    // Fallback to a sequential greedy algorithm for small remaining sets
    // to avoid the overhead of parallel primitives. The threshold is a tunable
    // parameter; 2048 is a reasonable choice for modern multicore machines.
    if (remaining < 2048) {
      for (vertexId u : active) {
        if (flags[u] == 0) { // Process only if still undecided
          bool is_neighbor_in_mis = false;
          for (size_t j = 0; j < G[u].degree; j++) {
            vertexId v = G[u].Neighbors[j];
            if (flags[v] == 1) {
              is_neighbor_in_mis = true;
              break;
            }
          }
          if (!is_neighbor_in_mis) {
            flags[u] = 1; // Add to MIS
            for (size_t j = 0; j < G[u].degree; j++) {
              vertexId v = G[u].Neighbors[j];
              // No CAS needed here as it's sequential.
              if (flags[v] == 0) flags[v] = 2;
            }
          } else {
            flags[u] = 2; // A neighbor is in MIS, so this vertex cannot be.
          }
        }
      }
      break; // All remaining vertices have been decided.
    }

    // 1. Propose: Assign random priorities to active vertices.
    // The vertexId is used as a tie-breaker to make priorities unique.
    std::uniform_int_distribution<uint64_t> dist;
    parlay::parallel_for(0, active.size(), [&](size_t i) {
      auto r = gen[i];
      vertexId u = active[i];
      priorities[u] = {dist(r), u};
    }, 1); // Use grainsize of 1 to ensure all threads contribute to random numbers.

    // 2. Select: A vertex is a winner if it has a higher priority than all its active neighbors.
    parlay::parallel_for(0, active.size(), [&](size_t i) {
      vertexId u = active[i];
      bool is_max = true;
      for (size_t j = 0; j < G[u].degree; j++) {
        vertexId v = G[u].Neighbors[j];
        // Only compare against neighbors that are also active (flags[v] == 0).
        if (flags[v] == 0 && priorities[v] > priorities[u]) {
          is_max = false;
          break;
        }
      }
      if (is_max) {
        // Mark as a winner. CAS is used to ensure a memory fence, making the
        // write visible to other threads in the next step.
        pbbs::atomic_compare_and_swap(&flags[u], (char)0, (char)1);
      }
    });

    // 3. Update: Mark neighbors of winners as out of the MIS.
    parlay::parallel_for(0, active.size(), [&](size_t i) {
      vertexId u = active[i];
      // Check if u was a winner in this round (flags[u] might have been 0 or 1).
      // We only need to process vertices that just won.
      if (flags[u] == 1 && priorities[u].second == u) { // priorities check confirms it's a new winner
        for (size_t j = 0; j < G[u].degree; j++) {
          vertexId v = G[u].Neighbors[j];
          // If a neighbor v is undecided, mark it as out.
          // CAS is necessary because multiple winners (e.g., u1, u2) that are not
          // neighbors of each other could both be neighbors of the same vertex v.
          pbbs::atomic_compare_and_swap(&flags[v], (char)0, (char)2);
        }
      }
    });

    // 4. Filter: Create the active set for the next round from undecided vertices.
    auto next_active = parlay::filter(active, [&](vertexId u) {
      return flags[u] == 0;
    });
    active = std::move(next_active);
    remaining = active.size();
  }

  return flags;
}

