//    break symmetries.
// 2. Vertices chosen for the MIS are marked as '1'.
// 3. Neighbors of these newly chosen vertices are marked as '2' (not in MIS).
// 4. The set of active (undecided) vertices is updated.
// The process repeats until no vertices are undecided. This approach avoids
// the high contention and spinning of lock-based retry loops, especially on
// graphs with high-degree vertices.
parlay::sequence<char> maximalIndependentSet(const Graph &G) {
  size_t n = G.n;
  parlay::sequence<char> flags(n, 0);

  if (n == 0) {
    return flags;
  }

  // Assign a unique random priority to each vertex.
  // Using a permutation ensures no two priorities are the same, which guarantees
  // that in every round, at least one vertex is added to the MIS if the active
  // set is non-empty. This ensures progress and termination.
  auto priorities = parlay::random_permutation<vertexId>(n);

  // The set of vertices that are still undecided (flag == 0).
  parlay::sequence<vertexId> active_vertices = parlay::iota<vertexId>(n);

  while (!active_vertices.empty()) {
