        vertexId u = v_node.Neighbors[j];
        if (flags[u] == 0 && priorities[u] > priorities[v]) {
          return false; // A neighbor has higher priority, so v cannot be in the MIS this round.
        }
      }
      return true; // v is a winner.
    });

