    auto still_active = parlay::delayed_seq<bool>(active_vertices.size(), [&](size_t i) {
      return flags[active_vertices[i]] == 0;
    });
    size_t new_size = parlay::pack_inplace(active_vertices, still_active);
    active_vertices.resize(new_size);
  }

  return flags;
