template <class Vtx>
struct oct_tree {
  using vtx = Vtx;
  using point = typename vtx::pointT;
  using coord = typename point::coord;
  static constexpr int dim = point::dim;
  static constexpr int num_children = 1 << dim;
  static constexpr size_t leaf_cutoff = 32;

  struct box_internal {
    point center;
    coord size;
  };
  using box = std::pair<point, point>;

  struct node {
    box_internal b;
    node* parent;
    std::atomic<int> count;

    node(box_internal _b, node* _p) : b(_b), parent(_p), count(0) {}
    virtual ~node() = default;
    virtual bool is_leaf() const = 0;
    virtual size_t depth() const = 0;
  };

  struct leaf : public node {
    parlay::sequence<vtx*> items;
    leaf(box_internal _b, node* _p, parlay::slice<vtx* const*> _items)
        : node(_b, _p), items(parlay::to_sequence(_items)) {
      this->count = items.size();
    }
    bool is_leaf() const override { return true; }
    size_t depth() const override {
      return (this->parent == nullptr) ? 0 : this->parent->depth() + 1;
    }
  };

  struct internal_node : public node {
    std::array<std::unique_ptr<node>, num_children> children;
    internal_node(box_internal _b, node* _p) : node(_b, _p) {
      children.fill(nullptr);
    }
    bool is_leaf() const override { return false; }
    size_t depth() const override {
      if (this->count == 0) return 0;
      size_t max_d = 0;
      for (const auto& child : children) {
        if (child) max_d = std::max(max_d, child->depth());
      }
      return max_d;
    }
  };

