  static box get_box(const parlay::sequence<vtx*>& points) {
    auto get_pair = [](vtx* p) { return std::make_pair(p->pt, p->pt); };
    auto reduce_op = parlay::make_monoid(
        [](const box& a, const box& b) {
          return std::make_pair(a.first.minCoords(b.first), a.second.maxCoords(b.second));
        }, get_pair(points[0]));
    return parlay::reduce(parlay::delayed_map(points, get_pair), reduce_op);
  }

  static box_internal to_box_internal(box b) {
    point center = b.first + (b.second - b.first) / 2.0;
    coord size = ((b.second - b.first) / 2.0).maxDim();
    if (size == 0) size = 1.0;
    return {center, size};
  }

  template <typename F>
  void map(F f) {
    map_recursive(root.get(), f);
  }

  parlay::sequence<vtx*> vertices() {
    parlay::sequence<vtx*> v_seq;
    if (!root) return v_seq;
    parlay::sequence<node*> q;
    q.push_back(root.get());
    size_t head = 0;
    while(head < q.size()) {
      node* curr = q[head++];
      if(!curr) continue;
      if(curr->is_leaf()) {
        leaf* l = static_cast<leaf*>(curr);
        v_seq.insert(v_seq.end(), l->items.begin(), l->items.end());
      } else {
        internal_node* in = static_cast<internal_node*>(curr);
        for(size_t i = 0; i < num_children; i++) {
          if (in->children[i]) q.push_back(in->children[i].get());
        }
      }
    }
    return v_seq;
  }

 private:
  std::unique_ptr<node> build_tree(parlay::slice<vtx* const*> points, box_internal b, node* parent) {
    if (points.size() <= leaf_cutoff) {
      return std::make_unique<leaf>(b, parent, points);
    }
    auto new_node = std::make_unique<internal_node>(b, parent);
    auto get_quadrant = [center = b.center](vtx* p) { return p->pt.quadrant(center); };
    auto split_points = parlay::split_by(points, get_quadrant);

    parlay::parallel_for(0, split_points.size(), [&](size_t i) {
      auto [quadrant, points_in_quadrant] = split_points[i];
      box_internal child_box;
      child_box.size = b.size / 2.0;
      child_box.center = b.center.offsetPoint(quadrant, child_box.size);
      new_node->children[quadrant] = build_tree(points_in_quadrant, child_box, new_node.get());
    }, 1);

    new_node->count = points.size();
    return new_node;
  }

  template <typename F>
  void map_recursive(node* n, F f) {
    if (!n) return;
    if (n->is_leaf()) {
      leaf* l = static_cast<leaf*>(n);
      for (auto p : l->items) {
        f(p, l);
      }
    } else {
      internal_node* in = static_cast<internal_node*>(n);
      parlay::parallel_for(0, num_children, [&](size_t i) {
        map_recursive(in->children[i].get(), f);
      }, 1);
    }
  }
};


