template <class Point, int K>
struct knn_vertex {
  using pointT = Point;
  using coord = typename pointT::coord;
  pointT pt;
  size_t id;
  size_t counter;

  std::pair<coord, size_t> ngh[K];
  int num_ngh;
  coord farthest_dist_sq;

  knn_vertex(pointT _pt, size_t _id) : pt(_pt), id(_id), counter(0) {}

  void init_search() {
    num_ngh = 0;
    farthest_dist_sq = std::numeric_limits<coord>::max();
  }

  void add_neighbor(const knn_vertex* neighbor, coord dist_sq, int k) {
    if (dist_sq >= farthest_dist_sq && num_ngh == k) {
      return;
    }
    int i = num_ngh - 1;
    while (i >= 0 && dist_sq < ngh[i].first) {
      if (i + 1 < k) {
        ngh[i + 1] = ngh[i];
      }
      i--;
    }
    if (i + 1 < k) {
      ngh[i + 1] = {dist_sq, neighbor->id};
      if (num_ngh < k) {
        num_ngh++;
      }
    }
    if (num_ngh == k) {
      farthest_dist_sq = ngh[k - 1].first;
    }
  }
};

template <class Vtx, int max_k>
struct k_nearest_neighbors {
 public:
  using vtx = Vtx;
  using point = typename vtx::pointT;
  using coord = typename point::coord;
  using o_tree = oct_tree<vtx>;
  using node = typename o_tree::node;
  using box = typename o_tree::box;
  using box_internal = typename o_tree::box_internal;
  using box_delta = std::pair<box, double>;

  std::unique_ptr<o_tree> tree;

  k_nearest_neighbors(parlay::sequence<vtx*>& V, box b)
      : tree(std::make_unique<o_tree>(parlay::make_slice(V), b)) {}

  void k_nearest(vtx* p, int k) {
    p->init_search();
    knn_search(p, tree->root.get(), k);
  }

  void k_nearest_leaf(vtx* p, node* start_node, int k) {
    p->init_search();
    p->counter = 0;
    auto* l = static_cast<typename o_tree::leaf*>(start_node);
    for (auto neighbor : l->items) {
      if (neighbor != p) {
        p->add_neighbor(neighbor, (p->pt - neighbor->pt).sqLength(), k);
      }
    }
    p->counter += l->items.size();
    node* curr = start_node;
    while (curr->parent != nullptr) {
      node* parent = curr->parent;
      auto* parent_internal = static_cast<typename o_tree::internal_node*>(parent);
      for (const auto& child : parent_internal->children) {
        if (child && child.get() != curr) {
          knn_search(p, child.get(), k);
        }
      }
      curr = parent;
    }
  }

  void knn_search(vtx* p, node* n, int k) {
    if (!n || p->farthest_dist_sq <= box_dist_sq(p->pt, n->b)) {
      return;
    }
    if (n->is_leaf()) {
      auto* l = static_cast<typename o_tree::leaf*>(n);
      p->counter += l->items.size();
      for (auto neighbor : l->items) {
        if (neighbor != p) {
          p->add_neighbor(neighbor, (p->pt - neighbor->pt).sqLength(), k);
        }
      }
    } else {
      auto* in = static_cast<typename o_tree::internal_node*>(n);
      std::array<std::pair<coord, int>, o_tree::num_children> child_dists;
      for (int i = 0; i < o_tree::num_children; ++i) {
        child_dists[i] = {in->children[i] ? box_dist_sq(p->pt, in->children[i]->b) : std::numeric_limits<coord>::max(), i};
      }
      std::sort(child_dists.begin(), child_dists.end());
      for (int i = 0; i < o_tree::num_children; ++i) {
        knn_search(p, in->children[child_dists[i].second].get(), k);
      }
    }
  }

  node* find_leaf(point q, node* n, box /*b*/, double /*delta*/) {
    if (n->is_leaf()) return n;
    auto in = static_cast<typename o_tree::internal_node*>(n);
    int quadrant = q.quadrant(n->b.center);
    if (in->children[quadrant]) {
      return find_leaf(q, in->children[quadrant].get(), {}, 0.0);
    }
    for (int i=0; i < o_tree::num_children; i++)
      if (in->children[i]) return find_leaf(q, in->children[i].get(), {}, 0.0);
    return n;
  }

  box_delta get_box_delta(int /*dims*/) {
    box_internal r_box = tree->root->b;
    auto size_vec = typename point::vector();
    for(int i=0; i<point::dim; i++) size_vec[i] = r_box.size;
    point p_min = r_box.center - size_vec;
    point p_max = r_box.center + size_vec;
    return {{p_min, p_max}, 0.0};
  }

  parlay::sequence<vtx*> vertices() { return tree->vertices(); }

 private:
  static coord box_dist_sq(const point& p, const box_internal& b) {
    coord dist = 0.0;
    for (int i = 0; i < point::dim; i++) {
      coord d = std::max((coord)0.0, std::abs(p[i] - b.center[i]) - b.size);
      dist += d * d;
    }
    return dist;
  }
};


