// *************************************************************
//    k-Heap for storing k-nearest neighbors
// *************************************************************
// A small, fixed-size, sorted collection for the k nearest neighbors.
// It's faster than std::priority_queue for small k.
template <class V, int max_k>
struct k_heap {
  std::array<std::pair<double, V*>, max_k> ngh;
  int k;
  int count;

  k_heap(int _k) : k(std::min(_k, max_k)), count(0) {}

  double max_dist_sq() const {
    return (count < k) ? std::numeric_limits<double>::infinity() : ngh[count - 1].first;
  }

  void add(double dist_sq, V* p) {
    if (count < k) {
      int i = count;
      while (i > 0 && dist_sq < ngh[i-1].first) {
        ngh[i] = ngh[i-1];
        i--;
      }
      ngh[i] = {dist_sq, p};
      count++;
    } else if (dist_sq < ngh[k-1].first) {
      int i = k-1;
      while (i > 0 && dist_sq < ngh[i-1].first) {
        ngh[i] = ngh[i-1];
        i--;
      }
      ngh[i] = {dist_sq, p};
    }
  }
};


