template <class Vtx, int max_k>
struct k_nearest_neighbors {
  using vtx = Vtx;
  using point = typename vtx::pointT;
  using coord = typename point::coord;
  static constexpr int D = point::dim;

  struct box {
    point pMin, pMax;
    box(point _pMin, point _pMax) : pMin(_pMin), pMax(_pMax) {}
    point center() const { return pMin + (pMax - pMin) / 2.0; }
    point size() const { return pMax - pMin; }

    double min_dist_sq(point p) const {
      double dist_sq = 0.0;
      for (int i = 0; i < D; ++i) {
        if (p[i] < pMin[i]) dist_sq += (pMin[i] - p[i]) * (pMin[i] - p[i]);
        else if (p[i] > pMax[i]) dist_sq += (p[i] - pMax[i]) * (p[i] - pMax[i]);
      }
      return dist_sq;
    }
  };

  struct node {
    box b;
    node* parent;
    size_t count;
    int d;

    std::variant<std::array<std::unique_ptr<node>, 1 << D>, parlay::sequence<vtx*>> data;

    node(box _b, node* _p, size_t _c, int _d) : b(_b), parent(_p), count(_c), d(_d) {}
    bool is_leaf() const { return std::holds_alternative<parlay::sequence<vtx*>>(data); }
    parlay::sequence<vtx*>& points() { return std::get<parlay::sequence<vtx*>>(data); }
    std::unique_ptr<node>& child(int i) { return std::get<std::array<std::unique_ptr<node>, 1 << D>>(data)[i]; }

    template <typename F>
    void map(F& f) {
      if (is_leaf()) {
        for (auto p : points()) {
          f(p, this);
        }
      } else {
        parlay::parallel_for(0, 1 << D, [&](size_t i) {
          if (child(i)) child(i)->map(f);
        }, 1);
      }
    }

    size_t depth() const {
      if (is_leaf()) return d;
      size_t max_d = 0;
      for (int i = 0; i < (1 << D); i++) {
        if (std::get<std::array<std::unique_ptr<node>, 1 << D>>(data)[i])
          max_d = std::max(max_d, std::get<std::array<std::unique_ptr<node>, 1 << D>>(data)[i]->depth());
      }
      return max_d;
    }
  };

  using o_tree = k_nearest_neighbors; // For compatibility with original code

  std::unique_ptr<node> tree;

  static box get_box(const parlay::sequence<vtx*>& v) {
    auto min_max = parlay::delayed_seq<std::pair<point, point>>(v.size(), [&](size_t i) {
      return std::make_pair(v[i]->pt, v[i]->pt);
    });
    point p_min, p_max;
    for (int i = 0; i < D; ++i) {
      p_min[i] = std::numeric_limits<coord>::max();
      p_max[i] = std::numeric_limits<coord>::lowest();
    }
    auto identity = std::make_pair(p_min, p_max);
    auto result = parlay::reduce(min_max, parlay::make_monoid([](const auto& a, const auto& b) {
      return std::make_pair(a.first.minCoords(b.first), a.second.maxCoords(b.second));
    }, identity));
    return box(result.first, result.second);
  }

  static std::unique_ptr<node> build(parlay::sequence<vtx*> P, const box& b, int d) {
    if (P.empty()) return nullptr;
    auto n = std::make_unique<node>(b, nullptr, P.size(), d);

    if (P.size() <= 32) { // Leaf node
      n->data = std::move(P);
    } else { // Internal node
      point center = b.center();
      auto get_quadrant = [center](vtx* p) { return p->pt.quadrant(center); };
      auto grouped = parlay::group_by_key(parlay::map(P, [=](vtx* p){ return std::make_pair(get_quadrant(p), p); }));

      auto children_data = parlay::tabulate(1 << D, [&](size_t i) -> parlay::sequence<vtx*> {
        auto it = std::lower_bound(grouped.begin(), grouped.end(), i, [](const auto& a, int b) { return a.first < b; });
        if (it != grouped.end() && it->first == i) return std::move(it->second);
        return parlay::sequence<vtx*>();
      });

      auto children_nodes = parlay::tabulate(1 << D, [&](size_t i) {
        point new_min = b.pMin;
        point new_max = b.pMax;
        for (int j = 0; j < D; j++) {
            if ((i >> j) & 1) new_min[j] = center[j];
            else new_max[j] = center[j];
        }
        return build(std::move(children_data[i]), box(new_min, new_max), d + 1);
      });

      n->data = std::move(children_nodes);
      for (int i = 0; i < (1 << D); ++i) {
        if (n->child(i)) n->child(i)->parent = n.get();
      }
    }
    return n;
  }

  k_nearest_neighbors(parlay::sequence<vtx*>& v, const box& b) {
    tree = build(v, b, 0);
  }

  void k_nearest_leaf(vtx* p, node* start_node, int k) {
    if (k == 0) return;

    k_heap<vtx, max_k> best(k);
    p->counter = 1; // Count the starting node

    // Process start leaf
    for(auto other : start_node->points()) {
      if (other != p) {
        double d2 = (p->pt - other->pt).sqLength();
        if (d2 < best.max_dist_sq()) {
          best.add(d2, other);
        }
      }
    }
    double radius_sq = best.max_dist_sq();

    // Walk up the tree, searching sibling nodes
    node* curr = start_node;
    while (curr->parent != nullptr) {
      node* p_node = curr->parent;
      p->counter++; // Count parent node
      for (int i = 0; i < (1 << D); ++i) {
        node* sibling = p_node->child(i).get();
        if (sibling && sibling != curr) {
          if (sibling->b.min_dist_sq(p->pt) < radius_sq) {
            search_subtree(sibling, p, best, radius_sq);
          }
        }
      }
      curr = p_node;
    }

    // Copy results
    p->k = best.count;
    for (int i = 0; i < best.count; ++i) {
      p->ngh[i] = best.ngh[i].second;
    }
  }

private:
  void search_subtree(node* n, vtx* p, k_heap<vtx, max_k>& best, double& radius_sq) {
    p->counter++; // Count nodes visited
    if (n->is_leaf()) {
      for (auto other : n->points()) {
        if (other != p) {
          double d2 = (p->pt - other->pt).sqLength();
          if (d2 < radius_sq) {
            best.add(d2, other);
            radius_sq = best.max_dist_sq();
          }
        }
      }
    } else { // Internal node
      std::array<int, 1 << D> child_indices;
      std::iota(child_indices.begin(), child_indices.end(), 0);

      // Sort children by distance to query point (best-bin-first)
      std::sort(child_indices.begin(), child_indices.end(), [&](int a, int b) {
          double da = n->child(a) ? n->child(a)->b.min_dist_sq(p->pt) : std::numeric_limits<double>::infinity();
          double db = n->child(b) ? n->child(b)->b.min_dist_sq(p->pt) : std::numeric_limits<double>::infinity();
          return da < db;
      });

      for (int i : child_indices) {
        node* child = n->child(i).get();
        if (child) {
          if (child->b.min_dist_sq(p->pt) < radius_sq) {
            search_subtree(child, p, best, radius_sq);
          } else {
            // Since children are sorted, we can prune the rest
            break;
          }
        }
      }
    }
  }

