// Bounding box for a node
template <class Point>
struct Box {
  using Coord = typename Point::coord;
  Point p_min, p_max;

  Box() : p_min(), p_max() {}
  Box(Point p) : p_min(p), p_max(p) {}
  Box(Point _min, Point _max) : p_min(_min), p_max(_max) {}

  Point center() const { return p_min + (p_max - p_min) / 2.0; }

  // Minimum squared distance from a point to the box
  double min_dist_sq(Point p) const {
    double dist_sq = 0.0;
    for (int i = 0; i < Point::dim; ++i) {
      double d = 0.0;
      if (p[i] < p_min[i]) d = p[i] - p_min[i];
      else if (p[i] > p_max[i]) d = p[i] - p_max[i];
      dist_sq += d * d;
    }
    return dist_sq;
  }

  // Combine two boxes
  static Box combine(const Box& a, const Box& b) {
    return Box(a.p_min.minCoords(b.p_min), a.p_max.maxCoords(b.p_max));
  }
};

// Fixed-size max-heap for the k nearest neighbors
template <int max_k>
struct KNeighborHeap {
  std::array<std::pair<double, int>, max_k> data;
  size_t count = 0;

  void push(double dist_sq, int id) {
    if (count < max_k) {
      data[count++] = {dist_sq, id};
      std::push_heap(data.begin(), data.begin() + count);
    } else if (dist_sq < data.front().first) {
      std::pop_heap(data.begin(), data.end());
      data.back() = {dist_sq, id};
      std::push_heap(data.begin(), data.end());
    }
  }

  double top_dist_sq() const {
    return (count < max_k) ? std::numeric_limits<double>::max() : data.front().first;
  }

  void get_neighbors(std::array<int, max_k>& out_ngh, int k) const {
    auto sorted_data = data;
    std::sort(sorted_data.begin(), sorted_data.begin() + count);
    size_t num_to_copy = std::min((size_t)k, count);
    for(size_t i = 0; i < num_to_copy; ++i) {
      out_ngh[i] = sorted_data[i].second;
    }
    for(size_t i = num_to_copy; i < k; ++i) {
        out_ngh[i] = -1; // Fill remaining with invalid index
    }
  }
};

// The Octree Node
template <int max_k, class Vtx>
struct OctreeNode {
  using Point = typename Vtx::pointT;
  using Node = OctreeNode<max_k, Vtx>;
  using BoxType = Box<Point>;
  static constexpr int num_children = 1 << Point::dim;

  struct Leaf {
    parlay::sequence<Vtx*> items;
  };

  struct Interior {
    BoxType box;
    Point center;
    std::array<std::unique_ptr<Node>, num_children> children;
  };

  std::variant<Leaf, Interior> variant_node;

  // Build constructor
  OctreeNode(parlay::slice<Vtx*> points, const BoxType& box) {
    if (points.size() <= 32) { // Leaf node threshold
      variant_node.template emplace<Leaf>(parlay::sequence<Vtx*>(points.begin(), points.end()));
    } else { // Interior node
      auto& interior = variant_node.template emplace<Interior>();
      interior.box = box;
      interior.center = box.center();

      auto groups = parlay::group_by_key(points, [&](Vtx* v) { return v->pt.quadrant(interior.center); });

      parlay::parallel_for(0, groups.size(), [&](size_t i) {
        const auto& group = groups[i];
        int octant = group.first;
        auto child_points = group.second;

        auto get_box = [](parlay::slice<Vtx*> s) {
            BoxType box(s[0]->pt);
            for(size_t j = 1; j < s.size(); ++j) {
                box.p_min = box.p_min.minCoords(s[j]->pt);
                box.p_max = box.p_max.maxCoords(s[j]->pt);
            }
            return box;
        };

        interior.children[octant] = std::make_unique<Node>(child_points, get_box(child_points));
      }, 1);
    }
  }

  // Map function for parallel processing
  template <typename F>
  void map(F f) {
    std::visit([&](auto& n) {
      using T = std::decay_t<decltype(n)>;
      if constexpr (std::is_same_v<T, Leaf>) {
        parlay::parallel_for(0, n.items.size(), [&](size_t i) {
          f(n.items[i], this);
        }, 1);
      } else if constexpr (std::is_same_v<T, Interior>) {
        parlay::parallel_for(0, num_children, [&](size_t i) {
            if (n.children[i]) {
              n.children[i]->map(f);
            }
        }, 1);
      }
    }, variant_node);
  }

  BoxType get_box() const {
    if (std::holds_alternative<Leaf>(variant_node)) {
      const auto& leaf = std::get<Leaf>(variant_node);
      if (leaf.items.empty()) return BoxType();
      auto get_box = [](parlay::slice<Vtx* const> s) {
        BoxType box(s[0]->pt);
        for (size_t i = 1; i < s.size(); i++) {
          box.p_min = box.p_min.minCoords(s[i]->pt);
          box.p_max = box.p_max.maxCoords(s[i]->pt);
        }
        return box;
      };
      return get_box(leaf.items);
    } else {
      return std::get<Interior>(variant_node).box;
    }
  }
};

// Main k_nearest_neighbors class
template <int max_k, class Vtx>
class k_nearest_neighbors {
public:
  using Point = typename Vtx::pointT;
  using Node = OctreeNode<max_k, Vtx>;
  using BoxType = Box<Point>;

  std::unique_ptr<Node> tree;
  parlay::sequence<Vtx*> vertices; // Store pointers to original vertices

  k_nearest_neighbors(parlay::sequence<Vtx*>& v_in) : vertices(v_in) {
    auto box = parlay::reduce(parlay::map(vertices, [](Vtx* p) { return BoxType(p->pt); }),
                              BoxType::combine);
    tree = std::make_unique<Node>(parlay::make_slice(vertices), box);
  }

  void search(int k) {
    auto search_func = [&](Vtx* p, const Node* n) {
      k_nearest_from_leaf(p, n, k);
    };
    tree->map(search_func);
  }

private:
  void k_nearest_from_leaf(Vtx* p, const Node* leaf_node, int k) {
    KNeighborHeap<max_k> heap;
    int query_id = p - vertices.data();

    // 1. Prime the heap with points from the local leaf
    const auto& leaf = std::get<typename Node::Leaf>(leaf_node->variant_node);
    for (const auto& other_p : leaf.items) {
      if (p != other_p) {
        double d_sq = (p->pt - other_p->pt).sqLength();
        heap.push(d_sq, other_p - vertices.data());
      }
    }

    // 2. Do a global search starting from the root, with the primed heap
    search_from_root(p, query_id, k, heap);
    heap.get_neighbors(p->ngh, k);
  }

  void search_from_root(Vtx* p, int query_id, int k, KNeighborHeap<max_k>& heap) {
    using pq_item = std::pair<double, const Node*>;
    std::priority_queue<pq_item, std::vector<pq_item>, std::greater<pq_item>> q;

    q.push({0.0, tree.get()});

    while (!q.empty()) {
      auto [dist_sq, node] = q.top();
      q.pop();

      if (dist_sq >= heap.top_dist_sq()) {
        break; 
      }

      std::visit([&](auto& n) {
        using T = std::decay_t<decltype(n)>;
        if constexpr (std::is_same_v<T, typename Node::Leaf>) {
          p->counter += n.items.size(); // for stats
          for (const auto& other_p : n.items) {
            if (p != other_p) {
              double d_sq = (p->pt - other_p->pt).sqLength();
              heap.push(d_sq, other_p - vertices.data());
            }
          }
        } else if constexpr (std::is_same_v<T, typename Node::Interior>) {
          for (int i = 0; i < Node::num_children; ++i) {
            if (n.children[i]) {
              double child_dist_sq = n.children[i]->get_box().min_dist_sq(p->pt);
              if (child_dist_sq < heap.top_dist_sq()) {
                q.push({child_dist_sq, n.children[i].get()});
              }
            }
          }
        }
      }, node->variant_node);
    }
  }
};

