// Finds the k nearest neighbors for all points in the input sequence 'v'.
// The algorithm builds an octree over the points and then, for each point,
// performs a parallel search for its neighbors starting from the leaf node
// containing that point. This approach is the most efficient because it leverages
// spatial locality and amortizes the cost of tree traversal across all points.
//
// The results (indices of neighbors) are stored in the .ngh field of each vertex.
template <int max_k, class vtx>
void ANN(parlay::sequence<vtx*> &v, int k) {
  timer t("ANN", report_stats);

  if (v.empty()) {
    return;
  }

  // Define types for convenience
  using knn_tree = k_nearest_neighbors<vtx, max_k>;
  using node = typename knn_tree::node;
  using box = typename knn_tree::box;

  // 1. Compute the bounding box of all points. This is a prerequisite for building the octree.
  box whole_box = knn_tree::o_tree::get_box(v);
  t.next("get_box");

  // 2. Build the octree. This partitions the space and is the main data structure for the search.
  // The tree construction is a highly parallel operation.
  knn_tree T(v, whole_box);
  t.next("build_tree");

  if (report_stats) {
    std::cout << "depth = " << T.tree->depth() << std::endl;
  }

  // 3. Perform the k-NN search for all points in parallel.
  // We use the tree's `map` function, which is a highly optimized parallel traversal.
  // It applies the given lambda function to each point 'p' and its containing leaf node 'n'.
  // This avoids n separate traversals from the root, providing excellent performance
  // and cache efficiency by processing all points within a leaf node together.
  auto knn_search_for_point = [&](vtx* p, node* n) {
    T.k_nearest_leaf(p, n, k);
  };
  T.tree->map(knn_search_for_point);

  t.next("k_nearest_search");

  if (report_stats) {
    // Collect statistics on the number of nodes visited per query point.
    // 'counter' is assumed to be a field in 'vtx' incremented during the search.
    auto s = parlay::delayed_seq<size_t>(v.size(), [&](size_t i) { return v[i]->counter; });
    size_t i = parlay::max_element(s) - s.begin();
    size_t sum = parlay::reduce(s);
    std::cout << "max_nodes_visited_per_query = " << s[i]
              << ", avg_nodes_visited_per_query = " << sum / static_cast<double>(v.size()) << std::endl;
    t.next("stats");
  }
} // The knn_tree T is destroyed here, freeing the tree memory.

