// Moller-Trumbore intersection algorithm with precomputed edges
inline coord rayTriangleIntersect(const ray_t& r, const precomputed_tri& tri) {
  constexpr double EPS = 1e-8;
  auto pvec = r.d.cross(tri.e2);
  double det = tri.e1.dot(pvec);

  if (det > -EPS && det < EPS) return -1.0;

  double inv_det = 1.0 / det;
  auto tvec = r.o - tri.v0;
  double u = tvec.dot(pvec) * inv_det;
  if (u < 0.0 || u > 1.0) return -1.0;

  auto qvec = tvec.cross(tri.e1);
  double v = r.d.dot(qvec) * inv_det;
  if (v < 0.0 || u + v > 1.0) return -1.0;

  double t = tri.e2.dot(qvec) * inv_det;
  return t;
}

// Fast ray-AABB intersection using the slab method
inline bool rayBoxIntersect(const ray_t& r, const BoundingBox& box, double& tmin, double& tmax) {
  for (int i = 0; i < 3; ++i) {
    double invD = 1.0 / r.d[i];
    double t0 = (box[i].min - r.o[i]) * invD;
    double t1 = (box[i].max - r.o[i]) * invD;
    if (invD < 0.0) std::swap(t0, t1);
    tmin = std::max(tmin, t0);
    tmax = std::min(tmax, t1);
    if (tmax <= tmin) return false;
  }
  return true;
}

