eventsPair splitEvents(Boxes &boxes, int cutDim,
		       sequence<event> const &events, 
		       float cutOff) {
  auto lower = delayed::map(events, [&](const event& e) {
    return boxes[cutDim][GET_INDEX(e)].min < cutOff;
  });
  auto upper = delayed::map(events, [&](const event& e) {
    return boxes[cutDim][GET_INDEX(e)].max > cutOff;
  });
  return parlay::two_pack(events, lower, upper);
}

treeNode* generateNode(Boxes &boxes,
		       Events&& events,
		       BoundingBox B,
		       const triangs& Tri,
		       size_t maxDepth) {
  index_t n = events[0].size();

  if (n <= 8 || maxDepth == 0) {
    auto indices = parlay::map(events[0], [](const event& e) { return GET_INDEX(e); });
    parlay::sort_inplace(indices);
    auto unique_indices = parlay::unique(indices);
    return treeNode::make_leaf(std::move(unique_indices), B, Tri);
  }

  std::array<cutInfo, 3> cuts = {
    cutInfo(0,0,0,0), cutInfo(0,0,0,0), cutInfo(0,0,0,0)
  };
  parallel_for(0, 3, [&](size_t d) {
    cuts[d] = bestCut(events[d], B[d], B[(d+1)%3], B[(d+2)%3]);
  }, 1);

  int cutDim = 0;
  for (int d = 1; d < 3; d++) 
    if (cuts[d].cost < cuts[cutDim].cost) cutDim = d;

  float cutOff = cuts[cutDim].cutOff;
  float area = boxSurfaceArea(B);
  float bestCost = CT + CL * cuts[cutDim].cost/area;
  float origCost = (float) (n/2);

  if (bestCost >= origCost || 
      cuts[cutDim].numLeft + cuts[cutDim].numRight > maxExpand * n/2) {
    auto indices = parlay::map(events[0], [](const event& e) { return GET_INDEX(e); });
    parlay::sort_inplace(indices);
    auto unique_indices = parlay::unique(indices);
    return treeNode::make_leaf(std::move(unique_indices), B, Tri);
  }

  BoundingBox BBL = B;
  BBL[cutDim].max = cutOff;
  Events leftEvents;

  BoundingBox BBR = B;
  BBR[cutDim].min = cutOff;
  Events rightEvents;

  parallel_for (0, 3, [&](size_t d) {
    eventsPair X = splitEvents(boxes, cutDim, events[d], cutOff);
    leftEvents[d] = std::move(X.first);
    rightEvents[d] = std::move(X.second);
  }, 1);

  events.fill(sequence<event>()); // Free memory
  treeNode *L, *R;
  par_do([&] () {L = generateNode(boxes, std::move(leftEvents), BBL, Tri, maxDepth-1);},
         [&] () {R = generateNode(boxes, std::move(rightEvents), BBR, Tri, maxDepth-1);});

  return treeNode::make_internal(L, R, cutDim, cutOff, B);
}

// =================================================================
//             FAST, STACK-BASED RAY TRAVERSAL
// =================================================================

size_t tcount = 0;
size_t ccount = 0;

index_t traceRay(const ray_t& r, treeNode* root, const BoundingBox& scene_box) {
  double t_min = 0.0, t_max = std::numeric_limits<double>::max();
  if (!rayBoxIntersect(r, scene_box, t_min, t_max)) {
    return -1;
  }

  index_t hit_idx = -1;
  double closest_t = t_max;

  std::stack<treeNode*> stack;
  stack.push(root);

  while (!stack.empty()) {
    treeNode* node = stack.top();
    stack.pop();

    double node_tmin = t_min, node_tmax = closest_t;
    if (!rayBoxIntersect(r, node->box, node_tmin, node_tmax)) {
      continue;
    }

    if (node->isLeaf()) {
      if (STATS) ccount++;
      auto& leaf = std::get<LeafNode>(node->node);
      if (STATS) tcount += leaf.tris.size();
      for (const auto& tri : leaf.tris) {
        double t = rayTriangleIntersect(r, tri);
        if (t > 0.0 && t < closest_t) {
          closest_t = t;
          hit_idx = tri.id;
        }
      }
      continue;
    }

    auto& internal = std::get<InternalNode>(node->node);
    int dim = internal.cutDim;
    double t_split = (internal.cutOff - r.o[dim]) / r.d[dim];

    treeNode *near_child, *far_child;
    if (r.d[dim] > 0) {
      near_child = internal.left;
      far_child = internal.right;
    } else {
      near_child = internal.right;
      far_child = internal.left;
    }

    if (t_split >= closest_t || t_split < 0) {
      stack.push(near_child);
    } else if (t_split <= t_min) {
      stack.push(far_child);
    } else {
      stack.push(far_child);
      stack.push(near_child);
    }
  }

  return hit_idx;
}

// =================================================================
//             BRUTE-FORCE CHECKING (for correctness)
// =================================================================

// Moller-Trumbore for original triangle format
inline coord rayTriangleIntersect_check(const ray_t& r, const point m[3]) {
  constexpr double EPS = 1e-8;
  const auto& v0 = m[0];
  const auto& v1 = m[1];
  const auto& v2 = m[2];

  auto e1 = v1 - v0;
  auto e2 = v2 - v0;
  auto pvec = r.d.cross(e2);
  double det = e1.dot(pvec);

  if (det > -EPS && det < EPS) return -1.0;

  double inv_det = 1.0 / det;
  auto tvec = r.o - v0;
  double u = tvec.dot(pvec) * inv_det;
  if (u < 0.0 || u > 1.0) return -1.0;

  auto qvec = tvec.cross(e1);
  double v = r.d.dot(qvec) * inv_det;
  if (v < 0.0 || u + v > 1.0) return -1.0;

  double t = e2.dot(qvec) * inv_det;
  return t;
}

inline float inBox(point p, BoundingBox B) {
  return (p.x >= (B[0].min - epsilon) && p.x <= (B[0].max + epsilon) &&
	  p.y >= (B[1].min - epsilon) && p.y <= (B[1].max + epsilon) &&
	  p.z >= (B[2].min - epsilon) && p.z <= (B[2].max + epsilon));
}

index_t findRay(ray_t r,
	       sequence<index_t> const &I, 
	       triangles<point> const &Tri,
	       BoundingBox B) {
  coord tMin = std::numeric_limits<double>::max();
  index_t k = -1;
  for (size_t i = 0; i < I.size(); i++) {
    index_t j = I[i];
    point m[3] = {Tri.P[Tri.T[j][0]],  Tri.P[Tri.T[j][1]],  Tri.P[Tri.T[j][2]]};
    coord t = rayTriangleIntersect_check(r, m);
    if (t > 0.0 && t < tMin && inBox(r.o + r.d*t, B)) {
      tMin = t;
      k = j;
    }
  }
  return k;
}

// =================================================================
//                     MAIN rayCast FUNCTION
// =================================================================

sequence<index_t> rayCast(triangles<point> const &Tri,
			  sequence<ray<point>> const &rays, bool verbose = false) {
  parlay::internal::timer t("ray cast", verbose);
  index_t numRays = rays.size();

  Boxes boxes;
  index_t n = Tri.T.size();
  for (int d = 0; d < 3; d++)
    boxes[d] = sequence<range>::uninitialized(n);

  parallel_for (0, n, [&](size_t i) {
    point p0 = Tri.P[Tri.T[i][0]];
    point p1 = Tri.P[Tri.T[i][1]];
    point p2 = Tri.P[Tri.T[i][2]];
    boxes[0][i] = fixRange(min({p0.x,p1.x,p2.x}), max({p0.x,p1.x,p2.x}));
    boxes[1][i] = fixRange(min({p0.y,p1.y,p2.y}), max({p0.y,p1.y,p2.y}));
    boxes[2][i] = fixRange(min({p0.z,p1.z,p2.z}), max({p0.z,p1.z,p2.z}));
  });

  Events events;
  BoundingBox boundingBox;
  parallel_for(0, 3, [&](int d) {
    events[d] = tabulate(2*n, [&](size_t i) -> event {
      return ((i % 2 == 0) ?
	      event(boxes[d][i/2].min, i/2, START) :
	      event(boxes[d][i/2].max, i/2, END));});
    sort_inplace(events[d], [](event a, event b) {return a.v < b.v;}); 
    if (2*n > 0)
      boundingBox[d] = range(events[d][0].v, events[d][2*n-1].v);
    else
      boundingBox[d] = range(0,0);
  });
  t.next("generate and sort events");

  size_t recursionDepth = min<size_t>(maxRecursionDepth, (n > 1) ? parlay::log2_up(n)-1 : 1);
  treeNode* R = generateNode(boxes, std::move(events), boundingBox, Tri, recursionDepth);
  t.next("build tree");

  if (STATS) {
      std::function<std::pair<size_t, size_t>(treeNode*)> get_stats = 
          [&](treeNode* node) -> std::pair<size_t, size_t> {
          if (node->isLeaf()) {
              return {std::get<LeafNode>(node->node).tris.size(), 1};
          }
          auto [l_tris, l_leaves] = get_stats(std::get<InternalNode>(node->node).left);
          auto [r_tris, r_leaves] = get_stats(std::get<InternalNode>(node->node).right);
          return {l_tris + r_tris, l_leaves + r_leaves};
      };
      auto [total_tris, total_leaves] = get_stats(R);
      cout << "Triangles across all leaves = " << total_tris 
           << " Leaves = " << total_leaves << endl;
  }

  tcount = 0;
  ccount = 0;

  auto results = tabulate(numRays, [&](size_t i) -> index_t {
    return traceRay(rays[i], R, boundingBox);
  });
  t.next("intersect rays");

  treeNode::delete_tree(R);
  t.next("delete tree");

  if (STATS)
    cout << "tcount=" << tcount << " ccount=" << ccount << " (avg tri/leaf=" << (double)tcount/ccount << ")" << endl;

  if (CHECK) {
    int nr = min((int)numRays, 10);
    auto indx = tabulate(n, [&](size_t i) -> index_t {return i;});
    for (int i= 0; i < nr; i++) {
      index_t expected = findRay(rays[i], indx, Tri, boundingBox);
      if (expected != results[i]) {
	cout << "bad intersect in checking ray " << i << ". Expected: " << expected << ", Got: " << results[i] << endl;
	abort();
      }
    }
    cout << "Checked " << nr << " rays successfully." << endl;
    t.next("check");
  }

  return results;
}

