#pragma once

using coord = double;
using point = point3d<double>;
using index_t = int;
using triangs = triangles<point>;

enum event_type {START, END};
struct event {
  float v;
  int i; // triangle index
  event_type type;
  event(float v, int i, event_type type) : v(v), i(i), type(type) {}
  event() = default;
};

#define IS_START(e) (e.type == START)
#define IS_END(e) (e.type == END)
#define GET_INDEX(e) (e.i)

struct range {
  float min, max;
  range(float min, float max) : min(min), max(max) {}
  range() : min(0.0), max(0.0) {}
};

using Boxes = std::array<parlay::sequence<range>, 3>;
using Events = std::array<parlay::sequence<event>, 3>;
using BoundingBox = std::array<range, 3>;

struct treeNode {
  BoundingBox box;
  bool leaf;
  union {
    struct { treeNode *left, *right; int cutDim; float cutOff; };
    struct { parlay::sequence<index_t> triangleIndices; };
  };
  size_t n;
  size_t leaves;

  treeNode() {}
  ~treeNode() {
    if (leaf) {
      triangleIndices.~sequence<index_t>();
    }
  }

  bool isLeaf() { return leaf; }

  // Deletion is handled by the memory pool.
  // We need to call destructors manually if we used placement new on non-trivial types.
  static void delete_tree(treeNode* T) {
    if (!T) return;
    if (!T->isLeaf()) {
      delete_tree(T->left);
      delete_tree(T->right);
    }
    T->~treeNode(); // Call destructor to destruct the sequence in leaf nodes
  }
};
// --- End of kdTree.h ---

