int CHECK = 0;
int STATS = 0;

// Tuned constants for SAH KD-Tree construction and parallelism
constexpr float CT = 6.0; // Cost of traversing an internal node
constexpr float CL = 1.25; // Cost of intersecting a triangle
constexpr float maxExpand = 1.6; // Max allowed imbalance in triangle counts
constexpr int maxRecursionDepth = 32; // Max depth of the tree
constexpr size_t LEAF_THRESHOLD = 32; // Max triangles in a leaf node
constexpr int minParallelSize = 4096; // Threshold for parallel algorithms

// Type aliases for clarity
using vect = typename point::vector;
using triangs = triangles<point>;
using ray_t = ray<point>;

// KD-Tree supporting data structures
struct range {
  coord min, max;
  range(coord min, coord max) : min(min), max(max) {}
  range() : min(0), max(0) {}
};

using BoundingBox = std::array<range, 3>;
using Boxes = std::array<sequence<range>, 3>;

enum eventType {START, END};
#define GET_INDEX(E) ((E).index)
#define IS_START(E) ((E).type == START)
#define IS_END(E) ((E).type == END)

struct event {
  float v;
  index_t index;
  char type;
  event(float v, index_t index, eventType type) : v(v), index(index), type((char)type) {}
  event() {}
};

using Events = std::array<sequence<event>, 3>;

struct cutInfo {
  float cost, cutOff;
  index_t numLeft, numRight;
  cutInfo(float cost, float cutOff, index_t numLeft, index_t numRight) :
    cost(cost), cutOff(cutOff), numLeft(numLeft), numRight(numRight) {}
};

struct treeNode {
  BoundingBox box;
  bool leaf;
  size_t n; // total triangles in subtree (for stats)
  size_t leaves; // total leaves in subtree (for stats)

  union {
    struct {
      std::unique_ptr<treeNode> left, right;
      int cutDim;
      float cutOff;
    };
    struct {
      parlay::sequence<index_t> triangleIndices;
      size_t num_tris;
    };
  };

  ~treeNode() {
    if (leaf) {
      triangleIndices.~sequence<index_t>();
    } else {
      left.reset();
      right.reset();
    }
  }

  bool isLeaf() const { return leaf; }

  static treeNode* newNode(parlay::sequence<index_t> &&indices, const BoundingBox& B) {
    auto node = new treeNode;
    node->leaf = true;
    new (&node->triangleIndices) parlay::sequence<index_t>(std::move(indices));
    node->num_tris = node->triangleIndices.size();
    node->box = B;
    node->n = node->num_tris;
    node->leaves = 1;
    return node;
  }

  static treeNode* newNode(treeNode* L, treeNode* R, int dim, float off, const BoundingBox& B) {
    auto node = new treeNode;
    node->leaf = false;
    node->left.reset(L);
    node->right.reset(R);
    node->cutDim = dim;
    node->cutOff = off;
    node->box = B;
    node->n = (L ? L->n : 0) + (R ? R->n : 0);
    node->leaves = (L ? L->leaves : 0) + (R ? R->leaves : 0);
    return node;
  }
};

using eventsPair = pair<sequence<event>, sequence<event>>;

namespace parlay {
  template <typename Seq, typename BSeq1, typename BSeq2>
  auto two_pack(Seq const &S, BSeq1 const &Fl1, BSeq2 const &Fl2) {
    using T = typename Seq::value_type;
    size_t n = S.size();
    auto twoAdd = pair_monoid(addm<size_t>(), addm<size_t>());
    auto twoFlags = delayed::tabulate(n, [&](size_t i) {
      return pair<size_t, size_t>((bool)Fl1[i], (bool)Fl2[i]);
    });
    auto [offsets, totals] = delayed::scan(twoFlags, twoAdd);
    auto result1 = sequence<T>::uninitialized(totals.first);
    auto result2 = sequence<T>::uninitialized(totals.second);
    parallel_for(0, n, [&](size_t i) {
      if (Fl1[i]) result1[offsets[i].first] = S[i];
      if (Fl2[i]) result2[offsets[i].second] = S[i];
    });
    return std::pair(std::move(result1), std::move(result2));
  }
}

float boxSurfaceArea(const BoundingBox& B) {
  float r0 = B[0].max - B[0].min;
  float r1 = B[1].max - B[1].min;
  float r2 = B[2].max - B[2].min;
  return 2.0f * (r0 * r1 + r1 * r2 + r0 * r2);
}

range fixRange(float minv, float maxv) {
  constexpr float epsilon = 1e-6f;
  if (minv == maxv) return range(minv, minv + epsilon);
  else return range(minv, maxv);
}

cutInfo bestCutSerial(const sequence<event>& E, const range& r, const range& r1, const range& r2) {
  double flt_max = std::numeric_limits<double>::max();
  index_t n = E.size();
  if (r.max - r.min == 0.0) return cutInfo(flt_max, r.min, n, n);
  float area = 2.0f * (r1.max - r1.min) * (r2.max - r2.min);
  float orthoPerimeter = 2.0f * ((r1.max - r1.min) + (r2.max - r2.min));

  index_t inLeft = 0;
  index_t inRight = n / 2;
  float minCost = flt_max;
  index_t k = 0;
  for (index_t i = 0; i < n; i++) {
    if (IS_END(E[i])) inRight--;
    float leftLength = E[i].v - r.min;
    float leftSurfaceArea = area + orthoPerimeter * leftLength;
    float rightLength = r.max - E[i].v;
    float rightSurfaceArea = area + orthoPerimeter * rightLength;
    float cost = (leftSurfaceArea * inLeft + rightSurfaceArea * inRight);
    if (cost < minCost) {
      minCost = cost;
      k = i;
    }
    if (IS_START(E[i])) inLeft++;
  }

  inLeft = 0; inRight = n / 2;
  for (index_t i = 0; i < k; i++) {
    if (IS_END(E[i])) inRight--;
    if (IS_START(E[i])) inLeft++;
  }
  if (IS_END(E[k])) inRight--;

  return cutInfo(minCost, E[k].v, inLeft, inRight);
}

cutInfo bestCut(const sequence<event>& E, const range& r, const range& r1, const range& r2) {
  index_t n = E.size();
  if (n < minParallelSize)
    return bestCutSerial(E, r, r1, r2);
  double flt_max = std::numeric_limits<double>::max();
  if (r.max - r.min == 0.0) return cutInfo(flt_max, r.min, n, n);

  float orthogArea = 2.0f * ((r1.max - r1.min) * (r2.max - r2.min));
  float orthoPerimeter = 2.0f * ((r1.max - r1.min) + (r2.max - r2.min));

  auto is_end = delayed::tabulate(n, [&](index_t i) -> index_t { return IS_END(E[i]); });
  auto end_counts = delayed::scan_inclusive(is_end);

  using rtype = std::tuple<float, index_t, index_t>;
  auto cost_f = [&](std::tuple<index_t, index_t> ni) -> rtype {
    auto [num_ends, i] = ni;
    index_t num_ends_before = num_ends - IS_END(E[i]);
    index_t inLeft = i - num_ends_before;
    index_t inRight = n / 2 - num_ends;
    float leftLength = E[i].v - r.min;
    float leftSurfaceArea = orthogArea + orthoPerimeter * leftLength;
    float rightLength = r.max - E[i].v;
    float rightSurfaceArea = orthogArea + orthoPerimeter * rightLength;
    float cost = leftSurfaceArea * inLeft + rightSurfaceArea * inRight;
    return rtype(cost, num_ends_before, i);
  };
  auto costs = delayed::map(delayed::zip(end_counts, iota<index_t>(n)), cost_f);

  auto min_f = [&](rtype a, rtype b) { return (std::get<0>(a) < std::get<0>(b)) ? a : b; };
  rtype identity(std::numeric_limits<float>::max(), 0, 0);
  auto [cost, num_ends_before, i] = delayed::reduce(costs, make_monoid(min_f, identity));

  index_t ln = i - num_ends_before;
  index_t rn = n / 2 - (num_ends_before + IS_END(E[i]));
  return cutInfo(cost, E[i].v, ln, rn);
}

eventsPair splitEvents(const sequence<range>& boxes, const sequence<event>& events, float cutOff) {
  index_t n = events.size();
  auto lower = sequence<bool>::uninitialized(n);
  auto upper = sequence<bool>::uninitialized(n);

  parallel_for(0, n, [&](index_t i) {
    index_t b = GET_INDEX(events[i]);
    lower[i] = boxes[b].min < cutOff;
    upper[i] = boxes[b].max > cutOff;
  }, minParallelSize);

  return parlay::two_pack(events, lower, upper);
}

treeNode* generateNode(Boxes& boxes, Events&& events, BoundingBox B, size_t maxDepth) {
  index_t n = events[0].size();
  if (n / 2 <= LEAF_THRESHOLD || maxDepth == 0) {
    auto indices = delayed::map(events[0], [](const event& e) { return GET_INDEX(e); });
    auto sorted_indices = parlay::sort(indices);
    auto unique_indices = parlay::unique(sorted_indices);
    return treeNode::newNode(std::move(unique_indices), B);
  }

  cutInfo cuts[3];
  parallel_for(0, 3, [&](size_t d) {
    cuts[d] = bestCut(events[d], B[d], B[(d + 1) % 3], B[(d + 2) % 3]);
  });

  int cutDim = 0;
  for (int d = 1; d < 3; d++)
    if (cuts[d].cost < cuts[cutDim].cost) cutDim = d;

  float area = boxSurfaceArea(B);
  float bestCost = CT + CL * cuts[cutDim].cost / area;
  float origCost = (float)(n / 2);

  if (bestCost >= origCost || cuts[cutDim].numLeft + cuts[cutDim].numRight > maxExpand * n / 2) {
    auto indices = delayed::map(events[0], [](const event& e) { return GET_INDEX(e); });
    auto sorted_indices = parlay::sort(indices);
    auto unique_indices = parlay::unique(sorted_indices);
    return treeNode::newNode(std::move(unique_indices), B);
  }

  float cutOff = cuts[cutDim].cutOff;
  BoundingBox BBL = B, BBR = B;
  BBL[cutDim].max = cutOff;
  BBR[cutDim].min = cutOff;

  array<sequence<event>, 3> leftEvents, rightEvents;
  parallel_for(0, 3, [&](size_t d) {
    eventsPair X = splitEvents(boxes[d], events[d], cutOff);
    leftEvents[d] = std::move(X.first);
    rightEvents[d] = std::move(X.second);
  });

  events[0].clear(); events[1].clear(); events[2].clear();

  treeNode *L, *R;
  par_do([&] { L = generateNode(boxes, std::move(leftEvents), BBL, maxDepth - 1); },
         [&] { R = generateNode(boxes, std::move(rightEvents), BBR, maxDepth - 1); });

  return treeNode::newNode(L, R, cutDim, cutOff, B);
}

size_t tcount = 0;
size_t ccount = 0;

inline pair<coord, coord> ray_AABB_intersect(const ray_t& r, const BoundingBox& B) {
  coord t_min = -numeric_limits<double>::max();
  coord t_max = numeric_limits<double>::max();
  for (int i = 0; i < 3; ++i) {
    coord inv_d = 1.0 / r.d[i];
    coord t1 = (B[i].min - r.o[i]) * inv_d;
    coord t2 = (B[i].max - r.o[i]) * inv_d;
    if (inv_d < 0.0) std::swap(t1, t2);
    t_min = std::max(t_min, t1);
    t_max = std::min(t_max, t2);
    if (t_min > t_max) return {1.0, 0.0};
  }
  return {t_min, t_max};
}

void findRay_leaf(const ray_t& r, treeNode* TN, const triangs& Tri, coord& t_hit, index_t& hit_idx) {
  if (STATS) { tcount += TN->num_tris; ccount += 1; }
  for (index_t j : TN->triangleIndices) {
    point m[3] = {Tri.P[Tri.T[j][0]], Tri.P[Tri.T[j][1]], Tri.P[Tri.T[j][2]]};
    coord t = rayTriangleIntersect(r, m);
    if (t > 1e-9 && t < t_hit) {
      t_hit = t;
      hit_idx = j;
    }
  }
}

index_t findRay(const ray_t& r, treeNode* root, const triangs& Tri) {
  coord t_hit = numeric_limits<double>::max();
  index_t hit_idx = -1;

  auto [ray_tmin, ray_tmax] = ray_AABB_intersect(r, root->box);
  if (ray_tmin > ray_tmax || ray_tmax < 1e-9) return -1;

  std::array<std::tuple<treeNode*, coord, coord>, maxRecursionDepth + 5> stack;
  int stack_ptr = 0;
  stack[stack_ptr++] = {root, std::max(0.0, ray_tmin), ray_tmax};

  while (stack_ptr > 0) {
    auto [node, t_min, t_max] = stack[--stack_ptr];

    if (t_hit < t_min) continue;

    if (node->isLeaf()) {
      findRay_leaf(r, node, Tri, t_hit, hit_idx);
      continue;
    }

    int axis = node->cutDim;
    coord inv_d = 1.0 / r.d[axis];
    coord t_split = (node->cutOff - r.o[axis]) * inv_d;

    treeNode *near_child, *far_child;
    if (r.d[axis] < 0) {
      near_child = node->right.get();
      far_child = node->left.get();
    } else {
      near_child = node->left.get();
      far_child = node->right.get();
    }

    if (t_split > t_max || t_split < 0) {
      if (near_child) stack[stack_ptr++] = {near_child, t_min, t_max};
    } else if (t_split < t_min) {
      if (far_child) stack[stack_ptr++] = {far_child, t_min, t_max};
    } else {
      if (far_child) stack[stack_ptr++] = {far_child, t_split, t_max};
      if (near_child) stack[stack_ptr++] = {near_child, t_min, t_split};
    }
  }
  return hit_idx;
}

index_t findRay_bruteforce(const ray_t& r, const parlay::sequence<index_t>& I, const triangs& Tri, const BoundingBox& B) {
  coord tMin = std::numeric_limits<double>::max();
  index_t k = -1;
  for (index_t j : I) {
    point m[3] = {Tri.P[Tri.T[j][0]], Tri.P[Tri.T[j][1]], Tri.P[Tri.T[j][2]]};
    coord t = rayTriangleIntersect(r, m);
    if (t > 1e-9 && t < tMin) {
      point p = r.o + r.d * t;
      if (p.x >= (B[0].min - 1e-6) && p.x <= (B[0].max + 1e-6) &&
          p.y >= (B[1].min - 1e-6) && p.y <= (B[1].max + 1e-6) &&
          p.z >= (B[2].min - 1e-6) && p.z <= (B[2].max + 1e-6)) {
        tMin = t;
        k = j;
      }
    }
  }
  return k;
}

sequence<index_t> rayCast(triangles<point> const &Tri,
			  sequence<ray<point>> const &rays, bool verbose = false) {
  parlay::internal::timer t("ray cast", verbose);
  index_t n = Tri.T.size();

  Boxes boxes;
  for (int d = 0; d < 3; d++) boxes[d] = sequence<range>::uninitialized(n);
  parallel_for(0, n, [&](size_t i) {
    point p0 = Tri.P[Tri.T[i][0]], p1 = Tri.P[Tri.T[i][1]], p2 = Tri.P[Tri.T[i][2]];
    boxes[0][i] = fixRange(min({p0.x,p1.x,p2.x}), max({p0.x,p1.x,p2.x}));
    boxes[1][i] = fixRange(min({p0.y,p1.y,p2.y}), max({p0.y,p1.y,p2.y}));
    boxes[2][i] = fixRange(min({p0.z,p1.z,p2.z}), max({p0.z,p1.z,p2.z}));
  });
  t.next("generate boxes");

  Events events;
  BoundingBox boundingBox;
  parallel_for(0, 3, [&](int d) {
    events[d] = tabulate(2 * n, [&](size_t i) -> event {
      return ((i & 1) == 0) ? event(boxes[d][i / 2].min, i / 2, START)
                            : event(boxes[d][i / 2].max, i / 2, END);
    });
    sort_inplace(events[d], [](event a, event b) { return a.v < b.v; });
    boundingBox[d] = range(events[d][0].v, events[d][2 * n - 1].v);
  });
  t.next("generate and sort events");

  size_t recursionDepth = min<size_t>(maxRecursionDepth, parlay::log2_up(n));
  unique_ptr<treeNode> R(generateNode(boxes, std::move(events), boundingBox, recursionDepth));
  t.next("build tree");

  if (STATS) cout << "Triangles across all leaves = " << R->n << " Leaves = " << R->leaves << endl;
  tcount = 0; ccount = 0;

  auto results = tabulate(rays.size(), [&](size_t i) { return findRay(rays[i], R.get(), Tri); });
  t.next("intersect rays");

  if (STATS) cout << "tcount=" << tcount << " ccount=" << ccount << endl;

  if (CHECK) {
    auto indx = iota<index_t>(n);
    parallel_for(0, min((size_t)10, rays.size()), [&](size_t i) {
      if (findRay_bruteforce(rays[i], indx, Tri, boundingBox) != results[i]) {
        cout << "bad intersect in checking ray intersection" << endl;
        abort();
      }
    });
    t.next("check");
  }

  return results;
}

#include <limits>
#include <algorithm>
#include <tuple>
#include "parlay/primitives.h"
#include "parlay/delayed.h"
#include "parlay/internal/get_time.h"
#include "common/geometry.h"
#include "ray.h"
#include "kdTree.h"
#include "rayTriangleIntersect.h"
using namespace std;

namespace delayed = parlay::delayed;
using parlay::tabulate;
using parlay::parallel_for;
using parlay::scan_inplace;
using parlay::sequence;
using parlay::par_do;
using parlay::pack;
using parlay::sort_inplace;
using parlay::to_sequence;

int CHECK = 0;  // if set checks 10 rays against brute force method
int STATS = 0;  // if set prints out some tree statistics

// Constants for deciding when to stop recursion in building the KDTree
float CT = 6.0;
float CL = 1.25;
float maxExpand = 1.6;
int maxRecursionDepth = 25;

// Constant for switching to sequential versions
int minParallelSize = 1000;

using vect = typename point::vector;
using triangs = triangles<point>;
using ray_t = ray<point>;

float boxSurfaceArea(BoundingBox B) {
  float r0 = B[0].max-B[0].min;
  float r1 = B[1].max-B[1].min;
  float r2 = B[2].max-B[2].min;
  return 2*(r0*r1 + r1*r2 + r0*r2);
}

float epsilon = .0000001;
range fixRange(float minv, float maxv) {
  if (minv == maxv) return range(minv,minv+epsilon);
  else return range(minv,maxv);
}

// Returns the interval [t_min, t_max] for the intersection of a ray with an AABB.
// If the ray misses, t_min will be >= t_max.
std::pair<coord, coord> intersect_ray_box(ray_t r, BoundingBox B) {
    coord t_min = 0.0;
    coord t_max = std::numeric_limits<coord>::max();

    for (int i = 0; i < 3; ++i) {
        if (std::abs(r.d[i]) < epsilon) {
            // Ray is parallel to the slab.
            // If origin is not inside the slab, then no intersection.
            if (r.o[i] < B[i].min || r.o[i] > B[i].max) {
                return {1.0, 0.0}; // No intersection
            }
        } else {
            coord inv_d = 1.0 / r.d[i];
            coord t1 = (B[i].min - r.o[i]) * inv_d;
            coord t2 = (B[i].max - r.o[i]) * inv_d;
            if (t1 > t2) std::swap(t1, t2);
            t_min = std::max(t_min, t1);
            t_max = std::min(t_max, t2);
            if (t_min > t_max) { // Use > instead of >= to handle grazing hits
                return {1.0, 0.0}; // No intersection
            }
        }
    }
    return {t_min, t_max};
}


// sequential version of best cut
cutInfo bestCutSerial(sequence<event> const &E, range r, range r1, range r2) {
  double flt_max = std::numeric_limits<double>::max();
  index_t n = E.size();
  if (r.max - r.min == 0.0) return cutInfo(flt_max, r.min, n, n);
  float area = 2 * (r1.max-r1.min) * (r2.max-r2.min);
  float orthoPerimeter = 2 * ((r1.max-r1.min) + (r2.max-r2.min));

  // calculate cost of each possible split
  index_t inLeft = 0;
  index_t inRight = n/2;
  float minCost = flt_max;
  index_t k = 0;
  index_t rn = inLeft;
  index_t ln = inRight;
  for (index_t i=0; i <n; i++) {
    if (IS_END(E[i])) inRight--;
    float leftLength = E[i].v - r.min;
    float leftSurfaceArea = area + orthoPerimeter * leftLength;
    float rightLength = r.max - E[i].v;
    float rightSurfaceArea = area + orthoPerimeter * rightLength;
    float cost = (leftSurfaceArea * inLeft + rightSurfaceArea * inRight);
    if (cost < minCost) {
      rn = inRight;
      ln = inLeft;
      minCost = cost;
      k = i;
    }
    if (IS_START(E[i])) inLeft++;
  }
  return cutInfo(minCost, E[k].v, ln, rn);
}

// parallel version of best cut
cutInfo bestCut(sequence<event> const &E, range r, range r1, range r2) {
  index_t n = E.size();
  if (n < minParallelSize)
    return bestCutSerial(E, r, r1, r2);
  double flt_max = std::numeric_limits<double>::max();
  if (r.max - r.min == 0.0) return cutInfo(flt_max, r.min, n, n);

  // area of two orthogonal faces
  float orthogArea = 2 * ((r1.max-r1.min) * (r2.max-r2.min));

  // length of the perimeter of the orthogonal faces
  float orthoPerimeter = 2 * ((r1.max-r1.min) + (r2.max-r2.min));

  // count number that end before i
  auto is_end = delayed::tabulate(n, [&] (index_t i) -> index_t {return IS_END(E[i]);});
  auto end_counts = delayed::scan_inclusive(is_end);

  // calculate cost of each possible split location,
  // return tuple with cost, number of ends before the location, and the index
  using rtype = std::tuple<float,index_t,index_t>;
  auto cost_f = [&] (std::tuple<index_t,index_t> ni) -> rtype {
    auto [ num_ends, i] = ni;
    index_t num_ends_before = num_ends - IS_END(E[i]);
    index_t inLeft = i - num_ends_before; // number of points intersecting left
    index_t inRight = n/2 - num_ends;   // number of points intersecting right
    float leftLength = E[i].v - r.min;
    float leftSurfaceArea = orthogArea + orthoPerimeter * leftLength;
    float rightLength = r.max - E[i].v;
    float rightSurfaceArea = orthogArea + orthoPerimeter * rightLength;
    float cost = leftSurfaceArea * inLeft + rightSurfaceArea * inRight;
    return rtype(cost, num_ends_before, i);};
  auto costs = delayed::map(delayed::zip(end_counts, parlay::iota<index_t>(n)), cost_f);

  // find minimum across all, returning the triple
  auto min_f = [&] (rtype a, rtype b) {return (std::get<0>(a) < std::get<0>(b)) ? a : b;};
  rtype identity(std::numeric_limits<float>::max(), 0, 0);
  auto [cost, num_ends_before, i] =
    delayed::reduce(costs, parlay::make_monoid(min_f, identity));

  index_t ln = i - num_ends_before;
  index_t rn = n/2 - (num_ends_before + IS_END(E[i]));
  return cutInfo(cost, E[i].v, ln, rn);
}

using eventsPair = pair<sequence<event>, sequence<event>>;

namespace parlay {
  template <typename Seq, typename BSeq1, typename BSeq2>
auto two_pack(Seq const &S, BSeq1 const &Fl1, BSeq2 const &Fl2) {
    using T = typename Seq::value_type;
  size_t n = S.size();
  auto twoAdd = pair_monoid(addm<size_t>(),addm<size_t>());
  auto twoFlags = delayed::tabulate(n, [&] (size_t i) {
       return pair<size_t,size_t>((bool) Fl1[i], (bool) Fl2[i]);});
  auto [offsets, totals] = delayed::scan(twoFlags, twoAdd);
  auto result1 = sequence<T>::uninitialized(totals.first);
  auto result2 = sequence<T>::uninitialized(totals.second);
  auto f = [&] (auto offset, auto i) -> void {
  	     if (Fl1[i]) result1[offset.first] = S[i];
  	     if (Fl2[i]) result2[offset.second] = S[i];};
  delayed::for_each(delayed::zip(offsets, iota(n)), f);
  return std::pair(std::move(result1), std::move(result2));
}
}

eventsPair splitEvents(sequence<range> const &boxes,
		       sequence<event> const &events,
		       float cutOff) {
  index_t n = events.size();

  // Using delayed sequences for flags can be more efficient as it avoids allocation
  auto lower = parlay::delayed::tabulate(n, [&](size_t i) {
    return boxes[GET_INDEX(events[i])].min < cutOff;
  });
  auto upper = parlay::delayed::tabulate(n, [&](size_t i) {
    return boxes[GET_INDEX(events[i])].max > cutOff;
  });

  return parlay::two_pack(events, lower, upper);
}

// n is the number of events (i.e. twice the number of triangles)
treeNode* generateNode(Boxes &boxes,
		       Events events,
		       BoundingBox B,
		       size_t maxDepth) {
  parlay::internal::timer t;
  index_t n = events[0].size();
  if (n <= 2 || maxDepth == 0)
    return treeNode::newNode(std::move(events), n, B);

  // loop over dimensions and find the best cut across all of them
  cutInfo cuts[3];
  parallel_for(0, 3, [&] (size_t d) {
    cuts[d] = bestCut(events[d], B[d], B[(d+1)%3], B[(d+2)%3]);
		     }, 10000/n + 1);

  int cutDim = 0;
  for (int d = 1; d < 3; d++)
    if (cuts[d].cost < cuts[cutDim].cost) cutDim = d;

  float cutOff = cuts[cutDim].cutOff;
  float area = boxSurfaceArea(B);
  float bestCost = CT + CL * cuts[cutDim].cost/area;
  float origCost = (float) (n/2);

  // quit recursion early if best cut is not very good
  if (bestCost >= origCost ||
      cuts[cutDim].numLeft + cuts[cutDim].numRight > maxExpand * n/2)
    return treeNode::newNode(std::move(events), n, B);

  // declare structures for recursive calls
  BoundingBox BBL;
  for (int i=0; i < 3; i++) BBL[i] = B[i];
  BBL[cutDim] = range(BBL[cutDim].min, cutOff);
  array<sequence<event>,3> leftEvents;

  BoundingBox BBR;
  for (int i=0; i < 3; i++) BBR[i] = B[i];
  BBR[cutDim] = range(cutOff, BBR[cutDim].max);
  array<sequence<event>,3> rightEvents;

  // now split each event array to the two sides
  parallel_for (0, 3, [&] (size_t d) {
    eventsPair X = splitEvents(boxes[d], events[d], cutOff);
    leftEvents[d] = std::move(X.first);
    rightEvents[d] = std::move(X.second);
  }, 10000/n + 1);

  // check cuts are the same size
  index_t nl = leftEvents[0].size();
  index_t nr = rightEvents[0].size();
  for (int d = 1; d < 3; d++) {
    if (leftEvents[d].size() != nl || rightEvents[d].size() != nr) {
      cout << "kdTree: mismatched lengths, something wrong" << endl;
      abort();
    }
  }

  // free (i.e. clear) old events and make recursive calls
  for (int i=0; i < 3; i++) events[i] = sequence<event>();
  treeNode *L;
  treeNode *R;
  par_do([&] () {L = generateNode(boxes, std::move(leftEvents),
				  BBL, maxDepth-1);},
         [&] () {R = generateNode(boxes, std::move(rightEvents),
				  BBR, maxDepth-1);});

  return treeNode::newNode(L, R, cutDim, cutOff, B);
}

size_t tcount = 0;
size_t ccount = 0;

// Given an a ray, a bounding box, and a sequence of triangles, returns the
// index of the first triangle the ray intersects inside the box.
// The triangles are given by n indices I into the triangle array Tri.
// -1 is returned if there is no intersection
index_t findRay(ray_t r,
	       sequence<index_t> const &I,
	       triangles<point> const &Tri,
	       BoundingBox B) {
  if (STATS) { tcount += I.size(); ccount += 1;}

  // Intersect ray with the leaf's bounding box to get a valid t-range
  auto [t_box_min, t_box_max] = intersect_ray_box(r, B);

  // If ray doesn't hit box, or hits entirely behind the origin, no intersection
  if (t_box_min >= t_box_max || t_box_max <= 0.0) {
      return -1;
  }

  coord tMin = t_box_max; // Only search for intersections up to t_box_max
  index_t k = -1;

  for (index_t j : I) {
    point m[3] = {Tri.P[Tri.T[j][0]],  Tri.P[Tri.T[j][1]],  Tri.P[Tri.T[j][2]]};
    coord t = rayTriangleIntersect(r, m);
    // Intersection must be within the ray's segment inside the box.
    // t_box_min is the earliest valid t, so t > t_box_min is sufficient.
    if (t > t_box_min && t < tMin) {
      tMin = t;
      k = j;
    }
  }
  return k;
}

// Given a ray and a tree node find the index of the first triangle the
// ray intersects inside the box represented by that node.
// -1 is returned if there is no intersection
index_t findRay(ray_t r, treeNode* TN, triangs const &Tri) {
  if (TN->isLeaf())
    return findRay(r, TN->triangleIndices, Tri, TN->box);

  int k = TN->cutDim;
  coord o_k = r.o[k];
  coord d_k = r.d[k];

  // Handle ray parallel to splitting plane
  if (std::abs(d_k) < epsilon) {
      if (o_k < TN->cutOff || (o_k == TN->cutOff && d_k <= 0))
          return findRay(r, TN->left, Tri);
      else
          return findRay(r, TN->right, Tri);
  }

  treeNode *near_child, *far_child;
  if (d_k > 0) {
      near_child = TN->left;
      far_child = TN->right;
  } else {
      near_child = TN->right;
      far_child = TN->left;
  }

  coord t_split = (TN->cutOff - o_k) / d_k;

  // If ray starts in the far child, or split plane is behind, only check far child
  if (t_split <= 0) {
      return findRay(r, far_child, Tri);
  }

  // Otherwise, check near child first
  index_t hit_idx = findRay(r, near_child, Tri);

  // If a valid intersection is found in the near child, we are done.
  // The leaf-level check ensures the intersection point is within the child's box,
  // so it must be the first hit.
  if (hit_idx != -1) {
      return hit_idx;
  }

  // No hit in near child. Check if ray crosses into far child's volume.
  // The ray must hit the splitting plane within the node's bounds to proceed.
  point p_i = r.o + r.d * t_split;
  int k1 = (k + 1) % 3;
  int k2 = (k + 2) % 3;
  if (p_i[k1] >= TN->box[k1].min - epsilon && p_i[k1] <= TN->box[k1].max + epsilon &&
      p_i[k2] >= TN->box[k2].min - epsilon && p_i[k2] <= TN->box[k2].max + epsilon) {
      return findRay(r, far_child, Tri);
  }

  return -1; // No hit
}

sequence<index_t> rayCast(triangles<point> const &Tri,
			  sequence<ray<point>> const &rays, bool verbose = false) {
  parlay::internal::timer t("ray cast", verbose);
  index_t numRays = rays.size();

  // Extract triangles into a separate array for each dimension with
  // the lower and upper bound for each triangle in that dimension.
  Boxes boxes;
  index_t n = Tri.T.size();
  for (int d = 0; d < 3; d++)
    boxes[d] = sequence<range>::uninitialized(n);

  parallel_for (0, n, [&] (size_t i) {
    point p0 = Tri.P[Tri.T[i][0]];
    point p1 = Tri.P[Tri.T[i][1]];
    point p2 = Tri.P[Tri.T[i][2]];
    boxes[0][i] = fixRange(min({p0.x,p1.x,p2.x}),max({p0.x,p1.x,p2.x}));
    boxes[1][i] = fixRange(min({p0.y,p1.y,p2.y}),max({p0.y,p1.y,p2.y}));
    boxes[2][i] = fixRange(min({p0.z,p1.z,p2.z}),max({p0.z,p1.z,p2.z}));
  }, (n > 1000) ? 0 : n);

  // Loop over the dimensions creating an array of events for each
  // dimension, sorting each one, and extracting the bounding box
  // from the first and last elements in the sorted events in each dim.
  Events events;
  BoundingBox boundingBox;
  for (int d = 0; d < 3; d++) {
    events[d] = tabulate(2*n, [&] (size_t i) -> event {
      return ((i % 2 == 0) ?
	      event(boxes[d][i/2].min, i/2, START) :
	      event(boxes[d][i/2].max, i/2, END));});
    sort_inplace(events[d], [] (event a, event b) {return a.v < b.v;});
    boundingBox[d] = range(events[d][0].v, events[d][2*n-1].v);
  }
  t.next("generate and sort events");

  // build the tree
  size_t recursionDepth = min<size_t>(maxRecursionDepth, parlay::log2_up(n)-1);
  treeNode* R = generateNode(boxes, std::move(events), boundingBox, recursionDepth);
  t.next("build tree");

  if (STATS)
    cout << "Triangles across all leaves = " << R->n
	 << " Leaves = " << R->leaves << endl;

  tcount = 0;
  ccount = 0;

  // get the intersections
  auto results = tabulate(numRays, [&] (size_t i) -> index_t {
			       return  findRay(rays[i], R, Tri);});
  t.next("intersect rays");

  treeNode::delete_tree(R);
  t.next("delete tree");

  if (STATS)
    cout << "tcount=" << tcount << " ccount=" << ccount << endl;

  if (CHECK) {
    int nr = min((int)numRays, 10);
    auto indx = tabulate(n, [&] (size_t i) -> index_t {return i;});
    parallel_for(0, nr, [&](size_t i) {
        if (findRay(rays[i], indx, Tri, boundingBox) != results[i]) {
            cout << "bad intersect in checking ray intersection for ray " << i << endl;
            // abort() is not thread-safe, so we just print and continue
        }
    });
    t.next("check");
  }

  return results;
}

