// serialQuickHull is a serial implementation of the recursive step of QuickHull.
// It is used as a base case for the parallel version to avoid the overhead of
// parallel primitives on small inputs.
//
// Points: The original array of all points.
// Idxs:   Indices of points to be processed in this step. These are points
//         "outside" the triangle formed by (l, mid, r).
// l, mid, r: Indices of the three points forming the current hull segment.
//
// Returns a sequence of indices of the hull points found between l and r.
parlay::sequence<indexT> serialQuickHull(parlay::sequence<point> const & Points,
                                         parlay::sequence<indexT> Idxs,
                                         indexT l, indexT mid, indexT r) {
  size_t n = Idxs.size();
  if (n <= 1) return Idxs;

  point lP = Points[l], midP = Points[mid], rP = Points[r];

  coord max_left_a = 0.0;
  coord max_right_a = 0.0;
  indexT maxleft = 0, maxright = 0; // Dummies, will be updated if points are found

  parlay::sequence<indexT> left_indices, right_indices;
  // Small heuristic to avoid some reallocations in std::vector backing parlay::sequence
  if (n > 10) {
    left_indices.reserve(n / 2);
    right_indices.reserve(n / 2);
  }

  // Single pass to partition points into "left" and "right" sets (of edges l-mid and mid-r)
  // and find the furthest point in each set.
  for (indexT j : Idxs) {
    coord lefta = triArea(lP, midP, Points[j]);
    if (lefta > 1e-12) { // Use a small epsilon for robustness
      left_indices.push_back(j);
      if (lefta > max_left_a) {
        max_left_a = lefta;
        maxleft = j;
      }
    } else {
      coord righta = triArea(midP, rP, Points[j]);
      if (righta > 1e-12) {
        right_indices.push_back(j);
        if (righta > max_right_a) {
          max_right_a = righta;
          maxright = j;
        }
      }
    }
  }
  Idxs.clear(); // Release memory early

  // Recurse on the left and right sets
  parlay::sequence<indexT> leftR, rightR;
  if (max_left_a > 0.0) {
    leftR = serialQuickHull(Points, std::move(left_indices), l, maxleft, mid);
  }
  if (max_right_a > 0.0) {
    rightR = serialQuickHull(Points, std::move(right_indices), mid, maxright, r);
  }

  // Combine the results: left_hull + mid + right_hull
  parlay::sequence<indexT> result;
  result.reserve(leftR.size() + rightR.size() + 1);
  result.insert(result.end(), leftR.begin(), leftR.end());
  result.push_back(mid);
  result.insert(result.end(), rightR.begin(), rightR.end());
  return result;
}

// The parallel quickhull algorithm
// For inputs larger than the threshold, it partitions the points and recurses in parallel.
// For smaller inputs, it switches to the optimized serialQuickHull implementation.
parlay::sequence<indexT> quickHull(parlay::sequence<point> const & Points,
				   parlay::sequence<indexT> Idxs,
				   indexT l, indexT mid, indexT r) {
  size_t n = Idxs.size();
  if (n <= 1) return Idxs;

  // Base case: switch to a faster serial version for small problems
  if (n <= 16384) {
    return serialQuickHull(Points, std::move(Idxs), l, mid, r);
  }
  else {
    using cipair = std::pair<coord,indexT>;
    using cipairs = std::pair<cipair,cipair>;
    auto pairMax = [&] (cipairs a, cipairs b) {
      return cipairs((a.first.first > b.first.first) ? a.first : b.first,
		     (a.second.first > b.second.first) ? a.second : b.second);};
    auto ci_monoid = parlay::make_monoid(pairMax,cipairs());

    // calculate furthest (positive) points from the lines l--mid and mid--r
    // at the same time set flags for those which are above each line
    auto leftFlag = parlay::sequence<bool>::uninitialized(n) ;
    auto rightFlag = parlay::sequence<bool>::uninitialized(n) ;

    point lP = Points[l], midP = Points[mid], rP = Points[r];
    auto P = parlay::delayed_tabulate(n, [&] (size_t i) {
	indexT j = Idxs[i];
	coord lefta = triArea(lP, midP, Points[j]);
	coord righta = triArea(midP, rP, Points[j]);
	leftFlag[i] = lefta > 1e-12; // Use a small epsilon for robustness
	rightFlag[i] = righta > 1e-12;
	return cipairs(cipair(lefta,j),cipair(righta,j));
      });
    cipairs prs = parlay::reduce(P, ci_monoid);
    indexT maxleft = prs.first.second;
    indexT maxright = prs.second.second;

    // keep those above each line
    parlay::sequence<indexT> left = parlay::pack(Idxs, leftFlag);
    parlay::sequence<indexT> right = parlay::pack(Idxs, rightFlag);
    Idxs.clear(); // clear and use std::move to avoid O(n log n) memory usage

    // recurse in parallel
    parlay::sequence<indexT> leftR, rightR;
    parlay::par_do(
	      [&] () {leftR = quickHull(Points, std::move(left), l, maxleft, mid);},
	      [&] () {rightR = quickHull(Points, std::move(right), mid, maxright, r);});

