// Serial QuickHull implementation using std::vector for efficiency in the base case.
// It is a standard recursive QuickHull algorithm, but implemented serially.
std::vector<indexT> serial_quickHull_rec(const parlay::sequence<point>& Points, std::vector<indexT>&& Idxs, indexT l, indexT r) {
    if (Idxs.size() <= 1) {
        return std::move(Idxs);
    }

    // 1. Find the point furthest from the line l-r
    auto max_it = std::max_element(std::begin(Idxs), std::end(Idxs), [&](indexT a, indexT b) {
        return triArea(Points[l], Points[r], Points[a]) < triArea(Points[l], Points[r], Points[b]);
    });
    indexT mid = *max_it;

    // 2. Partition the points into those "left" of l-mid and "right" of mid-r.
    // Points inside the triangle l-mid-r are discarded.
    std::vector<indexT> left_S, right_S;
    left_S.reserve(Idxs.size());
    right_S.reserve(Idxs.size());

    point lP = Points[l];
    point midP = Points[mid];
    point rP = Points[r];

    for (indexT i : Idxs) {
        if (triArea(lP, midP, Points[i]) > 0.0) {
            left_S.push_back(i);
        } else if (triArea(midP, rP, Points[i]) > 0.0) {
            right_S.push_back(i);
        }
    }
    left_S.shrink_to_fit();
    right_S.shrink_to_fit();

    // 3. Recurse on the two smaller sets
    auto left_hull = serial_quickHull_rec(Points, std::move(left_S), l, mid);
    auto right_hull = serial_quickHull_rec(Points, std::move(right_S), mid, r);

    // 4. Combine the results: left_hull + mid + right_hull
    left_hull.push_back(mid);
    left_hull.insert(left_hull.end(), std::make_move_iterator(right_hull.begin()), std::make_move_iterator(right_hull.end()));
    return left_hull;
}

