#include <algorithm>
#include <vector>

#include "common/geometry.h"
#include "parlay/primitives.h"
#include "hull.h"
#include "serialHull.h"

// This file implements a parallel Quickhull algorithm for finding the convex hull
// of a set of 2D points.
//
// The high-level strategy is as follows:
// 1. Handle small inputs by delegating to a fast serial implementation (serialHull).
// 2. In parallel, find the points with the minimum and maximum x-coordinates,
//    'l' and 'r'. These two points are guaranteed to be on the hull.
// 3. In a single parallel pass (using parlay::group_by_key), partition the
//    remaining points into three sets:
//      a) 'top_candidates': points to the left of the directed line l->r.
//      b) 'bottom_candidates': points to the left of the directed line r->l.
//      c) Points collinear with l and r, which are discarded.
// 4. Use parlay::par_do to recursively find the 'top_hull' and 'bottom_hull'
//    in parallel.
// 5. The recursive step, 'par_hull_rec', also uses a parallel Quickhull approach:
//      a) It has a cutoff (QUICKHULL_CUTOFF) to switch to a serial version
//         ('serial_hull_rec') for small subproblems, which is critical for
//         performance.
//      b) It finds the point 'h' furthest from the current dividing line.
//      c) It uses parlay::group_by_key to efficiently partition the remaining
//         candidates for the two new subproblems.
//      d) It makes two recursive calls in parallel.
// 6. Finally, the results are combined to form the full hull, sorted clockwise
//    starting from the point 'l'.

constexpr size_t QUICKHULL_CUTOFF = 4096;

// Parallel recursive quickhull step.
// Given a set of candidate point indices `Idxs`, and a line segment `p1-p2`,
// it finds the hull points "above" (to the left of) the directed line p1->p2.
// Returns the hull points in CCW order (i.e., ordered from p1 to p2), excluding p1 and p2.
parlay::sequence<indexT> par_hull_rec(parlay::sequence<indexT> const& Idxs, indexT p1, indexT p2, parlay::sequence<point> const& S) {
  // Base case: for small subproblems, switch to the serial implementation.
  if (Idxs.size() < QUICKHULL_CUTOFF) {
    return serial_hull_rec(Idxs, p1, p2, S);
  }

  // Find the point `h` with maximum perpendicular distance from the line p1-p2.
  // This is equivalent to maximizing the area of the triangle (p1, p2, h).
  auto furthest_it = parlay::max_element(Idxs, [&](indexT a, indexT b) {
    return triArea(S[p1], S[p2], S[a]) < triArea(S[p1], S[p2], S[b]);
  });
  indexT h = *furthest_it;

  // In parallel, partition remaining points into those left of p1-h and those left of h-p2.
  // Points inside triangle p1-h-p2 are discarded. This is done efficiently in
  // a single pass using parlay::group_by_key.
  auto get_loc = [&](indexT i) -> int {
    if (triArea(S[p1], S[h], S[i]) > 0.0) return 1; // Left of p1-h
    if (triArea(S[h], S[p2], S[i]) > 0.0) return 2; // Left of h-p2
    return 0; // Discard
  };

  auto p_rec = parlay::group_by_key(parlay::make_slice(Idxs), get_loc);
  parlay::sequence<indexT> s1, s2;
  for(const auto& [k, v] : p_rec) {
      if (k==1) s1 = parlay::sequence<indexT>(v.begin(), v.end());
      else if (k==2) s2 = parlay::sequence<indexT>(v.begin(), v.end());
  }

  parlay::sequence<indexT> h1, h2;
  parlay::par_do(
    [&]() { h1 = par_hull_rec(s1, p1, h, S); },
    [&]() { h2 = par_hull_rec(s2, h, p2, S); }
  );

  // Combine results: (hull from p1 to h), h, (hull from h to p2)
  h1.push_back(h);
  h1.append(h2);
  return h1;
}

parlay::sequence<indexT> hull(parlay::sequence<point> const &S) {
  size_t n = S.size();
  // For small N, the overhead of parallel scheduling is not worth it.
  // Fall back to a fully serial algorithm.
  if (n < QUICKHULL_CUTOFF) {
    return serialHull(S);
  }

  // Find points with min and max x-coordinate in parallel.
  // l: min x, tie-break with min y.
  // r: max x (any point with max x is fine).
  auto minmax_idx = parlay::minmax_element(parlay::iota<indexT>(n),
    [&](indexT i, indexT j) {
      return S[i].x < S[j].x || (S[i].x == S[j].x && S[i].y < S[j].y);
    });
  indexT l = *minmax_idx.first;
  indexT r = *parlay::max_element(parlay::iota<indexT>(n),
    [&](indexT i, indexT j) { return S[i].x < S[j].x; });

  // In parallel, partition points into those above and below the line l-r.
  auto get_loc = [&](indexT i) -> int {
    coord area = triArea(S[l], S[r], S[i]);
    if (area > 0.0) return 1; // top
    if (area < 0.0) return 2; // bottom
    return 0; // discard (collinear)
  };

  auto p = parlay::group_by_key(parlay::iota<indexT>(n), get_loc);
  parlay::sequence<indexT> top_candidates, bottom_candidates;
  for(const auto& [k, v] : p) {
      if (k==1) top_candidates = parlay::sequence<indexT>(v.begin(), v.end());
      else if (k==2) bottom_candidates = parlay::sequence<indexT>(v.begin(), v.end());
  }

  // Recursively find the upper and lower hulls in parallel.
  parlay::sequence<indexT> top_hull, bottom_hull;
  parlay::par_do(
    [&]() { top_hull = par_hull_rec(top_candidates, l, r, S); },
    [&]() { bottom_hull = par_hull_rec(bottom_candidates, r, l, S); }
  );

  // Combine the hulls: l, upper hull (CW), r, lower hull (CW)
  // The recursive calls return points in CCW order, so the top hull must be reversed.
  parlay::sequence<indexT> final_hull;
  final_hull.reserve(top_hull.size() + bottom_hull.size() + 2);
  final_hull.push_back(l);
  std::reverse(top_hull.begin(), top_hull.end());
  final_hull.append(top_hull);
  final_hull.push_back(r);
  final_hull.append(bottom_hull);

  return final_hull;
}

