using namespace std;

// Recursive serial Quickhull
// Finds the hull of points in 'indices' that are to the left of the directed line p1_idx -> p2_idx
// Returns a sequence of indices on the hull, ordered along the direction from p1 to p2.
parlay::sequence<indexT> serial_hull(const parlay::sequence<point>& P, parlay::sequence<indexT> indices, indexT p1_idx, indexT p2_idx) {
  if (indices.empty()) {
    return parlay::sequence<indexT>();
  }

  // Find the point with the maximum distance from the line (p1, p2)
  auto max_it = parlay::max_element(indices, [&](indexT a, indexT b) {
    return triArea(P[p1_idx], P[p2_idx], P[a]) < triArea(P[p1_idx], P[p2_idx], P[b]);
  });
  indexT max_idx = *max_it;

  // Partition the remaining points into those left of (p1, max_p) and those left of (max_p, p2)
  parlay::sequence<indexT> s1, s2;
  s1.reserve(indices.size());
  s2.reserve(indices.size());
  for (indexT i : indices) {
    // Points inside the triangle (p1, max, p2) are discarded
    if (triArea(P[p1_idx], P[max_idx], P[i]) > 0.0) {
      s1.push_back(i);
    } else if (triArea(P[max_idx], P[p2_idx], P[i]) > 0.0) {
      s2.push_back(i);
    }
  }

  // Recurse on the two subproblems
  auto h1 = serial_hull(P, std::move(s1), p1_idx, max_idx);
  auto h2 = serial_hull(P, std::move(s2), max_idx, p2_idx);

  // Combine results
  return parlay::append(h1, parlay::sequence<indexT>{max_idx}, h2);
}

// Recursive parallel Quickhull
parlay::sequence<indexT> par_hull(const parlay::sequence<point>& P, parlay::sequence<indexT> indices, indexT p1_idx, indexT p2_idx) {
  // Base case: if few points, switch to serial to reduce overhead
  if (indices.size() < 2000) {
    return serial_hull(P, std::move(indices), p1_idx, p2_idx);
  }

  // Find the point with the maximum distance from the line (p1, p2)
  auto max_it = parlay::max_element(indices, [&](indexT a, indexT b) {
    return triArea(P[p1_idx], P[p2_idx], P[a]) < triArea(P[p1_idx], P[p2_idx], P[b]);
  });
  indexT max_idx = *max_it;

  // Filter points to the left of (p1, max_p) and (max_p, p2) in parallel
  // Points inside the triangle (p1, max, p2) are discarded
  auto s1 = parlay::filter(indices, [&](indexT i) {
    return triArea(P[p1_idx], P[max_idx], P[i]) > 0.0;
  });
  auto s2 = parlay::filter(indices, [&](indexT i) {
    return triArea(P[max_idx], P[p2_idx], P[i]) > 0.0;
  });

  // Recurse on the two subproblems in parallel
  parlay::sequence<indexT> h1, h2;
  parlay::par_do(
    [&]() { h1 = par_hull(P, std::move(s1), p1_idx, max_idx); },
    [&]() { h2 = par_hull(P, std::move(s2), max_idx, p2_idx); }
  );

  // Combine results
  return parlay::append(h1, parlay::sequence<indexT>{max_idx}, h2);
}


parlay::sequence<indexT> hull(parlay::sequence<point> const &S) {
  size_t n = S.size();
  // For 0, 1, or 2 points, the hull is all the points
  if (n < 3) {
    return parlay::tabulate(n, [](size_t i) -> indexT { return i; });
  }

  // Find points with min and max x coordinates in parallel
  // Tie-break min-x with min-y to get a unique starting point
  auto minmax_idx = parlay::minmax_element(parlay::iota<indexT>(n),
    [&](indexT a, indexT b) {
      if (S[a].x != S[b].x) return S[a].x < S[b].x;
      return S[a].y < S[b].y;
    });

  indexT l_idx = *minmax_idx.first;
  indexT r_idx = *minmax_idx.second;

  // In a single parallel pass, partition points into those above and below the
  // line (l_idx, r_idx). parlay::split_two is highly efficient for this.
  auto candidates = parlay::delayed_seq<indexT>(n, [](size_t i) { return static_cast<indexT>(i); });
  auto [above, below] = parlay::split_two(candidates, [&](indexT i) {
    if (triArea(S[l_idx], S[r_idx], S[i]) > 0.0) {
      return parlay::split_tag::left; // "above"
    }
    if (triArea(S[r_idx], S[l_idx], S[i]) > 0.0) {
      return parlay::split_tag::right; // "below"
    }
    return parlay::split_tag::none; // Collinear or one of the endpoints
  });

  // Recursively find the upper and lower hulls in parallel
  parlay::sequence<indexT> upper, lower;
  parlay::par_do(
    [&]() { upper = par_hull(S, std::move(above), l_idx, r_idx); },
    [&]() { lower = par_hull(S, std::move(below), r_idx, l_idx); }
  );

  // Combine the results: l, upper hull, r, lower hull for a clockwise ordering
  return parlay::append(parlay::sequence<indexT>{l_idx}, upper, parlay::sequence<indexT>{r_idx}, lower);
}

