// serialQuickHull is defined in this file, which is not provided,
// but is included by the original hull.C
#include "serialHull.h"

// Forward declaration for the recursive parallel hull function
parlay::sequence<indexT> parallel_quick_hull(parlay::slice<const indexT> Idx,
                                             const point* P, indexT p1, indexT p2);

parlay::sequence<indexT> hull(parlay::sequence<point> const& S) {
  size_t n = S.size();
  if (n < 3) {
    return parlay::tabulate(n, [](size_t i) -> indexT { return i; });
  }

  const point* P = S.data();

  // 1. Find points with lexicographically min and max (x, y) coordinates.
  // These are guaranteed to be on the hull.
  auto minmax_its = parlay::minmax_element(parlay::iota<indexT>(n), [&](indexT i, indexT j) {
    return std::tie(P[i].x, P[i].y) < std::tie(P[j].x, P[j].y);
  });
  indexT l = *minmax_its.first;
  indexT r = *minmax_its.second;

  // If all points are collinear, l and r are the endpoints. All other points
  // will have triArea == 0 and be filtered out. The result will be {l, r},
  // which is correct. If all points are identical, l == r, and we handle
  // this by filtering, resulting in an empty set of candidates. The final
  // hull will be {l}, which is also correct.

  // 2. Partition other points into "upper" and "lower" sets.
  // A point p is in the "upper" set if it is to the left of the directed
  // line l->r (i.e., triArea(l, r, p) > 0).
  // It is in the "lower" set if it is to the left of r->l.
  auto candidates = parlay::filter(parlay::iota<indexT>(n), [&](indexT i) { return i != l && i != r; });

  parlay::sequence<indexT> upper_candidates(candidates.size());
  parlay::sequence<indexT> lower_and_collinear(candidates.size());

  // Use partition_into for a single pass to separate upper points
  // from lower and collinear points.
  auto p = parlay::partition_into(candidates,
      parlay::make_slice(upper_candidates),
      parlay::make_slice(lower_and_collinear),
      [&](indexT i) { return triArea(P[l], P[r], P[i]) > 0.0; });
  upper_candidates.resize(p.first.size());
  lower_and_collinear.resize(p.second.size());

  // Filter the second partition to get only the lower points.
  auto lower_candidates = parlay::filter(lower_and_collinear, [&](indexT i) {
    return triArea(P[r], P[l], P[i]) > 0.0;
  });

  // 3. Recursively find the upper and lower hulls in parallel.
  parlay::sequence<indexT> upper_hull, lower_hull;
  parlay::par_do(
      [&]() { upper_hull = parallel_quick_hull(parlay::make_slice(upper_candidates), P, l, r); },
      [&]() { lower_hull = parallel_quick_hull(parlay::make_slice(lower_candidates), P, r, l); });

  // 4. Combine results into a single clockwise sequence.
  // The recursive calls return points in CCW order between their endpoints.
  // To get a clockwise hull starting at l: l, reverse(upper_hull), r, lower_hull.
  parlay::sequence<indexT> final_hull;
  final_hull.reserve(1 + upper_hull.size() + 1 + lower_hull.size());
  final_hull.push_back(l);
  final_hull.insert(final_hull.end(), upper_hull.rbegin(), upper_hull.rend());
  final_hull.push_back(r);
  final_hull.insert(final_hull.end(), lower_hull.begin(), lower_hull.end());

  return final_hull;
}

parlay::sequence<indexT> parallel_quick_hull(parlay::slice<const indexT> Idx,
                                             const point* P, indexT p1, indexT p2) {
  // Granularity control: switch to serial version for small subproblems.
  constexpr size_t SERIAL_THRESHOLD = 4000;

  if (Idx.empty()) {
    return parlay::sequence<indexT>();
  }

  if (Idx.size() < SERIAL_THRESHOLD) {
    auto Idx_copy = parlay::to_sequence(Idx);
    // serialQuickHull modifies the input array and returns the count.
    // It may not be const-correct, so we use const_cast.
    size_t m = serialQuickHull(Idx_copy.data(), const_cast<point*>(P), Idx_copy.size(), p1, p2);
    return parlay::sequence<indexT>(Idx_copy.begin(), Idx_copy.begin() + m);
  }

  // Find the point furthest from the line p1-p2.
  auto furthest_it = parlay::max_element(Idx, [&](indexT i, indexT j) {
    return triArea(P[p1], P[p2], P[i]) < triArea(P[p1], P[p2], P[j]);
  });
  indexT p_max = *furthest_it;

  // In parallel, filter points to the left of p1-p_max and p_max-p2.
  // Points on the lines are excluded (triArea > 0.0).
  parlay::sequence<indexT> s1, s2;
  parlay::par_do(
      [&]() {
        s1 = parlay::filter(Idx, [&](indexT i) { return triArea(P[p1], P[p_max], P[i]) > 0.0; });
      },
      [&]() {
        s2 = parlay::filter(Idx, [&](indexT i) { return triArea(P[p_max], P[p2], P[i]) > 0.0; });
      });

  // Recurse in parallel.
  parlay::sequence<indexT> h1, h2;
  parlay::par_do(
      [&]() { h1 = parallel_quick_hull(parlay::make_slice(s1), P, p1, p_max); },
      [&]() { h2 = parallel_quick_hull(parlay::make_slice(s2), P, p_max, p2); });

  // Combine results: h1, p_max, h2. This gives CCW order from p1 to p2.
  // Use move semantics for efficiency.
  parlay::sequence<indexT> result = std::move(h1);
  result.push_back(p_max);
  result.insert(result.end(), std::make_move_iterator(h2.begin()), std::make_move_iterator(h2.end()));

  return result;
}

#include <algorithm>
#include "common/geometry.h"
#include "parlay/primitives.h"
#include "parlay/sequence.h"
#include "parlay/delayed.h"
#include "hull.h"

// The problem description implies that a serial implementation, `serialQuickHull`,
// is available in this header. We use it for the base cases of our parallel recursion.
#include "serialHull.h"

// Recursive helper for the parallel QuickHull algorithm.
// It finds the convex hull of the points in 'indices' that lie to one side
// of the line segment defined by indices p1 and p2.
// The returned sequence of indices is ordered along the hull from p1 to p2.
parlay::sequence<indexT> par_hull_rec(const parlay::sequence<indexT>& indices,
                                      indexT p1, indexT p2,
                                      const parlay::sequence<point>& S) {
    // Base case: For a small number of points, the overhead of parallelization
    // is not worth it. We switch to the provided serial implementation.
    // The threshold is chosen based on typical performance tuning.
    constexpr size_t SERIAL_THRESHOLD = 4000;
    if (indices.size() < SERIAL_THRESHOLD) {
        if (indices.empty()) {
            return parlay::sequence<indexT>();
        }
        // serialQuickHull modifies its input buffer, so we must pass a copy.
        auto I_copy = indices;
        size_t m = serialQuickHull(I_copy.data(), S.data(), I_copy.size(), p1, p2);
        return parlay::sequence<indexT>(I_copy.begin(), I_copy.begin() + m);
    }

    // Find the point 'f' that is furthest from the line segment (p1, p2).
    // This is a parallel reduction to find the maximum.
    auto f_it = parlay::max_element(indices, [&](indexT a, indexT b) {
        return triArea(S[p1], S[p2], S[a]) < triArea(S[p1], S[p2], S[b]);
    });
    indexT f = *f_it;

    // In parallel, partition the points into two sets:
    // 1. Points to the left of the directed line (p1, f).
    // 2. Points to the left of the directed line (f, p2).
    // Points inside the triangle (p1, f, p2) are discarded as they cannot be on the hull.
    auto left_indices = parlay::filter(indices, [&](indexT i) {
        return triArea(S[p1], S[f], S[i]) > 0.0;
    });
    auto right_indices = parlay::filter(indices, [&](indexT i) {
        return triArea(S[f], S[p2], S[i]) > 0.0;
    });

    // Recurse on the two sets in parallel using parlay::par_do.
    parlay::sequence<indexT> hull1, hull2;
    parlay::par_do(
        [&]() { hull1 = par_hull_rec(left_indices, p1, f, S); },
        [&]() { hull2 = par_hull_rec(right_indices, f, p2, S); }
    );

    // Combine the results: {hull from (p1,f)}, {f}, {hull from (f,p2)}.
    // parlay::append is an efficient way to concatenate sequences.
    return parlay::append(hull1, parlay::sequence<indexT>{f}, hull2);
}

parlay::sequence<indexT> hull(parlay::sequence<point> const &S) {
    size_t n = S.size();

    // The convex hull is trivial for fewer than 3 points.
    if (n < 3) {
        return parlay::tabulate(n, [](size_t i) -> indexT { return i; });
    }

    // In parallel, find the indices of the points with minimum and maximum x-coordinates.
    // The minimum x-coordinate point 'l' is the designated start of the hull.
    // Ties for 'l' are broken by choosing the minimum y-coordinate.
    auto min_it = parlay::min_element(S, [](const point& a, const point& b) {
        return a.x < b.x || (a.x == b.x && a.y < b.y);
    });
    // The maximum x-coordinate point 'r' is the other extreme of the initial partition.
    auto max_it = parlay::max_element(S, [](const point& a, const point& b) {
        return a.x < b.x;
    });

    indexT l = std::distance(S.begin(), min_it);
    indexT r = std::distance(S.begin(), max_it);

    // Handle the degenerate case where all points are identical.
    if (l == r) {
        return parlay::sequence<indexT>{l};
    }

    // Create a delayed sequence of all indices [0, n-1] to avoid materializing it,
    // which is more memory-efficient for the filtering step.
    auto all_indices = parlay::delayed_tabulate(n, [](size_t i) -> indexT { return i; });

    // In parallel, partition the points into those above and below the line (l, r).
    // Points on the line are discarded.
    auto upper_indices = parlay::filter(all_indices, [&](indexT i) {
        return triArea(S[l], S[r], S[i]) > 0.0;
    });
    auto lower_indices = parlay::filter(all_indices, [&](indexT i) {
        return triArea(S[r], S[l], S[i]) > 0.0;
    });

    // Compute the upper and lower hulls in parallel.
    parlay::sequence<indexT> upper_hull, lower_hull;
    parlay::par_do(
        [&]() { upper_hull = par_hull_rec(upper_indices, l, r, S); },
        [&]() { lower_hull = par_hull_rec(lower_indices, r, l, S); }
    );

    // Combine the results to form the final clockwise-ordered hull.
    // The required order is: l, upper hull (reversed), r, lower hull.
    // - par_hull_rec(..., l, r) returns upper hull points ordered from l to r.
    // - par_hull_rec(..., r, l) returns lower hull points ordered from r to l.
    // To get clockwise order starting from l, we trace the path:
    // l -> (points on upper hull from r to l) -> r -> (points on lower hull from r to l) -> l
    auto reversed_upper_hull = parlay::delayed::map(parlay::delayed::reversed(upper_hull), [](auto x) { return x; });

    return parlay::append(
        parlay::sequence<indexT>{l},
        reversed_upper_hull,
        parlay::sequence<indexT>{r},
        lower_hull
    );
}

#include <algorithm>
#include <vector>

#include "common/geometry.h"
