namespace {

// Forward declaration for the parallel recursive helper
parlay::sequence<indexT> quickHull_rec(parlay::slice<indexT*> indices, const parlay::sequence<point>& P, indexT p1, indexT p2);

// Serial fallback implementation of the recursive step of QuickHull.
// This is used for small subproblems to avoid parallel overhead.
// It uses parlay::filter which is less memory-efficient than the in-place
// partition of the parallel version, but simpler for a serial base case.
parlay::sequence<indexT> serial_hull_rec(parlay::slice<const indexT*> indices, const parlay::sequence<point>& P, indexT p1, indexT p2) {
  if (indices.empty()) {
    return parlay::sequence<indexT>();
  }

  // Find the point furthest from the line segment (p1, p2).
  // triArea gives a value proportional to the signed distance.
  auto furthest_it = parlay::max_element(indices, [&](indexT a, indexT b) {
    return triArea(P[p1], P[p2], P[a]) < triArea(P[p1], P[p2], P[b]);
  });
  indexT p_max = *furthest_it;

  // Recursively find the hull on the two new sets of points.
  // s1: points to the left of the directed line (p1, p_max)
  auto s1 = parlay::filter(indices, [&](indexT i) {
    return triArea(P[p1], P[p_max], P[i]) > 0.0;
  });

  // s2: points to the left of the directed line (p_max, p2)
  auto s2 = parlay::filter(indices, [&](indexT i) {
    return triArea(P[p_max], P[p2], P[i]) > 0.0;
  });

  // Recurse on the two subsets
  auto h1 = serial_hull_rec(s1, P, p1, p_max);
  auto h2 = serial_hull_rec(s2, P, p_max, p2);

  // Combine the results: H(p1,p_max), p_max, H(p_max,p2)
  return parlay::append(h1, parlay::sequence<indexT>{p_max}, h2);
}

// Parallel recursive implementation of QuickHull.
// It partitions the input indices in-place for memory efficiency.
parlay::sequence<indexT> quickHull_rec(parlay::slice<indexT*> indices, const parlay::sequence<point>& P, indexT p1, indexT p2) {
  // Use serial implementation for small subproblems.
  constexpr size_t SERIAL_THRESHOLD = 2000;
  if (indices.size() < SERIAL_THRESHOLD) {
    return serial_hull_rec(indices, P, p1, p2);
  }

  // Find the point furthest from the line segment (p1, p2)
  auto furthest_it = parlay::max_element(indices, [&](indexT a, indexT b) {
    return triArea(P[p1], P[p2], P[a]) < triArea(P[p1], P[p2], P[b]);
  });
  indexT p_max = *furthest_it;

  // Partition the points into two sets in-place.
  // s1: points to the left of (p1, p_max)
  // s2: points to the left of (p_max, p2)
  // Points inside the triangle (p1, p_max, p2) are discarded.
  auto s1_end = parlay::unstable_partition_in_place(indices, [&](indexT i) {
    return triArea(P[p1], P[p_max], P[i]) > 0.0;
  });
  auto s2_end = parlay::unstable_partition_in_place(parlay::make_slice(s1_end, indices.end()), [&](indexT i) {
    return triArea(P[p_max], P[p2], P[i]) > 0.0;
  });

  parlay::sequence<indexT> h1, h2;
  parlay::par_do(
    [&]() { h1 = quickHull_rec(parlay::make_slice(indices.begin(), s1_end), P, p1, p_max); },
    [&]() { h2 = quickHull_rec(parlay::make_slice(s1_end, s2_end), P, p_max, p2); }
  );

  // Combine the results: H(p1,p_max), p_max, H(p_max,p2)
  return parlay::append(h1, parlay::sequence<indexT>{p_max}, h2);
}

} // namespace

parlay::sequence<indexT> hull(parlay::sequence<point> const &S) {
  size_t n = S.size();

  // Handle small inputs: the hull is all points.
  // Sort them to match the output specification (clockwise from min-x).
  if (n <= 3) {
    auto I = parlay::tabulate(n, [](size_t i) -> indexT { return i; });
    parlay::sort_inplace(I, [&](indexT a, indexT b) {
      if (S[a].x != S[b].x) return S[a].x < S[b].x;
      return S[a].y < S[b].y;
    });
    // For 3 points, ensure clockwise order.
    if (n == 3 && triArea(S[I[0]], S[I[1]], S[I[2]]) < 0) {
      std::swap(I[1], I[2]);
    }
    return I;
  }

  // Find the points with minimum and maximum lexicographical coordinates.
  // l: min x, tie-break with min y.
  // r: max x, tie-break with max y.
  // These two points are guaranteed to be on the hull.
  auto minmax_its = parlay::minmax_element(parlay::iota(n), [&](indexT a, indexT b) {
    if (S[a].x != S[b].x) return S[a].x < S[b].x;
    return S[a].y < S[b].y;
  });
  indexT l = *minmax_its.first;
  indexT r = *minmax_its.second;

  // If all points are identical, the hull is a single point.
  if (l == r) {
    return parlay::sequence<indexT>{l};
  }

  // Create a mutable sequence of indices to be partitioned.
  auto I = parlay::tabulate(n, [](size_t i) -> indexT { return i; });

  // Partition indices into upper and lower hull candidates in-place.
  // Points on the line (l,r) are discarded here.
  auto upper_end = parlay::unstable_partition_in_place(I, [&](indexT i) {
    return triArea(S[l], S[r], S[i]) > 0.0;
  });
  auto lower_end = parlay::unstable_partition_in_place(parlay::make_slice(upper_end, I.end()), [&](indexT i) {
    return triArea(S[r], S[l], S[i]) > 0.0;
  });

  // Recursively find the upper and lower hulls in parallel.
  parlay::sequence<indexT> upper_hull, lower_hull;
  parlay::par_do(
      [&]() { upper_hull = quickHull_rec(parlay::make_slice(I.begin(), upper_end), S, l, r); },
      [&]() { lower_hull = quickHull_rec(parlay::make_slice(upper_end, lower_end), S, r, l); }
  );

  // Combine the results into the final clockwise hull.
  // Order: min-x point, upper hull, max-x point, lower hull.
  parlay::sequence<indexT> final_hull;
  final_hull.reserve(upper_hull.size() + lower_hull.size() + 2);
  final_hull.push_back(l);
  final_hull.insert(final_hull.end(), upper_hull.begin(), upper_hull.end());
  final_hull.push_back(r);
  final_hull.insert(final_hull.end(), lower_hull.begin(), lower_hull.end());

  return final_hull;
}

