// *************************************************************
//    NEW INDEX-BASED TOPOLOGY AND MESH STRUCTURE
// *************************************************************

constexpr int GHOST_TRI = -1;
constexpr int UNINITIALIZED = -1;

inline int mod3(int i) { return (i > 2) ? i - 3 : i; }

struct vertex {
  using point_t = point;
  point pt;
  int t_idx;
  int id;
  std::atomic<int> reserve;

  vertex(point p, int i) : pt(p), t_idx(UNINITIALIZED), id(i), reserve(UNINITIALIZED) {}
  vertex() : t_idx(UNINITIALIZED), id(UNINITIALIZED), reserve(UNINITIALIZED) {}
};

struct triangle {
  int ngh[3];
  int vtx[3];
  int id;

  triangle() : id(UNINITIALIZED) {
    ngh[0] = ngh[1] = ngh[2] = GHOST_TRI;
    vtx[0] = vtx[1] = vtx[2] = UNINITIALIZED;
  }

  int locate(int t_idx) {
    if (ngh[0] == t_idx) return 0;
    if (ngh[1] == t_idx) return 1;
    if (ngh[2] == t_idx) return 2;
    // This should not happen in a consistent mesh
    // std::cout << "did not locate back pointer in triangulation\n";
    // abort();
    return -1; // Error case
  }

  void update(int t_old_idx, int t_new_idx) {
    if (ngh[0] == t_old_idx) { ngh[0] = t_new_idx; return; }
    if (ngh[1] == t_old_idx) { ngh[1] = t_new_idx; return; }
    if (ngh[2] == t_old_idx) { ngh[2] = t_new_idx; return; }
    // This should not happen in a consistent mesh
    // std::cout << "did not update\n";
    // abort();
  }
};

struct simplex {
  int t_idx;
  int o;
  simplex(int tt, int oo) : t_idx(tt), o(oo) {}
  simplex() : t_idx(GHOST_TRI), o(0) {}
  bool valid() const { return t_idx != GHOST_TRI; }
};

using vertex_t = vertex;
using triang_t = triangle;
using simplex_t = simplex;
using vect = typename point::vector;

class DelaunayMesh {
public:
  sequence<vertex_t>& Vertices;
  sequence<triang_t>& Triangles;

  DelaunayMesh(sequence<vertex_t>& V, sequence<triang_t>& T) : Vertices(V), Triangles(T) {}

  simplex_t across(simplex_t s) const {
    int neighbor_t_idx = Triangles[s.t_idx].ngh[s.o];
    if (neighbor_t_idx == GHOST_TRI) return simplex(GHOST_TRI, 0);
    int o = Triangles[neighbor_t_idx].locate(s.t_idx);
    return simplex(neighbor_t_idx, o);
  }

  simplex_t rotClockwise(simplex_t s) const { return simplex(s.t_idx, mod3(s.o + 1)); }
  int firstVertex(simplex_t s) const { return Triangles[s.t_idx].vtx[s.o]; }

  bool inCirc(simplex_t s, int v_idx) const {
    const auto& t = Triangles[s.t_idx];
    return inCircle(Vertices[t.vtx[0]].pt, Vertices[t.vtx[1]].pt, Vertices[t.vtx[2]].pt, Vertices[v_idx].pt);
  }

  bool outside(simplex_t s, int v_idx) const {
    const auto& t = Triangles[s.t_idx];
    return counterClockwise(Vertices[t.vtx[mod3(s.o + 2)]].pt, Vertices[v_idx].pt, Vertices[t.vtx[s.o]].pt);
  }

  simplex_t find(int p_idx, simplex_t start) const {
    simplex_t t = start;
    while (t.valid()) {
      int i;
      for (i = 0; i < 3; i++) {
        t = rotClockwise(t);
        if (outside(t, p_idx)) {
          t = across(t);
          break;
        }
      }
      if (i == 3) return t;
    }
    return t; // Should be a boundary or invalid simplex
  }

  void flip(simplex_t s_my) {
    simplex_t s_across = across(s_my);
    triang_t& my_t = Triangles[s_my.t_idx];
    triang_t& across_t = Triangles[s_across.t_idx];

    int o1 = mod3(s_my.o + 1);
    int os1 = mod3(s_across.o + 1);

    int t1_idx = my_t.ngh[o1];
    int t2_idx = across_t.ngh[os1];
    int v1_idx = my_t.vtx[o1];
    int v2_idx = across_t.vtx[os1];

    Vertices[my_t.vtx[s_my.o]].t_idx = s_across.t_idx;
    my_t.vtx[s_my.o] = v2_idx;
    my_t.ngh[s_my.o] = t2_idx;
    if (t2_idx != GHOST_TRI) Triangles[t2_idx].update(s_across.t_idx, s_my.t_idx);
    my_t.ngh[o1] = s_across.t_idx;

    Vertices[across_t.vtx[s_across.o]].t_idx = s_my.t_idx;
    across_t.vtx[s_across.o] = v1_idx;
    across_t.ngh[s_across.o] = t1_idx;
    if (t1_idx != GHOST_TRI) Triangles[t1_idx].update(s_my.t_idx, s_across.t_idx);
    across_t.ngh[os1] = s_my.t_idx;
  }

  void split(simplex_t s, int v_idx, int t1_idx, int t2_idx) {
    Vertices[v_idx].t_idx = s.t_idx;
    triang_t& t0 = Triangles[s.t_idx];
    triang_t& t1 = Triangles[t1_idx];
    triang_t& t2 = Triangles[t2_idx];

    int t0_n1 = t0.ngh[1], t0_n2 = t0.ngh[2];
    int t0_v0 = t0.vtx[0], t0_v1 = t0.vtx[1], t0_v2 = t0.vtx[2];

    t0.ngh[1] = t1_idx; t0.ngh[2] = t2_idx;
    t0.vtx[1] = v_idx;

    t1.ngh[0] = t0_n1; t1.ngh[1] = t2_idx; t1.ngh[2] = s.t_idx;
    t1.vtx[0] = t0_v1; t1.vtx[1] = v_idx; t1.vtx[2] = t0_v0;

    t2.ngh[0] = t0_n2; t2.ngh[1] = s.t_idx; t2.ngh[2] = t1_idx;
    t2.vtx[0] = t0_v2; t2.vtx[1] = v_idx; t2.vtx[2] = t0_v1;

    if (t0_n1 != GHOST_TRI) Triangles[t0_n1].update(s.t_idx, t1_idx);
    if (t0_n2 != GHOST_TRI) Triangles[t0_n2].update(s.t_idx, t2_idx);
    Vertices[t0_v1].t_idx = t1_idx;
  }

  simplex_t extend(simplex_t s, int v_idx, int new_t_idx) {
    triang_t& t = Triangles[s.t_idx];
    triang_t& new_t = Triangles[new_t_idx];
    t.ngh[s.o] = new_t_idx;
    new_t.vtx[0] = t.vtx[s.o];
    new_t.vtx[1] = t.vtx[mod3(s.o + 2)];
    new_t.vtx[2] = v_idx;
    new_t.ngh[0] = GHOST_TRI;
    new_t.ngh[1] = s.t_idx;
    new_t.ngh[2] = GHOST_TRI;
    Vertices[v_idx].t_idx = new_t_idx;
    return simplex(new_t_idx, 0);
  }
};

struct Qs {
  std::vector<int> vertexQ;
  std::vector<simplex_t> simplexQ;
  Qs() {
    vertexQ.reserve(100);
    simplexQ.reserve(100);
  }
  void clear() {
    vertexQ.clear();
    simplexQ.clear();
  }
};
using Qs_t = Qs;

// *************************************************************
//    NEW GRID-BASED POINT LOCATOR
// *************************************************************

class Locator {
  parlay::sequence<std::atomic<int>> grid;
  point min_c;
  vect scale;
  size_t dim;
  int default_tri;

 public:
  Locator(const parlay::sequence<point>& P, int default_tri_idx) {
    auto minmax_p = parlay::minmax_element(P, [](point a, point b) { return a.x < b.x; });
    double min_x = minmax_p.first->x;
    double max_x = minmax_p.second->x;
    minmax_p = parlay::minmax_element(P, [](point a, point b) { return a.y < b.y; });
    double min_y = minmax_p.first->y;
    double max_y = minmax_p.second->y;
    min_c = point(min_x, min_y);
    point max_c = point(max_x, max_y);
    vect size = max_c - min_c;

    dim = static_cast<size_t>(ceil(sqrt(P.size() / 10.0))); // Heuristic: ~10 points per cell
    dim = std::max(dim, (size_t)1);
    scale = vect(dim / size.x, dim / size.y);
    grid = parlay::sequence<std::atomic<int>>(dim * dim);
    parallel_for(0, dim * dim, [&](size_t i) { grid[i].store(-1, std::memory_order_relaxed); });
    default_tri = default_tri_idx;
  }

  std::pair<size_t, size_t> get_cell(point p) const {
    vect P_shifted = p - min_c;
    size_t ix = static_cast<size_t>(P_shifted.x * scale.x);
    size_t iy = static_cast<size_t>(P_shifted.y * scale.y);
    return {std::min(ix, dim - 1), std::min(iy, dim - 1)};
  }

  int get_start_triangle(point p) const {
    auto [ix, iy] = get_cell(p);
    int tri_idx = grid[iy * dim + ix].load(std::memory_order_relaxed);
    if (tri_idx != -1) return tri_idx;

    for (int r = 1; r < (int)dim; ++r) {
      int i = ix - r, j = iy - r;
      for (int k = 0; k < 8 * r; k++) {
        if (i >= 0 && i < (int)dim && j >= 0 && j < (int)dim) {
          tri_idx = grid[j * dim + i].load(std::memory_order_relaxed);
          if (tri_idx != -1) return tri_idx;
        }
        if (k < 2 * r) i++; else if (k < 4 * r) j++; else if (k < 6 * r) i--; else j--;
      }
    }
    return default_tri;
  }

  void update(point p, int tri_idx) {
    auto [ix, iy] = get_cell(p);
    grid[iy * dim + ix].store(tri_idx, std::memory_order_relaxed);
  }
};

// *************************************************************
//    ROUTINES FOR FINDING AND INSERTING A NEW POINT
// *************************************************************

void findCavity(simplex_t t, int p_idx, Qs_t* q, const DelaunayMesh& mesh) {
  if (t.valid() && mesh.inCirc(t, p_idx)) {
    q->simplexQ.push_back(t);
    t = mesh.rotClockwise(t);
    findCavity(mesh.across(t), p_idx, q, mesh);
    q->vertexQ.push_back(mesh.firstVertex(t));
    t = mesh.rotClockwise(t);
    findCavity(mesh.across(t), p_idx, q, mesh);
  }
}

void reserve_for_insert(int v_idx, simplex_t t, Qs_t* q, DelaunayMesh& mesh) {
  for (int i = 0; i < 3; i++) {
    q->vertexQ.push_back(mesh.firstVertex(t));
    findCavity(mesh.across(t), v_idx, q, mesh);
    t = mesh.rotClockwise(t);
  }
  int p_id = mesh.Vertices[v_idx].id;
  for (int u_idx : q->vertexQ) {
    pbbs::write_max(&(mesh.Vertices[u_idx].reserve), p_id, std::less<int>());
  }
}

bool insert(int v_idx, simplex_t t, Qs_t* q, DelaunayMesh& mesh, Locator& locator) {
  int p_id = mesh.Vertices[v_idx].id;
  bool flag = false;
  for (int u_idx : q->vertexQ) {
    if (mesh.Vertices[u_idx].reserve.load() == p_id) {
      mesh.Vertices[u_idx].reserve.store(UNINITIALIZED, std::memory_order_relaxed);
    } else {
      flag = true;
    }
  }

  if (!flag) {
    int t1_idx = 2 * v_idx;
    int t2_idx = 2 * v_idx + 1;
    mesh.split(t, v_idx, t1_idx, t2_idx);
    for (const auto& s : q->simplexQ) {
      mesh.flip(s);
    }
