  sequence<int> buffer(max_block_size);
  sequence<int> remain;
  sequence<simplex_t> t(max_block_size);
  sequence<bool> flags(max_block_size);
  auto VQ = tabulate(max_block_size, [](size_t) { return Qs_t(); });

  size_t num_done = 0;
  size_t num_remain = 0;

  while (num_done < n) {
    size_t num_round = std::min({n - num_done, max_block_size, 1 + num_done / 50 + num_remain});
    size_t num_new = std::min(num_round, n - num_done);
    if (num_round > num_remain) num_new = num_round - num_remain;
    else num_new = 0;

    parallel_for(0, num_round, [&](size_t j) {
      buffer[j] = (j < num_remain) ? remain[j] : v_indices[j - num_remain + num_done];
