// Morton code helper functions
// Interleaves the bits of a 32-bit integer.
// From https://fgiesen.wordpress.com/2009/12/13/decoding-morton-codes/
uint64_t part1by1(uint32_t n) {
    n = (n ^ (n << 16)) & 0x0000ffff0000ffff;
    n = (n ^ (n << 8))  & 0x00ff00ff00ff00ff;
    n = (n ^ (n << 4))  & 0x0f0f0f0f0f0f0f0f;
    n = (n ^ (n << 2))  & 0x3333333333333333;
    n = (n ^ (n << 1))  & 0x5555555555555555;
    return n;
}

// Computes the 64-bit Morton code for a 2D point.
// The point's coordinates are scaled to fit into 30-bit unsigned integers.
uint64_t morton_code(point p, point min_c, double scale) {
    uint32_t x = static_cast<uint32_t>((p.x - min_c.x) * scale);
    uint32_t y = static_cast<uint32_t>((p.y - min_c.y) * scale);
    return (part1by1(y) << 1) | part1by1(x);
}

