void incrementally_add_points(parlay::sequence<parlay::sequence<vertex_t*>>& cells, vertex_t* start, size_t n) {
  if (n == 0) return;

  // various structures needed for each parallel insertion
  size_t max_block_size = std::min((size_t)8192, parlay::num_workers() * 128);

  sequence<vertex_t*> done(n);
  sequence<simplex_t> t(max_block_size);
