  auto VQ = tabulate(max_block_size, [&] (size_t) -> Qs_t {return Qs_t();});

  // create a point location structure
  using KNN = k_nearest_neighbors<vertex_t,1>;
  sequence<vertex_t*> init(1,start);
  KNN knn = KNN(init);

  size_t num_done = 0;
  size_t rounds = 0;
  size_t num_next_rebuild = 100;
  const size_t multiplier = 10;

  auto cell_cursors = parlay::sequence<std::atomic<size_t>>::from_function(cells.size(), [](size_t){ return 0; });
  auto cell_indices = parlay::random_permutation(parlay::iota(cells.size()));
  size_t cell_idx_ptr = 0;

  sequence<vertex_t*> work_q;
  work_q.reserve(max_block_size * 2);

  while (num_done < n) {
    // 1. Refill work_q from grid if it's not full
    size_t needed = max_block_size - work_q.size();
    if (needed > 0) {
      sequence<vertex_t*> new_points;
      new_points.reserve(needed);
      size_t attempts = 0;
      while (new_points.size() < needed && attempts < cells.size()) {
        size_t cell_idx = cell_indices[cell_idx_ptr];
        size_t point_idx = cell_cursors[cell_idx].fetch_add(1, std::memory_order_relaxed);
        if (point_idx < cells[cell_idx].size()) {
          new_points.push_back(cells[cell_idx][point_idx]);
          attempts = 0;
        } else {
          attempts++;
        }
        cell_idx_ptr = (cell_idx_ptr + 1) % cells.size();
      }
      work_q.insert(work_q.end(), new_points.begin(), new_points.end());
    }

    if (work_q.empty()) break;

    // 2. Rebuild k-NN structure periodically
    if (num_done >= num_next_rebuild) {
      auto vtxs = parlay::to_sequence(done.cut(0,num_done));
      if (!vtxs.empty()) {
        knn = KNN(vtxs);
        if (num_next_rebuild < n / multiplier)
           num_next_rebuild *= multiplier;
        else
           num_next_rebuild += n / multiplier;
      }
    }

    // 3. Determine batch size
    size_t num_round = std::min({work_q.size(), max_block_size, (size_t)1 + num_done / 25});

    // 4. Process the batch
    parallel_for (0, num_round, [&] (size_t j) {
      vertex_t* p = work_q[j];
      vertex_t *u = knn.nearest(p);
      t[j] = find(p, simplex(u->t, 0));
      reserve_for_insert(p, t[j], &VQ[j]);
