    parallel_for (0, num_round, [&] (size_t j) {
      flags[j] = insert(work_q[j], t[j], &VQ[j]);
    });

    // 5. Partition work_q into successful and failed
    auto succeeded_flags = parlay::delayed_seq<bool>(num_round, [&](size_t i) { return !flags[i]; });
    size_t succeeded_count = parlay::count(succeeded_flags, true);

    parlay::pack_into(parlay::map(parlay::iota(num_round), [&](size_t i){ return work_q[i]; }),
                      succeeded_flags, done.cut(num_done, num_done + succeeded_count));
    num_done += succeeded_count;

    auto next_work_q = parlay::pack(parlay::map(parlay::iota(num_round), [&](size_t i){ return work_q[i]; }),
                                    flags.cut(0, num_round));
    next_work_q.insert(next_work_q.end(), work_q.begin() + num_round, work_q.end());
    work_q = std::move(next_work_q);

    rounds++;
  }
}


