// Iterative routine for finding a cavity.
void findCavity(simplex_t t, int p_idx, Qs *q, const sequence<triang_t>& Triangles, const sequence<vertex_t>& Vertices) {
  parlay::sequence<simplex_t> stack;
  if (t.t_idx != -1) stack.push_back(t);

  while (!stack.empty()) {
    simplex_t curr = stack.back();
    stack.pop_back();
    if (simplex_inCirc(curr, p_idx, Triangles, Vertices)) {
      q->simplexQ.push_back(curr);
      curr = curr.rotClockwise();
      stack.push_back(simplex_across(curr, Triangles));
      q->vertexQ.push_back(curr.firstVertexIdx(Triangles));
      curr = curr.rotClockwise();
      stack.push_back(simplex_across(curr, Triangles));
    }
  }
}

void reserve_for_insert(int v_idx, simplex_t t, Qs *q, const sequence<triang_t>& Triangles, const sequence<vertex_t>& Vertices) {
  for (int i = 0; i < 3; i++) {
    q->vertexQ.push_back(t.firstVertexIdx(Triangles));
    findCavity(simplex_across(t, Triangles), v_idx, q, Triangles, Vertices);
    t = t.rotClockwise();
  }
  int v_id = Vertices[v_idx].id;
  for (int u_idx : q->vertexQ) {
    pbbs::write_max(&(Vertices[u_idx].reserve), v_id, std::less<int>());
  }
}

bool findAndReserveCavity(int v_idx, simplex_t& t, Qs* q, const sequence<triang_t>& Triangles, const sequence<vertex_t>& Vertices) {
  t = simplex_t(Vertices[v_idx].badT, 0);
  if (t.t_idx == -1 || Triangles[t.t_idx].bad == 0) return false;

  if (simplex_obtuse(t, Triangles, Vertices)) t = simplex_across(t, Triangles);
  while (t.isTriangle()) {
    int i;
    for (i = 0; i < 2; i++) {
      t = t.rotClockwise();
      if (simplex_obtuse(t, Triangles, Vertices)) {
        t = simplex_across(t, Triangles);
        break;
      }
    }
    if (i == 2) break;
  }

  if (!t.isBoundary()) {
    simplex_t temp_t = t;
    for (int i = 0; i < 3; i++) {
      if (simplex_across(temp_t, Triangles).isBoundary() && (simplex_farAngle(temp_t, Triangles, Vertices) > 45.0)) {
        t = temp_t;
        t.boundary = true;
        break;
      }
      temp_t = temp_t.rotClockwise();
    }
  }

  const_cast<vertex_t&>(Vertices[v_idx]).pt = circumcenter(t, Triangles, Vertices);
  reserve_for_insert(v_idx, t, q, Triangles, Vertices);
  return true;
}

bool addCavity(int v_idx, simplex_t t, Qs *q, TriangleTable& TT, sequence<triang_t>& Triangles, sequence<vertex_t>& Vertices) {
  bool flag = true;
  int v_id = Vertices[v_idx].id;
  for (int u_idx : q->vertexQ) {
    if (Vertices[u_idx].reserve.load(std::memory_order_relaxed) != v_id) {
      flag = false;
      break;
    }
  }

  if (flag) {
    for (int u_idx : q->vertexQ) {
      Vertices[u_idx].reserve.store(-1, std::memory_order_relaxed);
    }

    int t0_idx = t.t_idx;
    int t1_idx = Vertices[v_idx].t;
    int t2_idx = t1_idx + 1;
    Triangles[t1_idx].initialized = true;

    if (t.isBoundary()) {
      simplex_splitBoundary(t, v_idx, t1_idx, Triangles, Vertices);
    } else {
      Triangles[t2_idx].initialized = true;
      simplex_split(t, v_idx, t1_idx, t2_idx, Triangles, Vertices);
    }

    for (const auto& s : q->simplexQ) simplex_flip(s, Triangles, Vertices);

    q->simplexQ.push_back(simplex_t(t0_idx, 0));
    q->simplexQ.push_back(simplex_t(t1_idx, 0));
    if (!t.isBoundary()) q->simplexQ.push_back(simplex_t(t2_idx, 0));

    for (const auto& s : q->simplexQ) {
      int current_t_idx = s.t_idx;
      if (skinnyTriangle(current_t_idx, Triangles, Vertices)) {
        TT.insert(current_t_idx);
        Triangles[current_t_idx].bad = 1;
      } else {
        Triangles[current_t_idx].bad = 0;
      }
    }
    Vertices[v_idx].badT = -1;
  }
  q->simplexQ.clear();
  q->vertexQ.clear();
  return flag;
}


// *************************************************************
//    MAIN REFINEMENT LOOP
// *************************************************************

size_t addRefiningVertices(parlay::slice<int*, int*> V, TriangleTable &TT, vertexQs& VQ,
                           sequence<triang_t>& Triangles, sequence<vertex_t>& Vertices) {
  size_t n = V.size();
  size_t size = std::min(VQ.size(), n);

  sequence<simplex_t> t(size);
  sequence<bool> flags(size);

  size_t top = n;
  size_t num_failed = 0;

  while (top > 0) {
    size_t cnt = std::min<size_t>(size, top);
    size_t offset = top - cnt;

    parallel_for(0, cnt, [&](size_t j) {
      flags[j] = findAndReserveCavity(V[j + offset], t[j], &VQ[j], Triangles, Vertices);
    });

    parallel_for(0, cnt, [&](size_t j) {
      if (flags[j]) {
        flags[j] = !addCavity(V[j + offset], t[j], &VQ[j], TT, Triangles, Vertices);
      }
    });

    auto remain = pack(V.cut(offset, offset + cnt), flags.cut(0, cnt));
    parallel_for(0, remain.size(), [&](size_t j) { V[j + offset] = remain[j]; });
    num_failed += remain.size();
    top = top - cnt + remain.size();
  }
  return num_failed;
}

