inline bool skinnyTriangle(int t_idx, const sequence<triang_t>& Triangles, const sequence<vertex_t>& Vertices) {
  const auto& t = Triangles[t_idx];
  return minAngleCheck(Vertices[t.vtx[0]].pt, Vertices[t.vtx[1]].pt, Vertices[t.vtx[2]].pt, 30.0);
}

inline point circumcenter(simplex_t s, const sequence<triang_t>& Triangles, const sequence<vertex_t>& Vertices) {
  if (s.isTriangle()) {
    const auto& t = Triangles[s.t_idx];
    return triangleCircumcenter(Vertices[t.vtx[0]].pt, Vertices[t.vtx[1]].pt, Vertices[t.vtx[2]].pt);
  } else { // s.isBoundary()
    const auto& t = Triangles[s.t_idx];
    point p0 = Vertices[t.vtx[(s.o + 2) % 3]].pt;
    point p1 = Vertices[t.vtx[s.o]].pt;
    return p0 + (p1 - p0) / 2.0;
  }
}

