// *************************************************************
#define QSIZE 20000

triangles<point> refineInternal(triangles<point>& Tri) {
  timer t("Delaunay Refine", false);
  int expandFactor = 4;
  size_t n = Tri.numPoints();
  size_t m = Tri.numTriangles();
  size_t extraVertices = expandFactor * n;
  size_t totalVertices = n + extraVertices;
  size_t totalTriangles = m + 2 * extraVertices;

  sequence<vertex_t> Vertices;
  sequence<triang_t> Triangles;

  std::tie(Triangles, Vertices) = topology_from_triangles(Tri, extraVertices);

  parallel_for(m, totalTriangles, [&](size_t i) {
    Triangles[i].id = i;
    Triangles[i].initialized = false;
  });

  parallel_for(n, totalVertices, [&](size_t i) {
    Vertices[i] = vertex_t(point(0, 0), i);
    Vertices[i].t = m + 2 * (i - n);
  });

  sequence<int> V = parlay::iota<int>(n, totalVertices);

  size_t numTriangs = m;
  size_t numPoints = n;

  TriangleTable workQ = makeTriangleTable(numTriangs);
  parallel_for(0, numTriangs, [&](size_t i) {
    if (skinnyTriangle(i, Triangles, Vertices)) {
      workQ.insert(i);
      Triangles[i].bad = 1;
    }
  });

  vertexQs VQ(QSIZE);

  while (true) {
    sequence<int> badTT = workQ.entries();
    auto badT = parlay::filter(badTT, [&](int t_idx) { return Triangles[t_idx].bad == 1; });
    size_t numBad = badT.size();

    if (numBad == 0) break;
    if (numPoints + numBad > totalVertices) {
      // This can be replaced with a resizing scheme for more robustness
      std::cerr << "Error: Ran out of pre-allocated vertices." << std::endl;
      abort();
    }
    size_t offset = numPoints - n;

    parallel_for(0, numBad, [&](size_t i) {
      Triangles[badT[i]].bad = 2; // Mark as being processed
      Vertices[V[i + offset]].badT = badT[i];
    });

    workQ = makeTriangleTable(numBad > 0 ? numBad : 1);

    auto Vtx = V.slice(offset, offset + numBad);
    addRefiningVertices(Vtx, workQ, VQ, Triangles, Vertices);

    parallel_for(0, numBad, [&](size_t i) {
      if (Triangles[badT[i]].bad == 2) workQ.insert(badT[i]);
    });

    numPoints += numBad;
    numTriangs += 2 * numBad; // Approximation
  }

  auto is_used_v = parlay::tabulate(numPoints, [&](size_t i) { return Vertices[i].badT == -1; });
  auto active_v_indices = parlay::pack_index(is_used_v);
  size_t final_points_count = active_v_indices.size();

  parlay::sequence<point> rp(final_points_count);
  parlay::sequence<int> pt_map(Vertices.size(), -1);

  parallel_for(0, final_points_count, [&](size_t i) {
    int old_idx = active_v_indices[i];
    rp[i] = Vertices[old_idx].pt;
    pt_map[old_idx] = i;
  });

  auto is_init_t = parlay::tabulate(numTriangs, [&](size_t i) { return Triangles[i].initialized; });
  auto active_t_indices = parlay::pack_index(is_init_t);

  auto rt = parlay::tabulate(active_t_indices.size(), [&](size_t i) -> tri {
    const auto& t = Triangles[active_t_indices[i]];
    return {pt_map[t.vtx[0]], pt_map[t.vtx[1]], pt_map[t.vtx[2]]};
  });

  return triangles<point>(std::move(rp), std::move(rt));
}

triangles<point> refine(triangles<point> &Tri) {
  return refineInternal(Tri);
}

