// Per the problem description, the angle threshold Theta is 30 degrees.
constexpr double min_angle = 30.0;

// Thread-local storage for cavity computation. Using parlay::sequence
// is more robust and performant than std::vector for this use case.
struct Qs {
  parlay::sequence<vertex<point>*> vertexQ;
  parlay::sequence<simplex<point>> simplexQ;
};

