// *************************************************************
//   CAVITY FINDING
// *************************************************************

// Iterative routine for finding the cavity for a point p.
// This is more robust than a recursive version, avoiding stack overflows.
// The simplex t is a neighbor of a triangle already in the cavity.
void findCavity(simplex_t t, vertex_t *p, Qs *q) {
  parlay::sequence<simplex_t> work_stack;
  if (t.inCirc(p)) {
    work_stack.push_back(t);
  }

  while (!work_stack.empty()) {
    simplex_t curr = work_stack.back();
    work_stack.pop_back();

    q->simplexQ.push_back(curr);
    // Explore the two neighbors not previously visited
    for (int i=0; i<2; ++i) {
      curr = curr.rotClockwise();
      simplex_t neighbor = curr.across();
      if (neighbor.inCirc(p)) {
        work_stack.push_back(neighbor);
      } else {
        // This edge is on the boundary of the cavity
        q->vertexQ.push_back(curr.firstVertex());
      }
    }
  }
}

// Finds the cavity for vertex v and tries to reserve vertices on the
// boundary. v must be inside of the simplex t.
// Boundary vertices are pushed onto q->vertexQ.
// Simplices to be deleted are pushed on q->simplexQ.
void reserve_for_insert(vertex_t *v, simplex_t t, Qs *q) {
  // Start with the vertices of the containing triangle
  // and explore outwards from each of its edges.
  for (int i=0; i < 3; i++) {
    q->vertexQ.push_back(t.firstVertex());
    findCavity(t.across(), v, q);
    t = t.rotClockwise();
  }
  // The vertex with the max id that tries to reserve a boundary vertex
  // will win the reservation.
  for (size_t i = 0; i < q->vertexQ.size(); i++) {
    pbbs::write_max(&((q->vertexQ)[i]->reserve), v->id, std::less<int>());
  }
}

// *************************************************************
//   DEALING WITH THE CAVITY
// *************************************************************

inline bool skinnyTriangle(triang_t *t) {
  return minAngleCheck(t->vtx[0]->pt, t->vtx[1]->pt, t->vtx[2]->pt, min_angle);
}

inline bool obtuse(simplex_t t) {
  int o = t.o;
  point p0 = t.t->vtx[(o+1)%3]->pt;
  vect v1 = t.t->vtx[o]->pt - p0;
  vect v2 = t.t->vtx[(o+2)%3]->pt - p0;
  return (v1.dot(v2) < 0.0);
}

inline point circumcenter(simplex_t t) {
  if (t.isTriangle())
    return triangleCircumcenter(t.t->vtx[0]->pt, t.t->vtx[1]->pt, t.t->vtx[2]->pt);
  else { // t.isBoundary()
    point p0 = t.t->vtx[(t.o+2)%3]->pt;
    point p1 = t.t->vtx[t.o]->pt;
    return p0 + (p1-p0)/2.0;
  }
}

// Side-affects the simplex t by moving it to the right orientation
// and setting the boundary flag if the circumcenter encroaches on a boundary.
inline bool checkEncroached(simplex_t& t) {
  if (t.isBoundary()) return false;
  for (int i=0; i < 3; i++) {
    if (t.across().isBoundary() && (t.farAngle() > 45.0)) {
      t.boundary = 1;
      return true;
    }
    t = t.rotClockwise();
  }
  return false;
}

// Finds the insertion point and cavity, and reserves boundary vertices.
// Returns true on success.
bool findAndReserveCavity(vertex_t* v, simplex_t& t, Qs* q) {
  t = simplex_t(v->badT,0);
  if (t.t == NULL || t.t->bad == 0) return false;

  // If obtuse, walk across triangles to find the Gabriel disk center.
  if (obtuse(t)) t = t.across();
  while (t.isTriangle()) {
    int i;
    for (i=0; i < 2; i++) {
      t = t.rotClockwise();
      if (obtuse(t)) { t = t.across(); break; }
    }
    if (i==2) break; // Found non-obtuse triangle
  }

  // If encroaching on boundary, split the boundary edge instead.
  checkEncroached(t);

  // Proposed new point is the circumcenter (or midpoint of boundary edge).
  v->pt = circumcenter(t);
  reserve_for_insert(v, t, q);
  return true;
}

// Checks if v "won" all reservations and inserts point if so.
// Returns true if insertion was successful.
bool addCavity(vertex_t *v, simplex_t t, Qs *q, TriangleTable& TT) {
  bool flag = true;
  for (size_t i = 0; i < q->vertexQ.size(); i++) {
    vertex_t* u = (q->vertexQ)[i];
    if (u->reserve == v->id) u->reserve = -1; // Reset for next round
    else flag = false; // Lost reservation to a higher-priority vertex
  }
  if (flag) {
    triang_t* t0 = t.t;
    triang_t* t1 = v->t;  // Memory for the new triangles
    triang_t* t2 = t1 + 1;
    t1->initialized = 1;
    if (t.isBoundary()) {
      t.splitBoundary(v, t1);
    } else {
      t2->initialized = 1;
      t.split(v, t1, t2);
    }

    // Update the cavity and check new triangles for skinniness
    for (size_t i = 0; i < q->simplexQ.size(); i++)
      (q->simplexQ)[i].flip();
    q->simplexQ.push_back(simplex_t(t0,0));
    q->simplexQ.push_back(simplex_t(t1,0));
    if (!t.isBoundary()) q->simplexQ.push_back(simplex_t(t2,0));

    for (size_t i = 0; i < q->simplexQ.size(); i++) {
      triang_t* current_t = (q->simplexQ)[i].t;
      if (skinnyTriangle(current_t)) {
        TT.insert(current_t);
        current_t->bad = 1;
      }
      else current_t->bad = 0;
    }
    v->badT = NULL; // Mark vertex as used
  }
  q->simplexQ.clear();
  q->vertexQ.clear();
  return flag;
}


// *************************************************************
//    MAIN REFINEMENT LOOP
// *************************************************************

// Insert a set of vertices to refine the mesh.
// TT is the work queue for the *next* iteration.
template <typename Slice>
void addRefiningVertices(Slice &V, TriangleTable &TT, vertexQs& VQ) {
  size_t n = V.size();
  size_t size = min(VQ.size(), n);

  sequence<simplex_t> t(size);
  sequence<bool> flags(size);

  size_t top = n;

  // Process all vertices, retrying failures in subsequent chunks.
  while(top > 0) {
    size_t cnt = min<size_t>(size, top);
    size_t offset = top-cnt;

    // Phase 1: Find cavities and reserve vertices
    parallel_for (0, cnt, [&] (size_t j) {
      flags[j] = findAndReserveCavity(V[j+offset], t[j], &VQ[j]);});

    // Phase 2: Check reservations and insert points for winners
    parallel_for (0, cnt, [&] (size_t j) {
      // Flag is true if insertion FAILED.
      flags[j] = flags[j] && !addCavity(V[j+offset], t[j], &VQ[j], TT);});

    // Phase 3: Pack failed vertices to the front of the chunk to be retried.
    auto remain = pack(V.cut(offset,offset+cnt), flags.cut(0,cnt));
    parallel_for (0, remain.size(), [&] (size_t j) {V[j+offset] = remain[j];});
    top = top-cnt+remain.size(); // Adjust top of work stack
  }
}

