// *************************************************************

constexpr size_t QSIZE = 20000;

triangles<point> refine(triangles<point>& Tri) {
  int expandFactor = 4;
  size_t n = Tri.numPoints();
  size_t m = Tri.numTriangles();
  size_t extraVertices = expandFactor*n;
  size_t totalVertices = n + extraVertices;
  size_t totalTriangles = m + 2 * extraVertices;

  sequence<vertex_t> Vertices;
  sequence<triang_t> Triangles;

  std::tie(Triangles, Vertices) = topology_from_triangles(Tri, extraVertices);

  sequence<vertex_t*> V(extraVertices);

  // Set up pre-allocated memory for new triangles
  parallel_for (m, totalTriangles, [&] (size_t i) {
    Triangles[i].id = i;
    Triangles[i].initialized = 0;
  });

  // Set up pre-allocated memory for new vertices
  parallel_for (0, extraVertices, [&] (size_t i) {
    V[i] = new (&Vertices[i+n]) vertex_t(point(0,0), i+n);
    // Give each one a pointer to two triangles to use for splits
    V[i]->t = &Triangles[m + 2*i];
  });

  size_t numPoints = n;

  // Initial work queue of skinny triangles
  TriangleTable workQ = makeTriangleTable(numTriangs);
  parallel_for(0, m, [&] (size_t i) {
    if (skinnyTriangle(&Triangles[i])) {
      workQ.insert(&Triangles[i]);
      Triangles[i].bad = 1;
    } else {
      Triangles[i].bad = 0;
    }
  });

  vertexQs VQ(QSIZE);

  // Main refinement loop: process batches of bad triangles until none remain.
  while (true) {
    // Efficiently filter the work queue for triangles that are still bad.
    auto badT = parlay::filter(workQ, [](const triang_t* t) { return t->bad; });
    size_t numBad = badT.size();

    if (numBad == 0) break;
    if (numPoints + numBad > totalVertices) {
      // A more robust implementation might reallocate and continue.
      std::cerr << "Error: Ran out of pre-allocated vertices." << std::endl;
      abort();
    }
    size_t offset = numPoints - n;

    // Assign one new vertex per bad triangle
    parallel_for (0, numBad, [&] (size_t i) {
      badT[i]->bad = 2; // Mark as 'in progress'
      V[i + offset]->badT = badT[i];
    });

    // Create the work queue for the next iteration
    TriangleTable next_workQ = makeTriangleTable(numBad);

    // Perform insertions. New bad triangles are added to next_workQ.
    auto Vtx_slice = V.cut(offset, offset+numBad);
    addRefiningVertices(Vtx_slice, next_workQ, VQ);

    // Re-queue any triangles that were not processed in this round.
    parallel_for (0, numBad, [&] (size_t i) {
      if (badT[i]->bad == 2) {
        badT[i]->bad = 1; // Reset to 'bad'
        next_workQ.insert(badT[i]);
      }
    });

    workQ = std::move(next_workQ);
    numPoints += numBad;
  }

  // Extract final vertices for the output.
  // We re-ID them to be contiguous from 0.
  auto I = parlay::pack_index(parlay::tabulate(numPoints, [&](size_t i) {
    // Unused pre-allocated vertices still have a non-null badT
    return Vertices[i].badT == NULL;
  }));
  size_t final_num_points = I.size();

  parlay::sequence<point> rp(final_num_points);
  parallel_for (0, final_num_points, [&] (size_t i) {
    Vertices[I[i]].id = i;
    rp[i] = Vertices[I[i]].pt;
  });

  // Extract final triangles for the output, remapping vertex indices.
  auto TI = parlay::pack_index(parlay::tabulate(totalTriangles, [&](size_t i) {
    return Triangles[i].initialized;
  }));

  auto rt = parlay::tabulate(TI.size(), [&](size_t i) -> tri {
    auto& t = Triangles[TI[i]];
    return {static_cast<unsigned int>(t.vtx[0]->id),
            static_cast<unsigned int>(t.vtx[1]->id),
            static_cast<unsigned int>(t.vtx[2]->id)};
  });

  return triangles<point>(std::move(rp), std::move(rt));
}

