using parlay::parallel_for;
using parlay::sequence;
using parlay::pack;
using parlay::pack_index;

using vertex_t = vertex<point>;
using simplex_t = simplex<point>;
using triang_t = triangle<point>;
using vect = typename point::vector;

struct Qs {
  parlay::small_vector<vertex<point>*, 64> vertexQ;
  parlay::small_vector<simplex<point>, 64> simplexQ;
  Qs() = default;
};

using vertexQs = sequence<Qs>;

// *************************************************************
//   PARALLEL HASH TABLE TO STORE WORK QUEUE OF SKINNY TRIANGLES
// *************************************************************

struct hashTriangles {
  typedef triang_t* eType;
  typedef triang_t* kType;
  eType empty() {return NULL;}
  kType getKey(eType v) { return v;}
  size_t hash(kType s) { return hash64(s->id); }
  int cmp(kType s, kType s2) {
    return (s->id > s2->id) ? 1 : ((s->id == s2->id) ? 0 : -1);
  }
  bool cas(eType* p, eType o, eType n) {
    return pbbs::atomic_compare_and_swap(p, o, n);
  }
  bool replaceQ(eType s, eType s2) {return 0;}
};

typedef hashtable<hashTriangles> TriangleTable;
TriangleTable makeTriangleTable(size_t m) {
  return TriangleTable(m,hashTriangles());}

// *************************************************************
//   DEALING WITH THE CAVITY
// *************************************************************

// Uses the radius-edge ratio to check for small angles.
// A triangle is skinny if R/l_min > 1/(2*sin(Theta_min)),
// where R is circumradius, l_min is shortest edge length.
// This is equivalent to R^2/l_min^2 > 1/(4*sin^2(Theta_min)).
// This check avoids trigonometry and square roots in the common case.
inline bool skinnyTriangle(triang_t *t) {
  static const double min_angle_deg = 30.0;
  // Precompute the quality limit squared.
  static const double quality_limit_sq = [] {
    constexpr double PI = 3.14159265358979323846;
    double min_angle_rad = min_angle_deg * PI / 180.0;
    double sin_min_angle = std::sin(min_angle_rad);
    return 1.0 / (4.0 * sin_min_angle * sin_min_angle);
  }();

  point p1 = t->vtx[0]->pt;
  point p2 = t->vtx[1]->pt;
  point p3 = t->vtx[2]->pt;

  double a2 = (p2-p3).len_sq();
  double b2 = (p1-p3).len_sq();
  double c2 = (p1-p2).len_sq();

  double min_edge_sq = std::min({a2, b2, c2});

  // If the triangle is degenerate, it's not skinny.
  if (min_edge_sq < 1e-20) return false;

  // 2*Area = |p1.x(p2.y-p3.y) + p2.x(p3.y-p1.y) + p3.x(p1-p2.y)|
  double area_times_2 = std::abs(p1.x*(p2.y - p3.y) + p2.x*(p3.y - p1.y) + p3.x*(p1.y-p2.y));

  // If collinear, not skinny.
  if (area_times_2 < 1e-20) return false;

  // R^2 = (a^2 * b^2 * c^2) / (16 * Area^2) = (a^2 * b^2 * c^2) / (4 * (2*Area)^2)
  double circumradius_sq = (a2 * b2 * c2) / (4.0 * area_times_2 * area_times_2);

  return circumradius_sq > min_edge_sq * quality_limit_sq;
}

inline bool obtuse(simplex_t t) {
  int o = t.o;
  point p0 = t.t->vtx[(o+1)%3]->pt;
  vect v1 = t.t->vtx[o]->pt - p0;
  vect v2 = t.t->vtx[(o+2)%3]->pt - p0;
  return (v1.dot(v2) < 0.0);
}

inline point circumcenter(simplex_t t) {
  if (t.isTriangle())
    return triangleCircumcenter(t.t->vtx[0]->pt, t.t->vtx[1]->pt, t.t->vtx[2]->pt);
  else { // t.isBoundary()
    point p0 = t.t->vtx[(t.o+2)%3]->pt;
    point p1 = t.t->vtx[t.o]->pt;
    return p0 + (p1-p0)/2.0;
  }
}

// this side affects the simplex_t by moving it into the right orientation
// and setting the boundary if the circumcenter encroaches on a boundary
inline bool checkEncroached(simplex_t& t) {
  if (t.isBoundary()) return 0;
  int i;
  for (i=0; i < 3; i++) {
    if (t.across().isBoundary() && (t.farAngle() > 45.0)) break;
    t = t.rotClockwise();
  }
  if (i < 3) return t.boundary = 1;
  else return 0;
}

// Finds the cavity for v and its boundary vertices using BFS.
// The boundary vertices are pushed onto q->vertexQ and
// simplices to be deleted on q->simplexQ (both initially empty).
void find_cavity_and_boundary_bfs(vertex_t *v, simplex_t t, Qs *q) {
    parlay::small_vector<simplex_t, 64> q_bfs;
    parlay::hash_table<parlay::hash_struct<triang_t*>> visited_tris(128);

    q->simplexQ.clear();
    q->vertexQ.clear();

    q_bfs.push_back(t);
    visited_tris.insert(t.t);
    size_t head = 0;

    parlay::hash_table<parlay::hash_struct<vertex_t*>> boundary_verts(64);

    while(head < q_bfs.size()) {
        simplex_t curr = q_bfs[head++];
        q->simplexQ.push_back(curr);

        for (int i = 0; i < 3; i++) {
            simplex_t neighbor = curr.across();
            if (neighbor.isTriangle() && neighbor.inCirc(v)) {
                if (visited_tris.insert(neighbor.t)) { // If not already visited
                    q_bfs.push_back(neighbor);
                }
            } else {
                // This is a boundary edge of the cavity.
                // The vertices of this edge are part of the cavity boundary.
                boundary_verts.insert(curr.firstVertex());
                boundary_verts.insert(curr.rotClockwise().rotClockwise().firstVertex());
            }
            curr = curr.rotClockwise();
        }
    }
    q->vertexQ = boundary_verts.entries();
}

