#include "parlay/primitives.h"
#include "parlay/internal/get_time.h"
#include "pam/pam.h"
#include "sweep.h"
#include "range.h"

struct RangeQuery {
  // The set data structure for the sweep-line.
  // It stores points, ordered by y then x.
  struct set_t {
    using key_t = point;
    static bool comp(key_t a, key_t b) {
      return std::tie(a.y, a.x) < std::tie(b.y, b.x);
    }
  };
  using coord_set = pam_set<set_t>;

  // ts[i] stores a y-sorted set of all points with x-coordinate
  // less than the x-coordinate of the i-th point in the x-sorted input.
  parlay::sequence<coord_set> ts;
  // The sorted x-coordinates of the input points.
  parlay::sequence<coord> xs;

  RangeQuery(parlay::sequence<point> const &points) {
    // 1. Sort points by x-coordinate. This is the sweep order.
    auto sorted_points = parlay::sort(points, [](point a, point b) {
      return a.x < b.x;
    });

    // 2. Extract the sorted x-coordinates for binary search during queries.
    xs = parlay::map(sorted_points, [](point p) { return p.x; });

    // 3. Define the operations for the parallel sweep.
    auto insert = [](coord_set m, point a) {
      return coord_set::insert(std::move(m), a);
    };

    auto build = [](point* s, point* e) {
      return coord_set(s, e);
    };

    auto fold = [](coord_set m1, coord_set m2) {
      return coord_set::map_union(std::move(m1), std::move(m2));
    };

    // 4. Perform the parallel sweep.
    //    `sweep` computes a prefix structure. `ts[i]` will contain the union
    //    of points from `sorted_points[0...i-1]`, stored in a `coord_set`.
    //    We pass the x-sorted points, which fixes a bug in the baseline.
    ts = sweep<coord_set>(sorted_points, coord_set(), insert, build, fold);
  }

  // Query for a single rectangle. Marked const for correctness.
  long count_in_range(const query& q) const {
    // We want to count points `p` where `q.x1 <= p.x <= q.x2` and `q.y1 <= p.y <= q.y2`.
    // Using the sweep-line structure, this is equivalent to:
    // (count of points with `p.x <= q.x2` and y in range) - (count of points with `p.x < q.x1` and y in range)

    // Find index `l` for the `p.x < q.x1` boundary.
    // `std::lower_bound` finds the first element `>= q.x1`.
    // The prefix `ts[l]` contains points with x-coordinates less than `xs[l]`,
    // which are all points with `p.x < q.x1`. This is correct.
    auto it_l = std::lower_bound(xs.begin(), xs.end(), q.x1);
    size_t l = std::distance(xs.begin(), it_l);

    // Find index `r` for the `p.x <= q.x2` boundary.
    // `std::upper_bound` finds the first element `> q.x2`.
    // The prefix `ts[r]` contains points with x-coordinates less than `xs[r]`,
    // which are all points with `p.x <= q.x2`. This is correct and fixes a bug
    // in the baseline which used `lower_bound`.
    auto it_r = std::upper_bound(xs.begin(), xs.end(), q.x2);
    size_t r = std::distance(xs.begin(), it_r);

    // If the query's x-range is empty or invalid, no points can be inside.
    if (l >= r) {
      return 0;
    }

    // Define boundary points for the y-range query on the PAM sets.
    // `rank({-inf, y})` counts elements with coordinate < y.
    // `rank({+inf, y})` counts elements with coordinate <= y.
    // We want `count(y <= q.y2) - count(y < q.y1)`.
    const point y1_p(-std::numeric_limits<coord>::infinity(), q.y1);
    const point y2_p(std::numeric_limits<coord>::infinity(), q.y2);

    // Helper to perform a 1D range query on a given PAM set.
    auto query_y_range = [&](const coord_set& s) {
        return s.rank(y2_p) - s.rank(y1_p);
    };

    // Count in `ts[r]` (points with `p.x <= q.x2`)
    long right_count = query_y_range(ts[r]);

    // Count in `ts[l]` (points with `p.x < q.x1`)
    long left_count = query_y_range(ts[l]);

    return right_count - left_count;
  }

  void clear() {
    ts.clear();
    // This is crucial for the PAM library's concurrent garbage collection.
    coord_set::GC::finish();
  }
};

long range(Points const &points, Queries const &queries, bool verbose) {
  parlay::internal::timer t("range", verbose);

  RangeQuery r(points);
  t.next("build");

  // Use parlay::map_reduce for a more efficient query phase, avoiding
  // the materialization of an intermediate sequence of all counts.
  long total = parlay::map_reduce(queries,
    [&](const query& q) { return r.count_in_range(q); },
    parlay::add_monoid<long>());

  t.next("query");

  r.clear();
  t.next("clear");
  return total;
}

#include <algorithm>
#include <limits>
#include <cfloat>
#include "parlay/primitives.h"
#include "parlay/internal/get_time.h"
#include "pam/pam.h"
#include "sweep.h"
