// The set_t struct defines the key type and comparison for the PAM set.
// It stores points and compares them lexicographically by (y, x),
// which is necessary for the 1D data structure in our plane sweep.
struct set_t {
  using key_t = point;
  static bool comp(key_t a, key_t b) {
    if (a.y != b.y) return a.y < b.y;
    return a.x < b.x;
  }
};
using coord_set = pam::pam_set<set_t>;

long range(Points const &points, Queries const &queries, bool verbose) {
  parlay::internal::timer t("range", verbose);

  // Step 1: Collect all unique x-coordinates from points and query boundaries.
  // This defines the critical "event points" for our plane sweep. By only
  // considering these coordinates, we significantly reduce the number of
  // data structures to build compared to a version-per-point approach.
  auto px = parlay::map(points, [](const point& p){ return p.x; });
  auto qx1 = parlay::map(queries, [](const query& q){ return q.x1; });
  auto qx2 = parlay::map(queries, [](const query& q){ return q.x2; });
  auto all_x = parlay::flatten(parlay::make_slice(px, qx1, qx2));
  parlay::sort_inplace(all_x);
  auto unique_x = parlay::unique(all_x);
  auto unique_x_slice = parlay::make_slice(unique_x);

  t.next("collect_x");

  // Step 2: Group points into buckets based on their x-coordinate.
  // Each bucket corresponds to a vertical slab defined by adjacent unique x-coordinates.
  auto point_buckets = parlay::map(points, [&](const point& p) {
    auto it = std::upper_bound(unique_x_slice.begin(), unique_x_slice.end(), p.x);
    // The bucket index is the index of the interval the point falls into.
    // Since all point x-coordinates are in unique_x, this is safe.
    size_t bucket_idx = std::distance(unique_x_slice.begin(), it) - 1;
    return std::make_pair(bucket_idx, p);
  });
  auto grouped_points = parlay::group_by_key(point_buckets);

  t.next("group_points");

  // Step 3: For each bucket, build a PAM set of the points within it.
  // This gives us a 1D data structure for each vertical slab of the plane.
  // We do this in parallel for all buckets.
  parlay::sequence<coord_set> bucket_y_trees(unique_x.size(), coord_set{});
  parlay::for_each(grouped_points, [&](const auto& group) {
    auto points_in_bucket = parlay::map(group.second, [](const auto& pair) { return pair.second; });
    bucket_y_trees[group.first] = coord_set(points_in_bucket.begin(), points_in_bucket.end());
  });

  t.next("build_bucket_trees");

  // Step 4: Compute the prefix-union of the bucket trees.
  // `prefix_y_trees[i]` will contain all points with x < unique_x[i+1].
  // This is the core of the parallel plane sweep, efficiently implemented
  // with parlay::scan_inclusive and pam::map_union.
  auto prefix_y_trees = parlay::scan_inclusive(bucket_y_trees,
    [](const coord_set& a, const coord_set& b) {
      return coord_set::map_union(a, b);
    });

  t.next("prefix_union");

  // Step 5: Answer all queries in parallel.
  auto counts = parlay::map(queries, [&](const query& q) -> long {
    // Helper to count points in a PAM set within a given y-range [y1, y2].
    auto count_in_y_range = [&](const coord_set& s) {
      if (s.empty()) return 0L;
      // Use rank to count points in [y1, y2]. This is equivalent to
      // count(p.y <= y2) - count(p.y < y1).
      auto upper_p = point(std::numeric_limits<coord>::max(), q.y2);
      auto lower_p = point(std::numeric_limits<coord>::lowest(), q.y1);
      return static_cast<long>(s.rank(upper_p)) - static_cast<long>(s.rank(lower_p));
    };

    // The number of points in [x1, x2] x [y1, y2] is calculated using
    // inclusion-exclusion: count(x <= x2) - count(x < x1).

    // Find count for points with x <= x2.
    auto it_r = std::upper_bound(unique_x_slice.begin(), unique_x_slice.end(), q.x2);
    long count_r = 0;
    if (it_r != unique_x_slice.begin()) {
      size_t bucket_idx_r = std::distance(unique_x_slice.begin(), it_r) - 1;
      if (bucket_idx_r < prefix_y_trees.size()) {
          count_r = count_in_y_range(prefix_y_trees[bucket_idx_r]);
      }
    }

    // Find count for points with x < x1.
    auto it_l = std::lower_bound(unique_x_slice.begin(), unique_x_slice.end(), q.x1);
    long count_l = 0;
    if (it_l != unique_x_slice.begin()) {
      size_t bucket_idx_l = std::distance(unique_x_slice.begin(), it_l) - 1;
      if (bucket_idx_l < prefix_y_trees.size()) {
          count_l = count_in_y_range(prefix_y_trees[bucket_idx_l]);
      }
    }

    return count_r - count_l;
  });

  long total = parlay::reduce(counts);
  t.next("query");

  // Explicitly clear data structures to manage memory and trigger GC.
  bucket_y_trees.clear();
  prefix_y_trees.clear();
  coord_set::GC::finish();
  t.next("clear");

  return total;
}

