struct RangeQuery {
  // A balanced binary search tree storing points, ordered by y then x.
  struct set_t {
    using key_t = point;
    static bool comp(key_t a, key_t b) {
      if (a.y != b.y) return a.y < b.y;
      return a.x < b.x;
    }
  };
  using coord_set = pam_set<set_t>;

  // ts[i] contains all points p with p.x <= xs[i]
  parlay::sequence<coord_set> ts;
  // Unique, sorted x-coordinates from the input points
  parlay::sequence<coord> xs;

  RangeQuery(parlay::sequence<point> const &points) {
    // 1. Sort points primarily by x, secondarily by y.
    // The secondary sort on y improves cache-efficiency when building pam_sets from slices.
    auto sorted_points = parlay::sort(points, [](point a, point b) {
      if (a.x != b.x) return a.x < b.x;
      return a.y < b.y;
    });

    // 2. Group points by their x-coordinate.
    // This gives a sequence of pairs: (unique_x, slice_of_points_with_that_x)
    auto grouped_by_x = parlay::group_by_key(sorted_points, [](point p) { return p.x; });

    // 3. Extract the unique x-coordinates.
    xs = parlay::map(grouped_by_x, [](const auto& p) { return p.first; });

    // 4. For each unique x, create a pam_set of the corresponding points.
    // The points within each slice are already sorted by y, which can make
    // the pam_set constructor more efficient.
    auto sets_by_x = parlay::map(grouped_by_x, [](const auto& p) {
      return coord_set(p.second.begin(), p.second.end());
    });

    // 5. Compute the prefix union. ts[i] will be the union of all sets for x-coordinates up to xs[i].
    // This is the core of the plane sweep.
    ts = parlay::scan_inclusive(sets_by_x, [](const coord_set& a, const coord_set& b) {
      return coord_set::map_union(a, b);
    });
  }

  // Helper to count points in a set s with y-coordinate in [y1, y2]
  long count_y_range(const coord_set& s, coord y1, coord y2) const {
    // pam_set::rank(k) counts elements strictly less than k.
    // The comparator is: (a.y < b.y) || ((a.y == b.y) && (a.x < b.x))

    // To count points p where p.y <= y2:
    // We need a key K_upper such that for any p with p.y <= y2, p < K_upper.
    // The key point(max_coord, y2) works because for any point p with p.y == y2,
    // its x-coordinate will be less than max_coord.
    auto count_le_y2 = s.rank(point(std::numeric_limits<coord>::max(), y2));

    // To count points p where p.y < y1:
    // We need a key K_lower such that it's greater than all points with p.y < y1
    // and not greater than any point with p.y >= y1.
    // The key point(min_coord, y1) works. rank() will count points p where
    // (p.y < y1) or (p.y == y1 and p.x < min_coord), the second part of which is impossible.
    auto count_lt_y1 = s.rank(point(-std::numeric_limits<coord>::max(), y1));

    return count_le_y2 - count_lt_y1;
  }

  // Counts points in the closed rectangle [q.x1, q.x2] x [q.y1, q.y2]
  long count_in_range(query q) const {
    // Find points with x <= x2.
    // upper_bound finds the first element > q.x2.
    // The index r_idx gives the number of unique x-coords <= q.x2.
    auto r_it = std::upper_bound(xs.begin(), xs.end(), q.x2);
    size_t r_idx = std::distance(xs.begin(), r_it);

    // Find points with x < x1.
    // lower_bound finds the first element >= q.x1.
    // The index l_idx gives the number of unique x-coords < q.x1.
    auto l_it = std::lower_bound(xs.begin(), xs.end(), q.x1);
    size_t l_idx = std::distance(xs.begin(), l_it);

    // Count of points in (-inf, x2] x [y1, y2]
    long count_at_right_bound = 0;
    if (r_idx > 0) {
      count_at_right_bound = count_y_range(ts[r_idx - 1], q.y1, q.y2);
    }

    // Count of points in (-inf, x1) x [y1, y2]
    long count_at_left_bound = 0;
    if (l_idx > 0) {
      count_at_left_bound = count_y_range(ts[l_idx - 1], q.y1, q.y2);
    }

    return count_at_right_bound - count_at_left_bound;
  }

  void clear() {
    ts.clear();
    xs.clear();
    coord_set::GC::finish();
  }
};

long range(Points const &points, Queries const &queries, bool verbose) {
  parlay::internal::timer t("range", verbose);
  if (points.empty()) {
    // If there are no points, all query counts are 0.
    return 0L;
  }
  RangeQuery r(points);
  t.next("build");

  // Use delayed_map to avoid allocating an intermediate sequence of counts.
  // This computes the sum of counts for all queries in parallel.
  long total = parlay::reduce(parlay::delayed_map(queries, [&](const query& q) {
    return r.count_in_range(q);
  }));

  t.next("query");
  r.clear();
  t.next("clear");
  return total;
}

