// The RangeQuery class encapsulates the plane-sweep data structure.
// It is built on an x-sorted sequence of points. For each prefix of points,
// it maintains a persistent balanced binary search tree (a pam_set) of those
// points, ordered by y-coordinate. This allows for efficient querying.
struct RangeQuery {
  // Definition for the pam_set, ordering points by y then x.
  struct set_t {
    using key_t = point;
    static bool comp(key_t a, key_t b) {
      if (a.y != b.y) return a.y < b.y;
      return a.x < b.x;
    }
  };
  using coord_set = pam_set<set_t>;

  // ts[i] is the pam_set of points A[0...i] from the x-sorted sequence A.
  parlay::sequence<coord_set> ts;
  // xs[i] is the x-coordinate of point A[i].
  parlay::sequence<coord> xs;
  // A const empty set for boundary cases to avoid re-creation.
  const coord_set empty_set;

  // Constructor builds the plane-sweep structure.
  // This is the most expensive part of the process.
  // Work: O(N log N), Span: O(log^2 N), Space: O(N log N)
  RangeQuery(parlay::sequence<point> const &points) {
    // 1. Sort points by x-coordinate. This defines the sweep-line order.
    auto A = parlay::sort(points, [](point a, point b) { return a.x < b.x; });

    xs = parlay::map(A, [](point p) { return p.x; });

    // 2. Perform a parallel prefix sum (scan) over the x-sorted points.
    // The "sum" is the union of point sets. We use a persistent pam_set for the sets.
    // The sweep function is a specialized, optimized scan for this geometry pattern.
    auto insert = [](coord_set m, point a) {
      return coord_set::insert(std::move(m), a);
    };
    auto build = [](point* s, point* e) {
      // Build a set from a block of points. This involves sorting the block by y.
      return coord_set(s, e);
    };
    auto fold = [](coord_set m1, coord_set m2) {
      // Merge two sets. pam_set::map_union is a persistent, parallel union operation.
      return coord_set::map_union(std::move(m1), std::move(m2));
    };

    // The sweep function requires the points to be sorted by the sweep dimension (x).
    // The original code had a bug here, passing the unsorted 'points' sequence.
    ts = sweep<coord_set>(A, coord_set(), insert, build, fold);
  }

  // Counts points in a given y-range [y1, y2] within a pam_set.
  // Work: O(log N), Span: O(log N)
  static long count_in_y_range(const coord_set& s, coord y1, coord y2) {
    if (s.empty()) return 0L;
    // Count elements p where p.y <= y2.
    // rank(p_upper) counts elements strictly smaller than p_upper.
    // p_upper = (DBL_MAX, y2). An element p is smaller if (p.y < y2) or (p.y == y2 && p.x < DBL_MAX).
    // This correctly counts all elements with p.y <= y2.
    long upper_rank = s.rank(point(DBL_MAX, y2));

    // Count elements p where p.y < y1.
    // p_lower = (-DBL_MAX, y1). An element p is smaller if (p.y < y1) or (p.y == y1 && p.x < -DBL_MAX).
    // The second condition is impossible, so this correctly counts elements with p.y < y1.
    long lower_rank = s.rank(point(-DBL_MAX, y1));

    // The difference is count({p | y1 <= p.y <= y2})
    return upper_rank - lower_rank;
  }

  // Counts points within the query rectangle [x1, x2] x [y1, y2].
  // Work: O(log N), Span: O(log N)
  long count_in_range(query q) const {
    // We want to count points p such that:
    // q.x1 <= p.x <= q.x2  AND  q.y1 <= p.y <= q.y2
    // This is equivalent to the 2D range query using inclusion-exclusion:
    // count({p | p.x <= q.x2, y-range}) - count({p | p.x < q.x1, y-range})

    // Find the set of points {p | p.x < q.x1}.
    // These are the points A[0...l_idx-1] where xs[l_idx] is the first element >= q.x1.
    auto it_l = std::lower_bound(xs.begin(), xs.end(), q.x1);
    long l_idx = std::distance(xs.begin(), it_l);
    const coord_set& s_before_l = (l_idx == 0) ? empty_set : ts[l_idx - 1];

    // Find the set of points {p | p.x <= q.x2}.
    // These are the points A[0...r_idx-1] where xs[r_idx] is the first element > q.x2.
    auto it_r = std::upper_bound(xs.begin(), xs.end(), q.x2);
    long r_idx = std::distance(xs.begin(), it_r);
    const coord_set& s_up_to_r = (r_idx == 0) ? empty_set : ts[r_idx - 1];

    long count_r = count_in_y_range(s_up_to_r, q.y1, q.y2);
    long count_l = count_in_y_range(s_before_l, q.y1, q.y2);

    return count_r - count_l;
  }

  // Frees memory used by the pam_sets by triggering garbage collection.
  void clear() {
    ts.clear();
    coord_set::GC::finish();
  }
};

