// A Fenwick Tree (or Binary Indexed Tree) for fast prefix sums.
// It supports point updates and prefix queries in O(log N) time.
// This implementation is not thread-safe by itself; synchronization
// must be handled by the caller.
class FenwickTree {
public:
  FenwickTree(size_t size) : tree(size + 1, 0) {}

  void add(size_t index, long value) {
    index++; // 1-based indexing
    while (index < tree.size()) {
      tree[index] += value;
      index += index & (-index);
    }
  }

  long query(size_t index) const {
    index++; // 1-based indexing
    long sum = 0;
    while (index > 0) {
      sum += tree[index];
      index -= index & (-index);
    }
    return sum;
  }

  long query_range(size_t start, size_t end) const {
    if (start > end) return 0;
    return query(end) - (start > 0 ? query(start - 1) : 0);
  }

private:
  std::vector<long> tree;
};


enum EventType { QUERY_START, POINT, QUERY_END };

struct Event {
  coord x, y1, y2;
  EventType type;
  size_t q_idx;
  size_t cy1, cy2; // Compressed y-coordinates

  bool operator<(const Event& other) const {
    if (x != other.x) return x < other.x;
    return type < other.type;
  }
};

long range(Points const &points, Queries const &queries, bool verbose) {
  parlay::internal::timer t("range", verbose);

  // 1. Event Generation & Coordinate Compression
  size_t n = points.size();
  size_t m = queries.size();
  parlay::sequence<Event> events(n + 2 * m);
  parlay::sequence<coord> all_y(n + 2 * m);

  parlay::parallel_for(0, n, [&](size_t i) {
    events[i] = {points[i].x, points[i].y, 0.0, POINT, 0, 0, 0};
    all_y[i] = points[i].y;
  });

  parlay::parallel_for(0, m, [&](size_t i) {
    events[n + 2 * i] =     {queries[i].x1, queries[i].y1, queries[i].y2, QUERY_START, i, 0, 0};
    events[n + 2 * i + 1] = {queries[i].x2, queries[i].y1, queries[i].y2, QUERY_END, i, 0, 0};
    all_y[n + 2 * i] = queries[i].y1;
    all_y[n + 2 * i + 1] = queries[i].y2;
  });

  parlay::sort_inplace(all_y);
  auto unique_y = parlay::unique(all_y);
  size_t y_universe_size = unique_y.size();

  parlay::parallel_for(0, events.size(), [&](size_t i) {
    auto& event = events[i];
    auto it1 = std::lower_bound(unique_y.begin(), unique_y.end(), event.y1);
    event.cy1 = std::distance(unique_y.begin(), it1);
    if (event.type != POINT) {
      auto it2 = std::lower_bound(unique_y.begin(), unique_y.end(), event.y2);
      event.cy2 = std::distance(unique_y.begin(), it2);
    }
  });

  t.next("setup");

  // 2. Sort Events
  parlay::sort_inplace(events);
  t.next("sort");

  // 3. Parallel Plane Sweep
  parlay::sequence<std::atomic<long>> atomic_results(m);
  parlay::parallel_for(0, m, [&](size_t i) { atomic_results[i] = 0; });

  size_t block_size = 4096; // Tunable parameter
  size_t num_blocks = (events.size() + block_size - 1) / block_size;

  // Step 3a: Create delta maps for each block
  using DeltaMap = pam::map<size_t, int>;
  auto delta_maps = parlay::tabulate(num_blocks, [&](size_t i) {
    size_t start = i * block_size;
    size_t end = std::min((i + 1) * block_size, events.size());
    parlay::sequence<std::pair<size_t, int>> pairs;
    pairs.reserve(end - start);
    for (size_t j = start; j < end; j++) {
      if (events[j].type == POINT) {
        pairs.push_back({events[j].cy1, 1});
      }
    }
    return DeltaMap::from_key_vals(pairs, std::plus<int>());
  });
  t.next("deltas");

  // Step 3b: Scan the delta maps to get prefix sums of points
  auto scan_op = parlay::monoid(
      [](const DeltaMap& a, const DeltaMap& b) { return pam::map_union_with(a, b, std::plus<int>()); },
      DeltaMap()
  );
  auto prefix_sum_maps = parlay::scan(delta_maps, scan_op);
  t.next("scan");

  // Step 3c: Process each block with its corresponding prefix sum
  parlay::parallel_for(0, num_blocks, [&](size_t i) {
    FenwickTree bit(y_universe_size);
    if (i > 0) {
      for (auto const& [y, count] : prefix_sum_maps[i-1].first) {
        bit.add(y, count);
      }
    }

    size_t start = i * block_size;
    size_t end = std::min((i + 1) * block_size, events.size());

    for (size_t j = start; j < end; j++) {
      const auto& event = events[j];
      if (event.type == POINT) {
        bit.add(event.cy1, 1);
      } else {
        long count = bit.query_range(event.cy1, event.cy2);
        if (event.type == QUERY_START) {
          atomic_results[event.q_idx].fetch_add(-count, std::memory_order_relaxed);
        } else { // QUERY_END
          atomic_results[event.q_idx].fetch_add(count, std::memory_order_relaxed);
        }
      }
    }
