    // Lexicographical comparison: sort by y, then by x.
    static bool comp(key_t a, key_t b) {
      return std::tie(a.y, a.x) < std::tie(b.y, b.x);
    }
  };
  using coord_set = pam_set<set_t>;

  // A sequence of persistent PAMs. ts[i] contains all points from the
  // x-sorted input with index < i.
  parlay::sequence<coord_set> ts;
  // The sorted x-coordinates of the input points, for efficient searching.
  parlay::sequence<coord> xs;

  RangeQuery(parlay::sequence<point> const &points) {
    // 1. Sort the points by their x-coordinate. This is the sweep-line order.
    auto A = parlay::sort(points, [](point a, point b) { return a.x < b.x; });

    // 2. Extract the sorted x-coordinates for efficient binary searching during queries.
    xs = parlay::map(A, [](point p) { return p.x; });

    // 3. Define the operations for the parallel sweep.
    //    `insert`: Add a single point to a set.
    //    `build`: Create a set from a range of points (the base case for the sweep).
    //    `fold`: Merge two sets.
    //    Using std::move allows PAM to reuse tree nodes, reducing allocations.
    auto insert = [](coord_set m, point a) { return coord_set::insert(std::move(m), a); };
    auto build = [](point* s, point* e) { return coord_set(s, e); };
    auto fold = [](coord_set m1, coord_set m2) { return coord_set::map_union(std::move(m1), std::move(m2)); };

    // 4. Perform a parallel sweep over the x-sorted points.
    //    This is a parallel prefix sum (scan) that builds a sequence of persistent sets.
    //    ts[i] will be the union of sets built from points A[0]...A[i-1].
    //    A grain size of 2048 is chosen as a good trade-off between parallel
    //    slackness and the overhead of merging large sets. This is a crucial
    //    tuning parameter for performance.
    ts = sweep<coord_set>(A, coord_set(), insert, build, fold, 2048);
  }

  // Count points within the query rectangle [q.x1, q.x2] x [q.y1, q.y2].
  long count_in_range(query q) const {
    // The query is solved using the inclusion-exclusion principle on 2D ranges.
    // Count = (pts with x <= x2, y <= y2) - (pts with x <= x2, y < y1)
    //       - (pts with x < x1, y <= y2) + (pts with x < x1, y < y1)
    // This is equivalent to:
    // (count in y-range for slab x <= x2) - (count in y-range for slab x < x1)

    // Find the range of indices in the x-sorted points that cover [q.x1, q.x2].
    // l_it: iterator to the first point with x >= q.x1
    auto l_it = std::lower_bound(xs.begin(), xs.end(), q.x1);
    // r_it: iterator to the first point with x > q.x2
    auto r_it = std::upper_bound(xs.begin(), xs.end(), q.x2);

    // The corresponding persistent sets are ts[l_idx] and ts[r_idx].
    // ts[l_idx] contains all points with x < q.x1.
    // ts[r_idx] contains all points with x <= q.x2.
    const auto& set_before_l = ts[std::distance(xs.begin(), l_it)];
    const auto& set_before_r = ts[std::distance(xs.begin(), r_it)];

    // The number of points in a set with y-coordinate in [y1, y2] is
    // (count of y <= y2) - (count of y < y1).
    // We use rank queries on the y-sorted PAMs to find these counts.
    // A query point with DBL_MAX for x is larger than any other point with the
    // same y, effectively counting y <= y_query.
    // A query point with -DBL_MAX for x is smaller than any other point with the
    // same y, effectively counting y < y_query.
    long count_le_y2_before_l = set_before_l.rank(point(DBL_MAX, q.y2));
    long count_lt_y1_before_l = set_before_l.rank(point(-DBL_MAX, q.y1));

    long count_le_y2_before_r = set_before_r.rank(point(DBL_MAX, q.y2));
    long count_lt_y1_before_r = set_before_r.rank(point(-DBL_MAX, q.y1));

