// The points are stored in a tree sorted by y-coordinate.
struct RangeQuery {
  // A pam_set of points, ordered lexicographically by (y, x).
  // This is the data structure at each step of the sweep line.
  struct set_t {
    using key_t = point;
    static bool comp(key_t a, key_t b) { 
      // Lexicographical comparison is more robustly and cleanly written with std::tie
      return std::tie(a.y, a.x) < std::tie(b.y, b.x);
    }
  };
  using coord_set = pam::set<set_t>;

  parlay::sequence<coord_set> ts;
  parlay::sequence<coord> xs;

  RangeQuery(parlay::sequence<point> const &points) {
    // 1. Sort points by x-coordinate. This defines the sweep order.
    auto A = parlay::sort(points, [](point a, point b) { return a.x < b.x; });

    // 2. Extract the sorted x-coordinates. This array allows mapping
    //    an x-value to an index in the sweep structure.
    xs = parlay::map(A, [](point p) { return p.x; });

    // 3. Perform a parallel prefix sum (scan) on the x-sorted points.
    // The "sum" operation is the union of the pam_sets of points.
    // `sweep` is assumed to be a parallel scan implementation that returns
    // an "exclusive-scan" style result: a sequence of size n+1 where
    // ts[i] is the aggregate of the first i elements of A.
    // ts[0] is the identity (empty set).
    auto insert = [](coord_set m, point a) {
      return coord_set::insert(m, a);
    };
    auto build = [](point* s, point* e) {
      return coord_set(s, e);
    };
    auto fold = [](coord_set m1, coord_set m2) {
      return coord_set::map_union(std::move(m1), std::move(m2));
    };

    // The sweep must be performed on the x-sorted points.
    ts = sweep<coord_set>(A, coord_set(), insert, build, fold, 1);
  }

  // Clear the data structure and force garbage collection for PAM.
  void clear() {
    ts.clear();
    xs.clear();
    coord_set::GC::finish();
  }
};

// Main function to perform 2D range queries.
long range(Points const &points, Queries const &queries, bool verbose) {
  parlay::internal::timer t("range", verbose);

  // Build the 2D range query data structure.
  RangeQuery r(points);
  t.next("build");

  // --- Query Phase ---

  // 1. Batch extract query coordinates for efficient parallel processing.
  auto x1s = parlay::map(queries, [](const query& q) { return q.x1; });
  auto x2s = parlay::map(queries, [](const query& q) { return q.x2; });

