  // parlay::lower_bound finds the first element >= value.
  // parlay::upper_bound finds the first element > value.
  // This correctly identifies the slice of points with x in [x1, x2].
  auto l_iters = parlay::lower_bound(r.xs, x1s);
  auto r_iters = parlay::upper_bound(r.xs, x2s);

  // 3. For each query, use the precomputed indices to find the count.
  auto counts = parlay::tabulate(queries.size(), [&](size_t i) -> long {
    long l_idx = l_iters[i] - r.xs.begin();
    long r_idx = r_iters[i] - r.xs.begin();

    // The query rectangle is [queries[i].x1, queries[i].x2] x [queries[i].y1, queries[i].y2].
    // Points with x in [x1, x2] are in the sorted slice A[l_idx...r_idx-1].
