    // `rank(point(-DBL_MAX, y1))` counts points with `y < y1`.
    // The difference gives the count for `y` in `[y1, y2]`.
    auto y_range_count = [&](const RangeQuery::coord_set& s, const query& q) {
        return s.rank(point(DBL_MAX, q.y2)) - s.rank(point(-DBL_MAX, q.y1));
    };

    long count_at_r = y_range_count(r.ts[r_idx], queries[i]);
    long count_at_l = y_range_count(r.ts[l_idx], queries[i]);

