  // ts[i] is a pam_set containing all points from the x-sorted input
  // with an index less than i.
  parlay::sequence<coord_set> ts;
  // xs stores the x-coordinates of the points, sorted.
  parlay::sequence<coord> xs;

  RangeQuery(parlay::sequence<point> const &points) {
    // 1. Sort points by x-coordinate. This is the basis of the sweep-line
    // algorithm.
    auto A = parlay::sort(points, [](point a, point b) { return a.x < b.x; });

    // 2. Extract and store the sorted x-coordinates for efficient lookups.
    xs = parlay::map(A, [](point p) { return p.x; });

    // 3. Define the operations for the parallel prefix-sum (sweep).
    // This operation is never used if the block size > 1.
    auto insert = [](coord_set m, point a) {
      return coord_set::insert(m, a);
    };

    // Bulk building a pam_set from a range is much more efficient than
    // repeated single insertions.
    auto build = [](point *s, point *e) { return coord_set(s, e); };

    // The union of two pam_sets is a persistent operation, meaning it reuses
    // unchanged parts of the trees, leading to O(n log n) space complexity
    // for the entire prefix-sum structure.
    auto fold = [](coord_set m1, coord_set m2) {
      return coord_set::map_union(m1, std::move(m2));
    };

    // 4. Perform the sweep. This computes the prefix-union of the y-sorted sets.
    // ts[i] will store the union of the first i points from the sorted
    // sequence A. Using a large block size (e.g., 2048) ensures that the
    // efficient `build` operation is used, improving performance.
    // The original code incorrectly used the unsorted `points` sequence here.
    ts = sweep<coord_set>(A, coord_set(), insert, build, fold, 2048);
  }

  // Counts points in the inclusive rectangle [q.x1, q.x2] x [q.y1, q.y2].
  long count_in_range(query q) {
    // The count is computed using the principle of inclusion-exclusion:
    //   count(x <= q.x2, y in [q.y1, q.y2])
    // - count(x < q.x1,  y in [q.y1, q.y2])

    // Find index `l` such that all points with index < l have x < q.x1.
    // std::lower_bound finds the first element >= q.x1. The indices [0, l-1]
    // correspond to points with x < xs[l], which is x < q.x1.
    auto l_it = std::lower_bound(xs.begin(), xs.end(), q.x1);
    long l = std::distance(xs.begin(), l_it);

