// Fenwick Tree (or Binary Indexed Tree) for point updates and prefix sums
struct FenwickTree {
  std::vector<long> bit;
  int size;

  FenwickTree(int sz) : size(sz + 1), bit(sz + 1, 0) {}

  void add(int idx, int delta) {
    for (++idx; idx < size; idx += idx & -idx) {
      bit[idx] += delta;
    }
  }

  // Queries sum of [0, idx]
  long query(int idx) {
    long sum = 0;
    for (++idx; idx > 0; idx -= idx & -idx) {
      sum += bit[idx];
    }
    return sum;
  }

  // Queries sum of [l, r]
  long query(int l, int r) {
    if (l > r) return 0;
    return query(r) - query(l - 1);
  }

  // Get all non-zero updates.
  parlay::sequence<std::pair<int, int>> get_updates() {
    parlay::sequence<std::pair<int, int>> updates;
    std::vector<long> current_values(size - 1);
    if (size > 1) {
        current_values[0] = query(0);
        for (int i = 1; i < size - 1; i++) {
            current_values[i] = query(i) - query(i-1);
        }
    }
    for(int i = 0; i < size - 1; i++) {
        if (current_values[i] != 0) {
            updates.push_back({i, static_cast<int>(current_values[i])});
        }
    }
    return updates;
  }
};


