#include "parlay/primitives.h"
#include "parlay/internal/get_time.h"
#include "pam/pam.h"
#include "sweep.h"
#include "range.h"

// The RangeQuery data structure is built by a sweep-line algorithm.
// It sorts the points by x-coordinate and then performs a parallel scan (sweep).
// At each step of the sweep, it maintains a persistent balanced binary search tree
// (a PAM set) of the y-coordinates of the points seen so far.
//
// A query for a rectangle [x1, x2] x [y1, y2] is answered by taking the
// difference of two structures: one for points with x <= x2 and one for
// points with x < x1. This gives the set of points with x in [x1, x2].
// On this resulting logical set, we can query for the number of points with
// y in [y1, y2].
struct RangeQuery {
  // The PAM set stores points, ordered by y then x.
  struct set_t {
    using key_t = point;
    // Use std::tie for clean and correct lexicographical comparison.
    static bool comp(key_t a, key_t b) { 
      return std::tie(a.y, a.x) < std::tie(b.y, b.x);
    }
  };
  using coord_set = pam_set<set_t>;

  // ts[i] stores a y-sorted PAM set of the first i points from the x-sorted list.
  parlay::sequence<coord_set> ts;
  // xs stores the sorted x-coordinates of the input points.
  parlay::sequence<coord> xs;

  RangeQuery(parlay::sequence<point> const &points) {
    // Sort points by x-coordinate (and y for stability).
    auto A = parlay::sort(points, [](point a, point b) {
      return std::tie(a.x, a.y) < std::tie(b.x, b.y);
    });

    // Extract the sorted x-coordinates for efficient binary searching.
    xs = parlay::map(A, [](point p) { return p.x; });

    // The sweep function builds the sequence of persistent trees.
    // It requires the input points to be sorted by the sweep dimension (x).
    // We pass the sorted sequence 'A' to it.
    auto insert = [](coord_set m, point a) {
      return coord_set::insert(m, a);
    };
    auto build = [](point* s, point* e) {
      return coord_set(s, e);
    };
    auto fold = [](coord_set m1, coord_set m2) {
      return coord_set::map_union(std::move(m1), std::move(m2));
    };

    // The sweep function is a parallel prefix sum (scan) that builds up the PAM sets.
    ts = sweep<coord_set>(A, coord_set(), insert, build, fold, 1);
  }

  // Counts points in the query rectangle [q.x1, q.x2] x [q.y1, q.y2].
  long count_in_range(query q) {
    // Find the range of indices in the x-sorted array corresponding to [q.x1, q.x2].
    // 'l' is the index of the first point with x >= q.x1.
    // The set ts[l] contains all points with x < x_l, which are all points with x < q.x1.
    auto l_it = parlay::lower_bound(xs, q.x1);

    // 'r' is the index of the first point with x > q.x2.
    // The set ts[r] contains all points with x <= q.x2.
    auto r_it = parlay::upper_bound(xs, q.x2);

    long l = std::distance(xs.begin(), l_it);
    long r = std::distance(xs.begin(), r_it);

    // The set of points with x in [q.x1, q.x2] is the difference between the
    // set of points with x <= q.x2 (represented by ts[r]) and the set of
    // points with x < q.x1 (represented by ts[l]).

    // Count points with y in [q.y1, q.y2] within the set for x <= q.x2.
    // rank(k) counts elements strictly less than k.
    // rank({max, y2}) counts elements with y <= y2.
    // rank({lowest, y1}) counts elements with y < y1.
    // The difference is the count of elements with y in [y1, y2].
    long right = ts[r].rank(point(std::numeric_limits<coord>::max(), q.y2)) -
                 ts[r].rank(point(std::numeric_limits<coord>::lowest(), q.y1));

    // Count points with y in [q.y1, q.y2] within the set for x < q.x1.
    long left = ts[l].rank(point(std::numeric_limits<coord>::max(), q.y2)) -
                ts[l].rank(point(std::numeric_limits<coord>::lowest(), q.y1));

    return right - left;
  }

  void clear() {
    ts.clear();
    // PAM uses a custom garbage collector for its persistent nodes.
    // We must explicitly trigger it to reclaim memory.
    coord_set::GC::finish();
  }
};

long range(Points const &points, Queries const &queries, bool verbose) {
  parlay::internal::timer t("range", verbose);
  RangeQuery r(points);
  t.next("build");

  // Process all queries in parallel and sum the results.
  auto counts = parlay::map(queries, [&](query q) {
    return r.count_in_range(q);
  });
  long total = parlay::reduce(counts);

