      std::cout << "  Query rect: [" << queries[i].x1 << ", " << queries[i].x2 << "] x ["
                << queries[i].y1 << ", " << queries[i].y2 << "]" << std::endl;
    }
  }, 1); // Use coarse-grained parallelism for the check itself.
  std::cout << "Total from queries: " << total << std::endl;
#endif

  r.clear();
  t.next("clear");
  return total;
}

