parlay::type_allocator<node> node_pool;

template <typename Particles>
node* buildTree(Particles& particles, size_t effective_size) {
  size_t n = particles.size();
  size_t en = std::max(effective_size, n);

  auto minmax = [] (box a, box b) {
    return box((a.first).minCoords(b.first),
	       (a.second).maxCoords(b.second));};
  auto pairs = parlay::delayed_map(particles, [&] (particle* p) {
      return box(p->pt, p->pt);});
  box b = parlay::reduce(pairs, parlay::make_monoid(minmax,pairs[0]));

  if (en < BOXSIZE || n < 10)
    return node_pool.allocate(parlay::to_sequence(particles), b);

  size_t d = 0;
  double Delta = 0.0;
  for (int i=0; i < 3; i++) {
    if (b.second[i] - b.first[i] > Delta) {
      d = i;
      Delta = b.second[i] - b.first[i];
    }
  }

  double splitpoint = (b.first[d] + b.second[d])/2.0;

  auto isLeft = parlay::delayed_map(particles, [&] (particle* p) {
      return std::pair(p->pt[d] < splitpoint, p);});
  auto foo = parlay::group_by_index(isLeft, 2);
  particles.clear();

  auto r = parlay::map(foo, [&] (auto& x) {
      return buildTree(x, .4 * en);}, 1);
  return node_pool.allocate(r[0], r[1], n, b);
}

bool far(node* a, node* b) {
  double rmax = max(a->radius(), b->radius());
  double r = (a->center() - b->center()).Length();
  return r >= (ALPHA * rmax);
}

struct interactions_count {
  long direct;
  long indirect;
  interactions_count() : direct(0), indirect(0) {}
  interactions_count(long a, long b) : direct(a), indirect(b) {}
  interactions_count operator+ (interactions_count b) {
    return interactions_count(direct + b.direct, indirect + b.indirect);}
};

using indirect_interaction = std::pair<node*, node*>;
using direct_interaction = std::pair<node*, node*>;

struct interaction_lists {
  sequence<indirect_interaction> indirect;
  sequence<direct_interaction> direct;
};

auto interaction_monoid = parlay::make_monoid(
  [](interaction_lists a, interaction_lists b) {
    return interaction_lists{parlay::append(std::move(a.indirect), std::move(b.indirect)),
                             parlay::append(std::move(a.direct), std::move(b.direct))};
  },
  interaction_lists{}
);

interaction_lists get_interactions(node* Left, node* Right) {
  if (far(Left, Right)) {
    return {{std::make_pair(Left, Right)}, {}};
  } else {
    if (!Left->leaf() && (Left->lmax() >= Right->lmax() || Right->leaf())) {
      auto [l, r] = parlay::par_do_reduce(
          [&]() { return get_interactions(Left->left, Right); },
          [&]() { return get_interactions(Left->right, Right); },
          interaction_monoid
      );
      return l;
    } else if (!Right->leaf()) {
      auto [l, r] = parlay::par_do_reduce(
          [&]() { return get_interactions(Left, Right->left); },
          [&]() { return get_interactions(Left, Right->right); },
          interaction_monoid
      );
      return l;
    } else { // both are leaves
      return {{}, {std::make_pair(Left, Right)}};
    }
  }
}

interaction_lists get_interactions(node* tr) {
  if (tr->leaf()) {
    return interaction_lists{};
  }
  auto [l, r, cross] = parlay::par_do_reduce(
      [&]() { return get_interactions(tr->left); },
      [&]() { return get_interactions(tr->right); },
      [&]() { return get_interactions(tr->left, tr->right); },
      interaction_monoid
  );
  return l;
}

void doIndirect(node* tr) {
  for (size_t i = 0; i < tr->indirectNeighbors.size(); i++)
    tr->OutExp->addTo(tr->indirectNeighbors[i]->InExp);
  if (!tr->leaf()) {
    parlay::par_do([&] () {doIndirect(tr->left);},
		   [&] () {doIndirect(tr->right);});
  }
}

void upSweep(node* tr) {
  if (tr->leaf()) {
    for (size_t i=0; i < tr->n; i++) {
      particle* P = tr->particles[i];
      tr->InExp->addTo(P->pt, P->mass);
    }
  } else {
    parlay::par_do([&] () {upSweep(tr->left);},
		   [&] () {upSweep(tr->right);});
    tr->InExp->addTo(tr->left->InExp);
    tr->InExp->addTo(tr->right->InExp);
  }
}

void downSweep(node* tr) {
  if (tr->leaf()) {
    for (size_t i=0; i < tr->n; i++) {
      particle* P = tr->particles[i];
      P->force = P->force + tr->OutExp->force(P->pt, P->mass);
    }
  } else {
    parlay::par_do([&] () {tr->left->OutExp->addTo(tr->OutExp);
	                   downSweep(tr->left);},
		   [&] () {tr->right->OutExp->addTo(tr->OutExp);
		           downSweep(tr->right);});
  }
}

parlay::sequence<node*> getLeaves_par(node* tr) {
  if (tr->leaf()) {
    return parlay::sequence<node*>{tr};
  }
  auto [left_leaves, right_leaves] = parlay::par_do_reduce(
    [&]() { return getLeaves_par(tr->left); },
    [&]() { return getLeaves_par(tr->right); },
    parlay::make_monoid(
      [](parlay::sequence<node*> a, parlay::sequence<node*> b) {
        return parlay::append(std::move(a), std::move(b));
      },
      parlay::sequence<node*>{}
    )
  );
  return left_leaves;
}

void direct(node* Left, node* ngh, parlay::slice<vect3d> hold_slice) {
  auto LP = (Left->particles).data();
  auto R = (ngh->particles_d).data();
  size_t nl = Left->n;
  size_t nr = ngh->n;
  std::fill(hold_slice.begin(), hold_slice.end(), vect3d(0.,0.,0.));

  for (size_t i=0; i < nl; i++) {
    vect3d frc(0.,0.,0.);
    particle pa = *LP[i];
    for (size_t j=0; j < nr; j++) {
      particle& pb = R[j];
      vect3d v = pb.pt - pa.pt;
      double r2 = v.dot(v);
      if (r2 == 0.0) continue;
      vect3d force = (v * (pa.mass * pb.mass / (r2*sqrt(r2))));
      hold_slice[j] = hold_slice[j] - force;
      frc = frc + force;
    }
    LP[i]->force = LP[i]->force + frc;
  }
}

void self(node* Tr) {
  auto PP = (Tr->particles).data();
  for (size_t i=0; i < Tr->n; i++) {
    particle* pa = PP[i];
    for (size_t j=i+1; j < Tr->n; j++) {
	particle* pb = PP[j];
	vect3d v = (pb->pt) - (pa->pt);
	double r2 = v.dot(v);
    if (r2 == 0.0) continue;
	vect3d force = (v * (pa->mass * pb->mass / (r2*sqrt(r2))));
	pb->force = pb->force - force;
	pa->force = pa->force + force;
      }
  }
}

void doDirect(node* a) {
  auto Leaves = getLeaves_par(a);
  size_t nleaves = Leaves.size();

  parlay::parallel_for (0, nleaves, [&] (size_t i) {
      auto& leaf = *Leaves[i];
      auto& neighbors = leaf.rightNeighbors;
      size_t rn = neighbors.size();

      auto neighbor_sizes = parlay::map(neighbors, [](const edge& e){ return e.first->n; });
      auto scan_res = parlay::scan_inclusive(neighbor_sizes);
      leaf.hold_offsets = std::move(scan_res.first);
      leaf.hold_offsets.insert(leaf.hold_offsets.begin(), 0);

      leaf.hold.resize(scan_res.second);

      parlay::parallel_for(0, rn, [&](size_t j) {
          auto ngh = neighbors[j].first;
          auto slice_to_fill = leaf.hold.cut(leaf.hold_offsets[j], leaf.hold_offsets[j+1]);
          direct(&leaf, ngh, slice_to_fill);
      }, 1);
  }, 1);

  parlay::parallel_for (0, nleaves, [&] (size_t i) {
    node* L = Leaves[i];
    for (size_t j = 0; j < L->leftNeighbors.size(); j++) {
      auto [u, v] = L->leftNeighbors[j];
      auto force_slice = u->hold.cut(u->hold_offsets[v], u->hold_offsets[v+1]);
      for (size_t k=0; k < L->n; k++)
	    L->particles[k]->force = L->particles[k]->force + force_slice[k];
    }}, 1);

  parlay::parallel_for (0, nleaves, [&] (size_t i) {self(Leaves[i]);});
}

void stepBH(sequence<particle*> &particles, double alpha) {
  timer t("CK nbody");
  size_t n = particles.size();
  TRglobal->precompute();

  parlay::parallel_for (0, n, [&] (size_t i) {
      particles[i]->force = vect3d(0.,0.,0.);});

  sequence<particle*> part_copy = particles;

  node* a = buildTree(part_copy, 0);
  t.next("build tree");

  upSweep(a);
  t.next("up sweep");

  auto all_interactions = get_interactions(a);
  interactions_count z(0,0);
  for (const auto& p : all_interactions.indirect) {
    p.first->indirectNeighbors.push_back(p.second);
    p.second->indirectNeighbors.push_back(p.first);
    z.indirect += 2;
  }
  for (auto& p : all_interactions.direct) {
    node* Left = p.first;
    node* Right = p.second;
    if (Right->n > Left->n) swap(Right,Left);
    size_t rn = Right->leftNeighbors.size();
    size_t ln = Left->rightNeighbors.size();
    Right->leftNeighbors.push_back(edge(Left,ln));
    Left->rightNeighbors.push_back(edge(Right,rn));
    z.direct += Right->n*Left->n;
  }
  t.next("interactions");

  doIndirect(a);
  t.next("do Indirect");

  downSweep(a);
  t.next("down sweep");

  doDirect(a);
  t.next("do Direct");

  cout << "Direct = " << (long) z.direct << " Indirect = " << z.indirect
       << " Boxes = " << getLeaves_par(a).size() << endl;
  if (CHECK) {
    cout << "  Sampled RMS Error = "<< check(particles) << endl;
    t.next("check");
  }
}

void nbody(sequence<particle*> &particles) {
  stepBH(particles, ALPHA); }

#include <iostream>
#include <vector>
#include "common/get_time.h"
#include "common/geometry.h"
#include "parlay/primitives.h"
#include "spherical.h"
#include "nbody.h"

using namespace std;
using parlay::sequence;
using vect3d = vect;

#define CHECK 1

// Following for 1e-6 accuracy
#define ALPHA 2.6
#define terms 12
#define BOXSIZE 250

// A temporary structure to hold particle data along with its original index.
// This allows us to reorder particles for locality while still being able
// to write the final forces back to the correct original positions.
struct indexed_particle {
  point pt;
  double mass;
  int original_idx;
};

double check(sequence<particle*> const &p) {
  size_t n = p.size();
  size_t nCheck = min<size_t>(n, 200);
  sequence<double> Err(nCheck);

  parlay::parallel_for (0, nCheck, [&] (size_t i) {
    size_t idx = parlay::hash64(i)%n;
    vect3d force(0.,0.,0.);
    for (size_t j=0; j < n; j++) {
      if (idx != j) {
        vect3d v = (p[j]->pt) - (p[idx]->pt);
        double r2 = v.dot(v);
        if (r2 > 0) {
          force = force + (v * (p[j]->mass * p[idx]->mass / (r2*sqrt(r2))));
        }
      }
    }
    double err = (force - p[idx]->force).Length()/force.Length();
    Err[i] = (std::isfinite(err)) ? err : 0.0;
    });
  double total = parlay::reduce(Err);
  return total/nCheck;
}

// *************************************************************
//    FORCE CALCULATIONS
// *************************************************************

struct innerExpansion {
  Transform<terms>* TR;
  complex<double> coefficients[terms*terms];
  point center;
  void addTo(point pt, double mass) { TR->P2Madd(coefficients, mass, center, pt); }
  void addTo(innerExpansion* y) { TR->M2Madd(coefficients, center, y->coefficients, y->center); }
  innerExpansion(Transform<terms>* _TR, point _center) : TR(_TR), center(_center) {
    for (size_t i=0; i < terms*terms; i++) coefficients[i] = 0.0;
  }
  vect3d force(point y, double mass) {
    vect3d result; double potential;
    TR->M2P(potential, result, y, coefficients, center);
    return result*mass;
  }
};

parlay::type_allocator<innerExpansion> inner_pool;

struct outerExpansion {
  Transform<terms>* TR;
  complex<double> coefficients[terms*terms];
  point center;
  void addTo(innerExpansion* y) { TR->M2Ladd(coefficients, center, y->coefficients, y->center); }
  void addTo(outerExpansion* y) { TR->L2Ladd(coefficients, center, y->coefficients, y->center); }
  vect3d force(point y, double mass) {
    vect3d result; double potential;
    TR->L2P(potential, result, y, coefficients, center);
    return result*mass;
  }
  outerExpansion(Transform<terms>* _TR, point _center) : TR(_TR), center(_center) {
    for (size_t i=0; i < terms*terms; i++) coefficients[i] = 0.0;
  }
};

parlay::type_allocator<outerExpansion> outer_pool;

Transform<terms>* TRglobal = new Transform<terms>();

using box = pair<point,point>;

struct node {
  using edge = pair<node*, size_t>;
  node* left;
  node* right;
  parlay::slice<indexed_particle> particles;
  size_t n;
  box b;
  innerExpansion* InExp;
  outerExpansion* OutExp;
  vector<node*> indirectNeighbors;
  vector<edge> leftNeighbors;
  vector<edge> rightNeighbors;
  sequence<sequence<vect3d>> hold;
  bool leaf() {return left == NULL;}
  point center() { return b.first + (b.second-b.first)/2.0;}
  double radius() { return (b.second - b.first).Length()/2.0;}
  double lmax() { vect3d d = b.second-b.first; return max(d.x,max(d.y,d.z)); }
  void allocateExpansions() {
    InExp = inner_pool.allocate(TRglobal, center());
    OutExp = outer_pool.allocate(TRglobal, center());
  }
  node(node* L, node* R, parlay::slice<indexed_particle> p, box _b)
    : left(L), right(R), particles(p), n(p.size()), b(_b) {
    allocateExpansions();
  }
  node(parlay::slice<indexed_particle> P, box _b)
    : left(NULL), right(NULL), particles(P), n(P.size()), b(_b) {
    allocateExpansions();
  }
};

parlay::type_allocator<node> node_pool;

size_t numLeaves(node* tr) {
  if (tr->leaf()) return 1;
  auto [l, r] = parlay::par_do_reduce([&]() { return numLeaves(tr->left); },
                                      [&]() { return numLeaves(tr->right); },
                                      parlay::plus<size_t>());
  return l + r;
}

node* buildTree(parlay::slice<indexed_particle> p_slice, size_t effective_size) {
  size_t n = p_slice.size();
  size_t en = std::max(effective_size, n);

  auto minmax = [](box a, box b) {
    return box(a.first.minCoords(b.first), a.second.maxCoords(b.second));
  };
  auto get_box = [](const indexed_particle& p) { return box(p.pt, p.pt); };
  box b = parlay::reduce(parlay::delayed_map(p_slice, get_box),
                         parlay::make_monoid(minmax, get_box(p_slice[0])));

  if (en < BOXSIZE || n < 10)
    return node_pool.allocate(p_slice, b);

  vect3d d = b.second-b.first;
  int split_dim = (d.x > d.y && d.x > d.z) ? 0 : (d.y > d.z ? 1 : 2);
  double split_val = (b.first[split_dim] + b.second[split_dim])/2.0;

  auto middle = parlay::partition(p_slice, [&](const auto& p) { return p.pt[split_dim] < split_val; });
  auto s1 = p_slice.cut(0, middle - p_slice.begin());
  auto s2 = p_slice.cut(middle - p_slice.begin(), p_slice.size());

  node *L, *R;
  parlay::par_do(
    [&]() { L = buildTree(s1, s1.size()); },
    [&]() { R = buildTree(s2, s2.size()); }
  );
  return node_pool.allocate(L, R, p_slice, b);
}

bool far(node* a, node* b) {
  double rmax = max(a->radius(), b->radius());
  double r = (a->center() - b->center()).Length();
  return r >= (ALPHA * rmax);
}

struct interactions_count {
  long direct; long indirect;
  interactions_count() : direct(0), indirect(0) {}
  interactions_count(long a, long b) : direct(a), indirect(b) {}
  interactions_count operator+ (interactions_count b) { return interactions_count(direct + b.direct, indirect + b.indirect); }
};

interactions_count interactions(node* Left, node* Right) {
  if (far(Left,Right)) {
    Left->indirectNeighbors.push_back(Right);
    Right->indirectNeighbors.push_back(Left);
    return interactions_count(0,2);
  } else {
    if (!Left->leaf() && (Left->lmax() >= Right->lmax() || Right->leaf())) {
      return interactions(Left->left, Right) + interactions(Left->right, Right);
    } else if (!Right->leaf()) {
      return interactions(Left, Right->left) + interactions(Left, Right->right);
    } else { // both are leaves
      if (Right->n > Left->n) swap(Right,Left);
      size_t rn = Right->leftNeighbors.size();
      size_t ln = Left->rightNeighbors.size();
      Right->leftNeighbors.push_back({Left,ln});
      Left->rightNeighbors.push_back({Right,rn});
      return interactions_count(Right->n*Left->n,0);
    }
  }
}

interactions_count interactions(node* tr) {
  if (tr->leaf()) return interactions_count(0,0);
  auto [x, y] = parlay::par_do_reduce(
      [&]() { return interactions(tr->left); },
      [&]() { return interactions(tr->right); },
      parlay::plus<interactions_count>());
  interactions_count z = interactions(tr->left,tr->right);
  return x + y + z;
}

void doIndirect(node* tr) {
  for (auto neighbor : tr->indirectNeighbors)
    tr->OutExp->addTo(neighbor->InExp);
  if (!tr->leaf()) {
    parlay::par_do([&] () {doIndirect(tr->left);},
                   [&] () {doIndirect(tr->right);});
  }
}

void upSweep(node* tr) {
  if (tr->leaf()) {
    for (const auto& p : tr->particles) {
      tr->InExp->addTo(p.pt, p.mass);
    }
  } else {
    parlay::par_do([&] () {upSweep(tr->left);},
                   [&] () {upSweep(tr->right);});
    tr->InExp->addTo(tr->left->InExp);
    tr->InExp->addTo(tr->right->InExp);
  }
}

void downSweep(node* tr, parlay::sequence<vect3d>& forces) {
  if (tr->leaf()) {
    for (const auto& p : tr->particles) {
      forces[p.original_idx] = forces[p.original_idx] + tr->OutExp->force(p.pt, p.mass);
    }
  } else {
    parlay::par_do([&] () {tr->left->OutExp->addTo(tr->OutExp);
                           downSweep(tr->left, forces);},
                   [&] () {tr->right->OutExp->addTo(tr->OutExp);
                           downSweep(tr->right, forces);});
  }
}

void getLeaves_recursive(node* tr, parlay::slice<node**> out) {
  if (tr->leaf()) {
    out[0] = tr;
    return;
  }
  size_t l_leaves = numLeaves(tr->left);
  parlay::par_do(
    [&]() { getLeaves_recursive(tr->left, out.cut(0, l_leaves)); },
    [&]() { getLeaves_recursive(tr->right, out.cut(l_leaves, out.size())); }
  );
}

auto direct(node* Left, node* ngh, parlay::sequence<vect3d>& forces) {
  auto LP = Left->particles;
  auto RP = ngh->particles;
  size_t nl = LP.size();
  size_t nr = RP.size();
  parlay::sequence<vect3d> hold(nr, vect3d(0.,0.,0.));
  for (size_t i=0; i < nl; i++) {
    vect3d frc(0.,0.,0.);
    const auto& pa = LP[i];
    double pa_mass = pa.mass;
    point pa_pt = pa.pt;
    for (size_t j=0; j < nr; j++) {
      const auto& pb = RP[j];
      vect3d v = pb.pt - pa_pt;
      double r2 = v.dot(v);
      if (r2 > 1e-12) { // Avoid self-interaction and div-by-zero
        double inv_r3 = 1.0 / (r2 * sqrt(r2));
        vect3d force = v * (pa_mass * pb.mass * inv_r3);
        hold[j] = hold[j] - force;
        frc = frc + force;
      }
    }
    forces[pa.original_idx] = forces[pa.original_idx] + frc;
  }
  return hold;
}

void self(node* Tr, parlay::sequence<vect3d>& forces) {
  auto PP = Tr->particles;
  size_t n = PP.size();
  for (size_t i=0; i < n; i++) {
    const auto& pa = PP[i];
    double pa_mass = pa.mass;
    point pa_pt = pa.pt;
    int pa_idx = pa.original_idx;
    for (size_t j=i+1; j < n; j++) {
      const auto& pb = PP[j];
      vect3d v = pb.pt - pa_pt;
      double r2 = v.dot(v);
      if (r2 > 1e-12) {
        double inv_r3 = 1.0 / (r2 * sqrt(r2));
        vect3d force = v * (pa_mass * pb.mass * inv_r3);
        forces[pb.original_idx] = forces[pb.original_idx] - force;
        forces[pa_idx] = forces[pa_idx] + force;
      }
    }
  }
}

void doDirect(node* a, parlay::sequence<vect3d>& forces) {
  size_t nleaves = numLeaves(a);
  if (nleaves == 0) return;
  sequence <node*> Leaves(nleaves);
  getLeaves_recursive(a, parlay::make_slice(Leaves));

  parlay::parallel_for (0, nleaves, [&] (size_t i) {
    node* L = Leaves[i];
    size_t rn = L->rightNeighbors.size();
    L->hold = parlay::tabulate(rn, [&](size_t j) {
      return direct(L, L->rightNeighbors[j].first, forces);
    });
  });

  parlay::parallel_for (0, nleaves, [&] (size_t i) {
    node* L = Leaves[i];
    for (size_t j = 0; j < L->leftNeighbors.size(); j++) {
      auto [u, v] = L->leftNeighbors[j];
      const auto& neighbor_hold = u->hold[v];
      for (size_t k = 0; k < L->particles.size(); k++) {
        forces[L->particles[k].original_idx] = forces[L->particles[k].original_idx] + neighbor_hold[k];
      }
    }
  });

  parlay::parallel_for (0, nleaves, [&] (size_t i) {self(Leaves[i], forces);});
}

void stepBH(parlay::sequence<indexed_particle>& p_indexed, parlay::sequence<vect3d>& forces, double alpha) {
  timer t("CK nbody");
  TRglobal->precompute();

  node* a = buildTree(parlay::make_slice(p_indexed), 0);
  t.next("build tree");

  upSweep(a);
  t.next("up sweep");

  interactions_count z = interactions(a);
  t.next("interactions");

  doIndirect(a);
  t.next("do Indirect");

  downSweep(a, forces);
  t.next("down sweep");

  doDirect(a, forces);
  t.next("do Direct");

  cout << "Direct = " << (long) z.direct << " Indirect = " << z.indirect
       << " Boxes = " << numLeaves(a) << endl;
}

void nbody(sequence<particle*> &particles) {
  size_t n = particles.size();
  if (n == 0) return;

  // 1. Copy particles to a new sequence of indexed_particles for better locality.
  //    This allows us to reorder them in-place during the tree build.
  auto p_indexed = parlay::tabulate(n, [&](size_t i) -> indexed_particle {
    return {particles[i]->pt, particles[i]->mass, (int)i};
  });

  // 2. Create a sequence to store the calculated forces.
  auto forces = parlay::sequence<vect3d>::from_function(n, [](size_t) {
    return vect3d(0.,0.,0.);
  });

  // 3. Run the main algorithm.
  stepBH(p_indexed, forces, ALPHA);

  // 4. Copy the calculated forces back to the original particle sequence.
  parlay::parallel_for(0, n, [&](size_t i) {
    particles[i]->force = forces[i];
  });

  if (CHECK) {
    timer t("check", false);
    cout << "  Sampled RMS Error = "<< check(particles) << endl;
    t.next("check");
  }
}

#include <iostream>
#include <vector>
#include "common/get_time.h"
#include "common/geometry.h"
#include "parlay/primitives.h"
#include "spherical.h"
#include "nbody.h"

using namespace std;
using parlay::sequence;
using vect3d = vect;

#define CHECK 1

// Following for 1e-3 accuracy
//#define ALPHA 2.2
//#define terms 7
//#define BOXSIZE 150

// Following for 1e-6 accuracy (2.5x slower than above)
#define ALPHA 2.6
#define terms 12  
#define BOXSIZE 250

// Following for 1e-9 accuracy (2.2x slower than above)
// #define ALPHA 3.0
// #define terms 17
// #define BOXSIZE 550

// Following for 1e-12 accuracy (1.8x slower than above)
//#define ALPHA 3.2
//#define terms 22
//#define BOXSIZE 700

double check(sequence<particle*> const &p) {
  size_t n = p.size();
  size_t nCheck = min<size_t>(n, 200);
  sequence<double> Err(nCheck);

  parlay::parallel_for (0, nCheck, [&] (size_t i) {
    size_t idx = parlay::hash64(i)%n;
    vect3d force(0.,0.,0.);
    for (size_t j=0; j < n; j++) {
      if (idx != j) {
	vect3d v = (p[j]->pt) - (p[idx]->pt);
	double r2 = v.dot(v);
    if (r2 > 0)
	    force = force + (v * (p[j]->mass * p[idx]->mass / (r2*sqrt(r2))));
      }
    }
    double l_force = force.Length();
    if (l_force > 0)
      Err[i] = (force - p[idx]->force).Length()/l_force;
    else
      Err[i] = (force - p[idx]->force).Length();
    });
  double total = parlay::reduce(Err);
  return total/nCheck;
}

// *************************************************************
//    FORCE CALCULATIONS
// *************************************************************

// *************************************************************
//  Inner expansions (also called multipole expansion)
//  The spherical harmonic expansion of a set of nearby points around
//  a center for estimating forces at a distance.
// *************************************************************
struct innerExpansion {
  Transform<terms>* TR;
  complex<double> coefficients[terms*terms];
  point center;
  void addTo(point pt, double mass) {
    TR->P2Madd(coefficients, mass, center, pt);
  }
  void addTo(innerExpansion* y) {
    TR->M2Madd(coefficients, center, y->coefficients, y->center);
  }
  innerExpansion(Transform<terms>* _TR, point _center) : TR(_TR), center(_center) {
    for (size_t i=0; i < terms*terms; i++) coefficients[i] = 0.0;
  }
  vect3d force(point y, double mass) {
    vect3d result;
    double potential;
    TR->M2P(potential, result, y, coefficients, center);
    result = result*mass;
    return result;
  }
  innerExpansion() {}
};

parlay::type_allocator<innerExpansion> inner_pool;

// *************************************************************
//  Outer expansions (also called local)
//  The inverse spherical harmonic expansion of a set of distant
//  points around a center for estimating forces for nearby points.
// *************************************************************
struct outerExpansion {
  Transform<terms>* TR;
  complex<double> coefficients[terms*terms];
  point center;
  void addTo(innerExpansion* y) {
    TR->M2Ladd(coefficients, center, y->coefficients, y->center);}
  void addTo(outerExpansion* y) {
    TR->L2Ladd(coefficients, center, y->coefficients, y->center);
  }
  vect3d force(point y, double mass) {
    vect3d result;
    double potential;
    TR->L2P(potential, result, y, coefficients, center);
    result = result*mass;
    return result;
  }
  outerExpansion(Transform<terms>* _TR, point _center) : TR(_TR), center(_center) {
    for (size_t i=0; i < terms*terms; i++) coefficients[i] = 0.0;
  }
  outerExpansion() {}
};

parlay::type_allocator<outerExpansion> outer_pool;

// Set global constants for spherical harmonics
Transform<terms>* TRglobal = new Transform<terms>();

using box = pair<point,point>;
using vect3d = typename point::vector;

// *************************************************************
//  A node in the CK tree
//  Either a leaf (if children are null) or internal node.
//  If a leaf contains a set of points
//  If an internal node contains a left and right child as is
//  augmented with first inner than outer expansions.
//  The leftNeighbors and rightNeighbors contain edges in the CK
//  well separated decomposition.
// *************************************************************
struct node {
  using edge = pair<node*, size_t>;
  node* left;
  node* right;
  sequence<particle*> particles;
  sequence<particle> particles_d;
  size_t n;
  size_t leaf_count;
  box b;
  innerExpansion* InExp;
  outerExpansion* OutExp;
  vector<node*> indirectNeighbors;
  vector<edge> leftNeighbors;
  vector<edge> rightNeighbors;
  sequence<sequence<vect3d>> hold;
  bool leaf() {return left == NULL;}
  node() {}
  point center() { return b.first + (b.second-b.first)/2.0;}
  double radius() { return (b.second - b.first).Length()/2.0;}
  double lmax() {
    vect3d d = b.second-b.first;
    return max(d.x,max(d.y,d.z));
  }
  void allocateExpansions() {
    InExp = inner_pool.allocate(TRglobal, center());
    OutExp = outer_pool.allocate(TRglobal, center());
  }
  node(node* L, node* R, size_t n, box b)
    : left(L), right(R), n(n), leaf_count(L->leaf_count + R->leaf_count), b(b) {
    allocateExpansions();
  }
  node(parlay::sequence<particle*> P, box b) 
    : left(NULL), right(NULL), particles(std::move(P)), n(particles.size()), leaf_count(1), b(b) {
    particles_d = parlay::map(particles, [] (auto p) {return *p;});
    allocateExpansions();
  }
};

parlay::type_allocator<node> node_pool;

using edge = pair<node*, size_t>;

// *************************************************************
//  Build the CK tree
//  Similar to a kd-tree but always split along widest dimension
//  of the points instead of the next round-robin dimension.
// *************************************************************
template <typename Particles>
node* buildTree(Particles& particles, size_t effective_size) {

  size_t n = particles.size();
  size_t en = std::max(effective_size, n);

  auto minmax = [] (box a, box b) {
    return box((a.first).minCoords(b.first),
	       (a.second).maxCoords(b.second));};
  auto pairs = parlay::delayed_map(particles, [&] (particle* p) {
      return box(p->pt, p->pt);});
  box b = parlay::reduce(pairs, parlay::make_monoid(minmax,pairs[0]));

  if (en < BOXSIZE || n < 10) 
    return node_pool.allocate(parlay::to_sequence(particles), b);

  size_t d = 0;
  double Delta = 0.0;
  for (int i=0; i < 3; i++) {
    if (b.second[i] - b.first[i] > Delta) {
      d = i;
      Delta = b.second[i] - b.first[i];
    }
  }

  double splitpoint = (b.first[d] + b.second[d])/2.0;

  auto isLeft = parlay::delayed_map(particles, [&] (particle* p) {
      return std::pair(p->pt[d] < splitpoint, p);});
  auto foo = parlay::group_by_index(isLeft, 2);
  particles.clear();

  auto r = parlay::map(foo, [&] (auto& x) {
      return buildTree(x, .4 * en);}, 1);
  return node_pool.allocate(r[0], r[1], n, b);
}


// *************************************************************
//  Determine if a point is far enough to use approximation.
// *************************************************************
bool far(node* a, node* b) {
  double rmax = max(a->radius(), b->radius());
  double r = (a->center() - b->center()).Length();
  return r >= (ALPHA * rmax);
}

// *************************************************************
// Used to count the number of interactions, just for performance
// statistics not needed for correctness.
// *************************************************************
struct interactions_count {
  long direct;
  long indirect;
  interactions_count() : direct(0), indirect(0) {}
  interactions_count(long a, long b) : direct(a), indirect(b) {}
  interactions_count operator+ (interactions_count b) {
    return interactions_count(direct + b.direct, indirect + b.indirect);}
};

// *************************************************************
// The following two functions are the core of the CK method.
// They calculate the "well separated decomposition" of the points.
// *************************************************************
interactions_count interactions(node* Left, node* Right) {
  if (far(Left,Right)) {
    Left->indirectNeighbors.push_back(Right); 
    Right->indirectNeighbors.push_back(Left); 
    return interactions_count(0,2);
  } else {
    if (!Left->leaf() && (Left->lmax() >= Right->lmax() || Right->leaf())) {
      interactions_count x, y;
      parlay::par_do([&]() { x = interactions(Left->left, Right); },
                     [&]() { y = interactions(Left->right, Right); });
      return x + y;
    } else if (!Right->leaf()) {
      interactions_count x, y;
      parlay::par_do([&]() { x = interactions(Left, Right->left); },
                     [&]() { y = interactions(Left, Right->right); });
      return x + y;
    } else { // both are leaves
      if (Right->n > Left->n) swap(Right,Left);
      size_t rn = Right->leftNeighbors.size();
      size_t ln = Left->rightNeighbors.size();
      Right->leftNeighbors.push_back(edge(Left,ln)); 
      Left->rightNeighbors.push_back(edge(Right,rn));
      return interactions_count(Right->n*Left->n,0);
    }
  }
}

interactions_count interactions(node* tr) {
  if (tr->leaf()) return interactions_count(0,0);
  interactions_count x, y; 
  parlay::par_do([&] () {x = interactions(tr->left);},
                 [&] () {y = interactions(tr->right);});
  interactions_count z = interactions(tr->left,tr->right);
  return x + y + z;
}

// *************************************************************
// Translate from inner (multipole) expansion to outer (local)
// expansion along all far-field interactions.
// *************************************************************
void doIndirect(node* tr) {
  for (size_t i = 0; i < tr->indirectNeighbors.size(); i++) 
    tr->OutExp->addTo(tr->indirectNeighbors[i]->InExp);
  if (!tr->leaf()) {
    parlay::par_do([&] () {doIndirect(tr->left);},
		   [&] () {doIndirect(tr->right);});
  }
}

// *************************************************************
// Translate and accumulate inner (multipole) expansions up the tree,
// including translating particles to expansions at the leaves.
// *************************************************************
void upSweep(node* tr) {
  if (tr->leaf()) {
    for (size_t i=0; i < tr->n; i++) {
      particle* P = tr->particles[i];
      tr->InExp->addTo(P->pt, P->mass);
    }
  } else {
    parlay::par_do([&] () {upSweep(tr->left);},
		   [&] () {upSweep(tr->right);});
    tr->InExp->addTo(tr->left->InExp);
    tr->InExp->addTo(tr->right->InExp);
  }
}

// *************************************************************
// Translate and accumulate outer (local) expansions down the tree,
// including applying them to all particles at the leaves.
// *************************************************************
void downSweep(node* tr) {
  if (tr->leaf()) {
    for (size_t i=0; i < tr->n; i++) {
      particle* P = tr->particles[i];
      P->force = P->force + tr->OutExp->force(P->pt, P->mass);
    }
  } else {
    parlay::par_do([&] () {tr->left->OutExp->addTo(tr->OutExp);
	                   downSweep(tr->left);},
		   [&] () {tr->right->OutExp->addTo(tr->OutExp);
		           downSweep(tr->right);});
  }
}

// puts the leaves of tree tr into the array Leaves in left to right order (parallel)
void getLeaves_par(node* tr, parlay::slice<node**> leaves_slice) {
  if (leaves_slice.empty()) return;
  if (tr->leaf()) {
    leaves_slice[0] = tr;
    return;
  }
  auto left_slice = leaves_slice.cut(0, tr->left->leaf_count);
  auto right_slice = leaves_slice.cut(tr->left->leaf_count, tr->leaf_count);
  parlay::par_do(
    [&]() { getLeaves_par(tr->left, left_slice); },
    [&]() { getLeaves_par(tr->right, right_slice); }
  );
}

// *************************************************************
// Calculates the direct forces between all pairs of particles in two nodes.
// Accumulates forces for Left locally, and returns forces for ngh in hold.
// This improves cache performance and avoids race conditions.
// *************************************************************
auto direct(node* Left, node* ngh) {
  auto& L_data = Left->particles_d;
  auto& R_data = ngh->particles_d;
  size_t nl = L_data.size();
  size_t nr = R_data.size();

  parlay::sequence<vect3d> hold(nr, vect3d(0.,0.,0.));
  parlay::sequence<vect3d> left_forces(nl, vect3d(0.,0.,0.));

  for (size_t i = 0; i < nl; i++) {
    const auto& pa = L_data[i];
    for (size_t j = 0; j < nr; j++) {
      const auto& pb = R_data[j];
      vect3d v = pb.pt - pa.pt;
      double r2 = v.dot(v);
      if (r2 > 1e-20) { // Avoid division by zero for duplicate points
        double inv_r = 1.0 / sqrt(r2);
        double s = pa.mass * pb.mass * inv_r * inv_r * inv_r;
        vect3d force = v * s; // Force on pa from pb
        hold[j] = hold[j] - force;
        left_forces[i] = left_forces[i] + force;
      }
    }
  }

  // Write back accumulated forces to original particles
  for(size_t i = 0; i < nl; ++i) {
    Left->particles[i]->force = Left->particles[i]->force + left_forces[i];
  }

  return hold;
}

// *************************************************************
// Calculates local forces within a leaf
// *************************************************************
void self(node* Tr) {
  auto& P_data = Tr->particles_d;
  size_t n = P_data.size();
  if (n < 2) return;

  parlay::sequence<vect3d> forces(n, vect3d(0.,0.,0.));

  for (size_t i = 0; i < n; i++) {
    for (size_t j = i + 1; j < n; j++) {
      const auto& pa = P_data[i];
      const auto& pb = P_data[j];
      vect3d v = pb.pt - pa.pt;
      double r2 = v.dot(v);
      if (r2 > 1e-20) { // Avoid division by zero
        double inv_r = 1.0 / sqrt(r2);
        double s = pa.mass * pb.mass * inv_r * inv_r * inv_r;
        vect3d force = v * s;
        forces[i] = forces[i] + force;
        forces[j] = forces[j] - force;
      }
    }
  }

  // Write back accumulated forces
  for(size_t i = 0; i < n; ++i) {
    Tr->particles[i]->force = Tr->particles[i]->force + forces[i];
  }
}


// *************************************************************
// Calculates the direct interactions between and within leaves.
// Since the forces are symmetric, this calculates the force on one
// side (rightNeighbors) while storing them away (in hold).
// It then goes over the other side (leftNeighbors) picking up
// the precalculated results (from hold).
// It does not update both sides immediately since that would 
// generate a race condition.
// *************************************************************
void doDirect(node* a) {
  size_t nleaves = a->leaf_count;
  sequence <node*> Leaves(nleaves);
  getLeaves_par(a, parlay::make_slice(Leaves));

  // calculates interactions and put neighbor's results in hold
  parlay::parallel_for (0, nleaves, [&] (size_t i) {
      size_t rn = Leaves[i]->rightNeighbors.size();
      Leaves[i]->hold = parlay::tabulate(rn, [&] (size_t j) {
	  return direct(Leaves[i], Leaves[i]->rightNeighbors[j].first);}, rn);}, 1);

  // picks up results from neighbors that were left in hold
  parlay::parallel_for (0, nleaves, [&] (size_t i) {
    for (size_t j = 0; j < Leaves[i]->leftNeighbors.size(); j++) {
      node* L = Leaves[i];
      auto [u, v] = L->leftNeighbors[j];
      for (size_t k=0; k < L->n; k++) 
	L->particles[k]->force = L->particles[k]->force + u->hold[v][k];
    }}, 1);

  // calculate forces within a node
  parlay::parallel_for (0, nleaves, [&] (size_t i) {self(Leaves[i]);}, 1);
}

// *************************************************************
// STEP
// takes one step and places forces in particles[i]->force
// *************************************************************
void stepBH(sequence<particle*> &particles, double alpha) {
  timer t("CK nbody");
  size_t n = particles.size();
  TRglobal->precompute();

  parlay::parallel_for (0, n, [&] (size_t i) {
      particles[i]->force = vect3d(0.,0.,0.);});

  sequence<particle*> part_copy = particles;

  // build the CK tree
  node* a = buildTree(part_copy, 0);
  t.next("build tree");

  // Sweep up the tree calculating multipole expansions for each node
  upSweep(a);
  t.next("up sweep");

  // Determine all far-field interactions using the CK method
  interactions_count z = interactions(a);
  t.next("interactions");

  // Translate multipole to local expansions along the far-field
  // interactions
  doIndirect(a);
  t.next("do Indirect");

  // Translate the local expansions down the tree to the leaves
  downSweep(a);
  t.next("down sweep");

  // Add in all the direct (near-field) interactions
  doDirect(a);
  t.next("do Direct");

  cout << "Direct = " << (long) z.direct << " Indirect = " << z.indirect
       << " Boxes = " << a->leaf_count << endl;
  if (CHECK) {
    cout << "  Sampled RMS Error = "<< check(particles) << endl;
    t.next("check");
  }
}

void nbody(sequence<particle*> &particles) { 
  stepBH(particles, ALPHA); }

